# Auto-detect the correct venv python — works for both python3.14 and python3
def _find_python() -> str:
    for name in ("python3.14", "python3.13", "python3.12", "python3.11", "python3.10", "python3.9", "python3", "python"):
        p = ROOT / ".venv" / "bin" / name
        if p.exists():
            return str(p)
    return "python3"  # fallback to system python3

