async def send_menu(target, text: str = "⚡ *What's next?*"):
    """
    Send the quick-action menu as a fresh message after a task completes.
    target = a Telegram Message object (from update.message or query.message).
    """
    try:
        await target.reply_text(
            text,
            parse_mode="Markdown",
            reply_markup=_quick_menu_keyboard(),
        )
    except Exception as e:
        log.warning("send_menu failed: %s", e)


async def quick_menu_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle taps on the quick-action menu buttons."""
    query = update.callback_query
    if not query:
        return
    if not is_allowed(update):
        await query.answer("⛔ Not authorized.", show_alert=True)
        return
    await query.answer()

    action = query.data[len("qm:"):]
    msg    = query.message

    # Remove the keyboard so the button disappears after tapping
    try:
        await query.edit_message_reply_markup(reply_markup=None)
    except Exception:
        pass

    if action == "batch":
        await _qm_batch(msg, context)
    elif action == "upload":
        await _start_upload_flow(msg, context)
    elif action == "schedule":
        await msg.reply_text("Tap /schedule to open the scheduler.")
    elif action == "preview":
        await _qm_preview(msg, context)
    elif action == "status":
        await _qm_status(msg)
    elif action == "queue":
        await _qm_queue(msg)
    elif action == "tagboost":
        await msg.reply_text("Tap /tagboost to auto-apply SEO tags, or /tags to pick one beat.")
    elif action == "analytics":
        await _qm_analytics(msg)
    elif action == "social":
        await _qm_social(msg, context)
    elif action == "ai":
        await msg.reply_text("🤖 Just type your question and I'll answer it.")
    elif action == "airbit":
        await _start_airbit_flow(msg, context)
    elif action == "tools":
        await msg.reply_text("Tap /tools to open the toolkit.")


async def cmd_social(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/social — Post beats to TikTok, Instagram, and YouTube Shorts."""
    if not is_allowed(update):
        return await deny(update)
    await _qm_social(update.message, context)


async def _qm_social(msg, context):
    """Quick-menu social — show rendered beats to post to TikTok, Instagram & YT Shorts."""
    rendered = sorted(
        f for f in (ROOT / "output").glob("*.mp4")
        if _is_render_mp4(f)
    )
    if not rendered:
        await msg.reply_text("📭 No rendered videos yet. Render some beats first.")
        return

    # Build beat picker — each beat gets a button
    PAGE = 10
    stems = [f.stem for f in rendered]
    rows = []
    for stem in stems[:PAGE]:
        title = stem.replace("_", " ").title()[:25]
        rows.append([InlineKeyboardButton(
            f"📱 {title}",
            callback_data=f"socpick:beat:{stem}"[:64],
        )])
    if len(stems) > PAGE:
        rows.append([InlineKeyboardButton(
            f"📱 All {len(stems)} Beats",
            callback_data="socpick:all:0",
        )])
    rows.append([InlineKeyboardButton(
        f"📱 Post ALL to All 3",
        callback_data="socpick:allboth:0",
    )])
    rows.append([InlineKeyboardButton("❌ Cancel", callback_data="socpick:cancel")])
    kb = InlineKeyboardMarkup(rows)
    await msg.reply_text(
        f"📱 *Post to Social Media* — pick a beat ({len(stems)} rendered):",
        parse_mode="Markdown",
        reply_markup=kb,
    )


async def socpick_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle socpick:{action}:{param} — social media beat picker from quick menu."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query:
            await query.answer("⛔", show_alert=True)
        return
    await query.answer()

    try:
        await _socpick_inner(update, context, query)
    except Exception as e:
        log.exception("socpick_callback crashed: %s", e)
        try:
            await query.message.reply_text(f"⚠️ Social picker error: {e}")
        except Exception:
            pass


async def _socpick_inner(update, context, query):
    data = query.data
    parts = data.split(":")
    if len(parts) < 2:
        return

    action = parts[1]
    param = parts[2] if len(parts) > 2 else ""

    # Remove keyboard
    try:
        await query.edit_message_reply_markup(reply_markup=None)
    except Exception:
        pass

    if action == "cancel":
        await safe_edit(query.message, "❌ Social posting cancelled.")
        return

    if action == "beat":
        # Single beat — show platform picker
        stem = param
        _social_kb = InlineKeyboardMarkup([
            [
                InlineKeyboardButton("🎵 TikTok", callback_data=f"social:post:tt:{stem}"[:64]),
                InlineKeyboardButton("📸 Instagram", callback_data=f"social:post:ig:{stem}"[:64]),
            ],
            [
                InlineKeyboardButton("🎬 YT Shorts", callback_data=f"social:post:shorts:{stem}"[:64]),
                InlineKeyboardButton("🎵+📸 TT + IG", callback_data=f"social:post:both:{stem}"[:64]),
            ],
            [
                InlineKeyboardButton("📱 All 3", callback_data=f"social:post:all:{stem}"[:64]),
                InlineKeyboardButton("⏭ Skip", callback_data=f"social:skip:{stem}"[:64]),
            ],
        ])
        title = stem.replace("_", " ").title()
        await query.message.reply_text(
            f"📱 Post *{esc(title)}* to social media?",
            parse_mode="Markdown",
            reply_markup=_social_kb,
        )
        return

    if action == "all":
        # Show full list with pagination
        rendered = sorted(
            f.stem for f in (ROOT / "output").glob("*.mp4")
            if _is_render_mp4(f)
        )
        page = int(param) if param.isdigit() else 0
        PAGE = 15
        total_pages = max(1, (len(rendered) + PAGE - 1) // PAGE)
        page = max(0, min(page, total_pages - 1))
        chunk = rendered[page * PAGE : page * PAGE + PAGE]

        rows = []
        for stem in chunk:
            title = stem.replace("_", " ").title()[:25]
            rows.append([InlineKeyboardButton(
                f"📱 {title}",
                callback_data=f"socpick:beat:{stem}"[:64],
            )])
        nav = []
        if page > 0:
            nav.append(InlineKeyboardButton("⬅️", callback_data=f"socpick:all:{page - 1}"))
        nav.append(InlineKeyboardButton(f"{page+1}/{total_pages}", callback_data="socpick:noop"))
        if page < total_pages - 1:
            nav.append(InlineKeyboardButton("➡️", callback_data=f"socpick:all:{page + 1}"))
        rows.append(nav)
        rows.append([InlineKeyboardButton("❌ Cancel", callback_data="socpick:cancel")])
        await query.message.reply_text(
            f"📱 Pick a beat to post ({len(rendered)} total):",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(rows),
        )
        return

    if action == "allboth":
        # Post all rendered beats to both platforms
        rendered = sorted(
            f.stem for f in (ROOT / "output").glob("*.mp4")
            if _is_render_mp4(f)
        )
        if not rendered:
            await query.message.reply_text("📭 No rendered beats found.")
            return

        _batch_key = f"sbatch_{int(time.time())}_{os.urandom(3).hex()}"
        _SOCIAL_BATCH_STEMS[_batch_key] = rendered
        _batch_kb = InlineKeyboardMarkup([
            [InlineKeyboardButton("🎵 All to TikTok", callback_data=f"social:batch:tt:{_batch_key}"[:64])],
            [InlineKeyboardButton("📸 All to Instagram", callback_data=f"social:batch:ig:{_batch_key}"[:64])],
            [InlineKeyboardButton("🎬 All to YT Shorts", callback_data=f"social:batch:shorts:{_batch_key}"[:64])],
            [InlineKeyboardButton("📱 All to All 3", callback_data=f"social:batch:all:{_batch_key}"[:64])],
            [InlineKeyboardButton("⏭ Skip", callback_data="social:batch:skip:_")],
        ])
        await query.message.reply_text(
            f"📱 Post all {len(rendered)} beats to social media?",
            parse_mode="Markdown",
            reply_markup=_batch_kb,
        )
        return


async def _qm_batch(msg, context):
    """Quick-menu batch trigger — same logic as cmd_batch but uses msg directly."""
    beats   = sorted(list((ROOT / "beats").glob("*.mp3")) + list((ROOT / "beats").glob("*.wav")))
    pending = [b for b in beats if not already_rendered(b)]
    if not pending:
        await msg.reply_text("✅ All beats already rendered. Nothing to do.")
        return
    stems = [safe_stem(b) for b in pending]
    kb    = media_keyboard(stems, batch=True)
    if kb is None:
        await msg.reply_text("⚠️ No visualizer clips found in `images/`.", parse_mode="Markdown")
        return
    names = "\n".join(f"  • {s}" for s in stems[:10])
    if len(stems) > 10:
        names += f"\n  ...and {len(stems)-10} more"
    await msg.reply_text(f"🎬 {len(stems)} beats to render:\n{names}\n\nPick a clip:", reply_markup=kb)


async def _qm_preview(msg, context):
    """Quick-menu preview trigger."""
    rendered = sorted(f for f in (ROOT / "output").glob("*.mp4") if _is_render_mp4(f))
    if not rendered:
        await msg.reply_text("🎬 No rendered videos yet.")
        return
    stems = [f.stem for f in rendered]
    context.bot_data["preview_stems"] = stems
    await msg.reply_text("🎬 *Preview* — tap a beat:", parse_mode="Markdown", reply_markup=_preview_keyboard(stems, page=0))


async def _qm_status(msg):
    """Quick-menu status — inline version."""
    beats    = list((ROOT / "beats").glob("*.mp3")) + list((ROOT / "beats").glob("*.wav"))
    rendered = [f for f in (ROOT / "output").glob("*.mp4") if _is_render_mp4(f)]
    log_data = load_json_safe(ROOT / "uploads_log.json", {})
    uploaded = list(log_data.keys())
    not_rendered = [b for b in beats if not already_rendered(b)]
    lines = [
        "📊 *Status*\n",
        f"🎵 Beats:      {len(beats)}",
        f"🎬 Rendered:   {len(rendered)}",
        f"☁️  Uploaded:   {len(uploaded)}",
        f"🔲 Pending:    {len(not_rendered)}",
    ]
    await msg.reply_text("\n".join(lines), parse_mode="Markdown")


async def _qm_queue(msg):
    """Quick-menu queue — inline version."""
    rendered = {f.stem for f in (ROOT / "output").glob("*.mp4") if _is_render_mp4(f)}
    log_data = load_json_safe(ROOT / "uploads_log.json", {})
    uploaded = set(log_data.keys())
    ready    = sorted(rendered - uploaded)
    if not ready:
        await msg.reply_text("📭 Nothing queued — either all uploaded or nothing rendered yet.")
        return
    lines = [f"📋 *{len(ready)} ready to upload:*\n"]
    for s in ready[:20]:
        meta  = load_json_safe(ROOT / "metadata" / f"{s}.json")
        title = meta.get("title", s)
        lines.append(f"  • {esc(title)}")
    if len(ready) > 20:
        lines.append(f"  ...and {len(ready)-20} more")
    await msg.reply_text("\n".join(lines), parse_mode="Markdown")


async def _qm_analytics(msg):
    """Quick analytics — show upload log with links."""
    log_data = load_json_safe(ROOT / "uploads_log.json", {})
    if not log_data:
        await msg.reply_text("📭 No uploads yet.")
        return
    lines = [f"📈 *{len(log_data)} uploaded:*\n"]
    for stem, entry in list(log_data.items())[:15]:
        url   = entry.get("url", "")
        title = entry.get("title", stem)
        lines.append(f"  • [{esc(title[:35])}]({url})" if url else f"  • {esc(title[:35])}")
    await msg.reply_text("\n".join(lines), parse_mode="Markdown", disable_web_page_preview=True)


def get_clips(artist: str | None = None) -> list[Path]:
    """Return .mp4 clips, optionally filtered to an artist subfolder.

    artist=None  -> scan ALL artist subdirectories + flat images/ fallback
    artist="BiggKutt8" -> scan images/BiggKutt8/ only
    """
    images_dir = ROOT / "images"
    try:
        if artist:
            artist_dir = images_dir / artist
            if artist_dir.is_dir():
                return sorted(artist_dir.glob("*.mp4"))
            return []
        # No artist — union of all artist subdirs + flat fallback
        clips = []
        for subdir in sorted(images_dir.iterdir()):
            if subdir.is_dir() and not subdir.name.startswith("."):
                clips.extend(subdir.glob("*.mp4"))
        # Backward compat: also check flat images/*.mp4
        clips.extend(images_dir.glob("*.mp4"))
        # Deduplicate by resolved path
        seen = set()
        unique = []
        for c in clips:
            rp = c.resolve()
            if rp not in seen:
                seen.add(rp)
                unique.append(c)
        return sorted(unique, key=lambda p: p.name)
    except Exception:
        return []


def _get_artist_folders() -> list[str]:
    """Return sorted list of artist subfolder names under images/."""
    images_dir = ROOT / "images"
    try:
        return sorted(
            d.name for d in images_dir.iterdir()
            if d.is_dir() and not d.name.startswith(".")
        )
    except Exception:
        return []


def clip_label(clip: Path) -> str:
    """Human-friendly label for a clip button."""
    # Show artist folder prefix if clip is in a subfolder
    parent = clip.parent.name
    prefix = f"[{parent}] " if parent != "images" else ""
    try:
        r = subprocess.run(
            ["ffprobe", "-v", "quiet", "-print_format", "json", "-show_streams", str(clip)],
            capture_output=True, text=True, timeout=10,
        )
        streams = json.loads(r.stdout).get("streams", [])
        for s in streams:
            if s.get("codec_type") == "video":
                w, h = s.get("width", 0), s.get("height", 0)
                orient = "portrait" if h > w else "landscape"
                dur = int(float(s.get("duration", 0)))
                return f"{prefix}{clip.stem}  {w}x{h} {orient} {dur}s"
    except Exception:
        pass
    return f"{prefix}{clip.stem}"


def load_json_safe(path: Path, default=None):
    """Read + parse JSON, return default on any error."""
    try:
        if path.exists() and path.stat().st_size > 0:
            return json.loads(path.read_text())
    except Exception:
        pass
    return default if default is not None else {}


_AUX_SUFFIXES = ("_thumb", "_lit", "_preview_tmp", "_9x16", "_thumbopt_1", "_thumbopt_2", "_thumbopt_3")


def _is_render_mp4(f: Path) -> bool:
    """True if an output/*.mp4 is a real rendered beat (not a thumbnail/aux file)."""
    return not any(f.stem.endswith(s) for s in _AUX_SUFFIXES)


# ── Media session store ────────────────────────────────────────────────────────
# Stores stems server-side to stay under Telegram's 64-byte callback_data limit.
# Sessions are auto-expired after 1 hour to prevent memory leaks.

_media_sessions: dict[str, tuple[list[str], float]] = {}  # key → (stems, timestamp)
_media_session_counter = 0
_SESSION_TTL = 3600  # 1 hour


def _new_media_session(stems: list[str]) -> str:
    global _media_session_counter
    _media_session_counter += 1
    key = f"m{_media_session_counter}"
    _media_sessions[key] = (stems, time.time())
    # Purge expired sessions
    expired = [k for k, (_, ts) in _media_sessions.items() if time.time() - ts > _SESSION_TTL]
    for k in expired:
        del _media_sessions[k]
    return key


def _get_media_session(key: str) -> list[str] | None:
    """Return stems for a session key. Does NOT delete — buttons stay tappable."""
    entry = _media_sessions.get(key)
    if entry is None:
        return None
    stems, ts = entry
    if time.time() - ts > _SESSION_TTL:
        del _media_sessions[key]
        return None
    # Refresh timestamp so session stays alive as long as user is active
    _media_sessions[key] = (stems, time.time())
    return stems


# ── Concurrent task tracker ───────────────────────────────────────────────────
# Lets render and upload (and other long ops) run at the SAME TIME.
# Each task gets a unique ID; the user can check /tasks at any moment.

_active_tasks: dict[str, dict] = {}
# Format: { task_id: {"label": str, "started": float, "task": asyncio.Task | None} }
_task_counter = 0


def _new_task_id(label: str) -> str:
    global _task_counter
    _task_counter += 1
    tid = f"t{_task_counter}"
    _active_tasks[tid] = {"label": label, "started": time.time(), "task": None}
    return tid


def _finish_task(tid: str):
    _active_tasks.pop(tid, None)


def _tasks_summary() -> str:
    if not _active_tasks:
        return "💤 No active tasks right now."
    lines = [f"⚡ *{len(_active_tasks)} active task(s):*\n"]
    for tid, info in _active_tasks.items():
        elapsed = int(time.time() - info["started"])
        m, s    = divmod(elapsed, 60)
        lines.append(f"  • `{tid}` — {info['label']}  _{m}m {s}s_")
    return "\n".join(lines)


def media_keyboard(stems: list[str], batch: bool = False,
                   artist: str | None = None) -> InlineKeyboardMarkup | None:
    """
    Build inline clip-picker keyboard.
    Returns None if no clips are available.
    If artist is given, only show that artist's clips.
    """
    clips = get_clips(artist=artist)
    if not clips:
        # Fallback to all clips if artist folder is empty
        clips = get_clips()
    if not clips:
        return None
    images_dir = ROOT / "images"
    session_key = _new_media_session(stems)
    rows = []
    for clip in clips:
        # Use relative path from images/ (e.g. "BiggKutt8/visual_2.mp4")
        try:
            rel_name = str(clip.relative_to(images_dir))
        except ValueError:
            rel_name = clip.name
        data = f"mediapick:{rel_name}:{session_key}"
        # Telegram callback_data max = 64 bytes — fallback to bare name if too long
        if len(data.encode()) > 64:
            data = f"mediapick:{clip.name}:{session_key}"
        rows.append([InlineKeyboardButton(clip_label(clip), callback_data=data)])
    # Always show random — works for single beat or batch
    rows.append([InlineKeyboardButton(
        "🎲 Random for each beat",
        callback_data=f"mediapick:__random__:{session_key}"
    )])
    return InlineKeyboardMarkup(rows)


# ── Live render runner ────────────────────────────────────────────────────────

async def run_render_live(
    msg_target,
    script: str,
    only: str | None = None,
    clip: str | None = None,
    background: bool = False,
    force: bool = False,
    intensity: str | None = None,
):
    """
    Run render.py (or render_lit.py) with live per-beat progress updates.

    msg_target : Telegram Message object to reply into.
                 Works from command handlers (update.message) AND
                 callback queries (update.callback_query.message).
    only       : comma-separated stems to pass as --only
    clip       : filename from images/ to force as the visualizer (render.py only)
    intensity  : subtle/medium/fire (render_lit.py only)
    """
    cmd = [PYTHON, str(ROOT / script)]
    if only:
        cmd += ["--only", only]
    if clip and script == "render.py":
        cmd += ["--clip", clip]
    if force:
        cmd += ["--force"]
    if intensity and script == "render_lit.py":
        cmd += ["--intensity", intensity]
    # Build queue list for the live header
    if only:
        queue_stems = [s.strip() for s in only.split(",") if s.strip()]
    else:
        queue_stems = [
            safe_stem(b)
            for b in sorted(
                list((ROOT / "beats").glob("*.mp3")) +
                list((ROOT / "beats").glob("*.wav"))
            )
        ]
    total_beats = len(queue_stems)
    _completed_set: set[str] = set()

    # Register as a concurrent task so /tasks shows it
    _task_label = f"Render: {only or 'all'} ({total_beats} beat(s))"
    _tid = _new_task_id(_task_label)

    def _header(active: str | None, pct: float) -> str:
        bar = progress_bar(pct) if active else ""
        done = len(_completed_set)
        lines = [f"🎬 *Render started* — {done}/{total_beats} done"]
        if clip:
            lines.append(f"🎞 Clip: `{esc(clip)}`")
        lines.append("")
        for s in queue_stems[:10]:
            if s in _completed_set:
                lines.append(f"  ✅ {esc(s)}")
            elif s == active:
                lines.append(f"  🔄 {esc(s)}  `{bar}` {pct:.0f}%")
            else:
                lines.append(f"  ⏳ {esc(s)}")
        if len(queue_stems) > 10:
            lines.append(f"  ...and {len(queue_stems)-10} more")
        return "\n".join(lines)

    # Send the initial header
    try:
        status_msg = await msg_target.reply_text(_header(None, 0.0), parse_mode="Markdown")
    except Exception as e:
        log.error("run_render_live: could not send header: %s", e)
        return

    # Launch subprocess — wrap with caffeinate so macOS never sleeps mid-render
    try:
        proc = await asyncio.create_subprocess_exec(
            "caffeinate", "-i", "-s", *cmd,
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.PIPE,
            cwd=str(ROOT),
            limit=1024 * 1024,  # 1 MB — prevents LimitOverrunError on long ffmpeg lines
        )
    except Exception as e:
        await safe_edit(status_msg, f"❌ Could not start render: {e}")
        return

    completed    = []
    skipped      = []
    current_stem = None
    current_msg  = None
    current_dur  = 0.0
    last_pct     = -1.0
    last_hdr_pct = -10.0
    stderr_buf   = ""
    _last_progress_time = time.time()  # track when ffmpeg last made progress
    _STALL_TIMEOUT = 180               # kill ffmpeg after 3 min with no progress
    _stall_killed = False              # flag so summary knows it was a stall kill

    write_state(None, 0.0, completed, total_beats, script)

    async def _update_header(active: str | None, pct: float):
        nonlocal last_hdr_pct
        if active is not None and pct - last_hdr_pct < 10:
            return
        last_hdr_pct = pct
        await safe_edit(status_msg, _header(active, pct), parse_mode="Markdown")

    async def _stall_watchdog():
        """Kill ffmpeg if no progress for _STALL_TIMEOUT seconds."""
        nonlocal _stall_killed
        while proc.returncode is None:
            await asyncio.sleep(15)
            if proc.returncode is not None:
                break
            if current_stem and (time.time() - _last_progress_time) > _STALL_TIMEOUT:
                log.warning("Render stall detected: %s stuck at %.0f%% for %ds — killing ffmpeg",
                            current_stem, last_pct, _STALL_TIMEOUT)
                _stall_killed = True
                try:
                    proc.kill()
                except Exception:
                    pass
                if current_msg:
                    await safe_edit(
                        current_msg,
                        f"⚠️ *{esc(current_stem)}* stalled at {last_pct:.0f}% — killed after {_STALL_TIMEOUT}s",
                        parse_mode="Markdown",
                    )
                # Clean up partial output
                partial = ROOT / "output" / f"{current_stem}.mp4"
                if partial.exists():
                    try:
                        partial.unlink()
                        log.info("Removed partial render: %s", partial)
                    except Exception:
                        pass
                break

    async def read_stderr():
        nonlocal stderr_buf, last_pct, _last_progress_time
        try:
            async for raw in proc.stderr:
                line = raw.decode("utf-8", errors="replace")
                stderr_buf += line
                if current_stem and current_msg and current_dur > 0:
                    pct = parse_ffmpeg_percent(line, current_dur)
                    if pct is not None and pct - last_pct >= 5:
                        last_pct = pct
                        _last_progress_time = time.time()  # reset stall timer
                        bar = progress_bar(pct)
                        write_state(current_stem, pct, completed, total_beats, script)
                        await safe_edit(
                            current_msg,
                            f"🎬 *{esc(current_stem)}*\n`{bar}` {pct:.0f}%",
                            parse_mode="Markdown",
                        )
                        await _update_header(current_stem, pct)
                    elif pct is not None:
                        _last_progress_time = time.time()  # any progress resets timer
        except Exception as _se:
            # Never crash the whole render over a stream read error (e.g. LimitOverrunError)
            log.warning("read_stderr stream error (ignored — render continues): %s", _se)

    async def read_stdout():
        nonlocal current_stem, current_msg, current_dur, last_pct, last_hdr_pct, _last_progress_time
        try:
            async for raw in proc.stdout:
                line = raw.decode("utf-8", errors="replace").rstrip()
                log.debug("render stdout: %s", line)

                # [RENDER] stem — new beat starting
                stem_match = re.search(r"\[RENDER\]\s+(\S+)", line)
                if stem_match:
                    current_stem = stem_match.group(1)
                    last_pct     = -1.0
                    last_hdr_pct = -10.0
                    current_dur  = 0.0
                    _last_progress_time = time.time()  # reset stall timer for new beat
                    for ext in ("mp3", "wav"):
                        ap = ROOT / "beats" / f"{current_stem}.{ext}"
                        if ap.exists():
                            current_dur = get_audio_duration(ap)
                            break
                    write_state(current_stem, 0.0, completed, total_beats, script)
                    await _update_header(current_stem, 0.0)
                    try:
                        current_msg = await msg_target.reply_text(
                            f"🎬 *{esc(current_stem)}*\n`░░░░░░░░░░░░░░░░` 0%",
                            parse_mode="Markdown",
                        )
                    except Exception as e:
                        log.warning("Could not send beat message: %s", e)
                        current_msg = None
                    continue

                # [DONE] stem — beat finished successfully
                done_match = re.search(r"\[DONE\]\s+(\S+)", line)
                if done_match:
                    done_stem = done_match.group(1)
                    if done_stem == current_stem and current_msg:
                        last_pct = 100
                        completed.append(current_stem)
                        _completed_set.add(current_stem)
                        write_state(None, 0.0, completed, total_beats, script)
                        await safe_edit(
                            current_msg,
                            f"✅ *{esc(current_stem)}*\n`{progress_bar(100)}` 100%",
                            parse_mode="Markdown",
                        )
                        await _update_header(None, 0.0)
                        current_stem = None
                        current_msg  = None
                    continue

                # [FAIL] stem: reason — beat failed, mark it and move on
                fail_match = re.search(r"\[FAIL\]\s+(\S+)[:\s]+(.*)", line)
                if fail_match:
                    fail_stem   = fail_match.group(1)
                    fail_reason = fail_match.group(2)
                    if current_msg:
                        await safe_edit(
                            current_msg,
                            f"❌ *{esc(fail_stem)}* failed\n`{esc(fail_reason[:200])}`",
                            parse_mode="Markdown",
                        )
                    current_stem = None
                    current_msg  = None
                    continue

                # [SKIP] — already rendered — mark complete so header updates correctly
                if "[SKIP]" in line or "Already exists" in line:
                    skip_match = re.search(r"(?:Already exists|\[SKIP\])[:\s]+(\S+)", line)
                    if skip_match:
                        skip_stem = skip_match.group(1)
                        skipped.append(skip_stem)
                        _completed_set.add(skip_stem)   # treat skips as done in header
                        write_state(None, 0.0, completed, total_beats, script)
                        await _update_header(None, 0.0)  # refresh header immediately
        except Exception as _se:
            # Never crash the whole render over a stream read error (e.g. LimitOverrunError)
            log.warning("read_stdout stream error (ignored — render continues): %s", _se)

    # Overall render timeout: 20 min per beat max
    _OVERALL_TIMEOUT = max(total_beats * 20 * 60, 600)

    try:
        await asyncio.wait_for(
            asyncio.gather(read_stdout(), read_stderr(), _stall_watchdog()),
            timeout=_OVERALL_TIMEOUT,
        )
        await proc.wait()
    except asyncio.TimeoutError:
        log.error("Render overall timeout (%ds) exceeded — killing process", _OVERALL_TIMEOUT)
        try:
            proc.kill()
        except Exception:
            pass
        await proc.wait()
        if current_msg and current_stem:
            await safe_edit(
                current_msg,
                f"⚠️ *{esc(current_stem)}* timed out — render killed",
                parse_mode="Markdown",
            )
    finally:
        _finish_task(_tid)
    clear_state()

    # Final summary
    total_in_output = len([
        f for f in (ROOT / "output").glob("*.mp4")
        if _is_render_mp4(f)
    ])
    lines = ["🏁 *Render complete*\n"]
    lines.append(f"✅ Rendered this run: {len(completed)}")
    if skipped:
        lines.append(f"⏭ Skipped (exist):  {len(skipped)}")
    lines.append(f"🎬 Total in output/: {total_in_output} videos")
    if _stall_killed:
        lines.append(f"\n⚠️ Render was killed — ffmpeg stalled for {_STALL_TIMEOUT}s with no progress")
        lines.append(f"Partial output was cleaned up. Run the render again to retry.")
    if proc.returncode not in (0, None) and not _stall_killed:
        lines.append(f"⚠️ Exit code: {proc.returncode}")
        # Show last few lines of stderr for context
        if stderr_buf:
            tail = "\n".join(stderr_buf.strip().splitlines()[-5:])
            lines.append(f"\nLast error output:\n`{safe_md(tail, 300)}`")
    if completed:
        lines.append("\nJust rendered:")
        for s in completed:
            lines.append(f"  ✅ {esc(s)}")
        lines.append("\n💡 Run /bulktitle to edit titles before uploading")

    await safe_edit(status_msg, "\n".join(lines), parse_mode="Markdown")
    await send_menu(msg_target)


