def _build_artist_picker_kb(render_key: str, cat_index: int | None = None) -> InlineKeyboardMarkup:
    """Build inline keyboard for artist type-beat selection before render.

    cat_index=None → show top artists directly + auto-detect / skip / more
    cat_index=N   → show artists within that category
    cat_index=-1  → show category list (via "More Artists...")
    """
    rows = []

    if cat_index is None:
        # ── TOP-LEVEL: popular artists directly ──
        rows.append([InlineKeyboardButton(
            "🔍 Auto-Detect Artist",
            callback_data=f"artistpick:__auto__:{render_key}"
        )])
        # Flat grid of top artists in pairs
        pair = []
        for display, seo_name in _TOP_ARTISTS:
            short_seo = seo_name[:20]
            btn = InlineKeyboardButton(
                display,
                callback_data=f"artistpick:{short_seo}:{render_key}"
            )
            pair.append(btn)
            if len(pair) == 2:
                rows.append(pair)
                pair = []
        if pair:
            rows.append(pair)
        # More artists + skip
        rows.append([InlineKeyboardButton(
            "🔎 More Artists...",
            callback_data=f"ap_cat:list:{render_key}"
        )])
        rows.append([InlineKeyboardButton(
            "⏭ Skip (no artist tag)",
            callback_data=f"artistpick:__skip__:{render_key}"
        )])

    elif cat_index == -1:
        # ── CATEGORY LIST (via "More Artists...") ──
        pair = []
        for i, (emoji_label, _artists) in enumerate(_RENDER_ARTIST_CATS):
            short = emoji_label[:20]
            btn = InlineKeyboardButton(short, callback_data=f"ap_cat:{i}:{render_key}")
            pair.append(btn)
            if len(pair) == 2:
                rows.append(pair)
                pair = []
        if pair:
            rows.append(pair)
        rows.append([InlineKeyboardButton(
            "⬅️ Back",
            callback_data=f"ap_cat:back:{render_key}"
        )])

    else:
        # ── CATEGORY VIEW: individual artists ──
        cat_label, artists = _RENDER_ARTIST_CATS[cat_index]
        pair = []
        for display, seo_name in artists:
            short_seo = seo_name[:20]
            btn = InlineKeyboardButton(
                f"🎤 {display}",
                callback_data=f"artistpick:{short_seo}:{render_key}"
            )
            pair.append(btn)
            if len(pair) == 2:
                rows.append(pair)
                pair = []
        if pair:
            rows.append(pair)
        rows.append([InlineKeyboardButton(
            "⬅️ Back",
            callback_data=f"ap_cat:list:{render_key}"
        )])

    return InlineKeyboardMarkup(rows)


def _save_seo_artist(stems: list[str], artist: str | None) -> None:
    """Write seo_artist field to each stem's metadata JSON."""
    for stem in stems:
        meta_path = ROOT / "metadata" / f"{stem}.json"
        try:
            meta = json.loads(meta_path.read_text()) if meta_path.exists() else {}
            if artist:
                meta["seo_artist"] = artist
            else:
                meta.pop("seo_artist", None)
            meta_path.parent.mkdir(parents=True, exist_ok=True)
            meta_path.write_text(json.dumps(meta, indent=2))
        except Exception as e:
            log.warning("_save_seo_artist: could not update %s: %s", stem, e)


# ── Title review / edit helpers ──────────────────────────────────────────────

def _get_title_for_stem(stem: str) -> str:
    """Read current title from metadata JSON, or derive from stem."""
    meta_path = ROOT / "metadata" / f"{stem}.json"
    try:
        if meta_path.exists():
            return json.loads(meta_path.read_text()).get("title", stem.replace("_", " ").title())
    except Exception:
        pass
    return stem.replace("_", " ").title()


def _save_title_for_stem(stem: str, title: str) -> None:
    """Write title to metadata JSON."""
    meta_path = ROOT / "metadata" / f"{stem}.json"
    try:
        meta = json.loads(meta_path.read_text()) if meta_path.exists() else {}
        meta["title"] = title
        meta_path.parent.mkdir(parents=True, exist_ok=True)
        meta_path.write_text(json.dumps(meta, indent=2))
    except Exception as e:
        log.warning("_save_title_for_stem: could not update %s: %s", stem, e)


def _build_title_review_kb(render_key: str, stems: list[str]) -> InlineKeyboardMarkup:
    """Build keyboard showing each beat title with an edit button, plus Render."""
    rows = []
    for i, stem in enumerate(stems[:15]):  # cap at 15 to stay within Telegram limits
        title = _get_title_for_stem(stem)
        # Truncate display for button label
        display = title if len(title) <= 28 else title[:25] + "..."
        rows.append([InlineKeyboardButton(
            f"✏️ {display}",
            callback_data=f"tledit:{i}:{render_key}"
        )])
    rows.append([InlineKeyboardButton(
        "🎬 Looks Good — Render",
        callback_data=f"tlgo:{render_key}"
    )])
    return InlineKeyboardMarkup(rows)


def _title_review_text(stems: list[str]) -> str:
    """Build the title review message text."""
    lines = ["📝 Review titles before rendering:\n"]
    for i, stem in enumerate(stems[:15]):
        title = _get_title_for_stem(stem)
        lines.append(f"  {i+1}. {title}")
    if len(stems) > 15:
        lines.append(f"  ...and {len(stems) - 15} more")
    lines.append("\nTap a title to edit it, or hit Render:")
    return "\n".join(lines)


async def title_edit_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle tledit:{index}:{render_key} — prompt user to type new title."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("Not authorized.", show_alert=True)
        return
    await query.answer()

    parts = query.data.split(":", 2)
    if len(parts) != 3:
        await safe_edit(query.message, "Malformed callback.")
        return
    _, idx_str, render_key = parts
    idx = int(idx_str)

    sessions = context.bot_data.get("_render_sessions", {})
    session = sessions.get(render_key)
    if not session:
        session = _recover_render_session(context, render_key)
    if not session:
        await safe_edit(query.message, "Session expired — try again.")
        return

    stems = session["stems"]
    if idx >= len(stems):
        await safe_edit(query.message, "Invalid beat index.")
        return

    stem = stems[idx]
    current_title = _get_title_for_stem(stem)

    # Store in user_data so handle_plain_text knows to intercept the next message
    context.user_data["_title_edit"] = {
        "render_key": render_key,
        "stem": stem,
        "index": idx,
        "msg_id": query.message.message_id,
        "chat_id": query.message.chat_id,
    }

    await safe_edit(
        query.message,
        f"✏️ Editing title for beat {idx+1}:\n\n"
        f"Current: {current_title}\n\n"
        f"Type the new title below:"
    )


async def title_go_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle tlgo:{render_key} — user approved titles, launch render."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("Not authorized.", show_alert=True)
        return
    await query.answer()

    parts = query.data.split(":", 1)
    if len(parts) != 2:
        await safe_edit(query.message, "Malformed callback.")
        return
    _, render_key = parts

    sessions = context.bot_data.get("_render_sessions", {})
    session = sessions.get(render_key)
    if not session:
        session = _recover_render_session(context, render_key)
    if not session:
        await safe_edit(query.message, "Session expired — try again.")
        return

    stems       = session["stems"]
    clip_name   = session["clip_name"]
    random_mode = session["random_mode"]
    use_force   = session.get("use_force", False)

    # Ensure full metadata before rendering
    fixed, _ = _ensure_full_metadata(stems)
    if fixed:
        log.info("Render flow: auto-filled metadata for %d beat(s)", fixed)

    label = "🎲 random clip" if random_mode else esc(clip_name)
    await safe_edit(
        query.message,
        f"🎬 Rendering {len(stems)} beat(s) with {label}..."
    )

    await _launch_render_task(context, query.message, stems, clip_name, random_mode, use_force=use_force)


async def _launch_render_task(
    context: ContextTypes.DEFAULT_TYPE,
    reply_target,
    stems: list[str],
    clip_name: str,
    random_mode: bool,
    use_force: bool = False,
) -> None:
    """Shared helper: delete old output if force, then run render in bg task."""
    if use_force:
        for s in stems:
            mp4 = ROOT / "output" / f"{s}.mp4"
            thm = ROOT / "output" / f"{s}_thumb.jpg"
            if mp4.exists(): mp4.unlink()
            if thm.exists(): thm.unlink()

    images_dir = ROOT / "images"

    async def _go():
        if random_mode:
            import random as _rand
            clips = get_clips()
            if not clips:
                await reply_target.reply_text("No visualizer clips found in images/. Upload an .mp4 first.")
                return
            for stem in stems:
                c = _rand.choice(clips)
                # Use relative path from images/ so render.py finds subfolders
                try:
                    rel = str(c.relative_to(images_dir))
                except ValueError:
                    rel = c.name
                await run_render_live(reply_target, "render.py", only=stem, clip=rel)
        elif len(stems) == 1:
            await run_render_live(reply_target, "render.py", only=stems[0], clip=clip_name)
        else:
            await run_render_live(reply_target, "render.py", only=",".join(stems), clip=clip_name)

    bg = asyncio.create_task(_go())
    context.bot_data.setdefault("_bg_tasks", set()).add(bg)
    bg.add_done_callback(lambda t: context.bot_data.get("_bg_tasks", set()).discard(t))


def _recover_render_session(context, render_key: str) -> dict | None:
    """Try to recover a lost render session from disk-persisted upload sessions.

    If render_key starts with 'upla_', the corresponding upload session
    may still exist on disk even after a bot restart cleared bot_data.
    """
    if not render_key.startswith("upla_"):
        return None
    upl_key = render_key[5:]  # strip 'upla_' prefix
    upload_sessions = _get_upload_sessions(context)
    upl_session = upload_sessions.get(upl_key)
    if not upl_session:
        return None
    # Reconstruct the render session
    missing = upl_session.get("missing_artist", upl_session.get("stems", []))
    recovered = {
        "stems": missing,
        "clip_name": None,
        "random_mode": False,
        "use_force": False,
        "_upload_flow_key": upl_key,
    }
    context.bot_data.setdefault("_render_sessions", {})[render_key] = recovered
    log.info("Recovered render session %s from persisted upload session %s", render_key, upl_key)
    return recovered


async def artist_cat_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle ap_cat:{index}:{render_key} — navigate artist category picker."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("Not authorized.", show_alert=True)
        return
    await query.answer()

    parts = query.data.split(":", 2)
    if len(parts) != 3:
        await safe_edit(query.message, "⚠️ Malformed callback. Try again.")
        return
    _, cat_choice, render_key = parts

    sessions = context.bot_data.get("_render_sessions", {})
    session = sessions.get(render_key)
    if not session:
        # Try to recover from disk-persisted upload session
        session = _recover_render_session(context, render_key)
    if not session:
        await safe_edit(query.message, "⚠️ Session expired — send /batch or /fy3stash again.")
        return

    stems = session["stems"]
    beat_list = "\n".join(f"  🎵 {esc(s)}" for s in stems[:8])
    if len(stems) > 8:
        beat_list += f"\n  ...and {len(stems) - 8} more"

    if cat_choice == "back":
        # Back to top-level artist grid
        kb = _build_artist_picker_kb(render_key, cat_index=None)
        await safe_edit(
            query.message,
            f"🎤 What type beat?\n{beat_list}\n\nPick an artist or tap Auto-Detect:",
            reply_markup=kb,
        )
    elif cat_choice == "list":
        # Show category list (via "More Artists...")
        kb = _build_artist_picker_kb(render_key, cat_index=-1)
        await safe_edit(
            query.message,
            f"🎤 More Artists\n{beat_list}\n\nPick a category to see more artists:",
            reply_markup=kb,
        )
    else:
        cat_idx = int(cat_choice)
        cat_label = _RENDER_ARTIST_CATS[cat_idx][0]
        kb = _build_artist_picker_kb(render_key, cat_index=cat_idx)
        await safe_edit(
            query.message,
            f"🎤 {cat_label}\n{beat_list}\n\nPick the artist type beat:",
            reply_markup=kb,
        )


async def artist_pick_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle artistpick:{artist}:{render_key} — saves seo_artist then launches render."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("Not authorized.", show_alert=True)
        return
    await query.answer()

    parts = query.data.split(":", 2)
    if len(parts) != 3:
        await safe_edit(query.message, "⚠️ Malformed artist pick. Try again.")
        return
    _, artist_choice, render_key = parts

    sessions = context.bot_data.get("_render_sessions", {})
    session = sessions.get(render_key)
    if not session:
        # Try to recover from disk-persisted upload session
        session = _recover_render_session(context, render_key)
    if not session:
        await safe_edit(query.message, "⚠️ Session expired — send /batch or /fy3stash again.")
        return

    stems      = session["stems"]
    clip_name  = session["clip_name"]
    random_mode = session["random_mode"]
    use_force  = session.get("use_force", False)

    # Resolve artist
    if artist_choice == "__auto__":
        # Detect per-stem from filename
        for stem in stems:
            detected = _detect_stem_artist(stem)
            _save_seo_artist([stem], detected)
        artist_label = "🔍 auto-detected"
    elif artist_choice == "__skip__":
        artist_label = "⏭ no artist tag"
        # Don't touch seo_artist
    else:
        _save_seo_artist(stems, artist_choice)
        artist_label = f"🎤 {artist_choice}"

    # ── Upload flow: after artist pick, show metadata options ───────────
    upl_flow_key = session.get("_upload_flow_key")
    if upl_flow_key:
        # Regenerate SEO metadata with new artist
        for stem in stems:
            try:
                from seo_metadata import build_metadata
                meta_path = ROOT / "metadata" / f"{stem}.json"
                existing = load_json_safe(meta_path, {})
                updated = build_metadata(stem, existing)
                meta_path.write_text(json.dumps(updated, indent=2))
            except Exception as e:
                log.warning("upload flow seo regen failed for %s: %s", stem, e)

        upload_sessions = _get_upload_sessions(context)
        upl_session = upload_sessions.get(upl_flow_key)
        if upl_session:
            all_stems = upl_session["stems"]
            _ensure_full_metadata(all_stems)

            # Show metadata options — auto-set all or review individually
            kb = InlineKeyboardMarkup([
                [InlineKeyboardButton("✅ Auto-Set All Metadata", callback_data=f"uplmeta:auto:{upl_flow_key}")],
                [InlineKeyboardButton("✏️ Review & Edit Titles/Tags", callback_data=f"uplmeta:edit:0:{upl_flow_key}")],
                [InlineKeyboardButton("❌ Cancel", callback_data=f"uplgo:cancel:_:{upl_flow_key}")],
            ])

            # Show a quick preview of what auto-generated
            preview_lines = [f"Artist set: {artist_label}\n"]
            for s in all_stems[:5]:
                meta = load_json_safe(ROOT / "metadata" / f"{s}.json", {})
                t = meta.get("title", s)[:45]
                preview_lines.append(f"  {t}")
            if len(all_stems) > 5:
                preview_lines.append(f"  ...and {len(all_stems) - 5} more")
            preview_lines.append(f"\n{len(all_stems)} beat(s) — how do you want to handle metadata?")

            await safe_edit(
                query.message,
                "\n".join(preview_lines),
                reply_markup=kb,
            )
        else:
            await safe_edit(query.message, "Session expired — try /upload again.")
        sessions.pop(render_key, None)
        return

    # ── Normal render flow: show title review before rendering ──────────────
    kb = _build_title_review_kb(render_key, stems)
    await safe_edit(
        query.message,
        f"Artist set: {artist_label}\n\n" + _title_review_text(stems),
        reply_markup=kb,
    )


# ── Media picker callback ─────────────────────────────────────────────────────

async def media_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    Fired when user taps a clip button from media_keyboard().
    callback_data: mediapick:{clip_name}:{session_key}
    """
    query = update.callback_query
    if not query:
        return
    if not is_allowed(update):
        await query.answer("⛔ Not authorized.", show_alert=True)
        return
    await query.answer()

    parts = query.data.split(":", 2)
    if len(parts) != 3:
        await safe_edit(query.message, "⚠️ Malformed callback. Try again.")
        return

    _, clip_name, session_key = parts
    stems = _get_media_session(session_key)
    if not stems:
        await safe_edit(
            query.message,
            "⚠️ Session expired — send /batch or /fy3stash again."
        )
        return

    random_mode = clip_name == "__random__"
    label = "🎲 random clip per beat" if random_mode else esc(clip_name)

    # Check for existing renders
    existing = [s for s in stems if (ROOT / "output" / f"{s}.mp4").exists()]
    new_stems = [s for s in stems if s not in existing]

    if existing:
        # Some renders already exist — ask user what to do
        ow_key = f"ow_{int(time.time())}_{os.urandom(4).hex()}"
        context.bot_data.setdefault("_ow_sessions", {})[ow_key] = {
            "stems": stems, "existing": existing, "new_stems": new_stems,
            "clip_name": clip_name, "random_mode": random_mode,
            "confirmed_overwrite": set(), "pick_index": 0,
        }
        lines = [f"⚠️ *{len(existing)} of {len(stems)} beat(s) already rendered:*\n"]
        for s in existing:
            lines.append(f"  🔄 `{esc(s)}`")
        if new_stems:
            lines.append(f"\n🆕 {len(new_stems)} new beat(s) will render regardless.\n")
        lines.append("\nWhat do you want to do with existing ones?")
        kb = InlineKeyboardMarkup([
            [InlineKeyboardButton("🔄 Overwrite All",    callback_data=f"owall:{ow_key}")],
            [InlineKeyboardButton("⏭ Skip All Existing", callback_data=f"ownone:{ow_key}")],
            [InlineKeyboardButton("📋 Pick One by One",  callback_data=f"owpick:{ow_key}")],
        ])
        await safe_edit(query.message, "\n".join(lines), parse_mode="Markdown", reply_markup=kb)
        return

    # ── No existing renders — show artist picker before launching ─────────────
    render_key = f"rk_{int(time.time())}_{os.urandom(4).hex()}"
    context.bot_data.setdefault("_render_sessions", {})[render_key] = {
        "stems": stems, "clip_name": clip_name, "random_mode": random_mode,
        "use_force": False,
    }
    beat_list = "\n".join(f"  🎵 `{esc(s)}`" for s in stems[:8])
    if len(stems) > 8:
        beat_list += f"\n  …and {len(stems) - 8} more"
    kb = _build_artist_picker_kb(render_key)
    await safe_edit(
        query.message,
        f"🎤 *What type beat?*\n{beat_list}\n\n"
        f"Pick an artist or tap *Auto-Detect*:",
        parse_mode="Markdown",
        reply_markup=kb,
    )


async def overwrite_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("Not authorized.", show_alert=True)
        return
    await query.answer()
    parts = query.data.split(":", 1)
    if len(parts) != 2: return
    action, ow_key = parts
    sessions = context.bot_data.get("_ow_sessions", {})
    session = sessions.get(ow_key)
    if not session:
        await safe_edit(query.message, "Session expired. Try again.")
        return
    existing    = session["existing"]
    new_stems   = session["new_stems"]
    clip_name   = session["clip_name"]
    random_mode = session["random_mode"]
    stems       = session.get("stems", existing + new_stems)

    if action == "owall":
        render_stems = new_stems + existing
        use_force    = True
    elif action == "ownone":
        if not new_stems:
            await safe_edit(query.message, "⏭ Nothing new to render — all beats already exist.")
            return
        render_stems = new_stems
        use_force    = False
    else:
        render_stems = stems
        use_force    = False

    if not render_stems:
        await safe_edit(query.message, "Nothing to render.")
        return

    # ── Show artist picker before launching ────────────────────────────────
    render_key = f"rk_{int(time.time())}_{os.urandom(4).hex()}"
    context.bot_data.setdefault("_render_sessions", {})[render_key] = {
        "stems": render_stems, "clip_name": clip_name,
        "random_mode": random_mode, "use_force": use_force,
    }
    beat_list = "\n".join(f"  🎵 `{esc(s)}`" for s in render_stems[:8])
    if len(render_stems) > 8:
        beat_list += f"\n  …and {len(render_stems) - 8} more"
    kb = _build_artist_picker_kb(render_key)
    await safe_edit(
        query.message,
        f"🎤 *What type beat?*\n{beat_list}\n\n"
        f"Pick an artist or tap *Auto-Detect*:",
        parse_mode="Markdown",
        reply_markup=kb,
    )


# ── Simple script runner ──────────────────────────────────────────────────────

async def run_script_simple(update: Update, script: str, args: list[str] = []):
    """Run a script, capture all output, send as a single message when done."""
    msg = await update.message.reply_text(f"⏳ Running `{script}`...", parse_mode="Markdown")
    try:
        result = subprocess.run(
            [PYTHON, str(ROOT / script)] + args,
            capture_output=True, text=True, cwd=str(ROOT),
            timeout=600,
        )
        output = (result.stdout + result.stderr).strip() or "(no output)"
        output = safe_md(output, 3800)
        await safe_edit(msg, f"```\n{output}\n```", parse_mode="Markdown")
    except subprocess.TimeoutExpired:
        await safe_edit(msg, f"❌ `{script}` timed out after 10 minutes.", parse_mode="Markdown")
    except Exception as e:
        await safe_edit(msg, f"❌ Error: {esc(str(e))}", parse_mode="Markdown")


# ── File drop handler ─────────────────────────────────────────────────────────

async def handle_file(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    Accept file uploads:
      .mp3 / .wav  → beats/      (auto-renamed to safe stem)
      .mp4         → images/     (visualizer clip)
      .jpg / .jpeg / .png → images/  (thumbnail background)
    """
    if not is_allowed(update):
        return await deny(update)

    doc = update.message.document
    if not doc:
        return

    # ── Filename validation ────────────────────────────────────────────────────
    raw_fname = (doc.file_name or "").strip()
    if not raw_fname:
        await update.message.reply_text("⚠️ File has no name — cannot save.")
        return

    ext = Path(raw_fname).suffix.lower()

    # Normalise filename for audio — same safe_stem logic as render.py
    if ext in (".mp3", ".wav"):
        safe_name = safe_stem(Path(raw_fname)) + ext
        dest_dir  = ROOT / "beats"
        label     = "beats/"
        next_cmd  = "Now run /seo then pick it in /fy3stash to render."
    elif ext == ".mp4":
        # Download to temp, then ask which artist folder to save to
        MAX_BYTES = 20 * 1024 * 1024
        file_size = doc.file_size or 0
        if file_size > MAX_BYTES:
            await update.message.reply_text(
                f"File too large ({file_size // (1024*1024)} MB). "
                f"Telegram bot API limit is 20 MB.\n"
                f"Copy the file directly into the images/ folder on your Mac instead.",
            )
            return
        msg = await update.message.reply_text("Downloading clip...")
        try:
            tg_file = await context.bot.get_file(doc.file_id)
            temp_path = ROOT / "images" / f"_temp_{doc.file_id}.mp4"
            await tg_file.download_to_drive(str(temp_path))
            if not temp_path.exists() or temp_path.stat().st_size == 0:
                temp_path.unlink(missing_ok=True)
                await safe_edit(msg, "Download failed. Try again.")
                return
        except Exception as e:
            await safe_edit(msg, f"Download error: {e}")
            return
        # Store session for folder picker
        clip_upload_key = f"cu_{int(time.time())}_{os.urandom(4).hex()}"
        context.bot_data.setdefault("_clip_upload_sessions", {})[clip_upload_key] = {
            "temp_path": str(temp_path),
        }
        # Show artist folder picker
        artist_dirs = _get_artist_folders()
        if not artist_dirs:
            artist_dirs = ["BiggKutt8"]
        rows = []
        for ad in artist_dirs:
            rows.append([InlineKeyboardButton(
                f"📁 {ad}",
                callback_data=f"clipfolder:{ad}:{clip_upload_key}"
            )])
        rows.append([InlineKeyboardButton(
            "➕ New Artist Folder",
            callback_data=f"clipfolder:__new__:{clip_upload_key}"
        )])
        await safe_edit(msg, "Which artist folder should this clip go in?",
                        reply_markup=InlineKeyboardMarkup(rows))
        return
    elif ext in (".jpg", ".jpeg", ".png"):
        safe_name = re.sub(r"[^\w.\-]", "_", raw_fname)
        dest_dir  = ROOT / "images"
        label     = "images/"
        next_cmd  = "✅ Image saved. Use /thumbnail to assign it to a beat."
    else:
        await update.message.reply_text(
            f"⚠️ Unsupported file type: `{esc(ext)}`\n"
            "Accepted: `.mp3` `.wav` `.mp4` `.jpg` `.png`",
            parse_mode="Markdown",
        )
        return

    # ── Size guard: Telegram bots max ~20 MB for getFile ──────────────────────
    MAX_BYTES = 20 * 1024 * 1024  # 20 MB
    file_size = doc.file_size or 0
    if file_size > MAX_BYTES:
        await update.message.reply_text(
            f"⚠️ File too large ({file_size // (1024*1024)} MB). "
            f"Telegram bot API limit is 20 MB.\n"
            f"Copy the file directly into the `{label}` folder on your Mac instead.",
        )
        return

    dest_dir.mkdir(parents=True, exist_ok=True)
    dest_path = dest_dir / safe_name

    # Warn if renaming happened
    rename_note = ""
    if safe_name != raw_fname:
        rename_note = f"\n📝 Renamed: `{esc(raw_fname)}` → `{esc(safe_name)}`"

    msg = await update.message.reply_text(
        f"⬇️ Downloading `{esc(safe_name)}` → `{label}`...", parse_mode="Markdown"
    )

    try:
        tg_file = await context.bot.get_file(doc.file_id)
        await tg_file.download_to_drive(str(dest_path))

        # Verify the file actually landed and has content
        if not dest_path.exists() or dest_path.stat().st_size == 0:
            dest_path.unlink(missing_ok=True)
            await safe_edit(msg, "❌ Download failed — file is empty or missing. Try again.")
            return

        saved_mb = dest_path.stat().st_size / (1024 * 1024)

        # ── Auto-detect BPM + key for audio files ─────────────────────────────
        bpm_key_str = ""
        if ext in (".mp3", ".wav"):
            await safe_edit(msg, f"🔍 Analyzing BPM + Key for `{esc(safe_name)}`…", parse_mode="Markdown")
            try:
                loop = asyncio.get_event_loop()
                stem_name = safe_stem(dest_path)
                fl_meta   = _read_fl_metadata(str(dest_path))
                detected  = await loop.run_in_executor(None, _analyze_audio, str(dest_path))
                saved_meta = _merge_and_save_metadata(stem_name, fl_meta, detected)
                bpm = saved_meta.get("bpm")
                key = saved_meta.get("key")
                if bpm or key:
                    parts = []
                    if bpm: parts.append(f"BPM: *{bpm}*")
                    if key: parts.append(f"Key: *{key}*")
                    bpm_key_str = "  •  " + "  •  ".join(parts)
            except Exception as _ae:
                log.warning("handle_file: BPM/key detection failed: %s", _ae)

        await safe_edit(
            msg,
            f"✅ Saved `{esc(safe_name)}` → `{label}` ({saved_mb:.1f} MB){rename_note}{bpm_key_str}\n\n{next_cmd}",
            parse_mode="Markdown",
        )

        # ── For audio files: offer export/convert buttons ─────────────────────
        if ext in (".mp3", ".wav"):
            stem_key = safe_stem(dest_path)
            # Store the path so expu: callback can find it
            # We use user_data keyed by stem for retrieval in the callback
            context.user_data[f"expu_audio_{stem_key}"] = str(dest_path)
            try:
                await update.message.reply_text(
                    "🎛 *Export options:* Convert this beat or split into stems?",
                    parse_mode="Markdown",
                    reply_markup=_export_format_keyboard(stem_key, from_upload=True),
                )
            except Exception:
                pass  # Non-critical — main save already succeeded

            # ── Drop-and-forget pipeline: auto SEO → render → queue ──────
            asyncio.ensure_future(_auto_pipeline_beat(update.message, stem_key))

        await send_menu(update.message)
    except Exception as e:
        # Clean up partial download
        try:
            if dest_path.exists() and dest_path.stat().st_size == 0:
                dest_path.unlink()
        except Exception:
            pass
        log.error("handle_file download error: %s", e)
        await safe_edit(msg, f"❌ Download failed: {esc(str(e))}\n\nTry again or copy the file manually to `{label}`.", parse_mode="Markdown")


async def clipfolder_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle clipfolder:{artist}:{key} — save uploaded clip to artist subfolder."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query:
            await query.answer("Not authorized.", show_alert=True)
        return
    await query.answer()

    parts = query.data.split(":", 2)
    if len(parts) != 3:
        await safe_edit(query.message, "Malformed callback.")
        return
    _, artist_name, upload_key = parts

    sessions = context.bot_data.get("_clip_upload_sessions", {})
    session = sessions.get(upload_key)
    if not session:
        await safe_edit(query.message, "Session expired. Send the clip again.")
        return

    temp_path = Path(session["temp_path"])
    if not temp_path.exists():
        sessions.pop(upload_key, None)
        await safe_edit(query.message, "Temp file missing. Send the clip again.")
        return

    if artist_name == "__new__":
        # Ask user to type new folder name
        session["awaiting_folder_name"] = True
        context.user_data["_clip_folder_key"] = upload_key
        await safe_edit(query.message, "Type the new artist folder name (e.g. Travis Scott):")
        return

    # Save to artist folder with auto-numbered name
    artist_dir = ROOT / "images" / artist_name
    artist_dir.mkdir(parents=True, exist_ok=True)

    existing_nums = []
    for f in artist_dir.glob("visual_*.mp4"):
        m = re.match(r"visual_(\d+)\.mp4$", f.name)
        if m:
            existing_nums.append(int(m.group(1)))
    next_num = max(existing_nums, default=1) + 1
    # If no default_visual exists, make this one the default
    if not (artist_dir / "default_visual.mp4").exists() and not existing_nums:
        safe_name = "default_visual.mp4"
    else:
        safe_name = f"visual_{next_num}.mp4"

    dest = artist_dir / safe_name
    temp_path.rename(dest)
    sessions.pop(upload_key, None)

    saved_mb = dest.stat().st_size / (1024 * 1024)
    await safe_edit(
        query.message,
        f"Saved as {artist_name}/{safe_name} ({saved_mb:.1f} MB)\n"
        f"Pick it via /batch, /fy3stash, or /rerender."
    )


