async def cmd_status(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not is_allowed(update):
        return await deny(update)

    try:
        beats    = list((ROOT / "beats").glob("*.mp3")) + list((ROOT / "beats").glob("*.wav"))
        rendered = [f for f in (ROOT / "output").glob("*.mp4") if _is_render_mp4(f)]
        log_data = load_json_safe(ROOT / "uploads_log.json", {})
        uploaded = list(log_data.keys())

        not_rendered = [b for b in beats if not already_rendered(b)]

        msg = (
            f"📊 Status\n\n"
            f"🎵 Beats total:   {len(beats)}\n"
            f"🎬 Rendered:      {len(rendered)}\n"
            f"🔲 Not rendered:  {len(not_rendered)}\n"
            f"☁️  Uploaded:      {len(uploaded)}\n"
        )
        if not_rendered:
            names = "\n".join(f"  • {safe_stem(b)}" for b in not_rendered[:10])
            if len(not_rendered) > 10:
                names += f"\n  ...and {len(not_rendered)-10} more"
            msg += f"\nNot yet rendered:\n{names}"
        else:
            msg += "\n✅ All beats rendered!"

        await update.message.reply_text(msg)
    except Exception as e:
        await update.message.reply_text(f"❌ Status error: {e}")


async def cmd_reanalyze(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/reanalyze [stem] — force re-detect BPM + key for one beat or all beats missing them."""
    if not is_allowed(update):
        return await deny(update)

    target = " ".join(context.args or []).strip().lower()
    beats  = sorted(
        list((ROOT / "beats").glob("*.mp3")) +
        list((ROOT / "beats").glob("*.wav"))
    )
    if not beats:
        await update.message.reply_text("🎵 No beats in `beats/` yet.", parse_mode="Markdown")
        return

    if target:
        # Single beat
        matched = [b for b in beats if safe_stem(b) == target or target in safe_stem(b)]
        if not matched:
            await update.message.reply_text(
                f"❌ No beat matching `{target}` found.\n"
                "Use the stem name (e.g. `/reanalyze hood_legend`).",
                parse_mode="Markdown",
            )
            return
        queue = matched[:1]
    else:
        # All beats missing bpm or key
        queue = []
        for b in beats:
            m = load_json_safe(ROOT / "metadata" / f"{safe_stem(b)}.json", {})
            if not m.get("bpm") or not m.get("key"):
                queue.append(b)
        if not queue:
            await update.message.reply_text("✅ All beats already have BPM + Key detected!")
            return

    msg = await update.message.reply_text(
        f"🔍 Re-analyzing *{len(queue)}* beat(s)… this may take a minute.",
        parse_mode="Markdown",
    )

    loop    = asyncio.get_event_loop()
    results = []
    for b in queue:
        stem = safe_stem(b)
        try:
            fl_meta  = _read_fl_metadata(str(b))
            detected = await loop.run_in_executor(None, _analyze_audio, str(b))
            saved    = _merge_and_save_metadata(stem, fl_meta, detected)
            bpm      = saved.get("bpm", "?")
            key      = saved.get("key", "?")
            results.append(f"✅ `{stem}` → *{bpm} BPM* • *{key}*")
        except Exception as e:
            results.append(f"⚠️ `{stem}` failed: {e}")

    lines = "\n".join(results)
    await safe_edit(msg, f"🎵 *Re-analysis complete:*\n\n{lines}", parse_mode="Markdown")


