async def cmd_render(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not is_allowed(update):
        return await deny(update)
    # Show clip picker for /render too
    beats   = sorted(
        list((ROOT / "beats").glob("*.mp3")) +
        list((ROOT / "beats").glob("*.wav"))
    )
    pending = [b for b in beats if not already_rendered(b)]
    if not pending:
        await update.message.reply_text("✅ All beats already rendered.")
        return
    stems  = [safe_stem(b) for b in pending]
    kb     = media_keyboard(stems, batch=len(stems) > 1)
    if kb is None:
        # No clips — still show artist picker before rendering
        render_key = f"rk_{int(time.time())}_{os.urandom(4).hex()}"
        context.bot_data.setdefault("_render_sessions", {})[render_key] = {
            "stems": stems, "clip_name": "default_visual.mp4",
            "random_mode": False, "use_force": False,
        }
        beat_list = "\n".join(f"  🎵 `{esc(s)}`" for s in stems[:8])
        if len(stems) > 8:
            beat_list += f"\n  …and {len(stems) - 8} more"
        artist_kb = _build_artist_picker_kb(render_key)
        await update.message.reply_text(
            f"🎤 *What type beat?*\n{beat_list}\n\n"
            f"Pick an artist or tap *Auto-Detect*:",
            parse_mode="Markdown",
            reply_markup=artist_kb,
        )
        return
    names = "\n".join(f"  • {s}" for s in stems[:10])
    if len(stems) > 10:
        names += f"\n  ...and {len(stems)-10} more"
    await update.message.reply_text(
        f"🎬 {len(stems)} beats to render:\n{names}\n\nPick a visualizer clip:",
        reply_markup=kb,
    )


