# Module-level dict to track active upload sessions for cancel functionality
_ACTIVE_UPLOADS: dict[str, dict] = {}

# Module-level dict to store batch social share stems (too long for callback_data)
_SOCIAL_BATCH_STEMS: dict[str, list[str]] = {}  # batch_key → [stems]


async def run_upload_live(msg_target, extra_args: list[str] | None = None):
    """
    Run upload.py with live per-video progress streamed to Telegram.
    Signals: [UPLOAD], [DONE], [FAIL], [SKIP], [PROGRESS], [ERROR], [COMPLETE]
    Features:
    - Pre-flight check for client_secret.json
    - 30-minute overall timeout (kills process if hung)
    - Heartbeat every 30s so Telegram message stays alive
    - Throttled progress bar edits (max 1 per 4s) to avoid rate limits
    - Actionable error messages for quota/auth/API issues
    """
    cmd = [PYTHON, str(ROOT / "upload.py")] + (extra_args or [])

    _tid = _new_task_id("Upload to YouTube")

    # Pre-flight: check client_secret exists
    if not (ROOT / "client_secret.json").exists():
        await msg_target.reply_text(
            "❌ *YouTube not configured.*\n\n"
            "You need `client_secret.json` from Google Cloud Console.\n"
            "Run /ytsetup for step-by-step instructions.",
            parse_mode="Markdown",
        )
        _finish_task(_tid)
        return

    # Pre-flight: check token exists — if not, OAuth hasn't been done yet.
    # The bot can't open a browser interactively, so the user must do this
    # one-time step in Terminal first.
    if not (ROOT / "token.json").exists():
        await msg_target.reply_text(
            "🔑 *YouTube login required — one-time setup*\n\n"
            "`client_secret.json` is found ✅\n"
            "`token.json` is missing ❌\n\n"
            "You need to sign in once from Terminal. Open Terminal on your Mac and run:\n\n"
            "```\ncd /Users/fyefye/yt_automation\n"
            ".venv/bin/python3.14 upload.py --dry-run\n```\n\n"
            "A browser will open → sign in with your YouTube account → allow access.\n"
            "`token.json` is saved automatically.\n\n"
            "After that, /upload works forever (auto-refreshes the token).",
            parse_mode="Markdown",
        )
        _finish_task(_tid)
        return

    # Pre-flight: check token is valid / refreshable before wasting time launching
    try:
        from google.oauth2.credentials import Credentials
        from google.auth.transport.requests import Request as _GReq
        _creds = Credentials.from_authorized_user_file(str(ROOT / "token.json"))
        if not _creds.valid:
            if _creds.expired and _creds.refresh_token:
                _creds.refresh(_GReq())
                with open(ROOT / "token.json", "w") as _f:
                    _f.write(_creds.to_json())
            else:
                raise ValueError("token expired and no refresh_token")
    except Exception as _te:
        await msg_target.reply_text(
            f"🔑 *YouTube token expired or invalid.*\n\n"
            f"Error: `{esc(str(_te)[:200])}`\n\n"
            "Delete the old token and sign in again from Terminal:\n\n"
            "```\nrm /Users/fyefye/yt_automation/token.json\n"
            "cd /Users/fyefye/yt_automation\n"
            ".venv/bin/python3.14 upload.py --dry-run\n```",
            parse_mode="Markdown",
        )
        _finish_task(_tid)
        return

    # Generate unique session key for cancel button
    _upload_session_id = f"upl_{int(time.time())}_{os.urandom(3).hex()}"
    _cancel_kb = InlineKeyboardMarkup([[
        InlineKeyboardButton("🛑 Cancel Upload", callback_data=f"cancelupl:{_upload_session_id}")
    ]])

    status_msg = await msg_target.reply_text(
        "📤 *Starting upload...*\nConnecting to YouTube API...",
        parse_mode="Markdown",
        reply_markup=_cancel_kb,
    )

    proc = None
    try:
        try:
            proc = await asyncio.create_subprocess_exec(
                "caffeinate", "-i", *cmd,
                stdout=asyncio.subprocess.PIPE,
                stderr=asyncio.subprocess.PIPE,
                cwd=str(ROOT),
            )
        except FileNotFoundError:
            proc = await asyncio.create_subprocess_exec(
                *cmd,
                stdout=asyncio.subprocess.PIPE,
                stderr=asyncio.subprocess.PIPE,
                cwd=str(ROOT),
            )
    except Exception as e:
        await safe_edit(status_msg, f"❌ Could not start upload: `{esc(str(e))}`", parse_mode="Markdown")
        _finish_task(_tid)
        return

    uploaded     = []
    failed       = []
    skipped      = []
    stderr_lines = []
    current      = None
    current_msg  = None
    total_vids   = 0
    idx_vids     = 0
    last_edit    = asyncio.get_event_loop().time()
    last_pct     = -1
    cancelled    = False

    # Store upload session so the cancel callback can kill the process
    _upload_session = {
        "proc": proc, "uploaded": uploaded, "failed": failed,
        "skipped": skipped, "status_msg": status_msg, "cancelled": False,
    }
    _ACTIVE_UPLOADS[_upload_session_id] = _upload_session

    async def heartbeat():
        """Edit status_msg every 30s so Telegram keeps the message fresh."""
        while True:
            await asyncio.sleep(30)
            if proc.returncode is not None or _upload_session.get("cancelled"):
                break
            try:
                if current:
                    txt = (
                        f"📤 *Uploading {idx_vids}/{total_vids}*\n"
                        f"Current: `{esc(current)}`\n"
                        f"Done: {len(uploaded)} ✅  Failed: {len(failed)} ❌\n"
                        f"_(still running...)_"
                    )
                else:
                    txt = (
                        f"📤 *Upload in progress*\n"
                        f"Done: {len(uploaded)} ✅  Failed: {len(failed)} ❌  "
                        f"Skipped: {len(skipped)}\n_(still running...)_"
                    )
                await safe_edit(status_msg, txt, parse_mode="Markdown", reply_markup=_cancel_kb)
            except Exception:
                pass

    async def read_stderr():
        async for raw in proc.stderr:
            line = raw.decode("utf-8", errors="replace").rstrip()
            if line:
                stderr_lines.append(line)
                log.warning("upload stderr: %s", line)

    async def read_stdout():
        nonlocal current, current_msg, total_vids, idx_vids, last_edit, last_pct

        async for raw in proc.stdout:
            line = raw.decode("utf-8", errors="replace").rstrip()
            if not line:
                continue
            log.info("upload stdout: %s", line)

            # [UPLOAD] stem (idx/total)
            up_match = re.search(r"\[UPLOAD\]\s+(\S+)\s+\((\d+)/(\d+)\)", line)
            if up_match:
                current    = up_match.group(1)
                idx_vids   = int(up_match.group(2))
                total_vids = int(up_match.group(3))
                last_pct   = -1
                try:
                    current_msg = await msg_target.reply_text(
                        f"📤 *{esc(current)}* — {idx_vids}/{total_vids}\n⏳ Starting...",
                        parse_mode="Markdown",
                    )
                except Exception as e:
                    log.warning("upload: send video msg failed: %s", e)
                    current_msg = None
                await safe_edit(status_msg,
                    f"📤 *Upload running — {idx_vids}/{total_vids}*\n"
                    f"Done: {len(uploaded)} ✅  Failed: {len(failed)} ❌",
                    parse_mode="Markdown",
                    reply_markup=_cancel_kb,
                )
                continue

            # [DONE] stem → url
            done_match = re.search(r"\[DONE\]\s+(\S+)\s+→\s+(\S+)", line)
            if done_match:
                stem = done_match.group(1)
                url  = done_match.group(2)
                uploaded.append((stem, url))
                if current_msg:
                    await safe_edit(current_msg,
                        f"✅ *{esc(stem)}* uploaded!\n🔗 {url}",
                        parse_mode="Markdown",
                    )
                current = None; current_msg = None; last_pct = -1
                await safe_edit(status_msg,
                    f"📤 *Upload running — {idx_vids}/{total_vids}*\n"
                    f"Done: {len(uploaded)} ✅  Failed: {len(failed)} ❌  Skipped: {len(skipped)}",
                    parse_mode="Markdown",
                    reply_markup=_cancel_kb,
                )
                # ── Social media share menu after each upload ────────────
                try:
                    _social_kb = InlineKeyboardMarkup([
                        [
                            InlineKeyboardButton("🎵 TikTok", callback_data=f"social:post:tt:{stem}"[:64]),
                            InlineKeyboardButton("📸 Instagram", callback_data=f"social:post:ig:{stem}"[:64]),
                        ],
                        [
                            InlineKeyboardButton("🎵+📸 Both", callback_data=f"social:post:both:{stem}"[:64]),
                            InlineKeyboardButton("⏭ Skip", callback_data=f"social:skip:{stem}"[:64]),
                        ],
                    ])
                    await msg_target.reply_text(
                        f"📱 Share *{esc(stem)}* to social media?",
                        parse_mode="Markdown",
                        reply_markup=_social_kb,
                    )
                except Exception as _se:
                    log.warning("Social share menu failed for %s: %s", stem, _se)
                continue

            # [FAIL] stem: reason
            fail_match = re.search(r"\[FAIL\]\s+(\S+)[:\s]+(.*)", line)
            if fail_match:
                stem   = fail_match.group(1)
                reason = fail_match.group(2).strip()
                failed.append(stem)
                if current_msg:
                    await safe_edit(current_msg,
                        f"❌ *{esc(stem)}* failed\n`{esc(reason[:300])}`",
                        parse_mode="Markdown",
                    )
                current = None; current_msg = None
                low = reason.lower()
                if "quota" in low:
                    await msg_target.reply_text(
                        "⚠️ *YouTube daily quota exceeded.*\n"
                        "YouTube limits uploads on new accounts. Try again tomorrow\n"
                        "or use /schedule to spread uploads over multiple days.",
                        parse_mode="Markdown",
                    )
                elif any(x in low for x in ("token", "auth", "credential", "403", "invalid_grant")):
                    await msg_target.reply_text(
                        "🔑 *Auth error.* Run /ytsetup to re-authenticate with YouTube.",
                        parse_mode="Markdown",
                    )
                continue

            # [PROGRESS] pct — throttled to 1 edit per 4s
            prog_match = re.search(r"\[PROGRESS\]\s+(\d+)%", line)
            if prog_match and current_msg:
                pct = int(prog_match.group(1))
                now = asyncio.get_event_loop().time()
                if pct != last_pct and now - last_edit >= 4:
                    last_pct  = pct
                    last_edit = now
                    bar = progress_bar(pct)
                    await safe_edit(current_msg,
                        f"📤 *{esc(current)}* — {idx_vids}/{total_vids}\n`{bar}` {pct}%",
                        parse_mode="Markdown",
                    )
                continue

            # [SKIP]
            skip_match = re.search(r"\[SKIP\]\s+(.*)", line)
            if skip_match:
                parts = re.search(r":\s+(.*)", skip_match.group(1))
                if parts:
                    for s in parts.group(1).split(","):
                        s = s.strip()
                        if s:
                            skipped.append(s)
                await safe_edit(status_msg,
                    f"📤 *Upload running...*\n"
                    f"⏭ Skipping {len(skipped)} already uploaded\n"
                    f"Done: {len(uploaded)} ✅  Failed: {len(failed)} ❌",
                    parse_mode="Markdown",
                    reply_markup=_cancel_kb,
                )
                continue

            # [ERROR]
            if "[ERROR]" in line:
                err_txt = re.sub(r"\[ERROR\]\s*", "", line).strip()
                await msg_target.reply_text(f"⚠️ `{esc(err_txt)}`", parse_mode="Markdown")
                continue

            # [QUOTA] — YouTube daily quota limit reached
            if "[QUOTA]" in line:
                quota_txt = re.sub(r"\[QUOTA\]\s*", "", line).strip()
                remain_m = re.search(r"(\d+)\s+video", quota_txt)
                remaining = int(remain_m.group(1)) if remain_m else "?"
                await msg_target.reply_text(
                    f"📊 *YouTube daily quota reached*\n"
                    f"{'━' * 24}\n"
                    f"✅ Uploaded: {len(uploaded)}\n"
                    f"⏳ Remaining: {remaining}\n\n"
                    f"⏰ Quota resets at *midnight Pacific Time*\n"
                    f"Run /upload tomorrow to continue.\n"
                    f"_Progress saved automatically._",
                    parse_mode="Markdown",
                )
                continue

            # [COMPLETE] — batch finished signal
            if "[COMPLETE]" in line:
                continue

            # Authenticated confirmation
            if "authenticated" in line.lower() and "✓" in line:
                await safe_edit(status_msg,
                    "📤 *Upload running...*\n✅ YouTube authenticated — scanning queue...",
                    parse_mode="Markdown",
                    reply_markup=_cancel_kb,
                )
                continue

            # Nothing to upload
            if "nothing to upload" in line.lower():
                await safe_edit(status_msg,
                    "📭 *Nothing to upload.*\nAll rendered beats are already on YouTube.\n"
                    "Run /batch to render new beats.",
                    parse_mode="Markdown",
                )
                continue

    OVERALL_TIMEOUT = 1800  # 30 min
    try:
        await asyncio.wait_for(
            asyncio.gather(read_stdout(), read_stderr(), heartbeat()),
            timeout=OVERALL_TIMEOUT,
        )
    except asyncio.TimeoutError:
        log.warning("upload: overall timeout %ss", OVERALL_TIMEOUT)
        if proc and proc.returncode is None:
            proc.kill()
        await msg_target.reply_text(
            f"⏱ *Upload timed out after 30 minutes.*\n"
            f"Completed: {len(uploaded)} ✅  Failed: {len(failed)} ❌\n"
            f"Progress was saved — run /upload to continue where it left off.",
            parse_mode="Markdown",
        )
    except Exception as e:
        log.warning("upload gather error: %s", e)
    finally:
        if proc and proc.returncode is None:
            try:
                proc.kill()
                await proc.wait()
            except Exception:
                pass
        _finish_task(_tid)

    try:
        if proc:
            await asyncio.wait_for(proc.wait(), timeout=5)
    except asyncio.TimeoutError:
        pass

    rc         = proc.returncode if proc else -1
    stderr_buf = "\n".join(stderr_lines[-20:])  # last 20 lines enough for diagnosis

    # ── Clean up cancel session ──────────────────────────────────────────────
    _ACTIVE_UPLOADS.pop(_upload_session_id, None)
    cancelled = _upload_session.get("cancelled", False)

    # ── Final summary ─────────────────────────────────────────────────────────
    if cancelled:
        summary = ["🛑 *Upload cancelled*\n"]
    else:
        summary = ["🏁 *Upload session complete*\n"]
    summary.append(f"✅ Uploaded:  {len(uploaded)}")
    if skipped:
        summary.append(f"⏭ Skipped:   {len(skipped)} (already on YouTube)")
    if failed:
        summary.append(f"❌ Failed:    {len(failed)}")
        for f_stem in failed:
            summary.append(f"   • {esc(f_stem)}")
    if not uploaded and not failed and not skipped:
        summary.append("_(nothing was processed)_")

    if uploaded:
        summary.append("\n*Videos now live:*")
        for stem, url in uploaded:
            summary.append(f"  • [{esc(stem)}]({url})")

    # Stderr-based diagnostics
    if stderr_buf:
        low = stderr_buf.lower()
        if "client_secret" in low or "no such file" in low:
            summary += ["", "❌ *YouTube not set up.* Run /ytsetup for OAuth instructions."]
        elif "invalid_grant" in low or ("token" in low and "invalid" in low):
            summary += ["", "🔑 *Token expired.* Delete `token.json` and run /upload to re-auth."]
        elif "quota" in low:
            summary += ["", "📊 *Daily quota hit.* YouTube allows ~6 uploads/day on new channels.",
                        "Use /schedule to spread uploads over multiple days."]
        elif "403" in low or "forbidden" in low:
            summary += ["", "⚠️ *API permission error.* Ensure YouTube Data API v3 is enabled",
                        "in your Google Cloud Console."]

    await safe_edit(status_msg, "\n".join(summary), parse_mode="Markdown")

    # ── Batch social share menu after all uploads ────────────────────────────
    if uploaded and not cancelled:
        try:
            _batch_key = f"sbatch_{int(time.time())}_{os.urandom(3).hex()}"
            _SOCIAL_BATCH_STEMS[_batch_key] = [s for s, _ in uploaded]
            _batch_kb = InlineKeyboardMarkup([
                [InlineKeyboardButton("🎵 All to TikTok", callback_data=f"social:batch:tt:{_batch_key}"[:64])],
                [InlineKeyboardButton("📸 All to Instagram", callback_data=f"social:batch:ig:{_batch_key}"[:64])],
                [InlineKeyboardButton("🎵+📸 All to Both", callback_data=f"social:batch:both:{_batch_key}"[:64])],
                [InlineKeyboardButton("⏭ Skip", callback_data="social:batch:skip:_")],
            ])
            await msg_target.reply_text(
                f"📱 Share all {len(uploaded)} video(s) to social media?",
                parse_mode="Markdown",
                reply_markup=_batch_kb,
            )
        except Exception as _se:
            log.warning("Batch social share menu failed: %s", _se)

    await send_menu(msg_target)


def _get_upload_pending_stems() -> list[str]:
    """Get stems that are rendered but not yet uploaded."""
    log_data = load_json_safe(ROOT / "uploads_log.json", {})
    stems = []
    for mp4 in sorted((ROOT / "output").glob("*.mp4")):
        stem = mp4.stem
        if any(stem.endswith(s) for s in _AUX_SUFFIXES):
            continue
        if stem in log_data:
            continue
        if (ROOT / "metadata" / f"{stem}.json").exists():
            stems.append(stem)
    return stems


# ── Airbit Upload ─────────────────────────────────────────────────────────────

_ACTIVE_AIRBIT_UPLOADS: dict[str, dict] = {}


def _get_airbit_pending_stems() -> list[str]:
    """Get stems that have audio files but are not yet in airbit_uploads_log.json."""
    airbit_log = load_json_safe(ROOT / "airbit_uploads_log.json", {})
    stems = []
    for audio in sorted((ROOT / "beats").glob("*.mp3")):
        stem = audio.stem
        if stem.startswith("bg_"):
            continue
        if stem in airbit_log:
            continue
        stems.append(stem)
    return stems


async def run_airbit_live(msg_target, extra_args: list[str] | None = None):
    """Run airbit_upload.py with live progress streamed to Telegram."""
    cmd = [PYTHON, str(ROOT / "airbit_upload.py")] + (extra_args or [])
    _tid = _new_task_id("Upload to Airbit")

    # Pre-flight: check Chrome profile exists (means login was done)
    if not (ROOT / ".airbit_chrome_profile").exists() and "--login" not in (extra_args or []):
        await msg_target.reply_text(
            "🔑 *Airbit not set up yet.*\n\n"
            "You need to log in once first.\n"
            "From Terminal on your Mac:\n\n"
            "```\ncd /Users/fyefye/yt_automation\n"
            ".venv/bin/python3.14 airbit_upload.py --login\n```\n\n"
            "Chrome will open → log in to Airbit → come back and press Enter.\n"
            "After that, /airbit works from Telegram.",
            parse_mode="Markdown",
        )
        _finish_task(_tid)
        return

    # Pre-flight: clean stale Chrome lock files (prevents "cannot connect" errors)
    _profile_dir = ROOT / ".airbit_chrome_profile"
    if _profile_dir.exists():
        for _lock in ("SingletonLock", "SingletonSocket", "SingletonCookie"):
            _lp = _profile_dir / _lock
            if _lp.exists() or _lp.is_symlink():
                try:
                    _lp.unlink()
                except OSError:
                    pass

    _session_id = f"abupl_{int(time.time())}_{os.urandom(3).hex()}"
    _cancel_kb = InlineKeyboardMarkup([[
        InlineKeyboardButton("🛑 Cancel", callback_data=f"cancelab:{_session_id}")
    ]])

    status_msg = await msg_target.reply_text(
        "🎵 *Starting Airbit upload...*\nLaunching Chrome...",
        parse_mode="Markdown",
        reply_markup=_cancel_kb,
    )

    proc = None
    try:
        proc = await asyncio.create_subprocess_exec(
            *cmd,
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.PIPE,
            cwd=str(ROOT),
        )
    except Exception as e:
        await safe_edit(status_msg, f"❌ Could not start Airbit upload: `{esc(str(e))}`", parse_mode="Markdown")
        _finish_task(_tid)
        return

    uploaded = []
    failed   = []
    _session = {"proc": proc, "uploaded": uploaded, "failed": failed, "cancelled": False}
    _ACTIVE_AIRBIT_UPLOADS[_session_id] = _session

    current    = None
    total_vids = 0
    idx_vids   = 0
    last_edit  = asyncio.get_event_loop().time()

    async def read_stderr():
        async for raw in proc.stderr:
            line = raw.decode("utf-8", errors="replace").rstrip()
            if line:
                log.warning("airbit stderr: %s", line)

    async def read_stdout():
        nonlocal current, total_vids, idx_vids, last_edit
        async for raw in proc.stdout:
            line = raw.decode("utf-8", errors="replace").rstrip()
            if not line:
                continue
            log.info("airbit stdout: %s", line)

            # [UPLOAD] stem (idx/total)
            up_m = re.search(r"\[UPLOAD\]\s+(\S+)\s+\((\d+)/(\d+)\)", line)
            if up_m:
                current    = up_m.group(1)
                idx_vids   = int(up_m.group(2))
                total_vids = int(up_m.group(3))
                now = asyncio.get_event_loop().time()
                if now - last_edit >= 3:
                    last_edit = now
                    await safe_edit(status_msg,
                        f"🎵 *Airbit upload {idx_vids}/{total_vids}*\n"
                        f"Current: `{esc(current)}`\n"
                        f"Done: {len(uploaded)} ✅  Failed: {len(failed)} ❌",
                        parse_mode="Markdown", reply_markup=_cancel_kb)
                continue

            # [DONE] stem
            done_m = re.search(r"\[DONE\]\s+(\S+)", line)
            if done_m:
                stem = done_m.group(1)
                uploaded.append(stem)
                current = None
                await safe_edit(status_msg,
                    f"🎵 *Airbit upload {idx_vids}/{total_vids}*\n"
                    f"✅ `{esc(stem)}` uploaded\n"
                    f"Done: {len(uploaded)} ✅  Failed: {len(failed)} ❌",
                    parse_mode="Markdown", reply_markup=_cancel_kb)
                continue

            # [FAIL] reason
            fail_m = re.search(r"\[FAIL\]\s+(.*)", line)
            if fail_m:
                failed.append(fail_m.group(1).strip())
                current = None
                continue

            # [COMPLETE]
            if "[COMPLETE]" in line:
                continue

            # [ERROR]
            if "[ERROR]" in line:
                err = re.sub(r"\[ERROR\]\s*", "", line).strip()
                await msg_target.reply_text(f"⚠️ Airbit: `{esc(err[:300])}`", parse_mode="Markdown")
                continue

            # Dry-run output: relay interesting lines
            if "[DRY RUN]" in line or line.strip().startswith("["):
                now = asyncio.get_event_loop().time()
                if now - last_edit >= 3:
                    last_edit = now
                    await safe_edit(status_msg,
                        f"🎵 *Airbit dry run*\n`{esc(line[:200])}`",
                        parse_mode="Markdown", reply_markup=_cancel_kb)

    TIMEOUT = 2400  # 40 min (Selenium is slower)
    try:
        await asyncio.wait_for(asyncio.gather(read_stdout(), read_stderr()), timeout=TIMEOUT)
    except asyncio.TimeoutError:
        if proc and proc.returncode is not None:
            pass
        elif proc:
            proc.kill()
        await msg_target.reply_text("⏱ *Airbit upload timed out.* Progress saved.", parse_mode="Markdown")
    finally:
        if proc and proc.returncode is None:
            try:
                proc.kill()
                await proc.wait()
            except Exception:
                pass
        _finish_task(_tid)
        _ACTIVE_AIRBIT_UPLOADS.pop(_session_id, None)

    # Final summary
    summary = ["🏁 *Airbit upload complete*\n"]
    if uploaded:
        summary.append(f"✅ Uploaded: {len(uploaded)}")
        for s in uploaded[:15]:
            summary.append(f"   • {esc(s)}")
        if len(uploaded) > 15:
            summary.append(f"   ...+{len(uploaded) - 15} more")
    if failed:
        summary.append(f"❌ Failed: {len(failed)}")
        for f in failed[:5]:
            summary.append(f"   • {esc(f[:80])}")
    if not uploaded and not failed:
        summary.append("_(nothing processed)_")

    await safe_edit(status_msg, "\n".join(summary), parse_mode="Markdown")
    await send_menu(msg_target)


async def cancel_airbit_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle cancelab:{session_id} — kill Airbit upload subprocess."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query:
            await query.answer("⛔", show_alert=True)
        return
    await query.answer("🛑 Cancelling...")
    session_id = query.data.split(":", 1)[1]
    session = _ACTIVE_AIRBIT_UPLOADS.get(session_id)
    if not session:
        await safe_edit(query.message, "⚠️ Session not found or already finished.")
        return
    session["cancelled"] = True
    proc = session.get("proc")
    if proc and proc.returncode is None:
        try:
            proc.kill()
            await proc.wait()
        except Exception:
            pass
    n = len(session.get("uploaded", []))
    await safe_edit(query.message, f"🛑 *Airbit upload cancelled*\n✅ Uploaded before cancel: {n}", parse_mode="Markdown")
    _ACTIVE_AIRBIT_UPLOADS.pop(session_id, None)
    await send_menu(query.message)


async def _start_airbit_flow(msg, context):
    """Show Airbit upload status + action buttons."""
    pending = _get_airbit_pending_stems()
    airbit_log = load_json_safe(ROOT / "airbit_uploads_log.json", {})
    total_mp3 = sum(1 for f in (ROOT / "beats").glob("*.mp3") if not f.stem.startswith("bg_"))
    has_profile = (ROOT / ".airbit_chrome_profile").exists()

    lines = [
        "🎵 *Airbit Upload*\n",
        f"Total beats: {total_mp3}",
        f"Already on Airbit: {len(airbit_log)}",
        f"Pending: {len(pending)}",
    ]
    if pending:
        beat_list = "\n".join(f"  • `{esc(s)}`" for s in pending[:10])
        if len(pending) > 10:
            beat_list += f"\n  ...+{len(pending) - 10} more"
        lines.append(f"\n{beat_list}")

    rows = []
    if not has_profile:
        rows.append([InlineKeyboardButton("🔑 Login (first time)", callback_data="abact:login")])
    if pending:
        rows.append([InlineKeyboardButton("👁 Dry Run", callback_data="abact:dry")])
        rows.append([InlineKeyboardButton("🚀 Upload All", callback_data="abact:all")])
        rows.append([InlineKeyboardButton("🎯 Upload Specific...", callback_data="abact:pick")])
    if not pending and not rows:
        lines.append("\n✅ All beats are already on Airbit!")
    rows.append([InlineKeyboardButton("❌ Cancel", callback_data="abact:cancel")])

    await msg.reply_text("\n".join(lines), parse_mode="Markdown",
                         reply_markup=InlineKeyboardMarkup(rows))


# ── /queue — view and manage the upload queue ─────────────────────────────────

def _queue_kb(page: int = 0) -> InlineKeyboardMarkup:
    """Build paginated queue keyboard."""
    data = _load_upload_queue()
    q = data["queue"]
    # Sort same as _queue_next_n
    q_sorted = sorted(q, key=lambda e: (-e.get("priority", 0), e.get("added_at", "")))
    PAGE = 8
    start = page * PAGE
    chunk = q_sorted[start:start + PAGE]

    rows = []
    for i, entry in enumerate(chunk):
        pos = start + i + 1
        stem = entry["stem"]
        pin = "📌 " if entry.get("priority", 0) > 0 else ""
        rows.append([
            InlineKeyboardButton(f"{pos}. {pin}{stem[:40]}", callback_data=f"uq:noop:{start + i}"),
            InlineKeyboardButton("📌", callback_data=f"uq:pin:{start + i}:{page}"),
            InlineKeyboardButton("🗑", callback_data=f"uq:rm:{start + i}:{page}"),
        ])

    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("◀ Prev", callback_data=f"uq:pg:{page - 1}:0"))
    if start + PAGE < len(q_sorted):
        nav.append(InlineKeyboardButton("Next ▶", callback_data=f"uq:pg:{page + 1}:0"))
    if nav:
        rows.append(nav)

    buffer = _queue_buffer_days()
    rows.append([InlineKeyboardButton(
        f"📊 Buffer: {buffer} days | Queue: {len(q)} beats",
        callback_data="uq:noop:0:0",
    )])
    return InlineKeyboardMarkup(rows)


async def cmd_queue(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/queue — view upload queue."""
    if not is_allowed(update):
        return await deny(update)
    data = _load_upload_queue()
    q = data["queue"]
    if not q:
        await update.message.reply_text(
            "📭 Upload queue is empty.\n"
            "Run /seedqueue to populate from existing rendered beats,\n"
            "or drop a beat file here to add it.",
        )
        return
    await update.message.reply_text(
        f"📋 *Upload Queue* ({len(q)} beats)\n"
        f"Tap 📌 to pin to top, 🗑 to remove.",
        parse_mode="Markdown",
        reply_markup=_queue_kb(0),
    )


async def queue_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle uq: callbacks for queue management."""
    query = update.callback_query
    await query.answer()
    parts = query.data.split(":")
    if len(parts) < 3:
        return
    action = parts[1]

    if action == "noop":
        return

    if action == "pg":
        page = int(parts[2])
        await query.edit_message_reply_markup(reply_markup=_queue_kb(page))
        return

    if action in ("pin", "rm"):
        idx = int(parts[2])
        page = int(parts[3]) if len(parts) > 3 else 0
        data = _load_upload_queue()
        q_sorted = sorted(data["queue"],
                          key=lambda e: (-e.get("priority", 0), e.get("added_at", "")))
        if idx >= len(q_sorted):
            return

        target_stem = q_sorted[idx]["stem"]

        if action == "pin":
            # Toggle pin: set priority to 10 if 0, else 0
            for entry in data["queue"]:
                if entry["stem"] == target_stem:
                    entry["priority"] = 0 if entry.get("priority", 0) > 0 else 10
                    break
            _save_upload_queue(data)
        elif action == "rm":
            data["queue"] = [e for e in data["queue"] if e["stem"] != target_stem]
            _save_upload_queue(data)

        try:
            await query.edit_message_reply_markup(reply_markup=_queue_kb(page))
        except Exception:
            pass


async def cmd_seedqueue(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/seedqueue — populate queue from existing rendered beats not yet uploaded."""
    if not is_allowed(update):
        return await deny(update)

    ulog = load_json_safe(ROOT / "uploads_log.json", {})
    data = _load_upload_queue()
    existing_stems = {e["stem"] for e in data["queue"]}

    added = 0
    output_dir = ROOT / "output"
    for mp4 in sorted(output_dir.glob("*.mp4")):
        stem = mp4.stem
        # Skip thumbnails, shorts variants, and non-beat files
        if stem.endswith("_thumb") or stem.endswith("_9x16"):
            continue
        if stem in ulog or stem in existing_stems:
            continue
        # Skip bg_ (Bowl Gospel) beats
        if stem.startswith("bg_"):
            continue
        data["queue"].append({
            "stem": stem,
            "added_at": datetime.now(timezone.utc).isoformat(),
            "priority": 0,
        })
        existing_stems.add(stem)
        added += 1

    _save_upload_queue(data)
    buffer = _queue_buffer_days()
    await update.message.reply_text(
        f"✅ Added {added} beat(s) to queue.\n"
        f"📊 Buffer: {buffer} days | Queue: {len(data['queue'])} total",
    )


async def cmd_autopilot(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/autopilot — toggle daily auto-upload daemon."""
    if not is_allowed(update):
        return await deny(update)

    data = _load_upload_queue()
    currently_on = data["settings"].get("autopilot_enabled", True)

    # Toggle
    data["settings"]["autopilot_enabled"] = not currently_on
    _save_upload_queue(data)

    new_state = data["settings"]["autopilot_enabled"]
    buffer = _queue_buffer_days()
    status = "ON ✅" if new_state else "OFF ⏸"
    lines = [
        f"🤖 *Autopilot: {status}*",
        f"{'━' * 24}",
    ]
    if new_state:
        lines.extend([
            f"⏰ Next fire: 6 AM ET tomorrow",
            f"📺 Daily: 2 YouTube + 1 Short + TikTok + IG",
            f"📊 Buffer: {buffer} days",
        ])
    else:
        lines.append("Daily auto-uploads paused. Run /autopilot again to re-enable.")

    await update.message.reply_text("\n".join(lines), parse_mode="Markdown")


async def cmd_airbit(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/airbit — upload beats to Airbit store."""
    if not is_allowed(update):
        return await deny(update)
    await _start_airbit_flow(update.message, context)


async def airbit_action_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle abact:{action} — Airbit upload actions."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query:
            await query.answer("⛔ Not authorized.", show_alert=True)
        return
    await query.answer()

    action = query.data.split(":", 1)[1]
    msg = query.message

    try:
        await query.edit_message_reply_markup(reply_markup=None)
    except Exception:
        pass

    if action == "cancel":
        await msg.reply_text("❌ Airbit upload cancelled.")
        await send_menu(msg)
        return

    if action == "login":
        await msg.reply_text(
            "🔑 *Airbit Login*\n\n"
            "⚠️ *Close all Chrome windows on your Mac first!*\n\n"
            "Chrome will open on your Mac. Log in to Airbit,\n"
            "then the session is saved for future uploads.\n\n"
            "_Starting Chrome..._",
            parse_mode="Markdown",
        )
        task = asyncio.create_task(run_airbit_live(msg, extra_args=["--login"]))
        context.bot_data.setdefault("_bg_tasks", set()).add(task)
        task.add_done_callback(lambda t: context.bot_data.get("_bg_tasks", set()).discard(t))
        return

    if action == "dry":
        await msg.reply_text("👁 *Dry run — previewing Airbit uploads...*", parse_mode="Markdown")
        task = asyncio.create_task(run_airbit_live(msg, extra_args=["--dry-run"]))
        context.bot_data.setdefault("_bg_tasks", set()).add(task)
        task.add_done_callback(lambda t: context.bot_data.get("_bg_tasks", set()).discard(t))
        return

    if action == "all":
        pending = _get_airbit_pending_stems()
        await msg.reply_text(
            f"🚀 *Uploading {len(pending)} beat(s) to Airbit...*\n"
            f"⚠️ Chrome will open on your Mac. Don't close it!",
            parse_mode="Markdown",
        )
        task = asyncio.create_task(run_airbit_live(msg, extra_args=[]))
        context.bot_data.setdefault("_bg_tasks", set()).add(task)
        task.add_done_callback(lambda t: context.bot_data.get("_bg_tasks", set()).discard(t))
        return

    if action == "pick":
        pending = _get_airbit_pending_stems()
        if not pending:
            await msg.reply_text("📭 Nothing pending for Airbit.")
            await send_menu(msg)
            return
        context.user_data["_abpick_stems"] = pending
        context.user_data["_abpick_selected"] = set()
        await msg.reply_text(
            f"🎯 *Pick beats to upload to Airbit:*\n"
            f"Tap to select, tap again to deselect.\n"
            f"_{len(pending)} beats available_",
            parse_mode="Markdown",
            reply_markup=_airbit_pick_kb(pending, set(), 0),
        )
        return


def _airbit_pick_kb(all_stems: list, selected: set, page: int = 0) -> InlineKeyboardMarkup:
    """Paginated checkbox keyboard for picking Airbit beats."""
    PAGE = 8
    start = page * PAGE
    chunk = all_stems[start:start + PAGE]
    rows = []
    for i, stem in enumerate(chunk):
        check = "☑️" if stem in selected else "⬜"
        rows.append([InlineKeyboardButton(
            f"{check} {stem[:50]}",
            callback_data=f"abpick:{start + i}:{page}"
        )])
    # Navigation row
    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("◀ Prev", callback_data=f"abpick:pg:0:{page - 1}"))
    if start + PAGE < len(all_stems):
        nav.append(InlineKeyboardButton("Next ▶", callback_data=f"abpick:pg:0:{page + 1}"))
    if nav:
        rows.append(nav)
    # Action row
    action = []
    if selected:
        action.append(InlineKeyboardButton(
            f"🚀 Upload {len(selected)} beat(s)",
            callback_data="abpick:go:0:0"
        ))
    action.append(InlineKeyboardButton("❌ Cancel", callback_data="abpick:cancel:0:0"))
    rows.append(action)
    return InlineKeyboardMarkup(rows)


async def airbit_pick_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle abpick: callbacks — toggle beat selection, paginate, launch upload."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query:
            await query.answer("⛔", show_alert=True)
        return
    await query.answer()

    # Parse: abpick:{action_or_index}:{param}:{page_or_param}
    parts = query.data.split(":")
    if len(parts) < 3:
        return

    action_or_idx = parts[1]
    all_stems = context.user_data.get("_abpick_stems", [])
    selected = context.user_data.get("_abpick_selected", set())

    if not all_stems:
        await safe_edit(query.message, "⚠️ Session expired — tap /airbit again.")
        return

    # ── Pagination ──
    if action_or_idx == "pg":
        new_page = int(parts[3]) if len(parts) > 3 and parts[3].isdigit() else 0
        await query.edit_message_reply_markup(
            _airbit_pick_kb(all_stems, selected, new_page)
        )
        return

    # ── Cancel ──
    if action_or_idx == "cancel":
        context.user_data.pop("_abpick_stems", None)
        context.user_data.pop("_abpick_selected", None)
        await safe_edit(query.message, "❌ Airbit upload cancelled.")
        await send_menu(query.message)
        return

    # ── Go (upload selected) ──
    if action_or_idx == "go":
        if not selected:
            await query.answer("Select at least 1 beat first!", show_alert=True)
            return
        stems_list = sorted(selected)
        context.user_data.pop("_abpick_stems", None)
        context.user_data.pop("_abpick_selected", None)

        only = ",".join(stems_list)
        await safe_edit(query.message,
            f"🚀 *Uploading {len(stems_list)} beat(s) to Airbit...*\n"
            f"⚠️ Chrome will open on your Mac. Don't close it!\n\n"
            f"Selected: {', '.join(f'`{esc(s)}`' for s in stems_list[:10])}"
            f"{'...' if len(stems_list) > 10 else ''}",
            parse_mode="Markdown",
        )
        task = asyncio.create_task(
            run_airbit_live(query.message, extra_args=["--only", only])
        )
        context.bot_data.setdefault("_bg_tasks", set()).add(task)
        task.add_done_callback(lambda t: context.bot_data.get("_bg_tasks", set()).discard(t))
        return

    # ── Toggle selection (action_or_idx is a number = beat index) ──
    if action_or_idx.isdigit():
        idx = int(action_or_idx)
        page = int(parts[2]) if len(parts) > 2 and parts[2].isdigit() else 0
        if 0 <= idx < len(all_stems):
            stem = all_stems[idx]
            if stem in selected:
                selected.discard(stem)
            else:
                selected.add(stem)
            context.user_data["_abpick_selected"] = selected
        await query.edit_message_reply_markup(
            _airbit_pick_kb(all_stems, selected, page)
        )


# ── End Airbit Upload ─────────────────────────────────────────────────────────


def _stems_missing_artist(stems: list[str]) -> list[str]:
    """Return stems that have no seo_artist in their metadata."""
    missing = []
    for stem in stems:
        meta = load_json_safe(ROOT / "metadata" / f"{stem}.json", {})
        if not meta.get("seo_artist"):
            missing.append(stem)
    return missing


def _ensure_full_metadata(stems: list[str]) -> tuple[int, list[str]]:
    """Ensure every stem has title, description, and tags. Auto-generate if missing.

    Returns (fixed_count, still_broken) — stems that couldn't be fixed.
    """
    fixed = 0
    broken = []
    for stem in stems:
        meta_path = ROOT / "metadata" / f"{stem}.json"
        meta = load_json_safe(meta_path, {})
        changed = False

        # Title check — must not be empty, raw stem, or contain wrong producer name
        title = (meta.get("title") or "").strip()
        artist = meta.get("seo_artist", "BiggKutt8")
        title_bad = (
            not title
            or title.lower().replace(" ", "_") == stem.lower()
            or "leekthatsfye" in title.lower()
        )
        if title_bad:
            clean = stem.replace("_", " ").title()
            meta["title"] = f"{clean} {artist} Type Beat"
            changed = True

        # Description check
        desc = (meta.get("description") or "").strip()
        if not desc:
            meta["description"] = _build_seo_description(stem, meta)
            changed = True

        # Tags check
        tags = meta.get("tags") or []
        if not tags or len(tags) < 3:
            meta["tags"] = _suggest_tags(stem, meta)
            changed = True

        if changed:
            try:
                meta_path.parent.mkdir(parents=True, exist_ok=True)
                meta_path.write_text(json.dumps(meta, indent=2))
                fixed += 1
            except Exception as e:
                log.warning("_ensure_full_metadata: could not save %s: %s", stem, e)
                broken.append(stem)

    return fixed, broken


def _upload_action_kb(session_key: str) -> InlineKeyboardMarkup:
    """Build the upload action keyboard: Preview / Thumbnails / Upload Now / Schedule / Cancel."""
    return InlineKeyboardMarkup([
        [InlineKeyboardButton("👁 Preview (Title/Desc/Tags)", callback_data=f"uplgo:preview:0:{session_key}")],
        [InlineKeyboardButton("🖼 Pick Thumbnails", callback_data=f"thpick:start:0:{session_key}")],
        [InlineKeyboardButton("🚀 Upload Now (Public)", callback_data=f"uplgo:now:public:{session_key}")],
        [InlineKeyboardButton("🔒 Upload Now (Unlisted)", callback_data=f"uplgo:now:unlisted:{session_key}")],
        [InlineKeyboardButton("📅 Schedule...", callback_data=f"uplgo:schedmenu:_:{session_key}")],
        [InlineKeyboardButton("❌ Cancel", callback_data=f"uplgo:cancel:_:{session_key}")],
    ])


# ── Thumbnail picker ─────────────────────────────────────────────────────────

def _get_video_duration(mp4_path: Path) -> float:
    """Get video duration in seconds via ffprobe."""
    try:
        result = subprocess.run(
            ["ffprobe", "-v", "quiet", "-show_entries", "format=duration",
             "-of", "csv=p=0", str(mp4_path)],
            capture_output=True, text=True, timeout=10,
        )
        return float(result.stdout.strip())
    except Exception:
        return 120.0  # fallback


def _extract_thumb_frame(mp4_path: Path, out_jpg: Path, seek: float,
                         width: int = 1920, height: int = 1080) -> bool:
    """Extract a single frame from mp4 at seek seconds, save as JPEG."""
    try:
        out_jpg.parent.mkdir(parents=True, exist_ok=True)
        result = subprocess.run(
            ["ffmpeg", "-y", "-ss", str(seek), "-i", str(mp4_path),
             "-vframes", "1",
             "-vf", f"scale={width}:{height}:force_original_aspect_ratio=increase,crop={width}:{height}",
             "-q:v", "2", str(out_jpg)],
            capture_output=True, timeout=15,
        )
        return result.returncode == 0 and out_jpg.exists()
    except Exception:
        return False


def _generate_thumb_options(stem: str, count: int = 3) -> list[Path]:
    """Extract `count` thumbnail options from the rendered video at spread-out timestamps.
    Returns list of paths to temporary JPEG files."""
    mp4 = ROOT / "output" / f"{stem}.mp4"
    if not mp4.exists():
        return []
    duration = _get_video_duration(mp4)
    # Pick frames at 15%, 40%, 70% of duration (avoid very start/end)
    percentages = [0.15, 0.40, 0.70][:count]
    thumbs = []
    for i, pct in enumerate(percentages):
        seek = max(1.0, duration * pct)
        out = ROOT / "output" / f"{stem}_thumbopt_{i+1}.jpg"
        if _extract_thumb_frame(mp4, out, seek):
            # Stamp Harry Potter FY3 lightning logo (bottom-center)
            stamp_path = ROOT / "brand" / "fy3_hp_stamp.png"
            if not stamp_path.exists():
                stamp_path = ROOT / "brand" / "fy3_thumb_stamp.png"  # fallback
            if stamp_path.exists():
                try:
                    from PIL import Image
                    thumb = Image.open(out).convert("RGBA")
                    stamp = Image.open(stamp_path).convert("RGBA")
                    # Bottom-center with 20px padding from bottom
                    x = (thumb.width - stamp.width) // 2
                    y = thumb.height - stamp.height - 20
                    thumb.paste(stamp, (x, y), stamp)
                    thumb.convert("RGB").save(out, "JPEG", quality=95)
                except Exception:
                    pass
            thumbs.append(out)
    return thumbs


async def thumbpick_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle thpick:{action}:{param}:{session_key} — thumbnail picker flow."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("⛔", show_alert=True)
        return
    await query.answer()

    try:
        await _thumbpick_inner(update, context, query)
    except Exception as e:
        log.exception("thumbpick_callback crashed: %s", e)
        try:
            await query.message.reply_text(f"⚠️ Thumbnail error: {e}")
        except Exception:
            pass


async def _thumbpick_inner(update, context, query):
    data = query.data
    parts = data.split(":")
    if len(parts) < 4:
        await safe_edit(query.message, "⚠️ Malformed callback.")
        return

    action = parts[1]

    if action == "start" or action == "beat":
        # Show thumbnail options for beat at index
        idx = int(parts[2])
        session_key = parts[3]
        sessions = _get_upload_sessions(context)
        session = sessions.get(session_key)
        if not session:
            await safe_edit(query.message, "⚠️ Session expired — try /upload again.")
            return
        stems = session["stems"]
        if idx >= len(stems):
            # All done — back to upload actions
            await safe_edit(
                query.message,
                f"🖼 All thumbnails set!\n\n{len(stems)} beat(s) ready.",
                reply_markup=_upload_action_kb(session_key),
            )
            return

        stem = stems[idx]
        title = load_json_safe(ROOT / "metadata" / f"{stem}.json", {}).get("title", stem)

        await safe_edit(
            query.message,
            f"🖼 Generating thumbnail options for:\n{esc(title)}\n\nBeat {idx+1}/{len(stems)}...",
        )

        # Generate 3 options from the rendered video
        options = await asyncio.get_event_loop().run_in_executor(
            None, _generate_thumb_options, stem, 3
        )

        if not options:
            await query.message.reply_text(
                f"⚠️ Could not extract frames from {stem}.mp4\nSkipping thumbnail.",
            )
            # Auto-advance to next beat
            if idx < len(stems) - 1:
                kb = InlineKeyboardMarkup([
                    [InlineKeyboardButton("Next Beat ➡️", callback_data=f"thpick:beat:{idx+1}:{session_key}")],
                    [InlineKeyboardButton("⬅️ Done", callback_data=f"thpick:done:0:{session_key}")],
                ])
                await query.message.reply_text("Continue?", reply_markup=kb)
            return

        # Send each option as a photo with a pick button
        for i, thumb_path in enumerate(options):
            kb = InlineKeyboardMarkup([
                [InlineKeyboardButton(
                    f"✅ Use This One (#{i+1})",
                    callback_data=f"thpick:pick:{i+1}:{idx}:{session_key}"[:64],
                )],
            ])
            try:
                with open(thumb_path, "rb") as f:
                    await query.message.reply_photo(
                        photo=f,
                        caption=f"🖼 Option {i+1}/3 — {esc(title)}",
                        reply_markup=kb,
                    )
            except Exception as e:
                log.warning("Failed to send thumb option %d for %s: %s", i+1, stem, e)

        # Also add skip + done buttons
        nav_rows = []
        nav_rows.append([InlineKeyboardButton("⏭ Skip (keep current)", callback_data=f"thpick:beat:{idx+1}:{session_key}")])
        if idx >= len(stems) - 1:
            nav_rows.append([InlineKeyboardButton("✅ Done — Back to Upload", callback_data=f"thpick:done:0:{session_key}")])
        await query.message.reply_text(
            f"👆 Tap the one you like best, or skip.",
            reply_markup=InlineKeyboardMarkup(nav_rows),
        )
        return

    if action == "pick":
        # User picked a thumbnail: thpick:pick:{option_num}:{beat_idx}:{session_key}
        option_num = int(parts[2])
        idx = int(parts[3])
        session_key = parts[4]
        sessions = _get_upload_sessions(context)
        session = sessions.get(session_key)
        if not session:
            await safe_edit(query.message, "⚠️ Session expired.")
            return
        stems = session["stems"]
        stem = stems[idx]

        # Copy chosen option to the real thumb path
        chosen = ROOT / "output" / f"{stem}_thumbopt_{option_num}.jpg"
        real_thumb = ROOT / "output" / f"{stem}_thumb.jpg"
        if chosen.exists():
            import shutil
            shutil.copy2(chosen, real_thumb)

        # Clean up option files
        for i in range(1, 4):
            opt = ROOT / "output" / f"{stem}_thumbopt_{i}.jpg"
            if opt.exists():
                try:
                    opt.unlink()
                except Exception:
                    pass

        title = load_json_safe(ROOT / "metadata" / f"{stem}.json", {}).get("title", stem)
        next_idx = idx + 1

        if next_idx < len(stems):
            kb = InlineKeyboardMarkup([
                [InlineKeyboardButton("Next Beat ➡️", callback_data=f"thpick:beat:{next_idx}:{session_key}")],
                [InlineKeyboardButton("✅ Done — Back to Upload", callback_data=f"thpick:done:0:{session_key}")],
            ])
            await safe_edit(
                query.message,
                f"✅ Thumbnail #{option_num} saved for: {esc(title)}\n\n"
                f"Beat {idx+1}/{len(stems)} done — {len(stems) - next_idx} left.",
                reply_markup=kb,
            )
        else:
            kb = InlineKeyboardMarkup([
                [InlineKeyboardButton("✅ Done — Back to Upload", callback_data=f"thpick:done:0:{session_key}")],
            ])
            await safe_edit(
                query.message,
                f"✅ Thumbnail #{option_num} saved for: {esc(title)}\n\n"
                f"🖼 All {len(stems)} thumbnails set!",
                reply_markup=kb,
            )
        return

    if action == "done":
        # Back to upload action menu
        session_key = parts[3] if len(parts) >= 4 else parts[2]
        sessions = _get_upload_sessions(context)
        session = sessions.get(session_key)
        if not session:
            await safe_edit(query.message, "⚠️ Session expired — try /upload again.")
            return
        stems = session["stems"]
        names = "\n".join(f"  - {esc(s)}" for s in stems[:10])
        if len(stems) > 10:
            names += f"\n  ...and {len(stems)-10} more"
        await query.message.reply_text(
            f"🖼 Thumbnails ready.\n\n{names}\n\nHow do you want to upload?",
            reply_markup=_upload_action_kb(session_key),
        )
        return


