async def cmd_addbeat(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/addbeat <name> — fuzzy-import a beat from the cached scan index."""
    if not is_allowed(update):
        return await deny(update)

    query_str = " ".join(context.args or []).strip().lower()
    if not query_str:
        await update.message.reply_text(
            "Usage: `/addbeat <name>` — e.g. `/addbeat hood legend`\n\n"
            "Run /scanbeats first to build the index if you haven't already.",
            parse_mode="Markdown",
        )
        return

    idx = _load_beat_index()
    if not idx:
        await update.message.reply_text(
            "⚠️ No scan index found. Run /scanbeats first to build it.",
            parse_mode="Markdown",
        )
        return

    files = idx.get("files", [])
    # Fuzzy match: filter by all words present in filename
    words   = query_str.split()
    matches = [f for f in files if all(w in Path(f).name.lower() for w in words)]

    if not matches:
        await update.message.reply_text(
            f"🔍 No beats found matching `{query_str}`.\n"
            "Try /scanbeats to browse and search interactively.",
            parse_mode="Markdown",
        )
        return

    if len(matches) == 1:
        # Single match — import immediately
        src_path = matches[0]
        msg = await update.message.reply_text("🔍 Importing + detecting BPM & Key…")
        try:
            loop = asyncio.get_event_loop()
            stem, _ = await loop.run_in_executor(None, _import_beat_from_local, src_path)
        except FileExistsError:
            await safe_edit(msg, f"✅ `{safe_stem(Path(src_path))}` is already in beats/.", parse_mode="Markdown")
            return
        saved_meta = load_json_safe(ROOT / "metadata" / f"{stem}.json", {})
        bpm = saved_meta.get("bpm"); key = saved_meta.get("key")
        parts = []
        if bpm: parts.append(f"BPM: *{bpm}*")
        if key: parts.append(f"Key: *{key}*")
        bpm_key_str = "  •  " + "  •  ".join(parts) if parts else ""
        await safe_edit(
            msg,
            f"✅ Imported `{stem}` → `beats/`{bpm_key_str}\n\n▶ Run /seo then /fy3stash to render.",
            parse_mode="Markdown",
        )
        return

    # Multiple matches — show as inline picker (up to first 20)
    rows = []
    for i, fpath in enumerate(matches[:20]):
        fname = Path(fpath).name
        label = fname if len(fname) <= 34 else fname[:31] + "…"
        rows.append([InlineKeyboardButton(
            f"🎵 {label}", callback_data=f"addbeat_pick:{i}"
        )])
    rows.append([InlineKeyboardButton("❌ Cancel", callback_data="addbeat_pick:cancel")])

    context.user_data["addbeat_matches"] = matches[:20]
