async def addbeat_pick_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle inline pick from /addbeat multi-match list."""
    query = update.callback_query
    if not query:
        return
    await query.answer()
    data = query.data

    if data == "addbeat_pick:cancel":
        await safe_edit(query.message, "❌ Import cancelled.")
        return

    idx_n   = int(data.split(":")[1])
    matches = context.user_data.get("addbeat_matches", [])
    if idx_n >= len(matches):
        await query.answer("File not found.", show_alert=True)
        return

    src_path = matches[idx_n]
    await safe_edit(query.message, "🔍 Importing + detecting BPM & Key…")
