async def cmd_rendering(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Show what is currently rendering."""
    if not is_allowed(update):
        return await deny(update)

    if not STATE_FILE.exists():
        await update.message.reply_text("💤 Nothing is rendering right now.")
        return

    state = load_json_safe(STATE_FILE)
    if not state:
        await update.message.reply_text("💤 Nothing is rendering right now.")
        return

    if time.time() - state.get("updated", 0) > 30:
        clear_state()
        await update.message.reply_text("💤 Nothing is rendering right now.")
        return

    active    = state.get("active")
    pct       = state.get("pct", 0.0)
    completed = state.get("completed", [])
    total     = state.get("total", 0)
    script    = state.get("script", "render.py")
    done      = len(completed)
    bar       = progress_bar(pct) if active else progress_bar(100)

    lines = [f"🎬 Rendering in progress ({script})\n"]
    lines.append(f"Progress: {done}/{total} beats done")
    if active:
        lines.append(f"\nNow rendering: {active}")
        lines.append(f"{bar}  {pct:.0f}%")
    else:
        lines.append("\nBetween beats...")
    if completed:
        lines.append("\nLast completed:")
        for s in reversed(completed[-5:]):
            lines.append(f"  ✅ {s}")

    await update.message.reply_text("\n".join(lines))


# ── /play ─────────────────────────────────────────────────────────────────────

def _play_keyboard(beats: list, page: int = 0) -> InlineKeyboardMarkup:
    PAGE_SIZE = 8
    start = page * PAGE_SIZE
    chunk = beats[start : start + PAGE_SIZE]
    rows  = []
    for b in chunk:
        stem      = safe_stem(b)
        meta      = load_json_safe(ROOT / "metadata" / f"{stem}.json")
        bpm       = meta.get("bpm")
        key       = meta.get("key")
        label     = f"{stem}  {bpm}bpm · {key}" if (bpm and key) else stem
        # Truncate label to fit Telegram button (max ~60 chars)
        label = label[:58]
        rows.append([InlineKeyboardButton(label, callback_data=f"play:{stem}")])
    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("◀ Prev", callback_data=f"playpage:{page-1}"))
    if start + PAGE_SIZE < len(beats):
        nav.append(InlineKeyboardButton("Next ▶", callback_data=f"playpage:{page+1}"))
    if nav:
        rows.append(nav)
    return InlineKeyboardMarkup(rows)


async def cmd_play(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not is_allowed(update):
        return await deny(update)
    beats = sorted(
        list((ROOT / "beats").glob("*.mp3")) +
        list((ROOT / "beats").glob("*.wav"))
    )
    if not beats:
        await update.message.reply_text("🎵 No beats found in beats/")
        return
    context.bot_data["play_beats"] = [str(b) for b in beats]  # store as strings (survives longer)
    await update.message.reply_text(
        f"🎧 Beat Player  ({len(beats)} beats)\nTap one to play:",
        reply_markup=_play_keyboard(beats, page=0),
    )


async def play_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    if not query:
        return
    if not is_allowed(update):
        await query.answer("⛔ Not authorized.", show_alert=True)
        return
    await query.answer()

    data = query.data

    # Reload beats fresh in case bot was restarted
    all_beats = sorted(
        list((ROOT / "beats").glob("*.mp3")) +
        list((ROOT / "beats").glob("*.wav"))
    )
    # Also check bot_data cache
    cached = [Path(p) for p in context.bot_data.get("play_beats", [])]
    beats  = cached if cached else all_beats

    if data.startswith("playpage:"):
        try:
            page = int(data.split(":")[1])
        except (IndexError, ValueError):
            page = 0
        await query.edit_message_reply_markup(_play_keyboard(beats, page=page))
        return

    # play:{stem}
    stem = data[len("play:"):]
    beat_path = next((b for b in all_beats if safe_stem(b) == stem), None)
    if not beat_path:
        await safe_edit(query.message, "⚠️ Beat not found. Send /play to refresh.")
        return

    meta      = load_json_safe(ROOT / "metadata" / f"{stem}.json")
    title_tag = meta.get("title", stem)
    bpm       = meta.get("bpm")
    key       = meta.get("key")
    caption   = title_tag
    if bpm and key:
        caption += f"\n{bpm} BPM · {key}"

    await safe_edit(query.message, f"⏳ Loading {esc(stem)}...", parse_mode="Markdown")
    try:
        with open(beat_path, "rb") as f:
            await query.message.reply_audio(
                audio=f,
                filename=beat_path.name,
                caption=caption,
                title=title_tag,
                performer="LeekThatsFye",
            )
        # Restore the keyboard
        await safe_edit(
            query.message,
            f"🎧 Beat Player  ({len(beats)} beats)\nTap one to play:",
            parse_mode=None,
        )
        await query.message.edit_reply_markup(_play_keyboard(beats, page=0))
    except Exception as e:
        await safe_edit(query.message, f"❌ Failed to send audio: {esc(str(e))}", parse_mode="Markdown")


