async def rename_receive(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not is_allowed(update):
        return await deny(update)

    old_stem = context.user_data.get("rename_stem")
    ext      = context.user_data.get("rename_ext", ".mp3")
    beats    = context.user_data.get("rename_beats", [])

    if not old_stem:
        await update.message.reply_text("⚠️ Session expired. Send /rename again.")
        return ConversationHandler.END

    raw_new = update.message.text.strip()

    # Strip any path traversal chars, normalize same as safe_stem
    raw_new  = re.sub(r"[/\\]", "", raw_new)          # no slashes
    new_stem = re.sub(r"[^\w\s-]", "", raw_new.lower())
    new_stem = re.sub(r"[\s-]+", "_", new_stem).strip("_")

    if not new_stem:
        await update.message.reply_text("⚠️ Invalid name — letters, numbers, spaces only.")
        return RENAME_WAITING

    if new_stem == old_stem:
        await update.message.reply_text("ℹ️ Same name, nothing changed.")
        return ConversationHandler.END

    # Check for collision
    new_audio_path = (ROOT / "beats" / f"{raw_new}{ext}")
    if new_audio_path.exists():
        await update.message.reply_text(
            f"⚠️ A beat named `{esc(raw_new)}{ext}` already exists. Choose a different name.",
            parse_mode="Markdown",
        )
        return RENAME_WAITING

    old_audio = next((b for b in beats if safe_stem(b) == old_stem), None)
    if not old_audio or not old_audio.exists():
        await update.message.reply_text(f"❌ Could not find `{esc(old_stem)}{ext}` on disk.")
        return ConversationHandler.END

    try:
        old_audio.rename(new_audio_path)
    except Exception as e:
        await update.message.reply_text(f"❌ Rename failed: {e}")
        return ConversationHandler.END

    # Rename metadata
    old_meta = ROOT / "metadata" / f"{old_stem}.json"
    new_meta = ROOT / "metadata" / f"{new_stem}.json"
    if old_meta.exists():
        try:
            old_meta.rename(new_meta)
        except Exception:
            pass

    # Rename output files
    renamed_output = []
    for suffix in (".mp4", "_thumb.jpg"):
        old_out = ROOT / "output" / f"{old_stem}{suffix}"
        if old_out.exists():
            try:
                new_out = ROOT / "output" / f"{new_stem}{suffix}"
                old_out.rename(new_out)
                renamed_output.append(new_out.name)
            except Exception:
                pass

    lines = [f"✅ Renamed:  {old_stem}{ext}  →  {raw_new}{ext}"]
    if renamed_output:
        lines.append(f"Output updated: {', '.join(renamed_output)}")
    lines.append(f"New stem: {new_stem}")
    await update.message.reply_text("\n".join(lines), reply_markup=_STUDIO_BACK_KB)
    return ConversationHandler.END


async def rename_cancel(update: Update, context: ContextTypes.DEFAULT_TYPE):
    target = update.message or (update.callback_query and update.callback_query.message)
    if target:
        await target.reply_text("❌ Rename cancelled.")
    return ConversationHandler.END


