# ── /clips ────────────────────────────────────────────────────────────────────

async def cmd_clips(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Show all visualizer clips organized by artist folder."""
    if not is_allowed(update):
        return await deny(update)

    images_dir = ROOT / "images"
    lines = []
    total = 0

    # Scan artist subdirectories
    for subdir in sorted(images_dir.iterdir()):
        if not subdir.is_dir() or subdir.name.startswith("."):
            continue
        folder_clips = sorted(subdir.glob("*.mp4"))
        if folder_clips:
            lines.append(f"\n📁 {subdir.name} ({len(folder_clips)} clips)")
            for clip in folder_clips:
                lines.append(f"  - {clip.stem}  {clip_label(clip)}")
                total += 1

    # Check flat images/ for any unmoved clips
    flat_clips = sorted(images_dir.glob("*.mp4"))
    if flat_clips:
        lines.append(f"\n📁 (root) ({len(flat_clips)} clips)")
        for clip in flat_clips:
            lines.append(f"  - {clip.stem}  {clip_label(clip)}")
            total += 1

    if not lines:
        await update.message.reply_text(
            "No visualizer clips found. Send a .mp4 file to add one.",
        )
        return

    header = f"🎞 Visualizer clips ({total} total)\n"
    await update.message.reply_text(header + "\n".join(lines))


