# ── /preview ──────────────────────────────────────────────────────────────────

def _preview_keyboard(stems: list[str], page: int = 0) -> InlineKeyboardMarkup:
    PAGE_SIZE = 8
    start = page * PAGE_SIZE
    chunk = stems[start : start + PAGE_SIZE]
    rows  = []
    for s in chunk:
        meta  = load_json_safe(ROOT / "metadata" / f"{s}.json")
        label = meta.get("title", s)[:50]
        rows.append([InlineKeyboardButton(label, callback_data=f"preview:{s}")])
    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("◀ Prev", callback_data=f"previewpage:{page-1}"))
    if start + PAGE_SIZE < len(stems):
        nav.append(InlineKeyboardButton("Next ▶", callback_data=f"previewpage:{page+1}"))
    if nav:
        rows.append(nav)
    return InlineKeyboardMarkup(rows)


async def cmd_preview(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Send a rendered video to chat for review."""
    if not is_allowed(update):
        return await deny(update)
    rendered = sorted(
        f.stem for f in (ROOT / "output").glob("*.mp4")
        if _is_render_mp4(f)
    )
    if not rendered:
        await update.message.reply_text("🎬 No rendered videos yet. Run /batch first.")
        return
    context.bot_data["preview_stems"] = rendered
    await update.message.reply_text(
        f"🎬 *Preview* — tap a beat to send its video here:",
        parse_mode="Markdown",
        reply_markup=_preview_keyboard(rendered, page=0),
    )


async def preview_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    if not query:
        return
    if not is_allowed(update):
        await query.answer("⛔ Not authorized.", show_alert=True)
        return
    await query.answer()

    data   = query.data
    stems  = context.bot_data.get("preview_stems", [])

    if data.startswith("previewpage:"):
        try:
            page = int(data.split(":")[1])
        except (IndexError, ValueError):
            page = 0
        await query.edit_message_reply_markup(_preview_keyboard(stems, page=page))
        return

    stem     = data[len("preview:"):]
    vid_path = ROOT / "output" / f"{stem}.mp4"
    if not vid_path.exists():
        await safe_edit(query.message, f"❌ `{esc(stem)}.mp4` not found.", parse_mode="Markdown")
        return

    meta    = load_json_safe(ROOT / "metadata" / f"{stem}.json")
    caption = meta.get("title", stem)
    bpm     = meta.get("bpm")
    key     = meta.get("key")
    if bpm and key:
        caption += f"\n{bpm} BPM · {key}"

    size_mb = vid_path.stat().st_size / (1024 * 1024)
    preview_path = vid_path  # default: send original
    tmp_preview  = None      # track temp file for cleanup

    if size_mb > 45:
        await safe_edit(
            query.message,
            f"⏳ `{esc(stem)}.mp4` is {size_mb:.0f}MB — compressing preview...",
            parse_mode="Markdown",
        )
        # Compress to a temp file: scale to 720p, CRF 28 (good enough for preview)
        tmp_preview = ROOT / "output" / f"{stem}_preview_tmp.mp4"
        try:
            result = subprocess.run(
                [
                    "ffmpeg", "-y", "-i", str(vid_path),
                    "-vf", "scale=1280:720:force_original_aspect_ratio=decrease",
                    "-c:v", "libx264", "-preset", "fast", "-crf", "28",
                    "-c:a", "aac", "-b:a", "128k",
                    "-movflags", "+faststart",
                    str(tmp_preview),
                ],
                capture_output=True, timeout=300,
            )
            if result.returncode == 0 and tmp_preview.exists():
                compressed_mb = tmp_preview.stat().st_size / (1024 * 1024)
                preview_path  = tmp_preview
                await safe_edit(
                    query.message,
                    f"⏳ Sending `{esc(stem)}.mp4` preview ({compressed_mb:.0f}MB)...",
                    parse_mode="Markdown",
                )
            else:
                await safe_edit(
                    query.message,
                    f"❌ Compression failed — video is {size_mb:.0f}MB, too large for Telegram.\n"
                    f"Use `/queue` to see the YouTube link after upload.",
                    parse_mode="Markdown",
                )
                return
        except Exception as e:
            await safe_edit(query.message, f"❌ Compression error: {esc(str(e))}", parse_mode="Markdown")
            return
    else:
        await safe_edit(query.message, f"⏳ Sending `{esc(stem)}.mp4`...", parse_mode="Markdown")

    try:
        with open(preview_path, "rb") as f:
            await query.message.reply_video(
                video=f,
                caption=f"🎬 *{esc(caption)}*" + ("\n_(compressed preview)_" if tmp_preview else ""),
                parse_mode="Markdown",
                supports_streaming=True,
            )
        await safe_edit(
            query.message,
            "🎬 *Preview* — tap a beat to send its video here:",
            parse_mode="Markdown",
        )
        await query.message.edit_reply_markup(_preview_keyboard(stems, page=0))
    except Exception as e:
        await safe_edit(query.message, f"❌ Failed to send: {esc(str(e))}", parse_mode="Markdown")
    finally:
        # Always clean up the temp compressed file
        if tmp_preview and tmp_preview.exists():
            try:
                tmp_preview.unlink()
            except Exception:
                pass


# ── /beattitle — AI-suggested YouTube title generator ─────────────────────────

_BEATTITLE_WAITING = 301   # conversation state

# High-performing YouTube title templates for type beats
_TITLE_TEMPLATES = [
    # Only format: [FREE] Artist Type Beat Year - "Title"
    lambda title, artist, bpm, key, prod: (
        f'[FREE] {artist} Type Beat {datetime.now().year} - "{title.title()}"'
    ),
]

def _generate_title_variants(stem: str, meta: dict) -> list[str]:
    """Generate 3 high-performing YouTube title variants for a beat."""
    raw_title  = meta.get("title", stem.replace("_", " ").title())
    bpm        = str(meta.get("bpm", "")) if meta.get("bpm") else ""
    key        = meta.get("key", "")
    artist     = meta.get("seo_artist") or _detect_stem_artist(stem) or "BiggKutt8"
    prod       = "LeekThatsFye"

    variants = []
    for tmpl in _TITLE_TEMPLATES:
        try:
            v = tmpl(raw_title, artist, bpm, key, prod).strip()
            # YouTube title max 100 chars
            if len(v) > 100:
                v = v[:97] + "…"
            variants.append(v)
        except Exception:
            pass
    return variants


async def cmd_beattitle(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/beattitle — pick a beat, get 3 title variants, tap to apply."""
    if not is_allowed(update):
        return await deny(update)

    beats = sorted(
        list((ROOT / "beats").glob("*.mp3")) +
        list((ROOT / "beats").glob("*.wav"))
    )
    if not beats:
        await update.message.reply_text("❌ No beats found.")
        return ConversationHandler.END

    rows = []
    for i, b in enumerate(beats[:30]):
        stem = safe_stem(b)
        mf   = ROOT / "metadata" / f"{stem}.json"
        meta = {}
        if mf.exists():
            try: meta = json.loads(mf.read_text())
            except: pass
        current = meta.get("title", stem.replace("_", " ").title())
        rows.append([InlineKeyboardButton(
            f"🎵 {stem[:45]}",
            callback_data=f"beattitle:pick:{i}"
        )])
    context.bot_data["_beattitle_beats"] = [safe_stem(b) for b in beats[:30]]
    await update.message.reply_text(
        "🎯 *Beat Title Generator* — tap a beat to get 3 high-performing title options:",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(rows),
    )
    return _BEATTITLE_WAITING


async def beattitle_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle beattitle: actions."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("Not authorized.", show_alert=True)
        return _BEATTITLE_WAITING
    await query.answer()

    parts  = query.data.split(":", 2)
    action = parts[1] if len(parts) > 1 else ""
    value  = parts[2] if len(parts) > 2 else ""
    stems  = context.bot_data.get("_beattitle_beats", [])

    if action == "pick":
        idx  = int(value) if value.isdigit() else 0
        stem = stems[idx] if idx < len(stems) else None
        if not stem:
            await safe_edit(query.message, "⚠️ Session expired. Run /beattitle again.")
            return ConversationHandler.END

        mf   = ROOT / "metadata" / f"{stem}.json"
        meta = {}
        if mf.exists():
            try: meta = json.loads(mf.read_text())
            except: pass

        variants = _generate_title_variants(stem, meta)
        current  = meta.get("title", stem.replace("_", " ").title())
        context.bot_data["_beattitle_current"]  = stem
        context.bot_data["_beattitle_variants"] = variants

        rows = []
        for i, v in enumerate(variants):
            rows.append([InlineKeyboardButton(f"✏️ {v[:60]}", callback_data=f"beattitle:apply:{i}")])
        rows.append([InlineKeyboardButton("❌ Cancel", callback_data="beattitle:cancel:0")])

        await safe_edit(
            query.message,
            f"🎯 *Title options for `{esc(stem)}`*\n\n"
            f"Current: _{esc(current)}_\n\n"
            f"Tap one to apply it:",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(rows),
        )

    elif action == "apply":
        stem     = context.bot_data.get("_beattitle_current", "")
        variants = context.bot_data.get("_beattitle_variants", [])
        idx      = int(value) if value.isdigit() else 0
        chosen   = variants[idx] if idx < len(variants) else ""
        if not stem or not chosen:
            await safe_edit(query.message, "⚠️ Session expired.")
            return ConversationHandler.END
        mf = ROOT / "metadata" / f"{stem}.json"
        try:
            meta = json.loads(mf.read_text()) if mf.exists() else {}
            meta["title"] = chosen
            mf.write_text(json.dumps(meta, indent=2))
            await safe_edit(
                query.message,
                f"✅ Title saved for *`{esc(stem)}`*:\n\n_{esc(chosen)}_",
                parse_mode="Markdown",
            )
        except Exception as e:
            await safe_edit(query.message, f"❌ Error saving: {esc(str(e))}")
        return ConversationHandler.END

    elif action == "cancel":
        await safe_edit(query.message, "❌ Cancelled.")
        return ConversationHandler.END

    return _BEATTITLE_WAITING


