async def uploadnow_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle uploadnow: tap — render if needed, then upload."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("Not authorized.", show_alert=True)
        return
    await query.answer()

    idx   = int(query.data.split(":")[1]) if ":" in query.data else 0
    beats = context.bot_data.get("_uploadnow_beats", [])
    if idx >= len(beats):
        await safe_edit(query.message, "⚠️ Session expired. Run /uploadnow again.")
        return

    beat_path = beats[idx]
    stem      = safe_stem(beat_path)
    mp4_path  = ROOT / "output" / f"{stem}.mp4"
    log_data  = load_json_safe(ROOT / "uploads_log.json", {})

    if stem in log_data:
        vid_url = log_data[stem].get("url", "")
        await safe_edit(
            query.message,
            f"✅ *`{esc(stem)}`* is already on YouTube!\n{esc(vid_url)}",
            parse_mode="Markdown",
        )
        return

    msg = query.message

    # Step 1 — render if needed
    if not mp4_path.exists():
        await msg.reply_text(f"⏳ `{esc(stem)}` not rendered yet — rendering first…", parse_mode="Markdown")
        kb = media_keyboard([stem], batch=False)
        if kb:
            render_key = f"rk_{int(time.time())}_{os.urandom(4).hex()}"
            context.bot_data.setdefault("_render_sessions", {})[render_key] = {
                "stems": [stem], "clip_name": "default_visual.mp4",
                "random_mode": False, "use_force": False,
                "_after_upload": True,
            }
            await msg.reply_text(
                f"🎬 Pick a clip for `{esc(stem)}` — it'll auto-upload when done:",
                parse_mode="Markdown",
                reply_markup=kb,
            )
            return
        else:
            await msg.reply_text("❌ No visualizer clips found. Upload an .mp4 first.")
            return

    # Step 2 — go through the unified upload flow (artist check + schedule picker)
    await _start_upload_flow(msg, context, stems=[stem])


# ── /ytprivacy — bulk change privacy on already-uploaded videos ────────────────

async def cmd_ytprivacy(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/ytprivacy — show uploaded videos and let user flip their privacy status."""
    if not is_allowed(update):
        return await deny(update)

    log_data = load_json_safe(ROOT / "uploads_log.json", {})
    if not log_data:
        await update.message.reply_text("❌ No uploaded videos yet. Upload some beats first.")
        return

    msg = await update.message.reply_text("🔒 Fetching current privacy status from YouTube…")

    try:
        from youtube_auth import get_youtube_service
        yt = get_youtube_service()

        video_ids = [v["videoId"] for v in log_data.values() if v.get("videoId")]
        status_map = {}
        for i in range(0, len(video_ids), 50):
            batch = video_ids[i:i+50]
            resp  = yt.videos().list(part="status,snippet", id=",".join(batch)).execute()
            for item in resp.get("items", []):
                vid_id   = item["id"]
                privacy  = item.get("status", {}).get("privacyStatus", "unknown")
                title_yt = item.get("snippet", {}).get("title", vid_id)[:40]
                status_map[vid_id] = {"privacy": privacy, "title": title_yt}

        # Build stem → privacy mapping
        privacy_rows = []
        for stem, info in log_data.items():
            vid = info.get("videoId", "")
            if not vid:
                continue
            st = status_map.get(vid, {})
            privacy_rows.append((stem, vid, st.get("privacy", "unknown"), st.get("title", stem)))

        privacy_rows.sort(key=lambda x: x[2])  # group by privacy status
        context.bot_data["_ytprivacy_rows"] = privacy_rows

        # Show summary + action buttons
        counts = {}
        for _, _, p, _ in privacy_rows:
            counts[p] = counts.get(p, 0) + 1

        lines = ["🔒 *YouTube Privacy Manager*\n"]
        for status, count in sorted(counts.items()):
            icon = {"public": "🌐", "private": "🔒", "unlisted": "🔗"}.get(status, "❓")
            lines.append(f"{icon} {status.title()}: {count} video(s)")

        lines.append("\n_Choose an action:_")

        kb = InlineKeyboardMarkup([
            [InlineKeyboardButton("🌐 Make ALL Public",   callback_data="ytprivacy:all:public"),
             InlineKeyboardButton("🔒 Make ALL Private",  callback_data="ytprivacy:all:private")],
            [InlineKeyboardButton("🔗 Make ALL Unlisted", callback_data="ytprivacy:all:unlisted")],
            [InlineKeyboardButton("📋 Pick One by One",   callback_data="ytprivacy:pick:0")],
        ])
        await safe_edit(msg, "\n".join(lines), parse_mode="Markdown", reply_markup=kb)

    except Exception as e:
        await safe_edit(msg, f"❌ YouTube API error: {esc(str(e)[:200])}", parse_mode="Markdown")


async def ytprivacy_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle ytprivacy: actions."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("Not authorized.", show_alert=True)
        return
    await query.answer()

    parts  = query.data.split(":", 2)
    action = parts[1] if len(parts) > 1 else ""
    value  = parts[2] if len(parts) > 2 else ""
    rows   = context.bot_data.get("_ytprivacy_rows", [])

    async def _set_privacy(video_ids_to_set: list[str], new_status: str) -> tuple[int, int]:
        """Returns (success_count, fail_count)."""
        from youtube_auth import get_youtube_service
        yt = get_youtube_service()
        ok = fail = 0
        for vid_id in video_ids_to_set:
            try:
                yt.videos().update(
                    part="status",
                    body={"id": vid_id, "status": {"privacyStatus": new_status}},
                ).execute()
                ok += 1
            except Exception:
                fail += 1
        return ok, fail

    icon_map = {"public": "🌐", "private": "🔒", "unlisted": "🔗"}

    if action == "all":
        new_status = value  # public / private / unlisted
        if new_status not in ("public", "private", "unlisted"):
            await safe_edit(query.message, "⚠️ Unknown privacy status.")
            return
        # Confirm first
        icon = icon_map.get(new_status, "")
        kb = InlineKeyboardMarkup([[
            InlineKeyboardButton(f"✅ Yes, make all {new_status}", callback_data=f"ytprivacy:confirm:{new_status}"),
            InlineKeyboardButton("❌ Cancel", callback_data="ytprivacy:cancel:0"),
        ]])
        await safe_edit(
            query.message,
            f"{icon} *Make all {len(rows)} video(s) {new_status}?*\n\n"
            f"This changes privacy on YouTube immediately.",
            parse_mode="Markdown",
            reply_markup=kb,
        )

    elif action == "confirm":
        new_status = value
        await safe_edit(query.message, f"⏳ Updating {len(rows)} video(s) to {new_status}…")
        video_ids = [vid for _, vid, _, _ in rows]
        try:
            ok, fail = await asyncio.get_event_loop().run_in_executor(
                None, lambda: __import__('asyncio').get_event_loop().run_until_complete(
                    _set_privacy(video_ids, new_status)
                )
            )
        except Exception:
            # run_in_executor can't nest loops — call directly
            from youtube_auth import get_youtube_service
            yt = get_youtube_service()
            ok = fail = 0
            for _, vid_id, _, _ in rows:
                try:
                    yt.videos().update(
                        part="status",
                        body={"id": vid_id, "status": {"privacyStatus": new_status}},
                    ).execute()
                    ok += 1
                except Exception:
                    fail += 1
        icon = icon_map.get(new_status, "")
        await safe_edit(
            query.message,
            f"{icon} Done! *{ok}* video(s) → {new_status}" +
            (f"\n⚠️ {fail} failed" if fail else ""),
            parse_mode="Markdown",
        )

    elif action == "pick":
        page     = int(value) if value.isdigit() else 0
        PAGE     = 8
        chunk    = rows[page*PAGE:(page+1)*PAGE]
        priv_icons = {"public": "🌐", "private": "🔒", "unlisted": "🔗"}
        pick_rows = []
        for stem, vid, privacy, title in chunk:
            icon = priv_icons.get(privacy, "❓")
            pick_rows.append([InlineKeyboardButton(
                f"{icon} {stem[:38]} ({privacy})",
                callback_data=f"ytprivacy:one:{stem}"
            )])
        nav = []
        if page > 0:
            nav.append(InlineKeyboardButton("◀ Prev", callback_data=f"ytprivacy:pick:{page-1}"))
        if (page+1)*PAGE < len(rows):
            nav.append(InlineKeyboardButton("Next ▶", callback_data=f"ytprivacy:pick:{page+1}"))
        if nav:
            pick_rows.append(nav)
        pick_rows.append([InlineKeyboardButton("❌ Cancel", callback_data="ytprivacy:cancel:0")])
        await safe_edit(
            query.message,
            f"🔒 *Pick a video to change:*",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(pick_rows),
        )

    elif action == "one":
        stem     = value
        row      = next(((s, v, p, t) for s, v, p, t in rows if s == stem), None)
        if not row:
            await safe_edit(query.message, "⚠️ Video not found.")
            return
        _, vid_id, current_privacy, title = row
        icon = icon_map.get(current_privacy, "❓")
        kb = InlineKeyboardMarkup([
            [InlineKeyboardButton("🌐 Public",   callback_data=f"ytprivacy:setone:{stem}:public"),
             InlineKeyboardButton("🔒 Private",  callback_data=f"ytprivacy:setone:{stem}:private"),
             InlineKeyboardButton("🔗 Unlisted", callback_data=f"ytprivacy:setone:{stem}:unlisted")],
            [InlineKeyboardButton("« Back", callback_data="ytprivacy:pick:0")],
        ])
        await safe_edit(
            query.message,
            f"🔒 *`{esc(stem)}`*\nCurrently: {icon} {current_privacy}\n\nChange to:",
            parse_mode="Markdown",
            reply_markup=kb,
        )

    elif action == "setone":
        # value = "stem:new_status"
        sub = value.rsplit(":", 1)
        stem       = sub[0]
        new_status = sub[1] if len(sub) > 1 else "public"
        row        = next(((s, v, p, t) for s, v, p, t in rows if s == stem), None)
        if not row:
            await safe_edit(query.message, "⚠️ Video not found.")
            return
        _, vid_id, _, _ = row
        try:
            from youtube_auth import get_youtube_service
            yt = get_youtube_service()
            yt.videos().update(
                part="status",
                body={"id": vid_id, "status": {"privacyStatus": new_status}},
            ).execute()
            icon = icon_map.get(new_status, "")
            # Update local cache
            context.bot_data["_ytprivacy_rows"] = [
                (s, v, new_status if s == stem else p, t) for s, v, p, t in rows
            ]
            await safe_edit(
                query.message,
                f"✅ `{esc(stem)}` → {icon} *{new_status}*",
                parse_mode="Markdown",
            )
        except Exception as e:
            await safe_edit(query.message, f"❌ API error: {esc(str(e)[:200])}")

    elif action == "cancel":
        await safe_edit(query.message, "❌ Cancelled.")


# ── /beatpack — stitch N beats into one beat pack video ───────────────────────

BEATPACK_PICK   = 311   # conversation state — selecting beats
BEATPACK_CLIP   = 312   # conversation state — picking clip for pack video

async def cmd_beatpack(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/beatpack — select 3-8 beats, generate a combined beat pack video with chapters."""
    if not is_allowed(update):
        return await deny(update)

    beats = sorted(
        list((ROOT / "beats").glob("*.mp3")) +
        list((ROOT / "beats").glob("*.wav"))
    )
    if len(beats) < 2:
        await update.message.reply_text("❌ Need at least 2 beats to make a pack.")
        return ConversationHandler.END

    context.bot_data["_beatpack_all"]      = beats
    context.bot_data["_beatpack_selected"] = []

    await update.message.reply_text(
        "🎒 *Beat Pack Builder*\n\n"
        "Tap beats to add them to the pack (pick 3–8 beats).\n"
        "They'll be stitched into one video with chapter timestamps.\n\n"
        "_Tap a beat to select/deselect it:_",
        parse_mode="Markdown",
        reply_markup=_beatpack_kb(beats, []),
    )
    return BEATPACK_PICK


def _beatpack_kb(all_beats: list, selected: list, page: int = 0) -> InlineKeyboardMarkup:
    PAGE   = 8
    start  = page * PAGE
    chunk  = all_beats[start:start+PAGE]
    sel_set = set(selected)
    rows   = []
    for i, b in enumerate(chunk):
        stem  = safe_stem(b)
        check = "☑️" if stem in sel_set else "⬜"
        rows.append([InlineKeyboardButton(
            f"{check} {stem[:50]}",
            callback_data=f"bp:pick:{start+i}:{page}"
        )])
    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("◀ Prev", callback_data=f"bp:page:{page-1}"))
    if start + PAGE < len(all_beats):
        nav.append(InlineKeyboardButton("Next ▶", callback_data=f"bp:page:{page+1}"))
    if nav:
        rows.append(nav)
    action_row = []
    if len(selected) >= 2:
        action_row.append(InlineKeyboardButton(
            f"▶ Build Pack ({len(selected)} beats)",
            callback_data="bp:build:0"
        ))
    action_row.append(InlineKeyboardButton("❌ Cancel", callback_data="bp:cancel:0"))
    rows.append(action_row)
    return InlineKeyboardMarkup(rows)


async def beatpack_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle bp: callbacks for beat pack builder."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("Not authorized.", show_alert=True)
        return BEATPACK_PICK
    await query.answer()

    parts  = query.data.split(":", 2)
    action = parts[1] if len(parts) > 1 else ""
    value  = parts[2] if len(parts) > 2 else ""

    all_beats = context.bot_data.get("_beatpack_all", [])
    selected  = context.bot_data.get("_beatpack_selected", [])

    if action == "page":
        page = int(value) if value.isdigit() else 0
        await query.edit_message_reply_markup(_beatpack_kb(all_beats, selected, page))
        return BEATPACK_PICK

    elif action == "pick":
        sub  = value.split(":")
        idx  = int(sub[0]) if sub[0].isdigit() else 0
        page = int(sub[1]) if len(sub) > 1 and sub[1].isdigit() else 0
        if idx < len(all_beats):
            stem = safe_stem(all_beats[idx])
            if stem in selected:
                selected.remove(stem)
            else:
                if len(selected) >= 8:
                    await query.answer("Max 8 beats per pack!", show_alert=True)
                    return BEATPACK_PICK
                selected.append(stem)
            context.bot_data["_beatpack_selected"] = selected
        await query.edit_message_reply_markup(_beatpack_kb(all_beats, selected, page))
        return BEATPACK_PICK

    elif action == "build":
        if len(selected) < 2:
            await query.answer("Select at least 2 beats first!", show_alert=True)
            return BEATPACK_PICK
        if len(selected) > 8:
            await query.answer("Max 8 beats per pack.", show_alert=True)
            return BEATPACK_PICK

        # Show clip picker for the pack video
        clips = get_clips()
        if not clips:
            await safe_edit(query.message, "❌ No visualizer clips found. Upload an .mp4 first.")
            return ConversationHandler.END

        pack_name = f"beatpack_{'_'.join(selected[:3])}"
        context.bot_data["_beatpack_name"] = pack_name

        rows = []
        for clip in clips:
            rows.append([InlineKeyboardButton(
                clip_label(clip),
                callback_data=f"bp:clip:{clip.name}"
            )])
        rows.append([InlineKeyboardButton("🎲 Random", callback_data="bp:clip:__random__")])
        rows.append([InlineKeyboardButton("❌ Cancel",  callback_data="bp:cancel:0")])

        beat_list = " + ".join(f"`{esc(s)}`" for s in selected)
        await safe_edit(
            query.message,
            f"🎒 *Pack: {len(selected)} beats*\n{beat_list}\n\nPick a visualizer clip for the pack video:",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(rows),
        )
        return BEATPACK_CLIP

    elif action == "clip":
        clip_name = value
        if clip_name == "__random__":
            import random as _rand
            clips = get_clips()
            clip_name = _rand.choice(clips).name if clips else "default_visual.mp4"

        await safe_edit(query.message, f"🎒 Building beat pack with {len(selected)} beats… This may take a minute.")

        async def _build_pack():
            try:
                await _run_beatpack(query.message, selected, clip_name)
            except Exception as e:
                await query.message.reply_text(f"❌ Beat pack failed: {esc(str(e)[:200])}")

        bg = asyncio.create_task(_build_pack())
        context.bot_data.setdefault("_bg_tasks", set()).add(bg)
        bg.add_done_callback(lambda t: context.bot_data.get("_bg_tasks", set()).discard(t))
        return ConversationHandler.END

    elif action == "cancel":
        await safe_edit(query.message, "❌ Cancelled.")
        return ConversationHandler.END

    return BEATPACK_PICK


async def _run_beatpack(msg_target, stems: list[str], clip_name: str):
    """
    Build the beat pack video:
    1. Gather audio files
    2. Run ffmpeg concat to stitch audio
    3. Render video over stitched audio with chosen clip
    4. Generate chapter timestamps for description
    5. Save output as output/beatpack_{name}.mp4 + metadata
    """
    import tempfile

    try:
        import yaml as _yaml
        cfg = _yaml.safe_load((ROOT / "config.yaml").read_text()) or {}
    except Exception:
        cfg = {}
    render_cfg = cfg.get("render", {})
    width  = int(render_cfg.get("width",  1920))
    height = int(render_cfg.get("height", 1080))
    fps    = int(render_cfg.get("fps",    30))

    audio_files = []
    meta_list   = []
    for stem in stems:
        # Find audio file
        for ext in (".mp3", ".wav"):
            p = ROOT / "beats" / f"{stem}{ext}"
            if p.exists():
                audio_files.append(p)
                break
        # Load metadata
        mf = ROOT / "metadata" / f"{stem}.json"
        meta_list.append(json.loads(mf.read_text()) if mf.exists() else {})

    if not audio_files:
        await msg_target.reply_text("❌ No audio files found for selected beats.")
        return

    # ── Step 1: get durations and build chapter list ──────────────────────────
    durations = []
    for af in audio_files:
        try:
            r = subprocess.run(
                ["ffprobe", "-v", "quiet", "-print_format", "json",
                 "-show_streams", str(af)],
                capture_output=True, text=True, timeout=15
            )
            streams = json.loads(r.stdout).get("streams", [])
            dur = next((float(s["duration"]) for s in streams if s.get("duration")), 0.0)
            durations.append(dur)
        except Exception:
            durations.append(180.0)  # fallback 3 min

    # Build chapter timestamps
    chapters   = []
    cursor_sec = 0.0
    for i, (stem, dur, meta) in enumerate(zip(stems, durations, meta_list)):
        title = meta.get("title", stem.replace("_", " ").title())
        mins  = int(cursor_sec) // 60
        secs  = int(cursor_sec) % 60
        chapters.append(f"{mins:d}:{secs:02d} {title}")
        cursor_sec += dur

    total_sec = cursor_sec

    # ── Step 2: concat audio using ffmpeg concat demuxer ─────────────────────
    with tempfile.NamedTemporaryFile(mode="w", suffix=".txt", delete=False) as flist:
        for af in audio_files:
            flist.write(f"file '{af}'\n")
        concat_list = flist.name

    pack_name   = "beatpack_" + "_".join(stems[:3])
    out_audio   = ROOT / "output" / f"{pack_name}_audio.wav"
    out_mp4     = ROOT / "output" / f"{pack_name}.mp4"
    out_thumb   = ROOT / "output" / f"{pack_name}_thumb.jpg"

    await msg_target.reply_text(f"🎵 Stitching {len(audio_files)} beats ({total_sec/60:.1f} min total)…")

    concat_cmd = [
        "ffmpeg", "-y",
        "-f", "concat", "-safe", "0",
        "-i", concat_list,
        "-c:a", "pcm_s16le",
        str(out_audio),
    ]
    result = subprocess.run(concat_cmd, capture_output=True, timeout=300)
    if result.returncode != 0:
        await msg_target.reply_text(f"❌ Audio concat failed:\n`{result.stderr.decode()[-500:]}`", parse_mode="Markdown")
        return

    # ── Step 3: render video ──────────────────────────────────────────────────
    await msg_target.reply_text("🎬 Rendering beat pack video…")

    clip_path = ROOT / "images" / clip_name
    if not clip_path.exists():
        clip_path = ROOT / "images" / "default_visual.mp4"

    # Make thumbnail
    if clip_path.exists():
        subprocess.run([
            "ffmpeg", "-y", "-ss", "3", "-i", str(clip_path),
            "-vframes", "1",
            "-vf", f"scale={width}:{height}:force_original_aspect_ratio=increase,crop={width}:{height}",
            "-q:v", "2", str(out_thumb),
        ], capture_output=True, timeout=30)

    portrait = is_portrait(clip_path) if clip_path.exists() else False
    if portrait:
        bg_filter = (f"[0:v]scale={width}:{height}:force_original_aspect_ratio=increase,"
                     f"crop={width}:{height},boxblur=20:20,format=yuv420p[bg]")
        fg_filter = f"[0:v]scale=-2:{height},format=yuv420p[fg]"
        ov_filter = f"[bg][fg]overlay=(W-w)/2:(H-h)/2,format=yuv420p[out]"
        vf = f"{bg_filter};{fg_filter};{ov_filter}"
        render_cmd = [
            "ffmpeg", "-y",
            "-stream_loop", "-1", "-i", str(clip_path),
            "-i", str(out_audio),
            "-filter_complex", vf,
            "-map", "[out]", "-map", "1:a:0",
            "-r", str(fps),
            "-c:v", "libx264", "-preset", "veryfast", "-crf", "21",
            "-threads", "0",
            "-c:a", "aac", "-b:a", "192k",
            "-shortest", str(out_mp4),
        ]
    else:
        vf = (f"scale={width}:{height}:force_original_aspect_ratio=increase,"
              f"crop={width}:{height},format=yuv420p")
        render_cmd = [
            "ffmpeg", "-y",
            "-stream_loop", "-1", "-i", str(clip_path),
            "-i", str(out_audio),
            "-map", "0:v:0", "-map", "1:a:0",
            "-vf", vf,
            "-r", str(fps),
            "-c:v", "libx264", "-preset", "veryfast", "-crf", "21",
            "-threads", "0",
            "-c:a", "aac", "-b:a", "192k",
            "-shortest", str(out_mp4),
        ]

    result = subprocess.run(render_cmd, capture_output=True, timeout=600)
    # Cleanup temp files
    try:
        Path(concat_list).unlink(missing_ok=True)
        out_audio.unlink(missing_ok=True)
    except Exception:
        pass

    if result.returncode != 0 or not out_mp4.exists():
        await msg_target.reply_text(f"❌ Render failed:\n`{result.stderr.decode()[-500:]}`", parse_mode="Markdown")
        return

    # ── Step 4: save pack metadata ────────────────────────────────────────────
    pack_title  = f"FREE BEAT PACK {datetime.now().year} | " + " x ".join(
        meta.get("title", s.replace("_", " ").title())[:15] for s, meta in zip(stems, meta_list)
    )
    chapter_str = "\n".join(chapters)
    pack_desc   = (
        f"{pack_title}\n\n"
        f"🎒 {len(stems)}-Beat Pack | Prod. LeekThatsFye\n\n"
        f"📍 Chapters:\n{chapter_str}\n\n"
        f"🎤 Free for non-profit use — tag @leekthatsfye on IG\n"
        f"💰 For leases & exclusives, DM or check the link in bio\n\n"
        f"Beats produced by LeekThatsFye | {datetime.now().year}\n\n"
        f"#freebeats #beatpack #leekthatsfye #typebeat #{datetime.now().year}typebeat"
    )
    pack_tags = list(dict.fromkeys(
        ["free beat pack", f"beat pack {datetime.now().year}", "free beats", "type beat pack",
         "leekthatsfye", "trap beat pack", "free rap beats", "beats for sale"] +
        [t for meta in meta_list for t in meta.get("tags", [])[:3]]
    ))[:30]

    meta_path = ROOT / "metadata" / f"{pack_name}.json"
    meta_path.write_text(json.dumps({
        "title": pack_title[:100],
        "artist": "LeekThatsFye",
        "description": pack_desc,
        "tags": pack_tags,
    }, indent=2))

    size_mb = out_mp4.stat().st_size / (1024*1024)
    await msg_target.reply_text(
        f"✅ *Beat pack ready!*\n\n"
        f"📁 `{pack_name}.mp4` ({size_mb:.0f} MB)\n"
        f"⏱ {total_sec/60:.1f} minutes\n"
        f"🎵 {len(stems)} beats\n\n"
        f"📍 *Chapters:*\n`{chapter_str}`\n\n"
        f"Upload it with:\n`/uploadnow` → pick `{esc(pack_name)}`",
        parse_mode="Markdown",
    )


# ── /schedule ─────────────────────────────────────────────────────────────────
# Full button-based flow: pick date → pick time (ET) → confirm → upload

from datetime import datetime, timedelta, timezone

# Eastern time offset helpers
def _et_offset(dt: datetime) -> str:
    """Return -05:00 (EST) or -04:00 (EDT) for a naive date."""
    # DST: second Sunday in March → first Sunday in November
    year = dt.year
    # Second Sunday in March
    dst_start = datetime(year, 3,  8) + timedelta(days=(6 - datetime(year, 3,  8).weekday()) % 7)
    # First Sunday in November
    dst_end   = datetime(year, 11, 1) + timedelta(days=(6 - datetime(year, 11, 1).weekday()) % 7)
    if dst_start <= dt.replace(hour=2) < dst_end:
        return "-04:00"   # EDT
    return "-05:00"       # EST

def _et_label(dt: datetime) -> str:
    offset = _et_offset(dt)
    suffix = "EDT" if offset == "-04:00" else "EST"
    return dt.strftime(f"%-I:%M %p") + f" {suffix}"

# Times shown in the picker (24h values for Eastern time)
_SCHEDULE_TIMES = [
    ( 6,  0, "6:00 AM"),
    ( 8,  0, "8:00 AM"),
    ( 9,  0, "9:00 AM"),
    (10,  0, "10:00 AM"),
    (11,  0, "11:00 AM"),
    (12,  0, "12:00 PM Noon"),
    (13,  0, "1:00 PM"),
    (14,  0, "2:00 PM"),
    (15,  0, "3:00 PM"),
    (16,  0, "4:00 PM"),
    (17,  0, "5:00 PM"),
    (18,  0, "6:00 PM"),
    (19,  0, "7:00 PM"),
    (20,  0, "8:00 PM"),
    (21,  0, "9:00 PM"),
    (22,  0, "10:00 PM"),
    (23,  0, "11:00 PM"),
]


def _date_keyboard() -> InlineKeyboardMarkup:
    """Show the next 14 days as buttons (2 per row)."""
    today = datetime.now()
    rows  = []
    pair  = []
    for i in range(14):
        d     = today + timedelta(days=i)
        label = d.strftime("%a %b %-d") + (" (Today)" if i == 0 else " (Tomorrow)" if i == 1 else "")
        val   = d.strftime("%Y-%m-%d")
        pair.append(InlineKeyboardButton(label, callback_data=f"scheddate:{val}"))
        if len(pair) == 2:
            rows.append(pair)
            pair = []
    if pair:
        rows.append(pair)
    rows.append([InlineKeyboardButton("❌ Cancel", callback_data="schedcancel")])
    return InlineKeyboardMarkup(rows)


def _time_keyboard(date_str: str) -> InlineKeyboardMarkup:
    """Show all time slots as buttons (2 per row)."""
    rows = []
    pair = []
    for h, m, label in _SCHEDULE_TIMES:
        val = f"schedtime:{date_str}:{h:02d}:{m:02d}"
        pair.append(InlineKeyboardButton(label, callback_data=val))
        if len(pair) == 2:
            rows.append(pair)
            pair = []
    if pair:
        rows.append(pair)
    rows.append([InlineKeyboardButton("◀ Back", callback_data="schedback")])
    rows.append([InlineKeyboardButton("❌ Cancel", callback_data="schedcancel")])
    return InlineKeyboardMarkup(rows)


def _confirm_keyboard(iso: str) -> InlineKeyboardMarkup:
    return InlineKeyboardMarkup([[
        InlineKeyboardButton("✅ Schedule it",  callback_data=f"schedgo:{iso}"),
        InlineKeyboardButton("◀ Change time",  callback_data="schedback2"),
        InlineKeyboardButton("❌ Cancel",       callback_data="schedcancel"),
    ]])


async def cmd_schedule(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Entry point — check queue then show date picker."""
    if not is_allowed(update):
        return await deny(update)

    log_data = load_json_safe(ROOT / "uploads_log.json", {})
    uploaded = set(log_data.keys())
    ready = sorted(
        f.stem for f in (ROOT / "output").glob("*.mp4")
        if _is_render_mp4(f) and f.stem not in uploaded
    )
    if not ready:
        await update.message.reply_text(
            "📭 Nothing to schedule — all rendered beats are already uploaded.\n"
            "Run /batch first to render more."
        )
        return ConversationHandler.END

    context.user_data["schedule_stems"] = ready

    lines = [f"📅 *Schedule Upload* — {len(ready)} beats ready\n"]
    for s in ready[:8]:
        meta  = load_json_safe(ROOT / "metadata" / f"{s}.json")
        title = meta.get("title", s)
        lines.append(f"  • {esc(title)}")
    if len(ready) > 8:
        lines.append(f"  ...and {len(ready)-8} more")
    lines.append("\nEach beat uploads 1 day apart.\n\n*Step 1 — Pick a start date:*")

    await update.message.reply_text(
        "\n".join(lines),
        parse_mode="Markdown",
        reply_markup=_date_keyboard(),
    )
    return SCHEDULE_DATE


async def schedule_date_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle date button tap → show time picker."""
    query = update.callback_query
    if not query:
        return SCHEDULE_DATE
    if not is_allowed(update):
        await query.answer("⛔ Not authorized.", show_alert=True)
        return SCHEDULE_DATE
    await query.answer()

    if query.data == "schedcancel":
        await safe_edit(query.message, "❌ Schedule cancelled.")
        return ConversationHandler.END

    date_str = query.data[len("scheddate:"):]
    context.user_data["schedule_date"] = date_str

    d = datetime.strptime(date_str, "%Y-%m-%d")
    await safe_edit(
        query.message,
        f"📅 *{d.strftime('%A, %B %-d %Y')}*\n\n*Step 2 — Pick an upload time (Eastern):*",
        parse_mode="Markdown",
    )
    await query.message.edit_reply_markup(_time_keyboard(date_str))
    return SCHEDULE_TIME


async def schedule_time_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle time button tap → show confirmation."""
    query = update.callback_query
    if not query:
        return SCHEDULE_TIME
    if not is_allowed(update):
        await query.answer("⛔ Not authorized.", show_alert=True)
        return SCHEDULE_TIME
    await query.answer()

    data = query.data

    if data == "schedcancel":
        await safe_edit(query.message, "❌ Schedule cancelled.")
        return ConversationHandler.END

    if data == "schedback":
        await safe_edit(query.message, "*Step 1 — Pick a start date:*", parse_mode="Markdown")
        await query.message.edit_reply_markup(_date_keyboard())
        return SCHEDULE_DATE

    # schedtime:{date}:{HH}:{MM}
    _, date_str, hh, mm = data.split(":")
    context.user_data["schedule_date"] = date_str
    context.user_data["schedule_hhmm"] = (int(hh), int(mm))

    d      = datetime.strptime(date_str, "%Y-%m-%d").replace(hour=int(hh), minute=int(mm))
    offset = _et_offset(d)
    iso    = d.strftime(f"%Y-%m-%dT%H:%M:%S") + offset
    context.user_data["schedule_iso"] = iso

    stems = context.user_data.get("schedule_stems", [])
    time_label = _et_label(d)

    # Show schedule preview — first beat on chosen date, rest daily after
    preview_lines = [
        f"📅 *Confirm Schedule*\n",
        f"Start: *{d.strftime('%A, %B %-d %Y')}* at *{time_label}*",
        f"Beats: *{len(stems)}* total, one per day\n",
        f"First upload:  {d.strftime('%b %-d')} — {time_label}",
    ]
    for i in range(1, min(4, len(stems))):
        nd = d + timedelta(days=i)
        preview_lines.append(f"Day {i+1}:  {nd.strftime('%b %-d')} — {time_label}")
    if len(stems) > 4:
        nd_last = d + timedelta(days=len(stems)-1)
        preview_lines.append(f"  ...")
        preview_lines.append(f"Last:  {nd_last.strftime('%b %-d')} — {time_label}")

    await safe_edit(
        query.message,
        "\n".join(preview_lines),
        parse_mode="Markdown",
    )
    await query.message.edit_reply_markup(_confirm_keyboard(iso))
    return SCHEDULE_CONFIRM


async def schedule_confirm_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle confirm / back / cancel on the confirmation screen."""
    query = update.callback_query
    if not query:
        return SCHEDULE_CONFIRM
    if not is_allowed(update):
        await query.answer("⛔ Not authorized.", show_alert=True)
        return SCHEDULE_CONFIRM
    await query.answer()

    data = query.data

    if data == "schedcancel":
        await safe_edit(query.message, "❌ Schedule cancelled.")
        return ConversationHandler.END

    if data == "schedback2":
        date_str = context.user_data.get("schedule_date", "")
        await safe_edit(
            query.message,
            f"*Step 2 — Pick an upload time (Eastern):*",
            parse_mode="Markdown",
        )
        await query.message.edit_reply_markup(_time_keyboard(date_str))
        return SCHEDULE_TIME

    # schedgo:{iso}
    iso   = data[len("schedgo:"):]
    stems = context.user_data.get("schedule_stems", [])

    await safe_edit(
        query.message,
        f"📅 Scheduling {len(stems)} beats — one per day starting `{esc(iso)}`...",
        parse_mode="Markdown",
    )
    # Use live upload runner — passes schedule args so upload.py handles the timing
    await run_upload_live(
        query.message,
        extra_args=["--schedule-start", iso, "--every-minutes", "1440"],
    )
    return ConversationHandler.END


async def schedule_cancel(update: Update, context: ContextTypes.DEFAULT_TYPE):
    target = update.message or (update.callback_query and update.callback_query.message)
    if target:
        await target.reply_text("❌ Schedule cancelled.")
    return ConversationHandler.END


# ── /delete ───────────────────────────────────────────────────────────────────

def _delete_keyboard(beats: list[Path], page: int = 0) -> InlineKeyboardMarkup:
    PAGE_SIZE = 8
    start = page * PAGE_SIZE
    chunk = beats[start : start + PAGE_SIZE]
    rows  = []
    for b in chunk:
        stem  = safe_stem(b)
        label = stem[:55]
        rows.append([InlineKeyboardButton(f"🗑 {label}", callback_data=f"delpick:{stem}")])
    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("◀ Prev", callback_data=f"delpage:{page-1}"))
    if start + PAGE_SIZE < len(beats):
        nav.append(InlineKeyboardButton("Next ▶", callback_data=f"delpage:{page+1}"))
    if nav:
        rows.append(nav)
    return InlineKeyboardMarkup(rows)


async def cmd_delete(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Pick a beat to delete (audio + render + metadata)."""
    if not is_allowed(update):
        return await deny(update)
    beats = sorted(
        list((ROOT / "beats").glob("*.mp3")) +
        list((ROOT / "beats").glob("*.wav"))
    )
    if not beats:
        await update.message.reply_text("🎵 No beats to delete.")
        return ConversationHandler.END
    context.user_data["delete_beats"] = beats
    await update.message.reply_text(
        "🗑 *Delete Beat* — tap one to delete it and all its files:",
        parse_mode="Markdown",
        reply_markup=_delete_keyboard(beats, page=0),
    )
    return DELETE_CONFIRM


async def delete_pick_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    if not query:
        return DELETE_CONFIRM
    if not is_allowed(update):
        await query.answer("⛔ Not authorized.", show_alert=True)
        return DELETE_CONFIRM
    await query.answer()

    data  = query.data
    beats = context.user_data.get("delete_beats", [])

    if data.startswith("delpage:"):
        try:
            page = int(data.split(":")[1])
        except (IndexError, ValueError):
            page = 0
        await query.edit_message_reply_markup(_delete_keyboard(beats, page=page))
        return DELETE_CONFIRM

    if data.startswith("delconfirm:"):
        stem = data[len("delconfirm:"):]
        deleted = []

        # Audio file
        beat_path = next((b for b in beats if safe_stem(b) == stem), None)
        if beat_path and beat_path.exists():
            beat_path.unlink()
            deleted.append(beat_path.name)

        # Output mp4 + thumb
        for suffix in (".mp4", "_thumb.jpg"):
            p = ROOT / "output" / f"{stem}{suffix}"
            if p.exists():
                p.unlink()
                deleted.append(p.name)

        # Metadata
        meta_p = ROOT / "metadata" / f"{stem}.json"
        if meta_p.exists():
            meta_p.unlink()
            deleted.append(meta_p.name)

        lines = [f"🗑 *Deleted {stem}:*"]
        for d in deleted:
            lines.append(f"  • {d}")
        if not deleted:
            lines.append("  (nothing found on disk)")
        await safe_edit(query.message, "\n".join(lines), parse_mode="Markdown")
        return ConversationHandler.END

    # First tap — ask for confirmation
    stem = data[len("delpick:"):]
    context.user_data["delete_stem"] = stem
    beat_path = next((b for b in beats if safe_stem(b) == stem), None)
    has_render = (ROOT / "output" / f"{stem}.mp4").exists()
    has_meta   = (ROOT / "metadata" / f"{stem}.json").exists()

    what = [f"`{esc(stem)}`"]
    if beat_path:
        what.append(f"audio: {beat_path.name}")
    if has_render:
        what.append("rendered video + thumbnail")
    if has_meta:
        what.append("metadata JSON")

    kb = InlineKeyboardMarkup([[
        InlineKeyboardButton("✅ Yes, delete", callback_data=f"delconfirm:{stem}"),
        InlineKeyboardButton("❌ Cancel",      callback_data="delcancel"),
    ]])
    await safe_edit(
        query.message,
        f"⚠️ Delete *{esc(stem)}*?\n\nWill remove:\n" +
        "\n".join(f"  • {w}" for w in what),
        parse_mode="Markdown",
    )
    await query.message.edit_reply_markup(kb)
    return DELETE_CONFIRM


async def delete_cancel_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    if query:
        await query.answer()
        await safe_edit(query.message, "❌ Delete cancelled.")
    return ConversationHandler.END


async def delete_cancel(update: Update, context: ContextTypes.DEFAULT_TYPE):
    target = update.message or (update.callback_query and update.callback_query.message)
    if target:
        await target.reply_text("❌ Cancelled.")
