# ── /delrender — delete rendered video files (keep audio + metadata) ──────────

def _load_uploads_log() -> dict:
    """Return {stem: {...}} from uploads_log.json."""
    log_path = ROOT / "uploads_log.json"
    if log_path.exists():
        try:
            return json.loads(log_path.read_text())
        except Exception:
            pass
    return {}


def _delrender_keyboard(rendered: list[str], page: int = 0, selected: set | None = None) -> InlineKeyboardMarkup:
    """Build paginated keyboard for /delrender. Shows rendered stems with upload status."""
    PAGE_SIZE = 8
    selected = selected or set()
    uploads  = _load_uploads_log()
    start    = page * PAGE_SIZE
    chunk    = rendered[start : start + PAGE_SIZE]
    rows     = []
    for stem in chunk:
        uploaded = stem in uploads
        check    = "☑️" if stem in selected else ("✅" if uploaded else "🎬")
        label    = f"{check} {stem[:48]}"
        if uploaded:
            label += " ↑"
        rows.append([InlineKeyboardButton(label, callback_data=f"dr:pick:{stem}:{page}")])
    # Nav row
    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("◀ Prev", callback_data=f"dr:page:{page-1}"))
    if start + PAGE_SIZE < len(rendered):
        nav.append(InlineKeyboardButton("Next ▶", callback_data=f"dr:page:{page+1}"))
    if nav:
        rows.append(nav)
    # Action row
    action = []
    if selected:
        action.append(InlineKeyboardButton(f"🗑 Delete {len(selected)} selected", callback_data="dr:confirm_sel"))
    action.append(InlineKeyboardButton("🗑 Delete ALL renders", callback_data="dr:confirm_all"))
    rows.append(action)
    rows.append([InlineKeyboardButton("❌ Cancel", callback_data="dr:cancel")])
    return InlineKeyboardMarkup(rows)


async def cmd_delrender(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Show rendered videos and let user delete them (keeps audio + metadata)."""
    if not is_allowed(update):
        return await deny(update)

    output_dir = ROOT / "output"
    rendered   = sorted(
        p.stem for p in output_dir.glob("*.mp4")
        if _is_render_mp4(p)
    )

    if not rendered:
        await update.message.reply_text("🎬 No rendered videos found in output/")
        return

    uploads = _load_uploads_log()
    uploaded_count = sum(1 for s in rendered if s in uploads)

    context.bot_data["_dr_rendered"]  = rendered
    context.bot_data["_dr_selected"]  = set()

    await update.message.reply_text(
        f"🎬 *Delete Renders* — {len(rendered)} rendered video(s)\n"
        f"✅ = already uploaded to YouTube  🎬 = not yet uploaded\n\n"
        f"Tap a beat to select/deselect it, then tap Delete.\n"
        f"*Audio + metadata are kept — only the .mp4 and thumbnail are removed.*",
        parse_mode="Markdown",
        reply_markup=_delrender_keyboard(rendered, page=0),
    )


async def delrender_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle dr: prefixed callbacks for /delrender."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("⛔ Not authorized.", show_alert=True)
        return
    await query.answer()

    data     = query.data          # dr:{action}:{value}
    parts    = data.split(":", 2)
    action   = parts[1] if len(parts) > 1 else ""
    value    = parts[2] if len(parts) > 2 else ""

    rendered = context.bot_data.get("_dr_rendered", [])
    selected = context.bot_data.get("_dr_selected", set())

    def _do_delete(stems: list[str]) -> list[str]:
        deleted = []
        for stem in stems:
            for suffix in (".mp4", "_thumb.jpg"):
                p = ROOT / "output" / f"{stem}{suffix}"
                if p.exists():
                    p.unlink()
                    deleted.append(p.name)
        return deleted

    if action == "page":
        page = int(value) if value.isdigit() else 0
        await query.edit_message_reply_markup(
            _delrender_keyboard(rendered, page=page, selected=selected)
        )

    elif action == "pick":
        # value = "stem:page"
        sub = value.rsplit(":", 1)
        stem = sub[0]
        page = int(sub[1]) if len(sub) > 1 and sub[1].isdigit() else 0
        if stem in selected:
            selected.discard(stem)
        else:
            selected.add(stem)
        context.bot_data["_dr_selected"] = selected
        await query.edit_message_reply_markup(
            _delrender_keyboard(rendered, page=page, selected=selected)
        )

    elif action == "confirm_sel":
        if not selected:
            await safe_edit(query.message, "⚠️ Nothing selected — tap beats to select them first.")
            return
        stems = list(selected)
        kb = InlineKeyboardMarkup([[
            InlineKeyboardButton(f"✅ Yes, delete {len(stems)} render(s)", callback_data="dr:del_sel"),
            InlineKeyboardButton("❌ Cancel", callback_data="dr:cancel"),
        ]])
        names = "\n".join(f"  • `{esc(s)}`" for s in stems[:10])
        if len(stems) > 10:
            names += f"\n  …and {len(stems)-10} more"
        await safe_edit(
            query.message,
            f"⚠️ *Delete {len(stems)} render(s)?*\n{names}\n\n"
            f"_Audio + metadata will NOT be deleted._",
            parse_mode="Markdown",
            reply_markup=kb,
        )

    elif action == "confirm_all":
        kb = InlineKeyboardMarkup([[
            InlineKeyboardButton(f"✅ Yes, delete ALL {len(rendered)} renders", callback_data="dr:del_all"),
            InlineKeyboardButton("❌ Cancel", callback_data="dr:cancel"),
        ]])
        await safe_edit(
            query.message,
            f"⚠️ *Delete ALL {len(rendered)} rendered video(s)?*\n\n"
            f"_Audio files and metadata will NOT be deleted.\n"
            f"You can re-render any beat with /batch or /fy3stash._",
            parse_mode="Markdown",
            reply_markup=kb,
        )

    elif action == "del_sel":
        stems   = list(selected)
        deleted = _do_delete(stems)
        # Refresh rendered list
        context.bot_data["_dr_rendered"] = [s for s in rendered if s not in selected]
        context.bot_data["_dr_selected"] = set()
        lines = [f"🗑 *Deleted {len(stems)} render(s):*"]
        for f in deleted[:20]:
            lines.append(f"  • `{esc(f)}`")
        if len(deleted) > 20:
            lines.append(f"  …and {len(deleted)-20} more files")
        lines.append("\n_Re-render anytime with /batch or /fy3stash_")
        await safe_edit(query.message, "\n".join(lines), parse_mode="Markdown")

    elif action == "del_all":
        deleted = _do_delete(rendered)
        context.bot_data["_dr_rendered"] = []
        context.bot_data["_dr_selected"] = set()
        lines = [f"🗑 *Deleted all {len(rendered)} render(s)* — {len(deleted)} files removed."]
        lines.append("_Re-render anytime with /batch or /fy3stash_")
        await safe_edit(query.message, "\n".join(lines), parse_mode="Markdown")

    elif action == "cancel":
        await safe_edit(query.message, "❌ Cancelled.")


