async def editjson_pick_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle beat selection or field selection."""
    query = update.callback_query
    if not query:
        return EDIT_FIELD
    if not is_allowed(update):
        await query.answer("⛔ Not authorized.", show_alert=True)
        return EDIT_FIELD
    await query.answer()

    data  = query.data
    beats = context.user_data.get("edit_beats", [])

    if data.startswith("editpage:"):
        try:
            page = int(data.split(":")[1])
        except (IndexError, ValueError):
            page = 0
        await query.edit_message_reply_markup(_editjson_keyboard(beats, page=page))
        return EDIT_FIELD

    if data.startswith("editpick:"):
        stem = data[len("editpick:"):]
        context.user_data["edit_stem"] = stem
        meta = load_json_safe(ROOT / "metadata" / f"{stem}.json")
        kb = InlineKeyboardMarkup([
            [InlineKeyboardButton("📝 Title",       callback_data="editfield:title")],
            [InlineKeyboardButton("📄 Description", callback_data="editfield:description")],
            [InlineKeyboardButton("🏷 Tags",        callback_data="editfield:tags")],
        ])
        await safe_edit(
            query.message,
            f"✏️ *{esc(stem)}* — choose field to edit:\n\n"
            f"Title: {esc(meta.get('title','(none)'))}\n"
            f"Tags: {len(meta.get('tags',[]))} tags",
            parse_mode="Markdown",
        )
        await query.message.edit_reply_markup(kb)
        return EDIT_FIELD

    if data.startswith("editfield:"):
        field = data[len("editfield:"):]
        context.user_data["edit_field"] = field
        stem  = context.user_data.get("edit_stem", "")
        meta  = load_json_safe(ROOT / "metadata" / f"{stem}.json")

        if field == "title":
            current = meta.get("title", "")
            hint    = f"Current: `{esc(current)}`\n\nReply with new title. /cancel to abort."
        elif field == "description":
            current = meta.get("description", "")
            hint    = f"Current description ({len(current)} chars):\n`{safe_md(current, 200)}`\n\nReply with new description. /cancel to abort."
        else:  # tags
            current = meta.get("tags", [])
            hint    = f"Current tags ({len(current)}):\n`{', '.join(current[:10])}`\n\nReply with comma-separated tags. /cancel to abort."

        await safe_edit(query.message, f"✏️ Editing *{field}* for `{esc(stem)}`:\n\n{hint}", parse_mode="Markdown")
        return EDIT_VALUE

    return EDIT_FIELD


async def editjson_receive(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Receive new value and save to metadata JSON."""
    if not is_allowed(update):
        return await deny(update)

    stem  = context.user_data.get("edit_stem")
    field = context.user_data.get("edit_field")

    if not stem or not field:
        await update.message.reply_text("⚠️ Session expired. Send /editjson again.")
        return ConversationHandler.END

    meta_path = ROOT / "metadata" / f"{stem}.json"
    meta      = load_json_safe(meta_path)
    raw       = update.message.text.strip()

    if field == "tags":
        # Parse comma-separated tags, strip whitespace
        new_val = [t.strip() for t in raw.split(",") if t.strip()]
        meta["tags"] = new_val
        display = f"{len(new_val)} tags saved"
    else:
        meta[field] = raw
        display = f"`{esc(raw[:100])}`"

    try:
        meta_path.write_text(json.dumps(meta, indent=2))
        await update.message.reply_text(
            f"✅ Updated *{field}* for `{esc(stem)}`:\n{display}",
            parse_mode="Markdown",
            reply_markup=_STUDIO_BACK_KB,
        )
    except Exception as e:
        await update.message.reply_text(f"❌ Failed to save: {e}")

    return ConversationHandler.END


async def editjson_cancel(update: Update, context: ContextTypes.DEFAULT_TYPE):
    target = update.message or (update.callback_query and update.callback_query.message)
    if target:
        await target.reply_text("❌ Edit cancelled.")
    return ConversationHandler.END


