# Load user-added artists from JSON config (created by /addartist)
_ARTISTS_CONFIG_PATH = ROOT / "artists_config.json" if "ROOT" in dir() else None

def _load_artists_config() -> dict:
    """Load user-customized artist config. Returns {vibe: [artists], aliases: {word: artist}}."""
    if _ARTISTS_CONFIG_PATH and _ARTISTS_CONFIG_PATH.exists():
        try:
            return json.loads(_ARTISTS_CONFIG_PATH.read_text())
        except Exception:
            pass
    return {}

def _get_artists_by_vibe() -> dict[str, list[str]]:
    """Merge hardcoded + user-added artists."""
    result = {k: list(v) for k, v in _TAG_ARTISTS_BY_VIBE.items()}
    cfg = _load_artists_config()
    for vibe, artists in cfg.get("vibes", {}).items():
        if vibe in result:
            for a in artists:
                if a not in result[vibe]:
                    result[vibe].insert(0, a)   # user additions go first
        else:
            result[vibe] = artists
    return result

def _get_artist_aliases() -> dict[str, str | None]:
    """Merge hardcoded + user-added aliases."""
    result = dict(_ARTIST_ALIASES)
    cfg = _load_artists_config()
    result.update(cfg.get("aliases", {}))
    return result


def _detect_stem_artist(stem: str) -> str | None:
    """
    Check if the beat filename implies a specific artist.
    Returns canonical artist name or None.
    Priority: metadata seo_artist field > stem word match.
    """
    aliases = _get_artist_aliases()
    stem_lower = stem.lower().replace("_", " ")
    # Check each alias word against stem
    for word, artist in aliases.items():
        if artist is None:
            continue
        if word in stem_lower:
            return artist
    return None


def _suggest_tags(stem: str, meta: dict) -> list[str]:
    """
    Generate an optimised YouTube tag list for a beat.
    - Uses seo_artist field if set (pinned artist)
    - Detects artist from beat filename words
    - Falls back to BPM/key vibe-based artists
    - Fills the full 490-char YouTube budget
    - Never repeats a tag
    """
    bpm   = meta.get("bpm")
    key   = meta.get("key", "")
    title = meta.get("title", stem.replace("_", " ").title())

    # ── Step 1: Determine vibe from BPM + key ────────────────────────────────
    vibe = "trap"
    if bpm:
        for (lo, hi), v in _BPM_VIBE.items():
            if lo <= int(bpm) <= hi:
                vibe = v
                break
    if "Minor" in key and vibe in ("melodic", "trap"):
        vibe = "dark"
    elif "Major" in key and vibe == "emotional":
        vibe = "melodic"

    # ── Step 2: Determine primary artist ─────────────────────────────────────
    # Priority: pinned seo_artist > filename detection > vibe pool
    pinned_artist = meta.get("seo_artist", "")
    if pinned_artist:
        primary_artist = pinned_artist
    else:
        primary_artist = _detect_stem_artist(stem)

    # ── Step 3: Check for artist-specific SEO profile ──────────────────────
    _profiles_path = ROOT / "artist_seo_profiles.json"
    profile = None
    if primary_artist:
        try:
            if _profiles_path.exists():
                profile = json.loads(_profiles_path.read_text()).get(primary_artist)
        except Exception:
            pass

    if profile:
        # Use ONLY artist-curated related artists — no generic vibe pool
        related = profile.get("related_artists", [])
        artists = [primary_artist] + [a for a in related if a != primary_artist]
        profile_base_tags = list(profile.get("base_tags", []))
    else:
        vibe_artists = _get_artists_by_vibe().get(vibe, _TAG_ARTISTS_BY_VIBE["trap"])
        if primary_artist:
            artists = [primary_artist] + [a for a in vibe_artists if a != primary_artist]
        else:
            artists = vibe_artists
        profile_base_tags = []

    # ── Step 4: Build candidate tag list ─────────────────────────────────────
    # Clean readable beat name (strip "LeekThatsFye Type Beat" suffixes)
    readable = re.sub(
        r"\s+(leekthatsfye|type\s*beat|instrumental|free|prod\.?|by)\b.*$",
        "", title, flags=re.IGNORECASE
    ).strip() or stem.replace("_", " ")

    # Artist profile base tags first (highest priority when profile exists)
    # Then beat-specific tags
    specific = [
        f"{readable} type beat",
        f"{readable} beat",
        f"{readable} instrumental",
    ]

    # Primary artist tags (if detected/pinned)
    primary_tags = []
    if primary_artist:
        primary_tags = [
            f"{primary_artist} type beat",
            f"{primary_artist} instrumental",
            f"{primary_artist} type beat 2026",
            f"free {primary_artist} type beat",
        ]

    # Related artist tags (from profile or vibe pool)
    artist_tags = []
    for a in artists[1:10]:  # skip [0]=primary, use up to 9 related
        artist_tags.append(f"{a} type beat")
    for a in artists[1:5]:   # instrumental variant for top 4 related
        artist_tags.append(f"{a} instrumental")

    # BPM / key / vibe tags
    extra = []
    if bpm:
        extra.append(f"{bpm} bpm type beat")
        extra.append(f"{bpm} bpm instrumental")
    if key:
        key_clean = key.lower().replace(" ", " ")
        extra.append(f"{key_clean} type beat")
    extra.append(f"{vibe} type beat")
    extra.append(f"{vibe} instrumental")
    extra.append(f"{vibe} beat 2026")

    # Producer brand tags
    brand_tags = [
        "leekthatsfye", "leek thats fye",
        "prod by leekthatsfye", "leekthatsfye beats",
    ]

    # ── Step 5: Deduplicate + fill 490-char budget ───────────────────────────
    MAX_CHARS = 490
    MAX_TAGS  = 30
    seen: set[str] = set()
    tags: list[str] = []
    total_chars = 0

    # Profile base tags come first, then beat-specific, then primary, then related, etc.
    all_candidates = profile_base_tags + specific + primary_tags + artist_tags + extra + _BASE_TAGS + brand_tags

    for t in all_candidates:
        t_clean = t.strip()[:30]   # YouTube hard per-tag limit: 30 chars
        tl = t_clean.lower()
        if tl in seen or not t_clean:
            continue
        cost = len(t_clean) + (1 if tags else 0)   # comma separator
        if total_chars + cost > MAX_CHARS or len(tags) >= MAX_TAGS:
            break
        seen.add(tl)
        tags.append(t_clean)
        total_chars += cost

    return tags


def _seo_score(stem: str, meta: dict) -> tuple[int, list[str]]:
    """
    Score a beat's SEO quality 0-100. Returns (score, list_of_issues).
    Used by /seoaudit.
    """
    score = 0
    issues = []
    title = meta.get("title", "")
    desc  = meta.get("description", "")
    tags  = meta.get("tags", [])
    bpm   = meta.get("bpm")
    key   = meta.get("key", "")

    # Title checks (20 pts)
    if "2026" in title or "2025" in title:
        score += 5
    else:
        issues.append("Title missing year (2026)")

    if any(a.lower() in title.lower() for vibe in _TAG_ARTISTS_BY_VIBE.values() for a in vibe):
        score += 10
    else:
        issues.append("Title has no artist name")

    tlen = len(title)
    if 40 <= tlen <= 70:
        score += 5
    elif tlen < 40:
        issues.append(f"Title too short ({tlen} chars, aim for 40-70)")
    else:
        issues.append(f"Title too long ({tlen} chars, aim for 40-70)")

    # Description checks (30 pts)
    word_count = len(desc.split())
    if word_count >= 150:
        score += 15
    elif word_count >= 80:
        score += 7
        issues.append(f"Description only {word_count} words (aim ≥150)")
    else:
        issues.append(f"Description too short ({word_count} words, aim ≥150)")

    if bpm and str(bpm) in desc:
        score += 5
    elif bpm:
        issues.append("Description doesn't mention BPM")

    if any(w in desc.lower() for w in ("lease", "dm", "free", "purchase", "link")):
        score += 5
    else:
        issues.append("Description missing CTA (lease/DM link)")

    if "#" in desc:
        score += 5
    else:
        issues.append("No hashtags in description")

    # Tag checks (40 pts)
    tag_count = len(tags)
    if tag_count >= 15:
        score += 10
    elif tag_count >= 8:
        score += 5
        issues.append(f"Only {tag_count} tags (aim for 15+)")
    else:
        issues.append(f"Very few tags ({tag_count}), aim for 15+")

    total_tag_chars = sum(len(t) for t in tags)
    if total_tag_chars >= 400:
        score += 10
    elif total_tag_chars >= 250:
        score += 5
        issues.append(f"Tags only {total_tag_chars}/500 chars used")
    else:
        issues.append(f"Tags underutilizing budget ({total_tag_chars}/500 chars)")

    all_vibe_artists = [a for v in _TAG_ARTISTS_BY_VIBE.values() for a in v]
    has_artist_tag = any(
        any(a.lower() in t.lower() for a in all_vibe_artists)
        for t in tags
    )
    if has_artist_tag:
        score += 10
    else:
        issues.append("Tags missing artist type beat tags")

    if bpm and any(str(bpm) in t for t in tags):
        score += 5
    elif bpm:
        issues.append("Tags missing BPM tag")

    if key and any(key.lower().replace(" ", "") in t.lower().replace(" ", "") for t in tags):
        score += 5
    elif key:
        issues.append("Tags missing key/scale tag")

    # Bonus checks (10 pts)
    if meta.get("seo_artist"):
        score += 5
    if "0:00" in desc or "Intro" in desc:
        score += 5
    else:
        issues.append("No chapters/timestamps in description")

    return min(score, 100), issues


def _build_chapters(duration_secs: float) -> str:
    """Generate YouTube chapter timestamps for a beat."""
    if duration_secs < 30:
        return ""
    def fmt(s):
        m, sec = divmod(int(s), 60)
        return f"{m}:{sec:02d}"

    chapters = [f"0:00 Intro"]
    if duration_secs > 15:
        chapters.append(f"0:08 Main Beat")
    if duration_secs > 60:
        mid = duration_secs * 0.45
        chapters.append(f"{fmt(mid)} Hook / Loop")
    if duration_secs > 30:
        outro = max(duration_secs - 15, duration_secs * 0.85)
        chapters.append(f"{fmt(outro)} Outro")
    return "\n".join(chapters)


def _build_seo_description(stem: str, meta: dict) -> str:
    """
    Build a clean, concise YouTube description.
    Uses the purchase link from store_uploads_log or lanes_config.
    """
    try:
        _lcfg = json.loads((ROOT / "lanes_config.json").read_text())
    except Exception:
        _lcfg = {}
    store_profile = _lcfg.get("store_profile_url", "")

    # Try beat-specific URL from store log
    purchase_link = store_profile or "[Link in bio]"
    try:
        slog = ROOT / "store_uploads_log.json"
        if slog.exists():
            sdata = json.loads(slog.read_text())
            entry = sdata.get(stem, {})
            ab = entry.get("airbit", entry) if isinstance(entry, dict) else {}
            beat_url = ab.get("url", "")
            if beat_url and beat_url != store_profile:
                purchase_link = f"{beat_url}\n\nBrowse all beats:\n{store_profile}" if store_profile else beat_url
    except Exception:
        pass

    producer = _lcfg.get("producer", "leekthatsfy3")
    desc = f"Purchase / Download\n{purchase_link}\n\nprod. {producer}"
    return desc.strip()


# ── /seoaudit ─────────────────────────────────────────────────────────────────

async def cmd_seoaudit(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Score every beat's metadata on a 0-100 SEO rubric and show a ranked report."""
    if not is_allowed(update):
        return await deny(update)

    msg = await update.message.reply_text("🔍 Running SEO audit on all beats…")

    beats = sorted(
        list((ROOT / "beats").glob("*.mp3")) +
        list((ROOT / "beats").glob("*.wav"))
    )
    if not beats:
        await safe_edit(msg, "❌ No beats found in beats/")
        return

    results = []
    for b in beats:
        stem = safe_stem(b)
        mf   = ROOT / "metadata" / f"{stem}.json"
        meta = {}
        if mf.exists():
            try:
                meta = json.loads(mf.read_text())
            except Exception:
                pass
        score, issues = _seo_score(stem, meta)
        results.append((score, stem, issues))

    results.sort(key=lambda x: x[0])  # lowest first

    lines = ["📊 *SEO Audit — All Beats*", "━━━━━━━━━━━━━━━━━━━━━━"]
    critical = sum(1 for s, _, _ in results if s < 50)
    warn     = sum(1 for s, _, _ in results if 50 <= s < 76)
    good     = sum(1 for s, _, _ in results if s >= 76)
    lines.append(f"🔴 Critical (<50): {critical}  🟡 Needs work: {warn}  🟢 Good: {good}\n")

    for score, stem, issues in results:
        if score < 50:
            icon = "🔴"
        elif score < 76:
            icon = "🟡"
        else:
            icon = "🟢"
        lines.append(f"{icon} `{esc(stem)}` — *{score}/100*")
        for issue in issues[:3]:   # top 3 issues only to stay concise
            lines.append(f"   ↳ {esc(issue)}")

    # Auto-fix button for low scorers
    low_stems = [stem for score, stem, _ in results if score < 76]
    kb = None
    if low_stems:
        lines.append(f"\n💡 *{len(low_stems)} beat(s) scoring below 76.*")
        kb = InlineKeyboardMarkup([[
            InlineKeyboardButton(
                f"🚀 Auto-fix {len(low_stems)} low-score beat(s)",
                callback_data="seoaudit:fix"
            )
        ]])

    text = "\n".join(lines)
    # Store low stems for auto-fix
    context.bot_data["_seoaudit_low"] = low_stems
    await safe_edit(msg, text[:4096], parse_mode="Markdown", reply_markup=kb)


async def seoaudit_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle seoaudit:fix — regenerate tags+desc for all low-scoring beats."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("Not authorized.", show_alert=True)
        return
    await query.answer()

    low_stems = context.bot_data.get("_seoaudit_low", [])
    if not low_stems:
        await safe_edit(query.message, "Nothing to fix — all beats look good!")
        return

    await safe_edit(query.message, f"🚀 Auto-fixing {len(low_stems)} beat(s)…")

    fixed = []
    for stem in low_stems:
        mf = ROOT / "metadata" / f"{stem}.json"
        try:
            meta = json.loads(mf.read_text()) if mf.exists() else {}
            meta["tags"]        = _suggest_tags(stem, meta)
            meta["description"] = _build_seo_description(stem, meta)
            mf.parent.mkdir(parents=True, exist_ok=True)
            mf.write_text(json.dumps(meta, indent=2))
            new_score, _ = _seo_score(stem, meta)
            fixed.append(f"✅ `{esc(stem)}` → {new_score}/100")
        except Exception as e:
            fixed.append(f"❌ `{esc(stem)}` — {esc(str(e))[:60]}")

    lines = ["🚀 *SEO Auto-Fix Complete*", "━━━━━━━━━━━━━━━━━━━━━━"] + fixed
    lines.append("\n_Run /seoaudit again to see updated scores._")
    await safe_edit(query.message, "\n".join(lines)[:4096], parse_mode="Markdown")


# ── /seotags ─────────────────────────────────────────────────────────────────

async def cmd_seotags(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Pick a beat → view/regen tags and optionally pin an artist."""
    if not is_allowed(update):
        return await deny(update)

    beats = sorted(
        list((ROOT / "beats").glob("*.mp3")) +
        list((ROOT / "beats").glob("*.wav"))
    )
    if not beats:
        await update.message.reply_text("❌ No beats found.")
        return

    rows = []
    for i, b in enumerate(beats):
        stem = safe_stem(b)
        mf   = ROOT / "metadata" / f"{stem}.json"
        meta = {}
        if mf.exists():
            try: meta = json.loads(mf.read_text())
            except: pass
        score, _ = _seo_score(stem, meta)
        icon = "🔴" if score < 50 else ("🟡" if score < 76 else "🟢")
        rows.append([InlineKeyboardButton(
            f"{icon} {stem} ({score}/100)",
            callback_data=f"seotags:pick:{i}"
        )])
        if i >= 29: break   # max 30

    context.bot_data["_seotags_beats"] = [safe_stem(b) for b in beats[:30]]
    await update.message.reply_text(
        "🏷 *SEO Tags Editor* — tap a beat:",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(rows),
    )


async def seotags_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle seotags: actions — pick, artist, regen."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("Not authorized.", show_alert=True)
        return
    await query.answer()

    data = query.data  # seotags:{action}:{value}
    parts = data.split(":", 2)
    action = parts[1] if len(parts) > 1 else ""

    stems_list = context.bot_data.get("_seotags_beats", [])

    if action == "pick":
        idx  = int(parts[2]) if len(parts) > 2 else 0
        stem = stems_list[idx] if idx < len(stems_list) else None
        if not stem:
            await safe_edit(query.message, "⚠️ Session expired. Run /seotags again.")
            return
        mf   = ROOT / "metadata" / f"{stem}.json"
        meta = {}
        if mf.exists():
            try: meta = json.loads(mf.read_text())
            except: pass
        score, issues = _seo_score(stem, meta)
        tags    = meta.get("tags", [])
        pinned  = meta.get("seo_artist", "")
        tag_str = ", ".join(tags[:10]) + (f" …+{len(tags)-10}" if len(tags) > 10 else "")
        txt = (
            f"🏷 *`{esc(stem)}`* — Score: {score}/100\n"
            f"📌 Artist: {esc(pinned) if pinned else '_(none)_'}\n"
            f"🏷 Tags ({len(tags)}): {esc(tag_str)}\n\n"
            + ("\n".join(f"↳ {esc(i)}" for i in issues[:5]) if issues else "✅ Fully optimised")
        )
        context.bot_data["_seotags_current"] = stem
        kb = InlineKeyboardMarkup([
            [InlineKeyboardButton("🎯 Set Primary Artist", callback_data="seotags:artistmenu:0")],
            [InlineKeyboardButton("🔄 Auto-Regen Tags",    callback_data="seotags:regen:0")],
            [InlineKeyboardButton("« Back",               callback_data="seotags:back:0")],
        ])
        await safe_edit(query.message, txt, parse_mode="Markdown", reply_markup=kb)

    elif action == "artistmenu":
        stem = context.bot_data.get("_seotags_current", "")
        artists = _get_known_artists()
        rows = []
        for a in artists:
            rows.append([InlineKeyboardButton(f"🎤 {a}", callback_data=f"seotags:setartist:{a}")])
        rows.append([InlineKeyboardButton("🔍 Auto-detect", callback_data="seotags:setartist:__auto__")])
        rows.append([InlineKeyboardButton("❌ Clear artist pin", callback_data="seotags:setartist:__clear__")])
        rows.append([InlineKeyboardButton("« Back", callback_data=f"seotags:pick:{stems_list.index(stem) if stem in stems_list else 0}")])
        await safe_edit(query.message, f"🎤 *Set artist for `{esc(stem)}`*:", parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(rows))

    elif action == "setartist":
        stem    = context.bot_data.get("_seotags_current", "")
        choice  = parts[2] if len(parts) > 2 else ""
        mf      = ROOT / "metadata" / f"{stem}.json"
        try:
            meta = json.loads(mf.read_text()) if mf.exists() else {}
            if choice == "__auto__":
                detected = _detect_stem_artist(stem)
                meta["seo_artist"] = detected or ""
                label = f"🔍 auto-detected: {detected or 'none'}"
            elif choice == "__clear__":
                meta.pop("seo_artist", None)
                label = "❌ cleared"
            else:
                meta["seo_artist"] = choice
                label = f"🎤 {choice}"
            # Regen tags with new artist
            meta["tags"] = _suggest_tags(stem, meta)
            mf.write_text(json.dumps(meta, indent=2))
            score, _ = _seo_score(stem, meta)
            await safe_edit(query.message,
                f"✅ Artist set to {label} for `{esc(stem)}`\n"
                f"Tags regenerated. New score: *{score}/100*",
                parse_mode="Markdown")
        except Exception as e:
            await safe_edit(query.message, f"❌ Error: {esc(str(e))}")

    elif action == "regen":
        stem = context.bot_data.get("_seotags_current", "")
        mf   = ROOT / "metadata" / f"{stem}.json"
        try:
            meta  = json.loads(mf.read_text()) if mf.exists() else {}
            meta["tags"] = _suggest_tags(stem, meta)
            mf.write_text(json.dumps(meta, indent=2))
            score, _ = _seo_score(stem, meta)
            tags = meta["tags"]
            tag_str = ", ".join(tags[:10]) + (f" …+{len(tags)-10}" if len(tags) > 10 else "")
            await safe_edit(query.message,
                f"🔄 Tags regenerated for `{esc(stem)}`\n"
                f"Score: *{score}/100*\n"
                f"Tags ({len(tags)}): {esc(tag_str)}",
                parse_mode="Markdown")
        except Exception as e:
            await safe_edit(query.message, f"❌ Error: {esc(str(e))}")

    elif action == "back":
        await cmd_seotags.__wrapped__(update, context) if hasattr(cmd_seotags, '__wrapped__') else None


# ── /seodesc ─────────────────────────────────────────────────────────────────

async def cmd_seodesc(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Pick a beat → preview/generate SEO description."""
    if not is_allowed(update):
        return await deny(update)

    beats = sorted(
        list((ROOT / "beats").glob("*.mp3")) +
        list((ROOT / "beats").glob("*.wav"))
    )
    if not beats:
        await update.message.reply_text("❌ No beats found.")
        return

    rows = []
    for i, b in enumerate(beats[:30]):
        stem = safe_stem(b)
        mf   = ROOT / "metadata" / f"{stem}.json"
        has_desc = False
        if mf.exists():
            try:
                m = json.loads(mf.read_text())
                has_desc = bool(str(m.get("description","")).strip())
            except: pass
        icon = "✅" if has_desc else "⚠️"
        rows.append([InlineKeyboardButton(f"{icon} {stem}", callback_data=f"seodesc:pick:{i}")])

    context.bot_data["_seodesc_beats"] = [safe_stem(b) for b in beats[:30]]
    await update.message.reply_text(
        "📝 *SEO Description Editor* — tap a beat:\n✅=has desc  ⚠️=missing",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(rows),
    )


async def seodesc_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle seodesc: actions."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("Not authorized.", show_alert=True)
        return
    await query.answer()

    parts  = query.data.split(":", 2)
    action = parts[1] if len(parts) > 1 else ""
    stems_list = context.bot_data.get("_seodesc_beats", [])

    if action == "pick":
        idx  = int(parts[2]) if len(parts) > 2 else 0
        stem = stems_list[idx] if idx < len(stems_list) else None
        if not stem:
            await safe_edit(query.message, "⚠️ Session expired. Run /seodesc again.")
            return
        mf   = ROOT / "metadata" / f"{stem}.json"
        meta = {}
        if mf.exists():
            try: meta = json.loads(mf.read_text())
            except: pass
        desc     = str(meta.get("description", "")).strip()
        wc       = len(desc.split())
        preview  = desc[:300] + ("…" if len(desc) > 300 else "") if desc else "_(no description yet)_"
        context.bot_data["_seodesc_current"] = stem
        txt = f"📝 *`{esc(stem)}`*\nWord count: {wc}\n\n{esc(preview)}"
        kb  = InlineKeyboardMarkup([
            [InlineKeyboardButton("🤖 Auto-Generate", callback_data="seodesc:autogen:0")],
            [InlineKeyboardButton("« Back",           callback_data="seodesc:back:0")],
        ])
        await safe_edit(query.message, txt[:4096], parse_mode="Markdown", reply_markup=kb)

    elif action == "autogen":
        stem = context.bot_data.get("_seodesc_current", "")
        mf   = ROOT / "metadata" / f"{stem}.json"
        try:
            meta = json.loads(mf.read_text()) if mf.exists() else {}
            desc = _build_seo_description(stem, meta)
            wc   = len(desc.split())
            # Show preview with Apply/Cancel
            context.bot_data["_seodesc_preview"] = desc
            preview = desc[:600] + ("…" if len(desc) > 600 else "")
            kb = InlineKeyboardMarkup([
                [InlineKeyboardButton("✅ Apply",  callback_data="seodesc:apply:0")],
                [InlineKeyboardButton("❌ Cancel", callback_data=f"seodesc:pick:{stems_list.index(stem) if stem in stems_list else 0}")],
            ])
            await safe_edit(
                query.message,
                f"📝 *Generated description* ({wc} words):\n\n{esc(preview)}",
                parse_mode="Markdown",
                reply_markup=kb,
            )
        except Exception as e:
            await safe_edit(query.message, f"❌ Error generating description: {esc(str(e))}")

    elif action == "apply":
        stem = context.bot_data.get("_seodesc_current", "")
        desc = context.bot_data.get("_seodesc_preview", "")
        mf   = ROOT / "metadata" / f"{stem}.json"
        try:
            meta = json.loads(mf.read_text()) if mf.exists() else {}
            meta["description"] = desc
            mf.write_text(json.dumps(meta, indent=2))
            await safe_edit(query.message, f"✅ Description saved for `{esc(stem)}`\n({len(desc.split())} words)", parse_mode="Markdown")
        except Exception as e:
            await safe_edit(query.message, f"❌ Error saving: {esc(str(e))}")


