async def addartist_vibe_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Receive vibe choice → ask for filename aliases."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer()
        return ADDARTIST_VIBE
    await query.answer()
    vibe = query.data.split(":", 1)[1]
