# ── /thumbnail ────────────────────────────────────────────────────────────────
# Assign a custom thumbnail JPG to a specific beat from the bot.
# Flow: /thumbnail → pick beat (buttons) → drop the image as a File attachment.

THUMB_WAITING = 20

def _thumb_beat_keyboard(beats: list[Path], page: int = 0) -> InlineKeyboardMarkup:
    PAGE_SIZE = 8
    start = page * PAGE_SIZE
    chunk = beats[start : start + PAGE_SIZE]
    rows  = []
    for b in chunk:
        stem  = safe_stem(b)
        meta  = load_json_safe(ROOT / "metadata" / f"{stem}.json")
        label = meta.get("title", stem)[:52]
        rows.append([InlineKeyboardButton(label, callback_data=f"thumbpick:{stem}")])
    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("◀ Prev", callback_data=f"thumbpage:{page-1}"))
    if start + PAGE_SIZE < len(beats):
        nav.append(InlineKeyboardButton("Next ▶", callback_data=f"thumbpage:{page+1}"))
    if nav:
        rows.append(nav)
    rows.append([InlineKeyboardButton("❌ Cancel", callback_data="thumbcancel")])
    return InlineKeyboardMarkup(rows)


async def cmd_thumbnail(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Pick a beat to assign a custom thumbnail to."""
    if not is_allowed(update):
        return await deny(update)
    beats = sorted(
        list((ROOT / "beats").glob("*.mp3")) +
        list((ROOT / "beats").glob("*.wav"))
    )
    if not beats:
        await update.message.reply_text("🎵 No beats found.")
        return ConversationHandler.END
    context.user_data["thumb_beats"] = beats
    await update.message.reply_text(
        "🖼 *Thumbnail* — tap the beat you want to set a custom thumbnail for:",
        parse_mode="Markdown",
        reply_markup=_thumb_beat_keyboard(beats, page=0),
    )
    return THUMB_WAITING


async def thumbnail_pick_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle beat tap — store stem and ask for image drop."""
    query = update.callback_query
    if not query:
        return THUMB_WAITING
    if not is_allowed(update):
        await query.answer("⛔ Not authorized.", show_alert=True)
        return THUMB_WAITING
    await query.answer()

    data  = query.data
    beats = context.user_data.get("thumb_beats", [])

    if data == "thumbcancel":
        await safe_edit(query.message, "❌ Cancelled.")
        return ConversationHandler.END

    if data.startswith("thumbpage:"):
        try:
            page = int(data.split(":")[1])
        except (IndexError, ValueError):
            page = 0
        await query.edit_message_reply_markup(_thumb_beat_keyboard(beats, page=page))
        return THUMB_WAITING

    stem = data[len("thumbpick:"):]
    context.user_data["thumb_stem"] = stem
    existing = (ROOT / "images" / f"{stem}.jpg").exists()
    note = " (replaces existing)" if existing else ""
    await safe_edit(
        query.message,
        f"🖼 *{esc(stem)}*{note}\n\n"
        f"Now send the thumbnail image as a *File attachment*\n"
        f"(📎 → File → pick your `.jpg` or `.png`)\n\n"
        f"/cancel to abort.",
        parse_mode="Markdown",
    )
    return THUMB_WAITING


async def thumbnail_receive_file(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Receive the image file and save it as images/{stem}.jpg."""
    if not is_allowed(update):
        return await deny(update)

    stem = context.user_data.get("thumb_stem")
    if not stem:
        await update.message.reply_text("⚠️ Session expired. Send /thumbnail again.")
        return ConversationHandler.END

    doc = update.message.document
    if not doc:
        await update.message.reply_text(
            "⚠️ Send the image as a *File* attachment (📎 → File), not inline.",
            parse_mode="Markdown",
        )
        return THUMB_WAITING

    fname = doc.file_name or ""
    ext   = Path(fname).suffix.lower()
    if ext not in (".jpg", ".jpeg", ".png"):
        await update.message.reply_text(
            f"⚠️ Need a `.jpg` or `.png` file, got `{esc(ext)}`.",
            parse_mode="Markdown",
        )
        return THUMB_WAITING

    dest = ROOT / "images" / f"{stem}.jpg"
    msg  = await update.message.reply_text(f"⬇️ Saving thumbnail for `{esc(stem)}`...", parse_mode="Markdown")
    try:
        tg_file = await context.bot.get_file(doc.file_id)
        await tg_file.download_to_drive(str(dest))
        await safe_edit(
            msg,
            f"✅ Thumbnail saved as `images/{stem}.jpg`\n\n"
            f"Re-render this beat with /rerender to apply it.",
            parse_mode="Markdown",
        )
        await update.message.reply_text("↑ Done!", reply_markup=_STUDIO_BACK_KB)
    except Exception as e:
        await safe_edit(msg, f"❌ Failed: {esc(str(e))}", parse_mode="Markdown")

    return ConversationHandler.END


async def thumbnail_cancel(update: Update, context: ContextTypes.DEFAULT_TYPE):
    target = update.message or (update.callback_query and update.callback_query.message)
    if target:
        await target.reply_text("❌ Cancelled.")
    return ConversationHandler.END


# ── /rerender ─────────────────────────────────────────────────────────────────
# Re-render a specific beat — deletes existing output first then runs render.py.

RERENDER_WAITING = 21

def _rerender_keyboard(beats: list[Path], page: int = 0) -> InlineKeyboardMarkup:
    PAGE_SIZE = 8
    start = page * PAGE_SIZE
    chunk = beats[start : start + PAGE_SIZE]
    rows  = []
    for b in chunk:
        stem      = safe_stem(b)
        rendered  = (ROOT / "output" / f"{stem}.mp4").exists()
        icon      = "✅" if rendered else "⏳"
        rows.append([InlineKeyboardButton(f"{icon} {stem}", callback_data=f"rerenderpick:{stem}")])
    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("◀ Prev", callback_data=f"rerenderpage:{page-1}"))
    if start + PAGE_SIZE < len(beats):
        nav.append(InlineKeyboardButton("Next ▶", callback_data=f"rerenderpage:{page+1}"))
    if nav:
        rows.append(nav)
    return InlineKeyboardMarkup(rows)


async def cmd_rerender(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Pick a beat to re-render (deletes existing output first)."""
    if not is_allowed(update):
        return await deny(update)
    beats = sorted(
        list((ROOT / "beats").glob("*.mp3")) +
        list((ROOT / "beats").glob("*.wav"))
    )
    if not beats:
        await update.message.reply_text("🎵 No beats found.")
        return ConversationHandler.END
    context.user_data["rerender_beats"] = beats
    await update.message.reply_text(
        "🔁 *Re-render* — tap a beat to redo it with a fresh clip pick:",
        parse_mode="Markdown",
        reply_markup=_rerender_keyboard(beats, page=0),
    )
    return RERENDER_WAITING


async def rerender_pick_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle beat tap → wipe old output → show clip picker."""
    query = update.callback_query
    if not query:
        return RERENDER_WAITING
    if not is_allowed(update):
        await query.answer("⛔ Not authorized.", show_alert=True)
        return RERENDER_WAITING
    await query.answer()

    data  = query.data
    beats = context.user_data.get("rerender_beats", [])

    if data.startswith("rerenderpage:"):
        try:
            page = int(data.split(":")[1])
        except (IndexError, ValueError):
            page = 0
        await query.edit_message_reply_markup(_rerender_keyboard(beats, page=page))
        return RERENDER_WAITING

    stem = data[len("rerenderpick:"):]

    # Delete existing output so render.py doesn't skip it
    for suffix in (".mp4", "_thumb.jpg"):
        p = ROOT / "output" / f"{stem}{suffix}"
        if p.exists():
            try:
                p.unlink()
            except Exception:
                pass

    kb = media_keyboard([stem], batch=False)
    if kb is None:
        await safe_edit(
            query.message,
            "⚠️ No visualizer clips found in `images/`. Upload an `.mp4` first.",
            parse_mode="Markdown",
        )
        return ConversationHandler.END

    await safe_edit(
        query.message,
        f"🔁 Re-rendering *{esc(stem)}* — old output deleted.\n\nPick a visualizer clip:",
        parse_mode="Markdown",
    )
    await query.message.edit_reply_markup(kb)
    return ConversationHandler.END


async def rerender_cancel(update: Update, context: ContextTypes.DEFAULT_TYPE):
    target = update.message or (update.callback_query and update.callback_query.message)
    if target:
        await target.reply_text("❌ Cancelled.")
    return ConversationHandler.END


# ── /copycat ──────────────────────────────────────────────────────────────────
# Copy tags + description from one beat's metadata to another.

COPYCAT_SRC = 30
COPYCAT_DST = 31

def _copycat_keyboard(beats: list[Path], prefix: str, page: int = 0) -> InlineKeyboardMarkup:
    PAGE_SIZE = 8
    start = page * PAGE_SIZE
    chunk = beats[start : start + PAGE_SIZE]
    rows  = []
    for b in chunk:
        stem  = safe_stem(b)
        meta  = load_json_safe(ROOT / "metadata" / f"{stem}.json")
        label = meta.get("title", stem)[:52]
        rows.append([InlineKeyboardButton(label, callback_data=f"{prefix}:{stem}")])
    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("◀ Prev", callback_data=f"{prefix}page:{page-1}"))
    if start + PAGE_SIZE < len(beats):
        nav.append(InlineKeyboardButton("Next ▶", callback_data=f"{prefix}page:{page+1}"))
    if nav:
        rows.append(nav)
    rows.append([InlineKeyboardButton("❌ Cancel", callback_data=f"{prefix}cancel")])
    return InlineKeyboardMarkup(rows)


async def cmd_copycat(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Step 1 — pick the source beat to copy tags/description from."""
    if not is_allowed(update):
        return await deny(update)
    beats = sorted(
        list((ROOT / "beats").glob("*.mp3")) +
        list((ROOT / "beats").glob("*.wav"))
    )
    if not beats:
        await update.message.reply_text("🎵 No beats found.")
        return ConversationHandler.END
    context.user_data["copycat_beats"] = beats
    await update.message.reply_text(
        "📋 *Copy Metadata* — Step 1: tap the beat to *copy FROM*:",
        parse_mode="Markdown",
        reply_markup=_copycat_keyboard(beats, "ccsrc", page=0),
    )
    return COPYCAT_SRC


async def copycat_src_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Source beat picked — show destination picker."""
    query = update.callback_query
    if not query:
        return COPYCAT_SRC
    if not is_allowed(update):
        await query.answer("⛔ Not authorized.", show_alert=True)
        return COPYCAT_SRC
    await query.answer()

    data  = query.data
    beats = context.user_data.get("copycat_beats", [])

    if "cancel" in data:
        await safe_edit(query.message, "❌ Cancelled.")
        return ConversationHandler.END
    if "page" in data:
        try:
            page = int(data.split(":")[-1])
        except (IndexError, ValueError):
            page = 0
        await query.edit_message_reply_markup(_copycat_keyboard(beats, "ccsrc", page=page))
        return COPYCAT_SRC

    src_stem = data[len("ccsrc:"):]
    context.user_data["copycat_src"] = src_stem
    src_meta = load_json_safe(ROOT / "metadata" / f"{src_stem}.json")
    n_tags   = len(src_meta.get("tags", []))

    await safe_edit(
        query.message,
        f"📋 Copying from *{esc(src_stem)}* ({n_tags} tags)\n\n"
        f"Step 2: tap the beat to *copy TO*:",
        parse_mode="Markdown",
    )
    await query.message.edit_reply_markup(_copycat_keyboard(beats, "ccdst", page=0))
    return COPYCAT_DST


async def copycat_dst_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Destination beat picked — do the copy."""
    query = update.callback_query
    if not query:
        return COPYCAT_DST
    if not is_allowed(update):
        await query.answer("⛔ Not authorized.", show_alert=True)
        return COPYCAT_DST
    await query.answer()

    data  = query.data
    beats = context.user_data.get("copycat_beats", [])

    if "cancel" in data:
        await safe_edit(query.message, "❌ Cancelled.")
        return ConversationHandler.END
    if "page" in data:
        try:
            page = int(data.split(":")[-1])
        except (IndexError, ValueError):
            page = 0
        await query.edit_message_reply_markup(_copycat_keyboard(beats, "ccdst", page=page))
        return COPYCAT_DST

    dst_stem = data[len("ccdst:"):]
    src_stem = context.user_data.get("copycat_src", "")

    src_meta  = load_json_safe(ROOT / "metadata" / f"{src_stem}.json")
    dst_path  = ROOT / "metadata" / f"{dst_stem}.json"
    dst_meta  = load_json_safe(dst_path)

    # Copy tags and description only — preserve dst title, artist, bpm, key
    dst_meta["tags"]        = src_meta.get("tags", [])
    dst_meta["description"] = src_meta.get("description", "")

    try:
        dst_path.write_text(json.dumps(dst_meta, indent=2))
        n = len(dst_meta["tags"])
        await safe_edit(
            query.message,
            f"✅ Copied {n} tags + description\n"
            f"  From: *{esc(src_stem)}*\n"
            f"  To:   *{esc(dst_stem)}*",
            parse_mode="Markdown",
        )
        await send_menu(query.message)
    except Exception as e:
        await safe_edit(query.message, f"❌ Failed: {e}")

    return ConversationHandler.END


async def copycat_cancel(update: Update, context: ContextTypes.DEFAULT_TYPE):
    target = update.message or (update.callback_query and update.callback_query.message)
    if target:
        await target.reply_text("❌ Cancelled.")
    return ConversationHandler.END


# ── /bulkedit ─────────────────────────────────────────────────────────────────
# Apply same tags or description template to ALL beats that are missing them.

BULKEDIT_WAITING = 40

async def cmd_bulkedit(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Choose what to bulk-apply across all beats with empty fields."""
    if not is_allowed(update):
        return await deny(update)

    beats = sorted(
        list((ROOT / "beats").glob("*.mp3")) +
        list((ROOT / "beats").glob("*.wav"))
    )
    missing_tags = sum(
        1 for b in beats
        if len(load_json_safe(ROOT / "metadata" / f"{safe_stem(b)}.json").get("tags", [])) < 5
    )
    missing_desc = sum(
        1 for b in beats
        if not load_json_safe(ROOT / "metadata" / f"{safe_stem(b)}.json").get("description")
    )

    kb = InlineKeyboardMarkup([
        [InlineKeyboardButton(
            f"🏷 Apply tags to {missing_tags} beats with < 5 tags",
            callback_data="bulkedit:tags"
        )],
        [InlineKeyboardButton(
            f"📄 Build description for {missing_desc} beats with none",
            callback_data="bulkedit:desc"
        )],
        [InlineKeyboardButton(
            "🔄 Both — tags + description",
            callback_data="bulkedit:both"
        )],
        [InlineKeyboardButton("❌ Cancel", callback_data="bulkedit:cancel")],
    ])
    await update.message.reply_text(
        f"⚡ *Bulk Edit* — {len(beats)} beats total\n\n"
        f"• {missing_tags} beats have < 5 tags\n"
        f"• {missing_desc} beats have no description\n\n"
        "Choose what to fix:",
        parse_mode="Markdown",
        reply_markup=kb,
    )
    return BULKEDIT_WAITING


async def bulkedit_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    if not query:
        return BULKEDIT_WAITING
    if not is_allowed(update):
        await query.answer("⛔ Not authorized.", show_alert=True)
        return BULKEDIT_WAITING
    await query.answer()

    action = query.data[len("bulkedit:"):]
    if action == "cancel":
        await safe_edit(query.message, "❌ Cancelled.")
        return ConversationHandler.END

    beats = sorted(
        list((ROOT / "beats").glob("*.mp3")) +
        list((ROOT / "beats").glob("*.wav"))
    )

    await safe_edit(query.message, f"⚡ Running bulk edit ({action})...")

    updated_tags = 0
    updated_desc = 0

    for b in beats:
        stem      = safe_stem(b)
        meta_path = ROOT / "metadata" / f"{stem}.json"
        meta      = load_json_safe(meta_path)
        changed   = False

        if action in ("tags", "both"):
            if len(meta.get("tags", [])) < 5:
                meta["tags"] = _suggest_tags(stem, meta)
                changed = True
                updated_tags += 1

        if action in ("desc", "both"):
            if not meta.get("description"):
                title    = meta.get("title", stem.replace("_", " ").title())
                tags     = meta.get("tags", [])
                hashtags = " ".join(f"#{t.replace(' ','')}" for t in tags[:5])
                meta["description"] = (
                    f"{title} | Free for non-profit. Lease available at the link below.\n\n"
                    f"Producer: LeekThatsFye\n\n{hashtags}"
                )
                changed = True
                updated_desc += 1

        if changed:
            try:
                meta_path.write_text(json.dumps(meta, indent=2))
            except Exception:
                pass

    lines = ["⚡ *Bulk Edit Complete*\n"]
    if action in ("tags", "both"):
        lines.append(f"🏷 Tags updated: {updated_tags} beats")
    if action in ("desc", "both"):
        lines.append(f"📄 Descriptions added: {updated_desc} beats")
    lines.append(f"\n✅ All done — {len(beats)} beats processed")

    await safe_edit(query.message, "\n".join(lines), parse_mode="Markdown")
    await send_menu(query.message)
    return ConversationHandler.END


async def bulkedit_cancel(update: Update, context: ContextTypes.DEFAULT_TYPE):
    target = update.message or (update.callback_query and update.callback_query.message)
    if target:
        await target.reply_text("❌ Cancelled.")
    return ConversationHandler.END


# ── /bulktitle — bulk title editor ────────────────────────────────────────────
# Walk through all beats one-by-one, pick or type a title for each.

BTITLE_PICK    = 45   # picking a title variant or typing custom
BTITLE_CUSTOM  = 46   # waiting for custom title text

async def cmd_bulktitle(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/bulktitle — edit titles for all beats, one by one or auto-generate all."""
    if not is_allowed(update):
        return await deny(update)

    beats = sorted(
        list((ROOT / "beats").glob("*.mp3")) +
        list((ROOT / "beats").glob("*.wav"))
    )
    if not beats:
        await update.message.reply_text("🎵 No beats found in beats/")
        return ConversationHandler.END

    stems = [safe_stem(b) for b in beats]
    context.user_data["btitle_stems"] = stems
    context.user_data["btitle_index"] = 0

    # Count how many have default/missing titles
    default_count = 0
    for stem in stems:
        meta = load_json_safe(ROOT / "metadata" / f"{stem}.json")
        title = meta.get("title", "")
        # Consider it "default" if title matches the stem (auto-generated)
        if not title or title.lower().replace(" ", "_") == stem.lower():
            default_count += 1

    kb = InlineKeyboardMarkup([
        [InlineKeyboardButton(
            "✅ Auto-Generate All Titles",
            callback_data="btitle:autoall"
        )],
        [InlineKeyboardButton(
            "📝 Edit One by One",
            callback_data="btitle:onebyone"
        )],
        [InlineKeyboardButton("❌ Cancel", callback_data="btitle:cancel")],
    ])
    await update.message.reply_text(
        f"📝 *Bulk Title Editor* — {len(stems)} beats\n\n"
        f"• {default_count} have default/auto titles\n"
        f"• {len(stems) - default_count} have custom titles\n\n"
        f"*Auto-Generate* = SEO-optimized titles for all beats\n"
        f"*One by One* = walk through each beat, pick from 3 options or type your own",
        parse_mode="Markdown",
        reply_markup=kb,
    )
    return BTITLE_PICK


def _btitle_beat_kb(stem: str, variants: list[str]) -> InlineKeyboardMarkup:
    """Build keyboard with title variants + custom + skip for one beat."""
    rows = []
    for i, v in enumerate(variants[:3]):
        # Truncate display to fit button nicely
        display = v[:55] + "…" if len(v) > 55 else v
        rows.append([InlineKeyboardButton(display, callback_data=f"btitle:v{i}:{stem}")])
    rows.append([
        InlineKeyboardButton("✏️ Custom", callback_data=f"btitle:custom:{stem}"),
        InlineKeyboardButton("⏭ Skip", callback_data=f"btitle:skip:{stem}"),
    ])
    rows.append([InlineKeyboardButton("✅ Done (stop editing)", callback_data="btitle:done")])
    return InlineKeyboardMarkup(rows)


async def _btitle_show_next(msg, context):
    """Show the next beat in the one-by-one title editor."""
    stems = context.user_data.get("btitle_stems", [])
    idx = context.user_data.get("btitle_index", 0)

    if idx >= len(stems):
        await safe_edit(
            msg,
            f"✅ *All {len(stems)} titles done!*\n\n"
            f"Run /upload when ready to publish.",
            parse_mode="Markdown",
        )
        return ConversationHandler.END

    stem = stems[idx]
    meta = load_json_safe(ROOT / "metadata" / f"{stem}.json")
    current_title = meta.get("title", stem.replace("_", " ").title())
    variants = _generate_title_variants(stem, meta)

    kb = _btitle_beat_kb(stem, variants)
    await safe_edit(
        msg,
        f"📝 *Beat {idx + 1}/{len(stems)}* — `{esc(stem)}`\n\n"
        f"Current: _{esc(current_title)}_\n\n"
        f"Pick a title or type your own:",
        parse_mode="Markdown",
        reply_markup=kb,
    )
    return BTITLE_PICK


async def btitle_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle all btitle: callbacks."""
    query = update.callback_query
    if not query:
        return BTITLE_PICK
    if not is_allowed(update):
        await query.answer("⛔ Not authorized.", show_alert=True)
        return BTITLE_PICK
    await query.answer()

    data = query.data

    # ── Cancel ──
    if data == "btitle:cancel":
        await safe_edit(query.message, "❌ Cancelled.")
        return ConversationHandler.END

    # ── Done ──
    if data == "btitle:done":
        idx = context.user_data.get("btitle_index", 0)
        total = len(context.user_data.get("btitle_stems", []))
        await safe_edit(
            query.message,
            f"✅ *Title editing done!* Edited {idx} of {total} beats.\n\n"
            f"Run /upload when ready.",
            parse_mode="Markdown",
        )
        return ConversationHandler.END

    # ── Auto-generate ALL ──
    if data == "btitle:autoall":
        stems = context.user_data.get("btitle_stems", [])
        updated = 0
        for stem in stems:
            meta_path = ROOT / "metadata" / f"{stem}.json"
            meta = load_json_safe(meta_path)
            variants = _generate_title_variants(stem, meta)
            if variants:
                meta["title"] = variants[0]  # Use template A (best performing)
                try:
                    meta_path.write_text(json.dumps(meta, indent=2))
                    updated += 1
                except Exception:
                    pass
        await safe_edit(
            query.message,
            f"✅ *Auto-generated {updated} titles!*\n\n"
            f"All beats now have SEO-optimized titles.\n"
            f"Run /bulktitle again to edit any individually, or /upload to publish.",
            parse_mode="Markdown",
        )
        return ConversationHandler.END

    # ── One by One ──
    if data == "btitle:onebyone":
        context.user_data["btitle_index"] = 0
        return await _btitle_show_next(query.message, context)

    # ── Pick variant ──
    if data.startswith("btitle:v"):
        # btitle:v0:stem_name or btitle:v1:stem_name
        parts = data.split(":", 2)
        variant_idx = int(parts[1][1:])  # "v0" → 0
        stem = parts[2]

        meta_path = ROOT / "metadata" / f"{stem}.json"
        meta = load_json_safe(meta_path)
        variants = _generate_title_variants(stem, meta)
        if variant_idx < len(variants):
            meta["title"] = variants[variant_idx]
            try:
                meta_path.write_text(json.dumps(meta, indent=2))
            except Exception:
                pass

        # Move to next
        context.user_data["btitle_index"] = context.user_data.get("btitle_index", 0) + 1
        return await _btitle_show_next(query.message, context)

    # ── Skip ──
    if data.startswith("btitle:skip:"):
        context.user_data["btitle_index"] = context.user_data.get("btitle_index", 0) + 1
        return await _btitle_show_next(query.message, context)

    # ── Custom ──
    if data.startswith("btitle:custom:"):
        stem = data[len("btitle:custom:"):]
        context.user_data["btitle_custom_stem"] = stem
        await safe_edit(
            query.message,
            f"✏️ Type the new title for `{esc(stem)}`:\n\n"
            f"_(max 100 chars for YouTube)_",
            parse_mode="Markdown",
        )
        return BTITLE_CUSTOM

    return BTITLE_PICK


async def btitle_custom_text(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle custom title text input."""
    if not is_allowed(update):
        return await deny(update)

    text = (update.message.text or "").strip()
    if not text:
        await update.message.reply_text("⚠️ Title can't be empty. Try again or /cancel.")
        return BTITLE_CUSTOM

    if len(text) > 100:
        text = text[:97] + "…"

    stem = context.user_data.get("btitle_custom_stem", "")
    if stem:
        meta_path = ROOT / "metadata" / f"{stem}.json"
        meta = load_json_safe(meta_path)
        meta["title"] = text
        try:
            meta_path.write_text(json.dumps(meta, indent=2))
        except Exception:
            pass

    # Move to next
    context.user_data["btitle_index"] = context.user_data.get("btitle_index", 0) + 1
    msg = await update.message.reply_text(f"✅ Title set: _{esc(text)}_", parse_mode="Markdown")
    return await _btitle_show_next(msg, context)


async def btitle_cancel(update: Update, context: ContextTypes.DEFAULT_TYPE):
    target = update.message or (update.callback_query and update.callback_query.message)
    if target:
        await target.reply_text("❌ Title editing cancelled.")
    return ConversationHandler.END


# ── /thumbnail — update thumbnails on already-uploaded YouTube videos ─────────

async def cmd_ytthumb(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/ytthumb — pick new thumbnails for videos already on YouTube."""
    if not is_allowed(update):
        return await deny(update)

    log_data = load_json_safe(ROOT / "uploads_log.json", {})
    if not log_data:
        await update.message.reply_text("📭 No uploaded videos found. Upload something first with /upload.")
        return

    # Build list of uploaded beats that have a rendered video
    beats = []
    for stem, info in log_data.items():
        mp4 = ROOT / "output" / f"{stem}.mp4"
        if mp4.exists() and info.get("videoId"):
            beats.append((stem, info))

    if not beats:
        await update.message.reply_text("📭 No uploaded videos with local renders found.")
        return

    # Show beat picker — each beat is a button
    rows = []
    for stem, info in beats:
        title = info.get("title", stem.replace("_", " ").title())[:30]
        rows.append([InlineKeyboardButton(
            f"🖼 {title}",
            callback_data=f"thupl:beat:0:{stem}"[:64],
        )])
    rows.append([InlineKeyboardButton("❌ Cancel", callback_data="thupl:cancel")])
    kb = InlineKeyboardMarkup(rows)
    await update.message.reply_text(
        f"🖼 Pick a video to update its thumbnail ({len(beats)} uploaded):",
        reply_markup=kb,
    )


async def thupl_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle thupl:{action}:{param}:{stem} — thumbnail updater for uploaded videos."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("⛔", show_alert=True)
        return
    await query.answer()

    try:
        await _thupl_inner(update, context, query)
    except Exception as e:
        log.exception("thupl_callback crashed: %s", e)
        try:
            await query.message.reply_text(f"⚠️ Thumbnail update error: {e}")
        except Exception:
            pass


async def _thupl_inner(update, context, query):
    data = query.data
    parts = data.split(":")

    if len(parts) < 2:
        return

    action = parts[1]

    if action == "cancel":
        await safe_edit(query.message, "❌ Thumbnail update cancelled.")
        return

    if action == "beat":
        # Show 3 thumbnail options for this beat
        # thupl:beat:0:{stem}
        stem = parts[3] if len(parts) >= 4 else parts[2]

        mp4 = ROOT / "output" / f"{stem}.mp4"
        if not mp4.exists():
            await safe_edit(query.message, f"⚠️ No rendered video for {stem}.")
            return

        log_data = load_json_safe(ROOT / "uploads_log.json", {})
        info = log_data.get(stem, {})
        title = info.get("title", stem.replace("_", " ").title())

        await safe_edit(query.message, f"🖼 Generating thumbnail options for:\n{esc(title)}...")

        # Generate 3 options
        options = await asyncio.get_event_loop().run_in_executor(
            None, _generate_thumb_options, stem, 3
        )

        if not options:
            await query.message.reply_text(f"⚠️ Could not extract frames from {stem}.mp4")
            return

        # Send each option as a photo
        for i, thumb_path in enumerate(options):
            kb = InlineKeyboardMarkup([
                [InlineKeyboardButton(
                    f"✅ Use This One (#{i+1})",
                    callback_data=f"thupl:pick:{i+1}:{stem}"[:64],
                )],
            ])
            try:
                with open(thumb_path, "rb") as f:
                    await query.message.reply_photo(
                        photo=f,
                        caption=f"🖼 Option {i+1}/3 — {esc(title)}",
                        reply_markup=kb,
                    )
            except Exception as e:
                log.warning("Failed to send thumb option %d for %s: %s", i+1, stem, e)

        # Cancel button
        await query.message.reply_text(
            "👆 Pick the one you like, or cancel.",
            reply_markup=InlineKeyboardMarkup([
                [InlineKeyboardButton("❌ Cancel", callback_data="thupl:cancel")],
            ]),
        )
        return

    if action == "pick":
        # User picked a thumbnail — upload to YouTube
        # thupl:pick:{option_num}:{stem}
        option_num = int(parts[2])
        stem = parts[3]

        log_data = load_json_safe(ROOT / "uploads_log.json", {})
        info = log_data.get(stem, {})
        video_id = info.get("videoId")
        title = info.get("title", stem)

        if not video_id:
            await safe_edit(query.message, f"⚠️ No YouTube video ID found for {stem}.")
            return

        # Copy chosen option to the real thumb path
        chosen = ROOT / "output" / f"{stem}_thumbopt_{option_num}.jpg"
        real_thumb = ROOT / "output" / f"{stem}_thumb.jpg"
        if not chosen.exists():
            await safe_edit(query.message, "⚠️ Thumbnail file not found.")
            return

        import shutil
        shutil.copy2(chosen, real_thumb)

        # Clean up option files
        for i in range(1, 4):
            opt = ROOT / "output" / f"{stem}_thumbopt_{i}.jpg"
            if opt.exists():
                try:
                    opt.unlink()
                except Exception:
                    pass

        await safe_edit(query.message, f"⏳ Uploading thumbnail #{option_num} to YouTube for: {esc(title)}...")

        # Upload to YouTube API
        try:
            result = await asyncio.get_event_loop().run_in_executor(
                None, _upload_thumb_to_youtube, video_id, real_thumb
            )
            if result:
                await query.message.reply_text(
                    f"✅ Thumbnail updated on YouTube!\n\n"
                    f"🎵 {esc(title)}\n"
                    f"🔗 https://www.youtube.com/watch?v={video_id}",
                )
            else:
                await query.message.reply_text(f"⚠️ YouTube thumbnail upload failed for {stem}.")
        except Exception as e:
            await query.message.reply_text(f"⚠️ YouTube API error: {e}")
        return


def _upload_thumb_to_youtube(video_id: str, thumb_path: Path) -> bool:
    """Upload a thumbnail to YouTube. Runs in executor (blocking)."""
    try:
        from youtube_auth import get_youtube_service
        from googleapiclient.http import MediaFileUpload
        youtube = get_youtube_service()
        media = MediaFileUpload(str(thumb_path), mimetype="image/jpeg", resumable=False)
        youtube.thumbnails().set(videoId=video_id, media_body=media).execute()
        return True
    except Exception as e:
        log.error("_upload_thumb_to_youtube failed for %s: %s", video_id, e)
        return False


# ── /retitle — one-button auto-retitle recently uploaded beats ────────────────

async def cmd_retitle(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/retitle — auto-retitle recently uploaded beats to a chosen artist."""
    if not is_allowed(update):
        return await deny(update)

    log_data = load_json_safe(ROOT / "uploads_log.json", {})
    if not log_data:
        await update.message.reply_text("No uploads found. Upload beats first with /upload.")
        return

    # Sort by upload time, most recent first
    sorted_stems = sorted(
        log_data.keys(),
        key=lambda s: log_data[s].get("uploadedAt", ""),
        reverse=True,
    )

    # Store stems for the callback
    rt_key = f"rt_{int(time.time())}_{os.urandom(4).hex()}"
    context.bot_data.setdefault("_retitle_sessions", {})[rt_key] = {
        "stems": sorted_stems,
        "ts": time.time(),
    }

    # Show current titles
    lines = ["📝 Your uploaded beats:\n"]
    for i, stem in enumerate(sorted_stems[:20]):
        title = log_data[stem].get("title", stem)
        lines.append(f"  {i+1}. {title}")
    if len(sorted_stems) > 20:
        lines.append(f"  ...and {len(sorted_stems) - 20} more")
    lines.append(f"\nTotal: {len(sorted_stems)} uploaded beats")
    lines.append("\nPick an artist to retitle them all:")

    # Build artist picker for retitle
    rows = []
    for display, seo_name in _TOP_ARTISTS:
        rows.append([InlineKeyboardButton(
            f"🎤 {display}",
            callback_data=f"retitle:{seo_name[:20]}:{rt_key}"
        )])
    rows.append([InlineKeyboardButton("❌ Cancel", callback_data=f"retitle:__cancel__:{rt_key}")])
    kb = InlineKeyboardMarkup(rows)

    await update.message.reply_text("\n".join(lines), reply_markup=kb)


async def retitle_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle retitle:{artist}:{rt_key} — auto-retitle all uploaded beats."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("Not authorized.", show_alert=True)
        return
    await query.answer()

    parts = query.data.split(":", 2)
    if len(parts) != 3:
        await safe_edit(query.message, "Malformed callback.")
        return
    _, artist_choice, rt_key = parts

    if artist_choice == "__cancel__":
        await safe_edit(query.message, "❌ Retitle cancelled.")
        return

    sessions = context.bot_data.get("_retitle_sessions", {})
    session = sessions.pop(rt_key, None)
    if not session:
        await safe_edit(query.message, "Session expired. Send /retitle again.")
        return

    stems = session["stems"]
    year = datetime.now().year

    await safe_edit(query.message, f"Retitling {len(stems)} beats as {artist_choice} type beats...")

    updated = 0
    log_path = ROOT / "uploads_log.json"
    log_data = load_json_safe(log_path, {})

    for stem in stems:
        meta_path = ROOT / "metadata" / f"{stem}.json"
        meta = load_json_safe(meta_path, {})

        # Get clean beat name from stem (strip existing type beat suffixes)
        raw_title = meta.get("title", stem.replace("_", " ").title())
        # Remove any existing "Type Beat" / "LeekThatsFye" / "[FREE]" suffixes
        clean = re.sub(
            r"\s*(leekthatsfye|type\s*beat|instrumental|free|\[free\]|prod\.?|by)\b.*$",
            "", raw_title, flags=re.IGNORECASE
        ).strip().strip('"').strip("'").strip()
        if not clean:
            clean = stem.replace("_", " ").title()

        new_title = f'[FREE] {artist_choice} Type Beat {year} - "{clean.title()}"'

        # Cap at 100 chars for YouTube
        if len(new_title) > 100:
            # Shorten beat name
            max_clean = 100 - len(f'[FREE] {artist_choice} Type Beat {year} - ""') - 3
            new_title = f'[FREE] {artist_choice} Type Beat {year} - "{clean.title()[:max_clean]}..."'

        # Save to metadata
        meta["title"] = new_title
        meta["seo_artist"] = artist_choice
        try:
            meta_path.parent.mkdir(parents=True, exist_ok=True)
            meta_path.write_text(json.dumps(meta, indent=2))
        except Exception as e:
            log.warning("retitle: could not save metadata for %s: %s", stem, e)
            continue

        # Update uploads_log.json
        if stem in log_data:
            log_data[stem]["title"] = new_title

        updated += 1

    # Save updated uploads log
    try:
        log_path.write_text(json.dumps(log_data, indent=2))
    except Exception as e:
        log.warning("retitle: could not save uploads_log: %s", e)

    # Show preview of new titles
    lines = [f"✅ Retitled {updated} beats as {artist_choice} type beats:\n"]
    for stem in stems[:10]:
        meta = load_json_safe(ROOT / "metadata" / f"{stem}.json", {})
        title = meta.get("title", stem)
        lines.append(f"  {title}")
    if len(stems) > 10:
        lines.append(f"  ...and {len(stems) - 10} more")

    await safe_edit(query.message, "\n".join(lines))


# ── Remote Control (phone → Mac) ──────────────────────────────────────────────

async def cmd_shell(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/shell <cmd> — run any terminal command on the Mac and get output back."""
    if not is_allowed(update):
        return await deny(update)
    cmd_text = " ".join(context.args or []).strip()
    if not cmd_text:
        await update.message.reply_text(
            "⚙️ *Shell — run any command on your Mac*\n\n"
            "Usage: `/shell <command>`\n\n"
            "Examples:\n"
            "`/shell ls output/`\n"
            "`/shell python3 seo_metadata.py`\n"
            "`/shell df -h`\n"
            "`/shell ps aux | grep python`",
            parse_mode="Markdown",
        )
        return

    msg = await update.message.reply_text(
        f"⚙️ `{esc(cmd_text[:200])}`…", parse_mode="Markdown"
    )
    try:
        proc = await asyncio.create_subprocess_shell(
            cmd_text,
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.STDOUT,
            cwd=str(ROOT),
            env={**os.environ, "PATH": "/opt/homebrew/bin:/usr/local/bin:/usr/bin:/bin:" + os.environ.get("PATH", "")},
        )
        try:
            stdout, _ = await asyncio.wait_for(proc.communicate(), timeout=30)
            output = stdout.decode("utf-8", errors="replace").strip()
        except asyncio.TimeoutError:
            try:
                proc.kill()
            except Exception:
                pass
            await safe_edit(msg, "⏱ Command timed out after 30s.", parse_mode="Markdown")
            return
    except Exception as _se:
        output = f"Error starting command: {_se}"

    # Cap at Telegram message limit
    if len(output) > 3800:
        output = "…(truncated, showing last 3800 chars)\n" + output[-3800:]
    rc_str = f"  (exit {proc.returncode})" if proc.returncode else ""
    await safe_edit(
        msg,
        f"```\n{output or '(no output)'}\n```{rc_str}",
        parse_mode="Markdown",
    )


def _do_restart_bot():
    """Called via call_later — unloads then loads the LaunchAgent."""
    import time as _t
    _plist = os.path.expanduser("~/Library/LaunchAgents/com.ytautomation.telegrambot.plist")
    subprocess.Popen(["launchctl", "unload", _plist])
    _t.sleep(1.5)
    subprocess.Popen(["launchctl", "load", _plist])


async def cmd_restart(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/restart — restart the bot via LaunchAgent."""
    if not is_allowed(update):
        return await deny(update)
    await update.message.reply_text(
        "🔄 *Restarting bot…*\nWill be back in ~5 seconds. "
        "Send any message after to confirm it's alive.",
        parse_mode="Markdown",
    )
    # Delay 1s so the reply sends before the process dies
    asyncio.get_event_loop().call_later(1.0, _do_restart_bot)


# ── /tiktok — TikTok uploader with scheduler ────────────────────────────────

async def cmd_tiktok(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/tiktok — TikTok uploader with Create TikTok + batch modes."""
    if not is_allowed(update):
        return await deny(update)

    from tiktok_auth import load_token, is_token_valid

    token = load_token()
    if not token or not is_token_valid():
        await update.message.reply_text(
            "\u274c TikTok not connected.\n"
            "Run /tiktok\\_setup to connect your TikTok account.",
        )
        return

    # Find all rendered beats
    out_dir = ROOT / "output"
    rendered = sorted(
        p.stem for p in out_dir.glob("*.mp4")
        if not p.stem.endswith("_9x16") and not p.stem.endswith("_thumb")
    )
    if not rendered:
        await update.message.reply_text("\u274c No rendered videos found in output/.")
        return

    # Check social log for already-uploaded
    from social_upload import load_social_log
    slog = load_social_log()
    already = {s for s, v in slog.items() if isinstance(v, dict) and v.get("tiktok")}
    pending_raw = [s for s in rendered if s not in already]

    # Reorder for maximum clip variety
    clip_map = _load_clip_map()
    pending = _reorder_for_clip_variety(pending_raw, clip_map) if clip_map else pending_raw

    pct_done = int((len(already) / len(rendered)) * 100) if rendered else 0
    bar_len = 15
    filled = int((len(already) / len(rendered)) * bar_len) if rendered else 0
    bar = "\u2588" * filled + "\u2591" * (bar_len - filled)

    lines = [
        f"\U0001f3b5 *TikTok Uploads*",
        f"@fy33fy33",
        f"",
        f"[{bar}] {pct_done}%",
        f"\u2705 {len(already)} posted  \u00b7  \u23f3 {len(pending)} pending  \u00b7  \U0001f3ac {len(rendered)} total",
        "",
    ]
    if not pending:
        lines.append("\u2705 All beats already posted to TikTok!")
        await update.message.reply_text("\n".join(lines), parse_mode="Markdown")
        return

    lines.append("What would you like to do?")

    # Build inline keyboard
    batch_key = f"tt{os.urandom(4).hex()}"
    _SOCIAL_BATCH_STEMS[batch_key] = pending

    buttons = [
        [InlineKeyboardButton(
            "\U0001f3b5 Create TikTok",
            callback_data=f"ttsched:pick:{batch_key}",
        )],
        [InlineKeyboardButton(
            f"\U0001f680 Upload all {len(pending)} now",
            callback_data=f"ttsched:now:{batch_key}",
        )],
        [InlineKeyboardButton(
            "\U0001f4c5 1 per day",
            callback_data=f"ttsched:daily:{batch_key}",
        ),
        InlineKeyboardButton(
            "\u23f0 Every 12h",
            callback_data=f"ttsched:12h:{batch_key}",
        )],
        [InlineKeyboardButton(
            "\U0001f552 Pick a time",
            callback_data=f"ttsched:picktime:{batch_key}",
        )],
        [InlineKeyboardButton(
            "\u274c Cancel",
            callback_data=f"ttsched:cancel:{batch_key}",
        )],
    ]
    await update.message.reply_text(
        "\n".join(lines),
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(buttons),
    )


_TT_QUEUE: dict[str, dict] = {}  # queue_key → {stems, index, ok, fail, delay_min}


async def ttsched_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle TikTok scheduler button presses."""
    query = update.callback_query
    await query.answer()
    data = query.data  # ttsched:{mode}:{batch_key}
    parts = data.split(":", 2)
    if len(parts) < 3:
        return
    _, mode, batch_key = parts

    if mode == "cancel":
        _SOCIAL_BATCH_STEMS.pop(batch_key, None)
        _TT_QUEUE.pop(batch_key, None)
        await query.edit_message_text("\u274c Cancelled.")
        return

    # ── Create TikTok: show beat picker (page 0) ──
    if mode == "pick":
        stems = _SOCIAL_BATCH_STEMS.get(batch_key)
        if not stems:
            await query.edit_message_text("\u26a0\ufe0f Session expired. Run /tiktok again.")
            return
        await _tt_show_picker(query, batch_key, page=0)
        return

    # ── Handle picker page navigation ──
    if mode.startswith("page"):
        page = int(mode.replace("page", ""))
        await _tt_show_picker(query, batch_key, page=page)
        return

    # ── Handle single beat selection from picker ──
    if mode == "one":
        bk, stem = batch_key.rsplit(":", 1) if ":" in batch_key else (batch_key, "")
        stems_list = _SOCIAL_BATCH_STEMS.get(bk)
        if not stems_list or stem not in stems_list:
            await query.edit_message_text("\u26a0\ufe0f Session expired. Run /tiktok again.")
            return
        queue_key = f"ttq{os.urandom(4).hex()}"
        _TT_QUEUE[queue_key] = {
            "stems": [stem], "index": 0, "ok": 0, "fail": 0,
            "delay_min": 0, "chat_id": query.message.chat_id,
        }
        log.info("ttsched_callback: created single queue_key=%s for stem=%s", queue_key, stem)
        await query.edit_message_text(
            f"\U0001f3b5 *Create TikTok:* `{stem}`\n"
            f"{'━' * 24}\n"
            f"Preparing preview...",
            parse_mode="Markdown",
        )
        await _tt_show_preview(query.message.chat_id, queue_key, context)
        return

    # ── Pick a time: show time grid ──
    if mode == "picktime":
        stems = _SOCIAL_BATCH_STEMS.get(batch_key)
        if not stems:
            await query.edit_message_text("\u26a0\ufe0f Session expired. Run /tiktok again.")
            return
        await _tt_show_time_picker(query, batch_key)
        return

    # ── Pick a time: frequency picker (after time selected) ──
    if mode == "tfreq":
        rest = batch_key  # e.g. "14:00:ttabcdef12"
        await _tt_show_freq_picker(query, rest)
        return

    # ── Pick a time: start scheduled queue at chosen time + frequency ──
    if mode == "tgo":
        parts2 = batch_key.split(":", 3)
        if len(parts2) < 4:
            await query.edit_message_text("\u26a0\ufe0f Bad schedule data. Run /tiktok again.")
            return
        delay_str, hh, mm, bk = parts2
        delay_min = int(delay_str)
        stems = _SOCIAL_BATCH_STEMS.pop(bk, None)
        if not stems:
            await query.edit_message_text("\u26a0\ufe0f Session expired. Run /tiktok again.")
            return

        from datetime import datetime, timezone
        from zoneinfo import ZoneInfo
        tz = ZoneInfo("America/New_York")
        now = datetime.now(tz)
        target = now.replace(hour=int(hh), minute=int(mm), second=0, microsecond=0)
        if target <= now:
            target = target + __import__("datetime").timedelta(days=1)
        wait_secs = (target - now).total_seconds()

        queue_key = f"ttq{os.urandom(4).hex()}"
        _TT_QUEUE[queue_key] = {
            "stems": stems, "index": 0, "ok": 0, "fail": 0,
            "delay_min": delay_min, "chat_id": query.message.chat_id,
            "start_wait_secs": wait_secs,
        }
        # Persist schedule to disk so it survives bot restarts
        _add_schedule({
            "queue_key": queue_key, "platform": "tt", "type": "batch",
            "stems": stems, "index": 0, "ok": 0, "fail": 0,
            "delay_min": delay_min, "chat_id": query.message.chat_id,
            "fire_at_utc": target.astimezone(timezone.utc).isoformat(),
        })
        total = len(stems)
        freq_label = "1/day" if delay_min == 1440 else "every 12h" if delay_min == 720 else f"every {delay_min}m"
        target_str = target.strftime("%-I:%M %p EST")
        wait_hrs = int(wait_secs // 3600)
        wait_mins = int((wait_secs % 3600) // 60)
        wait_label = f"{wait_hrs}h {wait_mins}m" if wait_hrs else f"{wait_mins}m"

        log.info("ttsched tgo: queue_key=%s stems=%d delay=%d start=%s (in %ds)",
                 queue_key, total, delay_min, target_str, int(wait_secs))

        cancel_kb = InlineKeyboardMarkup([[
            InlineKeyboardButton("\u274c Cancel", callback_data=f"ttrev:cancel:{queue_key}"),
        ]])
        wait_msg = await query.edit_message_text(
            f"\U0001f552 *Scheduled: {total} TikToks*\n"
            f"{'━' * 24}\n"
            f"\U0001f4c5 First post at *{target_str}*  ({wait_label} from now)\n"
            f"\u23f0 Then {freq_label}\n\n"
            f"Waiting...",
            parse_mode="Markdown",
            reply_markup=cancel_kb,
        )

        async def _tgo_bg():
            _slept = 0
            while _slept < wait_secs:
                await asyncio.sleep(min(5, wait_secs - _slept))
                _slept += 5
                if _TT_QUEUE.get(queue_key, {}).get("cancelled"):
                    log.info("ttsched tgo: cancelled during wait (after %ds)", int(_slept))
                    _remove_schedule(queue_key)
                    return
            _remove_schedule(queue_key)  # schedule fired — remove from persistent store
            _TT_QUEUE.get(queue_key, {}).pop("scheduled", None)
            _TT_QUEUE.get(queue_key, {}).pop("_sched_task", None)
            try:
                await wait_msg.delete()
            except Exception:
                pass
            await context.bot.send_message(
                query.message.chat_id,
                f"\U0001f680 *Time's up \u2014 starting TikTok queue!*\n"
                f"{'━' * 24}\n"
                f"{total} videos \u00b7 {freq_label}",
                parse_mode="Markdown",
            )
            await _tt_show_preview(query.message.chat_id, queue_key, context)

        _TT_QUEUE[queue_key]["scheduled"] = True
        _TT_QUEUE[queue_key]["_sched_task"] = asyncio.create_task(_tgo_bg())
        return

    # ── Batch modes ──
    stems = _SOCIAL_BATCH_STEMS.pop(batch_key, None)
    if not stems:
        await query.edit_message_text("\u26a0\ufe0f Session expired. Run /tiktok again.")
        return

    if mode == "now":
        delay_min = 0
    elif mode == "daily":
        delay_min = 1440
    elif mode == "12h":
        delay_min = 720
    else:
        delay_min = 0

    queue_key = f"ttq{os.urandom(4).hex()}"
    _TT_QUEUE[queue_key] = {
        "stems": stems, "index": 0, "ok": 0, "fail": 0,
        "delay_min": delay_min, "chat_id": query.message.chat_id,
    }
    log.info("ttsched_callback: created queue_key=%s with %d stems, delay=%d", queue_key, len(stems), delay_min)
    total = len(stems)
    pct = 0
    bar_len = 15
    bar = "\u2591" * bar_len
    await query.edit_message_text(
        f"\U0001f3b5 *Starting TikTok queue*\n"
        f"{'━' * 24}\n"
        f"[{bar}] {pct}%  \u2014  0/{total}\n\n"
        f"Loading first preview...",
        parse_mode="Markdown",
    )
    await _tt_show_preview(query.message.chat_id, queue_key, context)


async def _tt_show_time_picker(query, batch_key: str):
    """Show a grid of common posting times (EST) for scheduled TikToks."""
    from datetime import datetime
    from zoneinfo import ZoneInfo
    tz = ZoneInfo("America/New_York")
    now = datetime.now(tz)
    now_str = now.strftime("%-I:%M %p")

    time_slots = [
        ("9:00 AM",  "09", "00"),
        ("12:00 PM", "12", "00"),
        ("2:00 PM",  "14", "00"),
        ("5:00 PM",  "17", "00"),
        ("7:00 PM",  "19", "00"),
        ("9:00 PM",  "21", "00"),
    ]

    buttons = []
    row = []
    for label, hh, mm in time_slots:
        cb = f"ttsched:tfreq:{hh}:{mm}:{batch_key}"
        row.append(InlineKeyboardButton(label, callback_data=cb))
        if len(row) == 3:
            buttons.append(row)
            row = []
    if row:
        buttons.append(row)
    buttons.append([InlineKeyboardButton("\u274c Back", callback_data=f"ttsched:cancel:{batch_key}")])

    stems = _SOCIAL_BATCH_STEMS.get(batch_key, [])
    await query.edit_message_text(
        f"\U0001f552 *Pick a start time (EST)*\n"
        f"{'━' * 24}\n"
        f"Now: {now_str} EST\n"
        f"{len(stems)} TikToks queued\n\n"
        f"First TikTok posts at the time you pick.\n"
        f"Then choose how often (daily / 12h).",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(buttons),
    )


async def _tt_show_freq_picker(query, rest: str):
    """After time is picked, ask for frequency (daily / 12h)."""
    parts = rest.split(":", 2)
    if len(parts) < 3:
        await query.edit_message_text("\u26a0\ufe0f Bad time data. Run /tiktok again.")
        return
    hh, mm, bk = parts
    from datetime import datetime
    from zoneinfo import ZoneInfo
    tz = ZoneInfo("America/New_York")
    now = datetime.now(tz)
    target = now.replace(hour=int(hh), minute=int(mm), second=0, microsecond=0)
    if target <= now:
        target = target + __import__("datetime").timedelta(days=1)
        day_label = "tomorrow"
    else:
        day_label = "today"
    time_label = target.strftime("%-I:%M %p EST")

    stems = _SOCIAL_BATCH_STEMS.get(bk, [])
    buttons = [
        [InlineKeyboardButton(
            "\U0001f4c5 1 per day",
            callback_data=f"ttsched:tgo:1440:{hh}:{mm}:{bk}",
        ),
        InlineKeyboardButton(
            "\u23f0 Every 12h",
            callback_data=f"ttsched:tgo:720:{hh}:{mm}:{bk}",
        )],
        [InlineKeyboardButton(
            "\u25c0 Change time",
            callback_data=f"ttsched:picktime:{bk}",
        )],
    ]
    await query.edit_message_text(
        f"\U0001f552 *Starting at {time_label}* ({day_label})\n"
        f"{'━' * 24}\n"
        f"{len(stems)} TikToks queued\n\n"
        f"How often should TikToks post?",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(buttons),
    )


async def _tt_show_picker(query, batch_key: str, page: int = 0):
    """Show paginated beat picker for Create TikTok."""
    stems = _SOCIAL_BATCH_STEMS.get(batch_key, [])
    if not stems:
        await query.edit_message_text("\u26a0\ufe0f Session expired. Run /tiktok again.")
        return

    PAGE_SIZE = 8
    total_pages = (len(stems) + PAGE_SIZE - 1) // PAGE_SIZE
    page = max(0, min(page, total_pages - 1))
    page_stems = stems[page * PAGE_SIZE : (page + 1) * PAGE_SIZE]

    buttons = []
    for s in page_stems:
        title = s.replace("_", " ").title()
        cb = f"ttsched:one:{batch_key}:{s}"
        if len(cb.encode()) <= 64:
            buttons.append([InlineKeyboardButton(f"\U0001f3b5 {title}", callback_data=cb)])
        else:
            short_s = s[:20]
            buttons.append([InlineKeyboardButton(
                f"\U0001f3b5 {title[:25]}",
                callback_data=f"ttsched:one:{batch_key}:{short_s}",
            )])

    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("\u25c0 Prev", callback_data=f"ttsched:page{page-1}:{batch_key}"))
    nav.append(InlineKeyboardButton(f"{page+1}/{total_pages}", callback_data=f"ttsched:page{page}:{batch_key}"))
    if page < total_pages - 1:
        nav.append(InlineKeyboardButton("Next \u25b6", callback_data=f"ttsched:page{page+1}:{batch_key}"))
    buttons.append(nav)
    buttons.append([InlineKeyboardButton("\u274c Back", callback_data=f"ttsched:cancel:{batch_key}")])

    await query.edit_message_text(
        f"\U0001f3b5 *Create TikTok \u2014 pick a beat*\n"
        f"{'━' * 24}\n"
        f"Page {page+1}/{total_pages}  \u00b7  {len(stems)} beats available",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(buttons),
    )


def _tt_bar(done: int, total: int, bar_len: int = 15) -> str:
    """Build a progress bar string for TikTok queue."""
    pct = int((done / total) * 100) if total else 0
    filled = int((done / total) * bar_len) if total else 0
    bar = "\u2588" * filled + "\u2591" * (bar_len - filled)
    return f"[{bar}] {pct}%"


async def _tt_show_preview(chat_id: int, queue_key: str, context):
    """Show thumbnail preview for TikTok upload — no conversion here."""
    from social_upload import build_social_caption

    q = _TT_QUEUE.get(queue_key)
    if not q:
        return

    stems = q["stems"]
    idx = q["index"]
    total = len(stems)
    done = q["ok"] + q["fail"]

    if idx >= total:
        await context.bot.send_message(
            chat_id,
            f"\U0001f3b5 *TikTok uploads complete!*\n"
            f"{'━' * 24}\n"
            f"{_tt_bar(total, total)}\n\n"
            f"\u2705 {q['ok']} posted  \u00b7  \u274c {q['fail']} failed\n\n"
            f"\u26a0\ufe0f _Unaudited app: videos are PRIVATE on TikTok._",
            parse_mode="Markdown",
        )
        _TT_QUEUE.pop(queue_key, None)
        return

    stem = stems[idx]
    beat_title = stem.replace("_", " ").title()

    try:
        caption = build_social_caption(stem)
    except Exception:
        caption = f"{beat_title} \U0001f525\U0001f3b5"
    caption_preview = caption[:300] + ("..." if len(caption) > 300 else "")

    preview_text = (
        f"\U0001f3b5 *New TikTok*  \u2014  {idx + 1}/{total}\n"
        f"{'━' * 24}\n\n"
        f"\U0001f3b5 *{beat_title}*\n\n"
        f"\U0001f4dd {esc(caption_preview)}\n\n"
        f"{'━' * 24}\n"
        f"{_tt_bar(done, total)}\n"
        f"\u2705 {q['ok']}  \u00b7  \u274c {q['fail']}  \u00b7  "
        f"\u23f3 {total - idx} left"
    )

    buttons = [
        [
            InlineKeyboardButton("\U0001f199 Post now", callback_data=f"ttrev:post:{queue_key}"),
            InlineKeyboardButton("\U0001f552 Schedule", callback_data=f"ttrev:sched:{queue_key}"),
        ],
        [
            InlineKeyboardButton("\u23e9 Skip", callback_data=f"ttrev:skip:{queue_key}"),
            InlineKeyboardButton("\U0001f6d1 Stop", callback_data=f"ttrev:stop:{queue_key}"),
        ],
    ]

    sent = False
    thumb = ROOT / "output" / f"{stem}_thumb.jpg"

    if thumb.exists():
        try:
            with open(thumb, "rb") as img:
                await context.bot.send_photo(
                    chat_id, img,
                    caption=preview_text,
                    parse_mode="Markdown",
                    reply_markup=InlineKeyboardMarkup(buttons),
                )
            sent = True
        except Exception as e:
            log.warning("Thumb preview send failed for %s: %s", stem, e)

    if not sent:
        await context.bot.send_message(
            chat_id, preview_text,
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(buttons),
        )


async def ttrev_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle TikTok preview approve/skip/stop."""
    query = update.callback_query
    try:
        await query.answer()
    except Exception:
        pass

    data = query.data  # ttrev:{action}:{queue_key}  or  ttrev:sat:HH:MM:{queue_key}
    parts = data.split(":", 2)
    if len(parts) < 3:
        log.warning("ttrev_callback: malformed data=%s", data)
        return
    _, action, queue_key = parts

    if action == "sat":
        sat_bits = queue_key.split(":", 2)
        if len(sat_bits) >= 3:
            queue_key = sat_bits[2]

    log.info("ttrev_callback: action=%s key=%s found=%s", action, queue_key, queue_key in _TT_QUEUE)

    q = _TT_QUEUE.get(queue_key)
    if not q:
        try:
            await query.edit_message_text("\u26a0\ufe0f Session expired \u2014 run /tiktok again.")
        except Exception:
            try:
                await query.edit_message_reply_markup(reply_markup=None)
            except Exception:
                pass
        return

    try:
        await _ttrev_handle(query, action, queue_key, q, context)
    except Exception as e:
        log.error("ttrev_callback CRASH: %s", e, exc_info=True)
        try:
            await context.bot.send_message(
                q.get("chat_id", query.message.chat_id),
                f"\u274c *TikTok error:* {esc(str(e)[:200])}\n\nRun /tiktok to retry.",
                parse_mode="Markdown",
            )
        except Exception:
            pass


async def _ttrev_handle(query, action, queue_key, q, context):
    """Inner handler for ttrev_callback."""
    stem = q["stems"][q["index"]]
    chat_id = q["chat_id"]
    total = len(q["stems"])
    beat_title = stem.replace("_", " ").title()

    # ── Stop ──
    if action == "stop":
        try:
            await query.edit_message_reply_markup(reply_markup=None)
        except Exception:
            pass
        remaining = total - q["index"]
        await context.bot.send_message(
            chat_id,
            f"\U0001f6d1 *Queue stopped*\n"
            f"{'━' * 24}\n"
            f"{_tt_bar(q['ok'] + q['fail'], total)}\n"
            f"\u2705 {q['ok']} shared  \u00b7  \u274c {q['fail']} failed  \u00b7  "
            f"\u23f3 {remaining} remaining\n\n"
            f"Run /tiktok to continue.",
            parse_mode="Markdown",
        )
        _TT_QUEUE.pop(queue_key, None)
        return

    # ── Skip ──
    if action == "skip":
        _cancel_pending_schedule(q, queue_key)
        try:
            await query.edit_message_reply_markup(reply_markup=None)
        except Exception:
            pass
        q["index"] += 1
        await _tt_show_preview(chat_id, queue_key, context)
        return

    # ── Cancel (during upload/wait) ──
    if action == "cancel":
        _cancel_pending_schedule(q, queue_key)
        try:
            await query.edit_message_reply_markup(reply_markup=None)
        except Exception:
            pass
        q["cancelled"] = True
        remaining = total - q["index"]
        await context.bot.send_message(
            chat_id,
            f"\U0001f6d1 *Cancelled*\n"
            f"{'━' * 24}\n"
            f"\u2705 {q['ok']} shared  \u00b7  \u274c {q['fail']} failed  \u00b7  "
            f"\u23f3 {remaining} skipped\n\n"
            f"Run /tiktok to continue.",
            parse_mode="Markdown",
        )
        _TT_QUEUE.pop(queue_key, None)
        _remove_schedule(queue_key)
        return

    # ── Schedule (show inline time picker) ──
    if action == "sched":
        from datetime import datetime
        from zoneinfo import ZoneInfo
        tz = ZoneInfo("America/New_York")
        now = datetime.now(tz)
        now_str = now.strftime("%-I:%M %p")
        time_slots = [
            ("9 AM",  "09", "00"), ("12 PM", "12", "00"),
            ("2 PM",  "14", "00"), ("5 PM",  "17", "00"),
            ("7 PM",  "19", "00"), ("9 PM",  "21", "00"),
        ]
        rows = []
        for i in range(0, len(time_slots), 3):
            row = []
            for label, hh, mm in time_slots[i:i+3]:
                row.append(InlineKeyboardButton(
                    label, callback_data=f"ttrev:sat:{hh}:{mm}:{queue_key}",
                ))
            rows.append(row)
        rows.append([InlineKeyboardButton("\u2b05 Back", callback_data=f"ttrev:back:{queue_key}")])
        try:
            await query.edit_message_reply_markup(
                reply_markup=InlineKeyboardMarkup(rows),
            )
        except Exception:
            pass
        return

    # ── Schedule at specific time ──
    if action == "sat":
        sat_parts = query.data.split(":", 5)
        if len(sat_parts) < 5:
            return
        _, _, hh, mm, qk = sat_parts[0], sat_parts[1], sat_parts[2], sat_parts[3], sat_parts[4]
        queue_key = qk
        q = _TT_QUEUE.get(queue_key)
        if not q:
            try:
                await query.edit_message_text("\u26a0\ufe0f Session expired. Run /tiktok again.")
            except Exception:
                pass
            return

        from datetime import datetime, timedelta, timezone
        from zoneinfo import ZoneInfo
        tz = ZoneInfo("America/New_York")
        now = datetime.now(tz)
        target = now.replace(hour=int(hh), minute=int(mm), second=0, microsecond=0)
        if target <= now:
            target += timedelta(days=1)
        wait_secs = (target - now).total_seconds()
        target_str = target.strftime("%-I:%M %p EST")
        wait_hrs = int(wait_secs // 3600)
        wait_mins = int((wait_secs % 3600) // 60)
        wait_label = f"{wait_hrs}h {wait_mins}m" if wait_hrs else f"{wait_mins}m"
        stem_name = q["stems"][q["index"]].replace("_", " ").title()

        cancel_kb = InlineKeyboardMarkup([[
            InlineKeyboardButton("\u274c Cancel", callback_data=f"ttrev:cancel:{queue_key}"),
        ]])
        try:
            await query.edit_message_text(
                f"\U0001f552 *Scheduled*\n"
                f"{'━' * 24}\n"
                f"\U0001f3b5 {stem_name}\n"
                f"\U0001f4c5 Posting at *{target_str}*  ({wait_label})\n\n"
                f"Waiting...",
                parse_mode="Markdown",
                reply_markup=cancel_kb,
            )
        except Exception:
            await context.bot.send_message(
                chat_id, f"\U0001f552 Scheduled: {stem_name} at {target_str}",
                reply_markup=cancel_kb,
            )

        # Persist single-post schedule to disk
        _add_schedule({
            "queue_key": queue_key, "platform": "tt", "type": "single",
            "stems": q["stems"], "index": q["index"], "ok": q["ok"], "fail": q["fail"],
            "delay_min": q["delay_min"], "chat_id": chat_id,
            "fire_at_utc": target.astimezone(timezone.utc).isoformat(),
        })

        async def _sat_bg(_q=q, _qk=queue_key, _ws=wait_secs, _ctx=context, _cid=chat_id):
            _slept = 0
            while _slept < _ws:
                await asyncio.sleep(min(5, _ws - _slept))
                _slept += 5
                if _q.get("cancelled"):
                    _remove_schedule(_qk)
                    return
            _q.pop("scheduled", None)
            _q.pop("_sched_task", None)
            _remove_schedule(_qk)  # schedule fired
            await _tt_do_post(_qk, _q, _ctx)
        q["scheduled"] = True
        q["_sched_task"] = asyncio.create_task(_sat_bg())
        return

    # ── Back (from schedule picker → original preview) ──
    if action == "back":
        _cancel_pending_schedule(q, queue_key)
        try:
            await query.edit_message_reply_markup(reply_markup=None)
        except Exception:
            pass
        await _tt_show_preview(chat_id, queue_key, context)
        return

    # ── Post ──
    if action == "post":
        _cancel_pending_schedule(q, queue_key)
        try:
            await query.edit_message_reply_markup(reply_markup=None)
        except Exception:
            pass
        asyncio.create_task(_tt_do_post(queue_key, q, context))
        return


async def _tt_do_post(queue_key: str, q: dict, context):
    """Background task: convert → upload to TikTok → delay → next preview."""
    from social_upload import tiktok_upload, build_social_caption, convert_to_portrait

    chat_id = q["chat_id"]
    total = len(q["stems"])
    stem = q["stems"][q["index"]]
    beat_title = stem.replace("_", " ").title()

    # Handle delay between posts
    if q["delay_min"] > 0 and q["ok"] > 0:
        wait = q["delay_min"]
        hrs = wait // 60
        mins = wait % 60
        time_str = f"{hrs}h" if hrs and not mins else f"{mins}m" if not hrs else f"{hrs}h {mins}m"
        wait_msg = await context.bot.send_message(
            chat_id,
            f"\u23f0 *Next post in {time_str}*\n"
            f"{'━' * 24}\n"
            f"{_tt_bar(q['ok'] + q['fail'], total)}\n"
            f"\u2705 {q['ok']}/{total} posted so far",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton("\u274c Cancel", callback_data=f"ttrev:cancel:{queue_key}"),
            ]]),
        )
        _wait_total = wait * 60
        _waited = 0
        while _waited < _wait_total:
            await asyncio.sleep(min(5, _wait_total - _waited))
            _waited += 5
            if q.get("cancelled"):
                log.info("ttrev post: cancelled during delay (after %ds)", int(_waited))
                return
        try:
            await wait_msg.delete()
        except Exception:
            pass

    done = q["ok"] + q["fail"]

    # ── Phase 1: Convert to portrait ──
    portrait_path = ROOT / "output" / f"{stem}_9x16.mp4"
    need_convert = not portrait_path.exists()

    cancel_kb = InlineKeyboardMarkup([[
        InlineKeyboardButton("\u274c Cancel", callback_data=f"ttrev:cancel:{queue_key}"),
    ]])

    if need_convert:
        progress_msg = await context.bot.send_message(
            chat_id,
            f"\U0001f504 *Converting to portrait...*\n"
            f"{'━' * 24}\n"
            f"\U0001f3b5 {beat_title}  ({done + 1}/{total})\n"
            f"[{'░' * 15}] 0%",
            parse_mode="Markdown",
            reply_markup=cancel_kb,
        )

        conv_progress = {"pct": 0.0}
        spinner = ["\U0001f504", "\u23f3", "\U0001f4e1", "\u2699\ufe0f"]

        def _run_convert():
            def _on_pct(pct):
                conv_progress["pct"] = pct
            convert_to_portrait(stem, progress_cb=_on_pct)

        loop = asyncio.get_event_loop()
        convert_task = asyncio.ensure_future(
            loop.run_in_executor(None, _run_convert)
        )

        tick = 0
        last_pct = -1
        import time as _time
        t0 = _time.monotonic()
        while not convert_task.done():
            await asyncio.sleep(1.5)
            if convert_task.done() or q.get("cancelled"):
                break
            tick += 1
            pct = int(conv_progress["pct"])
            if abs(pct - last_pct) < 2 and tick % 4 != 0:
                continue
            last_pct = pct
            bar_filled = int((pct / 100) * 15)
            bar = "\u2588" * bar_filled + "\u2591" * (15 - bar_filled)
            icon = spinner[tick % len(spinner)]
            elapsed = int(_time.monotonic() - t0)
            try:
                await progress_msg.edit_text(
                    f"{icon} *Converting to portrait...*\n"
                    f"{'━' * 24}\n"
                    f"\U0001f3b5 {beat_title}  ({done + 1}/{total})\n"
                    f"[{bar}] {pct}%  \u00b7  {elapsed}s",
                    parse_mode="Markdown",
                    reply_markup=cancel_kb,
                )
            except Exception:
                pass

        try:
            convert_task.result()
        except Exception as e:
            log.error("Portrait conversion failed for %s: %s", stem, e)
            try:
                import subprocess as _sp
                _sp.run(["pkill", "-9", "-f", f"{stem}_9x16"],
                        capture_output=True, timeout=5)
            except Exception:
                pass
            if portrait_path.exists():
                try:
                    portrait_path.unlink()
                except Exception:
                    pass
            q["fail"] += 1
            try:
                await progress_msg.edit_text(
                    f"\u274c *Conversion failed:* {beat_title}\n"
                    f"{'━' * 24}\n"
                    f"{esc(str(e)[:200])}",
                    parse_mode="Markdown",
                )
            except Exception:
                pass
            if q.get("cancelled"):
                return
            q["index"] += 1
            await asyncio.sleep(1)
            await _tt_show_preview(chat_id, queue_key, context)
            return

        if q.get("cancelled"):
            try:
                import subprocess as _sp
                _sp.run(["pkill", "-9", "-f", f"{stem}_9x16"],
                        capture_output=True, timeout=5)
            except Exception:
                pass
            return

        try:
            await progress_msg.edit_text(
                f"\u2705 *Converted!*\n"
                f"{'━' * 24}\n"
                f"\U0001f3b5 {beat_title}  ({done + 1}/{total})\n"
                f"[{'█' * 15}] 100%\n\n"
                f"\U0001f199 Now uploading to TikTok...",
                parse_mode="Markdown",
                reply_markup=cancel_kb,
            )
        except Exception:
            pass
    else:
        cancel_kb = InlineKeyboardMarkup([[
            InlineKeyboardButton("\u274c Cancel", callback_data=f"ttrev:cancel:{queue_key}"),
        ]])
        progress_msg = await context.bot.send_message(
            chat_id,
            f"\U0001f199 *Uploading to TikTok...*\n"
            f"{'━' * 24}\n"
            f"\U0001f3b5 {beat_title}  ({done + 1}/{total})\n"
            f"{_tt_bar(done, total)}\n\n"
            f"\u2705 {q['ok']} shared  \u00b7  \u274c {q['fail']} failed",
            parse_mode="Markdown",
            reply_markup=cancel_kb,
        )

    # ── Phase 2: Upload to TikTok (with live progress) ──
    loop = asyncio.get_event_loop()
    max_upload_retries = 2
    upload_timeout = 600
    upload_ok = False
    _upload_progress = {"phase": "init", "pct": 0, "detail": "Starting...", "chunk": 0, "chunks": 0}

    import functools as _ft

    for upload_attempt in range(max_upload_retries):
        if q.get("cancelled"):
            return

        try:
            caption = build_social_caption(stem)
        except Exception:
            caption = f"{beat_title} \U0001f525\U0001f3b5"

        _upload_progress.update(phase="init", pct=0, detail="Starting...", chunk=0, chunks=0)

        upload_task = asyncio.ensure_future(
            asyncio.wait_for(
                loop.run_in_executor(
                    None, _ft.partial(tiktok_upload, stem, caption, progress=_upload_progress)
                ),
                timeout=upload_timeout,
            )
        )

        # Live progress loop — update Telegram message every 2 seconds
        spinner = ["\U0001f4e4", "\U0001f4e1", "\u2601\ufe0f", "\U0001f680"]  # 📤 📡 ☁️ 🚀
        tick = 0
        last_shown_pct = -1
        import time as _time
        t0 = _time.monotonic()

        while not upload_task.done():
            await asyncio.sleep(2)
            if upload_task.done() or q.get("cancelled"):
                break
            tick += 1
            phase = _upload_progress.get("phase", "init")
            pct = int(_upload_progress.get("pct", 0))
            detail = _upload_progress.get("detail", "")
            chunk = _upload_progress.get("chunk", 0)
            chunks = _upload_progress.get("chunks", 0)
            elapsed = int(_time.monotonic() - t0)

            # Only update if pct changed by ≥2% or every 3rd tick
            if abs(pct - last_shown_pct) < 2 and tick % 3 != 0:
                continue
            last_shown_pct = pct

            icon = spinner[tick % len(spinner)]
            bar_filled = int((pct / 100) * 15)
            bar = "\u2588" * bar_filled + "\u2591" * (15 - bar_filled)

            if phase == "uploading" and chunks > 0:
                phase_text = f"Uploading chunk {chunk}/{chunks}"
            elif phase == "processing":
                phase_text = "Processing on TikTok"
            else:
                phase_text = detail or "Starting"

            try:
                await progress_msg.edit_text(
                    f"{icon} *Uploading to TikTok...*\n"
                    f"{'━' * 24}\n"
                    f"\U0001f3b5 {beat_title}  ({done + 1}/{total})\n"
                    f"[{bar}] {pct}%  \u00b7  {elapsed}s\n"
                    f"_{phase_text}_",
                    parse_mode="Markdown",
                    reply_markup=cancel_kb,
                )
            except Exception:
                pass

        # Harvest the result
        try:
            result = upload_task.result()
            if result.get("status") == "ok":
                upload_ok = True
                break
            elif upload_attempt < max_upload_retries - 1:
                log.warning("TikTok upload attempt %d for %s returned status=%s, retrying...",
                            upload_attempt + 1, stem, result.get("status"))
                await asyncio.sleep(5)
            else:
                log.error("TikTok upload failed for %s after %d attempts: %s",
                          stem, max_upload_retries, result)
        except asyncio.TimeoutError:
            log.error("TikTok upload timed out for %s (attempt %d)", stem, upload_attempt + 1)
            if upload_attempt < max_upload_retries - 1:
                await asyncio.sleep(5)
        except Exception as e:
            log.error("TikTok upload error for %s: %s", stem, e, exc_info=True)
            if upload_attempt < max_upload_retries - 1:
                await asyncio.sleep(5)
            else:
                break

    if upload_ok:
        q["ok"] += 1
        try:
            await progress_msg.edit_text(
                f"\u2705 *Posted to TikTok!*\n"
                f"{'━' * 24}\n"
                f"\U0001f3b5 {beat_title}\n"
                f"{_tt_bar(q['ok'] + q['fail'], total)}\n"
                f"\u2705 {q['ok']}  \u00b7  \u274c {q['fail']}",
                parse_mode="Markdown",
            )
        except Exception:
            pass
    else:
        q["fail"] += 1
        try:
            await progress_msg.edit_text(
                f"\u274c *Upload failed:* {beat_title}\n"
                f"{'━' * 24}\n"
                f"{_tt_bar(q['ok'] + q['fail'], total)}\n"
                f"\u2705 {q['ok']}  \u00b7  \u274c {q['fail']}",
                parse_mode="Markdown",
            )
        except Exception:
            pass

    if q.get("cancelled"):
        return

    q["index"] += 1
    await asyncio.sleep(1)
    await _tt_show_preview(chat_id, queue_key, context)


# ── /shorts — YouTube Shorts uploader ─────────────────────────────────────────

async def cmd_shorts(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/shorts — YouTube Shorts uploader with Create Short + batch modes."""
    if not is_allowed(update):
        return await deny(update)

    # Check YouTube auth
    try:
        from youtube_auth import get_youtube_service
        _yt = get_youtube_service()
    except Exception as e:
        await update.message.reply_text(
            "\u274c YouTube not connected.\n"
            "Run /ytsetup to connect your YouTube account.",
        )
        return

    # Find all rendered beats
    out_dir = ROOT / "output"
    rendered = sorted(
        p.stem for p in out_dir.glob("*.mp4")
        if not p.stem.endswith("_9x16") and not p.stem.endswith("_thumb")
    )
    if not rendered:
        await update.message.reply_text("\u274c No rendered videos found in output/.")
        return

    # Filter by duration ≤3 min (YouTube Shorts allows up to 3 min since Oct 2024)
    from social_upload import _get_duration
    eligible = []
    skipped_long = 0
    for s in rendered:
        vid = out_dir / f"{s}.mp4"
        dur = _get_duration(vid)
        if dur > 0 and dur <= 180:
            eligible.append(s)
        elif dur > 180:
            skipped_long += 1
        else:
            eligible.append(s)  # unknown duration — let YouTube decide

    if not eligible:
        msg = "\u274c No beats eligible for Shorts (all are over 3 minutes)."
        if skipped_long:
            msg += f"\n\u26a0\ufe0f {skipped_long} beats skipped (over 3 min)."
        await update.message.reply_text(msg)
        return

    # Check social log for already-uploaded
    from social_upload import load_social_log
    slog = load_social_log()
    already = {s for s, v in slog.items() if isinstance(v, dict) and v.get("youtube_shorts")}
    pending_raw = [s for s in eligible if s not in already]

    # Reorder for clip variety
    clip_map = _load_clip_map()
    pending = _reorder_for_clip_variety(pending_raw, clip_map) if clip_map else pending_raw

    pct_done = int((len(already) / len(eligible)) * 100) if eligible else 0
    bar_len = 15
    filled = int((len(already) / len(eligible)) * bar_len) if eligible else 0
    bar = "\u2588" * filled + "\u2591" * (bar_len - filled)

    lines = [
        f"\U0001f3ac *YouTube Shorts*",
        f"",
        f"[{bar}] {pct_done}%",
        f"\u2705 {len(already)} posted  \u00b7  \u23f3 {len(pending)} pending  \u00b7  \U0001f3ac {len(eligible)} total",
    ]
    if skipped_long:
        lines.append(f"\u26a0\ufe0f {skipped_long} beats skipped (over 3 min)")
    lines.append("")

    if not pending:
        lines.append("\u2705 All eligible beats already posted as Shorts!")
        await update.message.reply_text("\n".join(lines), parse_mode="Markdown")
        return

    lines.append("What would you like to do?")

    # Build inline keyboard
    batch_key = f"yts{os.urandom(4).hex()}"
    _SOCIAL_BATCH_STEMS[batch_key] = pending

    buttons = [
        [InlineKeyboardButton(
            "\U0001f3ac Create Short",
            callback_data=f"ytssched:pick:{batch_key}",
        )],
        [InlineKeyboardButton(
            f"\U0001f680 Upload all {len(pending)} now",
            callback_data=f"ytssched:now:{batch_key}",
        )],
        [InlineKeyboardButton(
            "\U0001f4c5 1 per day",
            callback_data=f"ytssched:daily:{batch_key}",
        ),
        InlineKeyboardButton(
            "\u23f0 Every 12h",
            callback_data=f"ytssched:12h:{batch_key}",
        )],
        [InlineKeyboardButton(
            "\U0001f552 Pick a time",
            callback_data=f"ytssched:picktime:{batch_key}",
        )],
        [InlineKeyboardButton(
            "\u274c Cancel",
            callback_data=f"ytssched:cancel:{batch_key}",
        )],
    ]
    await update.message.reply_text(
        "\n".join(lines),
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(buttons),
    )


_YTS_QUEUE: dict[str, dict] = {}  # queue_key → {stems, index, ok, fail, delay_min}


async def ytssched_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle YouTube Shorts scheduler button presses."""
    query = update.callback_query
    await query.answer()
    data = query.data  # ytssched:{mode}:{batch_key}
    parts = data.split(":", 2)
    if len(parts) < 3:
        return
    _, mode, batch_key = parts

    if mode == "cancel":
        _SOCIAL_BATCH_STEMS.pop(batch_key, None)
        _YTS_QUEUE.pop(batch_key, None)
        await query.edit_message_text("\u274c Cancelled.")
        return

    # ── Create Short: show beat picker (page 0) ──
    if mode == "pick":
        stems = _SOCIAL_BATCH_STEMS.get(batch_key)
        if not stems:
            await query.edit_message_text("\u26a0\ufe0f Session expired. Run /shorts again.")
            return
        await _yts_show_picker(query, batch_key, page=0)
        return

    # ── Handle picker page navigation ──
    if mode.startswith("page"):
        page = int(mode.replace("page", ""))
        await _yts_show_picker(query, batch_key, page=page)
        return

    # ── Handle single beat selection from picker ──
    if mode == "one":
        bk, stem = batch_key.rsplit(":", 1) if ":" in batch_key else (batch_key, "")
        stems_list = _SOCIAL_BATCH_STEMS.get(bk)
        if not stems_list:
            await query.edit_message_text("\u26a0\ufe0f Session expired. Run /shorts again.")
            return
        # Support index-based lookup for long stems (e.g. "#5")
        if stem.startswith("#") and stem[1:].isdigit():
            idx = int(stem[1:])
            if idx < 0 or idx >= len(stems_list):
                await query.edit_message_text("\u26a0\ufe0f Session expired. Run /shorts again.")
                return
            stem = stems_list[idx]
        elif stem not in stems_list:
            await query.edit_message_text("\u26a0\ufe0f Session expired. Run /shorts again.")
            return
        queue_key = f"ytsq{os.urandom(4).hex()}"
        _YTS_QUEUE[queue_key] = {
            "stems": [stem], "index": 0, "ok": 0, "fail": 0,
            "delay_min": 0, "chat_id": query.message.chat_id,
        }
        log.info("ytssched_callback: created single queue_key=%s for stem=%s", queue_key, stem)
        await query.edit_message_text(
            f"\U0001f3ac *Create Short:* `{stem}`\n"
            f"{'━' * 24}\n"
            f"Preparing preview...",
            parse_mode="Markdown",
        )
        await _yts_show_preview(query.message.chat_id, queue_key, context)
        return

    # ── Pick a time: show time grid ──
    if mode == "picktime":
        stems = _SOCIAL_BATCH_STEMS.get(batch_key)
        if not stems:
            await query.edit_message_text("\u26a0\ufe0f Session expired. Run /shorts again.")
            return
        await _yts_show_time_picker(query, batch_key)
        return

    # ── Pick a time: frequency picker (after time selected) ──
    if mode == "tfreq":
        rest = batch_key  # e.g. "14:00:ytsabcdef12"
        await _yts_show_freq_picker(query, rest)
        return

    # ── Pick a time: start scheduled queue at chosen time + frequency ──
    if mode == "tgo":
        parts2 = batch_key.split(":", 3)
        if len(parts2) < 4:
            await query.edit_message_text("\u26a0\ufe0f Bad schedule data. Run /shorts again.")
            return
        delay_str, hh, mm, bk = parts2
        delay_min = int(delay_str)
        stems = _SOCIAL_BATCH_STEMS.pop(bk, None)
        if not stems:
            await query.edit_message_text("\u26a0\ufe0f Session expired. Run /shorts again.")
            return

        from datetime import datetime, timedelta, timezone
        from zoneinfo import ZoneInfo
        tz = ZoneInfo("America/New_York")
        now = datetime.now(tz)
        target = now.replace(hour=int(hh), minute=int(mm), second=0, microsecond=0)
        if target <= now:
            target = target + timedelta(days=1)
        wait_secs = (target - now).total_seconds()

        queue_key = f"ytsq{os.urandom(4).hex()}"
        _YTS_QUEUE[queue_key] = {
            "stems": stems, "index": 0, "ok": 0, "fail": 0,
            "delay_min": delay_min, "chat_id": query.message.chat_id,
            "start_wait_secs": wait_secs,
        }
        # Persist schedule to disk so it survives bot restarts
        _add_schedule({
            "queue_key": queue_key, "platform": "yts", "type": "batch",
            "stems": stems, "index": 0, "ok": 0, "fail": 0,
            "delay_min": delay_min, "chat_id": query.message.chat_id,
            "fire_at_utc": target.astimezone(timezone.utc).isoformat(),
        })
        total = len(stems)
        freq_label = "1/day" if delay_min == 1440 else "every 12h" if delay_min == 720 else f"every {delay_min}m"
        target_str = target.strftime("%-I:%M %p EST")
        wait_hrs = int(wait_secs // 3600)
        wait_mins = int((wait_secs % 3600) // 60)
        wait_label = f"{wait_hrs}h {wait_mins}m" if wait_hrs else f"{wait_mins}m"

        log.info("ytssched tgo: queue_key=%s stems=%d delay=%d start=%s (in %ds)",
                 queue_key, total, delay_min, target_str, int(wait_secs))

        cancel_kb = InlineKeyboardMarkup([[
            InlineKeyboardButton("\u274c Cancel", callback_data=f"ytsrev:cancel:{queue_key}"),
        ]])
        wait_msg = await query.edit_message_text(
            f"\U0001f552 *Scheduled: {total} Shorts*\n"
            f"{'━' * 24}\n"
            f"\U0001f4c5 First post at *{target_str}*  ({wait_label} from now)\n"
            f"\u23f0 Then {freq_label}\n\n"
            f"Waiting...",
            parse_mode="Markdown",
            reply_markup=cancel_kb,
        )

        async def _yts_tgo_bg():
            _slept = 0
            while _slept < wait_secs:
                await asyncio.sleep(min(5, wait_secs - _slept))
                _slept += 5
                if _YTS_QUEUE.get(queue_key, {}).get("cancelled"):
                    log.info("ytssched tgo: cancelled during wait (after %ds)", int(_slept))
                    _YTS_QUEUE.pop(queue_key, None)
                    _remove_schedule(queue_key)
                    return
            _remove_schedule(queue_key)  # schedule fired
            _YTS_QUEUE.get(queue_key, {}).pop("scheduled", None)
            _YTS_QUEUE.get(queue_key, {}).pop("_sched_task", None)
            try:
                await wait_msg.delete()
            except Exception:
                pass
            await context.bot.send_message(
                query.message.chat_id,
                f"\U0001f680 *Time's up \u2014 starting Shorts queue!*\n"
                f"{'━' * 24}\n"
                f"{total} videos \u00b7 {freq_label}",
                parse_mode="Markdown",
            )
            await _yts_show_preview(query.message.chat_id, queue_key, context)

        _YTS_QUEUE[queue_key]["scheduled"] = True
        _YTS_QUEUE[queue_key]["_sched_task"] = asyncio.create_task(_yts_tgo_bg())
        return

    # ── Batch modes ──
    stems = _SOCIAL_BATCH_STEMS.pop(batch_key, None)
    if not stems:
        await query.edit_message_text("\u26a0\ufe0f Session expired. Run /shorts again.")
        return

    if mode == "now":
        delay_min = 0
    elif mode == "daily":
        delay_min = 1440
    elif mode == "12h":
        delay_min = 720
    else:
        delay_min = 0

    queue_key = f"ytsq{os.urandom(4).hex()}"
    _YTS_QUEUE[queue_key] = {
        "stems": stems, "index": 0, "ok": 0, "fail": 0,
        "delay_min": delay_min, "chat_id": query.message.chat_id,
    }
    log.info("ytssched_callback: created queue_key=%s with %d stems, delay=%d", queue_key, len(stems), delay_min)
    total = len(stems)
    pct = 0
    bar_len = 15
    bar = "\u2591" * bar_len
    await query.edit_message_text(
        f"\U0001f3ac *Starting Shorts queue*\n"
        f"{'━' * 24}\n"
        f"[{bar}] {pct}%  \u2014  0/{total}\n\n"
        f"Loading first preview...",
        parse_mode="Markdown",
    )
    await _yts_show_preview(query.message.chat_id, queue_key, context)


async def _yts_show_time_picker(query, batch_key: str):
    """Show a grid of common posting times (EST) for scheduled Shorts."""
    from datetime import datetime
    from zoneinfo import ZoneInfo
    tz = ZoneInfo("America/New_York")
    now = datetime.now(tz)
    now_str = now.strftime("%-I:%M %p")

    time_slots = [
        ("9:00 AM",  "09", "00"),
        ("12:00 PM", "12", "00"),
        ("2:00 PM",  "14", "00"),
        ("5:00 PM",  "17", "00"),
        ("7:00 PM",  "19", "00"),
        ("9:00 PM",  "21", "00"),
    ]

    buttons = []
    row = []
    for label, hh, mm in time_slots:
        cb = f"ytssched:tfreq:{hh}:{mm}:{batch_key}"
        row.append(InlineKeyboardButton(label, callback_data=cb))
        if len(row) == 3:
            buttons.append(row)
            row = []
    if row:
        buttons.append(row)
    buttons.append([InlineKeyboardButton("\u274c Back", callback_data=f"ytssched:cancel:{batch_key}")])

    stems = _SOCIAL_BATCH_STEMS.get(batch_key, [])
    await query.edit_message_text(
        f"\U0001f552 *Pick a start time (EST)*\n"
        f"{'━' * 24}\n"
        f"Now: {now_str} EST\n"
        f"{len(stems)} Shorts queued\n\n"
        f"First Short posts at the time you pick.\n"
        f"Then choose how often (daily / 12h).",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(buttons),
    )


async def _yts_show_freq_picker(query, rest: str):
    """After time is picked, ask for frequency (daily / 12h)."""
    parts = rest.split(":", 2)
    if len(parts) < 3:
        await query.edit_message_text("\u26a0\ufe0f Bad time data. Run /shorts again.")
        return
    hh, mm, bk = parts
    from datetime import datetime, timedelta
    from zoneinfo import ZoneInfo
    tz = ZoneInfo("America/New_York")
    now = datetime.now(tz)
    target = now.replace(hour=int(hh), minute=int(mm), second=0, microsecond=0)
    if target <= now:
        target = target + timedelta(days=1)
        day_label = "tomorrow"
    else:
        day_label = "today"
    time_label = target.strftime("%-I:%M %p EST")

    stems = _SOCIAL_BATCH_STEMS.get(bk, [])
    buttons = [
        [InlineKeyboardButton(
            "\U0001f4c5 1 per day",
            callback_data=f"ytssched:tgo:1440:{hh}:{mm}:{bk}",
        ),
        InlineKeyboardButton(
            "\u23f0 Every 12h",
            callback_data=f"ytssched:tgo:720:{hh}:{mm}:{bk}",
        )],
        [InlineKeyboardButton(
            "\u25c0 Change time",
            callback_data=f"ytssched:picktime:{bk}",
        )],
    ]
    await query.edit_message_text(
        f"\U0001f552 *Starting at {time_label}* ({day_label})\n"
        f"{'━' * 24}\n"
        f"{len(stems)} Shorts queued\n\n"
        f"How often should Shorts post?",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(buttons),
    )


async def _yts_show_picker(query, batch_key: str, page: int = 0):
    """Show paginated beat picker for Create Short."""
    stems = _SOCIAL_BATCH_STEMS.get(batch_key, [])
    if not stems:
        await query.edit_message_text("\u26a0\ufe0f Session expired. Run /shorts again.")
        return

    PAGE_SIZE = 8
    total_pages = (len(stems) + PAGE_SIZE - 1) // PAGE_SIZE
    page = max(0, min(page, total_pages - 1))
    page_stems = stems[page * PAGE_SIZE : (page + 1) * PAGE_SIZE]

    buttons = []
    for local_idx, s in enumerate(page_stems):
        title = s.replace("_", " ").title()
        cb = f"ytssched:one:{batch_key}:{s}"
        if len(cb.encode()) <= 64:
            buttons.append([InlineKeyboardButton(f"\U0001f3ac {title}", callback_data=cb)])
        else:
            # Use global index instead of truncated stem to avoid lookup failures
            global_idx = page * PAGE_SIZE + local_idx
            buttons.append([InlineKeyboardButton(
                f"\U0001f3ac {title[:25]}",
                callback_data=f"ytssched:one:{batch_key}:#{global_idx}",
            )])

    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("\u25c0 Prev", callback_data=f"ytssched:page{page-1}:{batch_key}"))
    nav.append(InlineKeyboardButton(f"{page+1}/{total_pages}", callback_data=f"ytssched:page{page}:{batch_key}"))
    if page < total_pages - 1:
        nav.append(InlineKeyboardButton("Next \u25b6", callback_data=f"ytssched:page{page+1}:{batch_key}"))
    buttons.append(nav)
    buttons.append([InlineKeyboardButton("\u274c Back", callback_data=f"ytssched:cancel:{batch_key}")])

    await query.edit_message_text(
        f"\U0001f3ac *Create Short \u2014 pick a beat*\n"
        f"{'━' * 24}\n"
        f"Page {page+1}/{total_pages}  \u00b7  {len(stems)} beats available",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(buttons),
    )


def _yts_bar(done: int, total: int, bar_len: int = 15) -> str:
    """Build a progress bar string for YouTube Shorts queue."""
    pct = int((done / total) * 100) if total else 0
    filled = int((done / total) * bar_len) if total else 0
    bar = "\u2588" * filled + "\u2591" * (bar_len - filled)
    return f"[{bar}] {pct}%"


async def _yts_show_preview(chat_id: int, queue_key: str, context):
    """Show thumbnail preview for YouTube Shorts upload."""
    from social_upload import build_social_caption

    q = _YTS_QUEUE.get(queue_key)
    if not q:
        return

    stems = q["stems"]
    idx = q["index"]
    total = len(stems)
    done = q["ok"] + q["fail"]

    if idx >= total:
        await context.bot.send_message(
            chat_id,
            f"\U0001f3ac *YouTube Shorts uploads complete!*\n"
            f"{'━' * 24}\n"
            f"{_yts_bar(total, total)}\n\n"
            f"\u2705 {q['ok']} posted  \u00b7  \u274c {q['fail']} failed",
            parse_mode="Markdown",
        )
        _YTS_QUEUE.pop(queue_key, None)
        return

    stem = stems[idx]
    beat_title = stem.replace("_", " ").title()

    try:
        caption = build_social_caption(stem)
    except Exception:
        caption = f"{beat_title} \U0001f525\U0001f3b5"
    caption_preview = (caption + " #Shorts")[:300]

    preview_text = (
        f"\U0001f3ac *New Short*  \u2014  {idx + 1}/{total}\n"
        f"{'━' * 24}\n\n"
        f"\U0001f3b5 *{beat_title}*\n\n"
        f"\U0001f4dd {esc(caption_preview)}\n\n"
        f"{'━' * 24}\n"
        f"{_yts_bar(done, total)}\n"
        f"\u2705 {q['ok']}  \u00b7  \u274c {q['fail']}  \u00b7  "
        f"\u23f3 {total - idx} left"
    )

    buttons = [
        [
            InlineKeyboardButton("\U0001f199 Post now", callback_data=f"ytsrev:post:{queue_key}"),
            InlineKeyboardButton("\U0001f552 Schedule", callback_data=f"ytsrev:sched:{queue_key}"),
        ],
        [
            InlineKeyboardButton("\u23e9 Skip", callback_data=f"ytsrev:skip:{queue_key}"),
            InlineKeyboardButton("\U0001f6d1 Stop", callback_data=f"ytsrev:stop:{queue_key}"),
        ],
    ]

    sent = False
    thumb = ROOT / "output" / f"{stem}_thumb.jpg"

    if thumb.exists():
        try:
            with open(thumb, "rb") as img:
                await context.bot.send_photo(
                    chat_id, img,
                    caption=preview_text,
                    parse_mode="Markdown",
                    reply_markup=InlineKeyboardMarkup(buttons),
                )
            sent = True
        except Exception as e:
            log.warning("Shorts thumb preview send failed for %s: %s", stem, e)

    if not sent:
        await context.bot.send_message(
            chat_id, preview_text,
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(buttons),
        )


async def ytsrev_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle YouTube Shorts preview approve/skip/stop."""
    query = update.callback_query
    try:
        await query.answer()
    except Exception:
        pass

    data = query.data  # ytsrev:{action}:{queue_key}  or  ytsrev:sat:HH:MM:{queue_key}
    parts = data.split(":", 2)
    if len(parts) < 3:
        log.warning("ytsrev_callback: malformed data=%s", data)
        return
    _, action, queue_key = parts

    if action == "sat":
        sat_bits = queue_key.split(":", 2)
        if len(sat_bits) >= 3:
            queue_key = sat_bits[2]

    log.info("ytsrev_callback: action=%s key=%s found=%s", action, queue_key, queue_key in _YTS_QUEUE)

    q = _YTS_QUEUE.get(queue_key)
    if not q:
        try:
            await query.edit_message_text("\u26a0\ufe0f Session expired \u2014 run /shorts again.")
        except Exception:
            try:
                await query.edit_message_reply_markup(reply_markup=None)
            except Exception:
                pass
        return

    try:
        await _ytsrev_handle(query, action, queue_key, q, context)
    except Exception as e:
        log.error("ytsrev_callback CRASH: %s", e, exc_info=True)
        try:
            await context.bot.send_message(
                q.get("chat_id", query.message.chat_id),
                f"\u274c *Shorts error:* {esc(str(e)[:200])}\n\nRun /shorts to retry.",
                parse_mode="Markdown",
            )
        except Exception:
            pass


async def _ytsrev_handle(query, action, queue_key, q, context):
    """Inner handler for ytsrev_callback."""
    stem = q["stems"][q["index"]]
    chat_id = q["chat_id"]
    total = len(q["stems"])
    beat_title = stem.replace("_", " ").title()

    # ── Stop ──
    if action == "stop":
        try:
            await query.edit_message_reply_markup(reply_markup=None)
        except Exception:
            pass
        remaining = total - q["index"]
        await context.bot.send_message(
            chat_id,
            f"\U0001f6d1 *Queue stopped*\n"
            f"{'━' * 24}\n"
            f"{_yts_bar(q['ok'] + q['fail'], total)}\n"
            f"\u2705 {q['ok']} shared  \u00b7  \u274c {q['fail']} failed  \u00b7  "
            f"\u23f3 {remaining} remaining\n\n"
            f"Run /shorts to continue.",
            parse_mode="Markdown",
        )
        _YTS_QUEUE.pop(queue_key, None)
        return

    # ── Skip ──
    if action == "skip":
        _cancel_pending_schedule(q, queue_key)
        try:
            await query.edit_message_reply_markup(reply_markup=None)
        except Exception:
            pass
        q["index"] += 1
        await _yts_show_preview(chat_id, queue_key, context)
        return

    # ── Cancel (during upload/wait) ──
    if action == "cancel":
        _cancel_pending_schedule(q, queue_key)
        try:
            await query.edit_message_reply_markup(reply_markup=None)
        except Exception:
            pass
        q["cancelled"] = True
        remaining = total - q["index"]
        await context.bot.send_message(
            chat_id,
            f"\U0001f6d1 *Cancelled*\n"
            f"{'━' * 24}\n"
            f"\u2705 {q['ok']} shared  \u00b7  \u274c {q['fail']} failed  \u00b7  "
            f"\u23f3 {remaining} skipped\n\n"
            f"Run /shorts to continue.",
            parse_mode="Markdown",
        )
        _YTS_QUEUE.pop(queue_key, None)
        _remove_schedule(queue_key)
        return

    # ── Schedule (show inline time picker) ──
    if action == "sched":
        from datetime import datetime
        from zoneinfo import ZoneInfo
        tz = ZoneInfo("America/New_York")
        now = datetime.now(tz)
        now_str = now.strftime("%-I:%M %p")
        time_slots = [
            ("9 AM",  "09", "00"), ("12 PM", "12", "00"),
            ("2 PM",  "14", "00"), ("5 PM",  "17", "00"),
            ("7 PM",  "19", "00"), ("9 PM",  "21", "00"),
        ]
        rows = []
        for i in range(0, len(time_slots), 3):
            row = []
            for label, hh, mm in time_slots[i:i+3]:
                row.append(InlineKeyboardButton(
                    label, callback_data=f"ytsrev:sat:{hh}:{mm}:{queue_key}",
                ))
            rows.append(row)
        rows.append([InlineKeyboardButton("\u2b05 Back", callback_data=f"ytsrev:back:{queue_key}")])
        try:
            await query.edit_message_reply_markup(
                reply_markup=InlineKeyboardMarkup(rows),
            )
        except Exception:
            pass
        return

    # ── Schedule at specific time ──
    if action == "sat":
        sat_parts = query.data.split(":", 5)
        if len(sat_parts) < 5:
            return
        _, _, hh, mm, qk = sat_parts[0], sat_parts[1], sat_parts[2], sat_parts[3], sat_parts[4]
        queue_key = qk
        q = _YTS_QUEUE.get(queue_key)
        if not q:
            try:
                await query.edit_message_text("\u26a0\ufe0f Session expired. Run /shorts again.")
            except Exception:
                pass
            return

        from datetime import datetime, timedelta
        from zoneinfo import ZoneInfo
        tz = ZoneInfo("America/New_York")
        now = datetime.now(tz)
        target = now.replace(hour=int(hh), minute=int(mm), second=0, microsecond=0)
        if target <= now:
            target += timedelta(days=1)
        wait_secs = (target - now).total_seconds()
        target_str = target.strftime("%-I:%M %p EST")
        wait_hrs = int(wait_secs // 3600)
        wait_mins = int((wait_secs % 3600) // 60)
        wait_label = f"{wait_hrs}h {wait_mins}m" if wait_hrs else f"{wait_mins}m"
        stem_name = q["stems"][q["index"]].replace("_", " ").title()

        cancel_kb = InlineKeyboardMarkup([[
            InlineKeyboardButton("\u274c Cancel", callback_data=f"ytsrev:cancel:{queue_key}"),
        ]])
        try:
            await query.edit_message_text(
                f"\U0001f552 *Scheduled*\n"
                f"{'━' * 24}\n"
                f"\U0001f3b5 {stem_name}\n"
                f"\U0001f4c5 Posting at *{target_str}*  ({wait_label})\n\n"
                f"Waiting...",
                parse_mode="Markdown",
                reply_markup=cancel_kb,
            )
        except Exception:
            await context.bot.send_message(
                chat_id, f"\U0001f552 Scheduled: {stem_name} at {target_str}",
                reply_markup=cancel_kb,
            )

        # Persist single-post schedule to disk
        from datetime import timezone as _tz_mod
        _add_schedule({
            "queue_key": queue_key, "platform": "yts", "type": "single",
            "stems": q["stems"], "index": q["index"], "ok": q["ok"], "fail": q["fail"],
            "delay_min": q["delay_min"], "chat_id": chat_id,
            "fire_at_utc": target.astimezone(_tz_mod.utc).isoformat(),
        })

        async def _yts_sat_bg(_q=q, _qk=queue_key, _ws=wait_secs, _ctx=context, _cid=chat_id):
            _slept = 0
            while _slept < _ws:
                await asyncio.sleep(min(5, _ws - _slept))
                _slept += 5
                if _q.get("cancelled"):
                    _remove_schedule(_qk)
                    return
            _q.pop("scheduled", None)
            _q.pop("_sched_task", None)
            _remove_schedule(_qk)  # schedule fired
            await _yts_do_post(_qk, _q, _ctx)
        q["scheduled"] = True
        q["_sched_task"] = asyncio.create_task(_yts_sat_bg())
        return

    # ── Back (from schedule picker → original preview) ──
    if action == "back":
        _cancel_pending_schedule(q, queue_key)
        try:
            await query.edit_message_reply_markup(reply_markup=None)
        except Exception:
            pass
        await _yts_show_preview(chat_id, queue_key, context)
        return

    # ── Post ──
    if action == "post":
        _cancel_pending_schedule(q, queue_key)
        try:
            await query.edit_message_reply_markup(reply_markup=None)
        except Exception:
            pass
        asyncio.create_task(_yts_do_post(queue_key, q, context))
        return


async def _yts_quota_stop(context, chat_id, queue_key, q, remaining, total):
    """Notify user of quota limit and stop the Shorts queue."""
    await context.bot.send_message(
        chat_id,
        f"📊 *YouTube daily quota reached*\n"
        f"{'━' * 24}\n"
        f"{_yts_bar(q['ok'] + q['fail'], total)}\n\n"
        f"✅ {q['ok']} Shorts posted\n"
        f"❌ {q['fail']} failed\n"
        f"⏳ {remaining} remaining\n\n"
        f"⏰ Quota resets at *midnight Pacific Time*\n"
        f"Run /shorts tomorrow to continue.\n"
        f"_Already-posted Shorts are tracked and won't re-upload._",
        parse_mode="Markdown",
    )
    _YTS_QUEUE.pop(queue_key, None)


async def _yts_do_post(queue_key: str, q: dict, context):
    """Background task: convert → upload to YouTube Shorts → delay → next preview."""
    from social_upload import youtube_shorts_upload, build_social_caption, convert_to_portrait

    chat_id = q["chat_id"]
    total = len(q["stems"])
    stem = q["stems"][q["index"]]
    beat_title = stem.replace("_", " ").title()

    # Handle delay between posts
    if q["delay_min"] > 0 and q["ok"] > 0:
        wait = q["delay_min"]
        hrs = wait // 60
        mins = wait % 60
        time_str = f"{hrs}h" if hrs and not mins else f"{mins}m" if not hrs else f"{hrs}h {mins}m"
        wait_msg = await context.bot.send_message(
            chat_id,
            f"\u23f0 *Next post in {time_str}*\n"
            f"{'━' * 24}\n"
            f"{_yts_bar(q['ok'] + q['fail'], total)}\n"
            f"\u2705 {q['ok']}/{total} posted so far",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton("\u274c Cancel", callback_data=f"ytsrev:cancel:{queue_key}"),
            ]]),
        )
        _wait_total = wait * 60
        _waited = 0
        while _waited < _wait_total:
            await asyncio.sleep(min(5, _wait_total - _waited))
            _waited += 5
            if q.get("cancelled"):
                log.info("ytsrev post: cancelled during delay (after %ds)", int(_waited))
                return
        try:
            await wait_msg.delete()
        except Exception:
            pass

    done = q["ok"] + q["fail"]
    progress_msg = None  # initialized early to avoid unbound errors

    # ── Phase 1: Convert to portrait ──
    portrait_path = ROOT / "output" / f"{stem}_9x16.mp4"
    need_convert = not portrait_path.exists()

    cancel_kb = InlineKeyboardMarkup([[
        InlineKeyboardButton("\u274c Cancel", callback_data=f"ytsrev:cancel:{queue_key}"),
    ]])

    if need_convert:
        progress_msg = await context.bot.send_message(
            chat_id,
            f"\U0001f504 *Converting to portrait...*\n"
            f"{'━' * 24}\n"
            f"\U0001f3b5 {beat_title}  ({done + 1}/{total})\n"
            f"[{'░' * 15}] 0%",
            parse_mode="Markdown",
            reply_markup=cancel_kb,
        )

        conv_progress = {"pct": 0.0}
        spinner = ["\U0001f504", "\u23f3", "\U0001f4e1", "\u2699\ufe0f"]

        def _run_convert():
            def _on_pct(pct):
                conv_progress["pct"] = pct
            convert_to_portrait(stem, progress_cb=_on_pct)

        loop = asyncio.get_event_loop()
        convert_task = asyncio.ensure_future(
            loop.run_in_executor(None, _run_convert)
        )

        tick = 0
        last_pct = -1
        import time as _time
        t0 = _time.monotonic()
        while not convert_task.done():
            await asyncio.sleep(1.5)
            if convert_task.done() or q.get("cancelled"):
                break
            tick += 1
            pct = int(conv_progress["pct"])
            if abs(pct - last_pct) < 2 and tick % 4 != 0:
                continue
            last_pct = pct
            bar_filled = int((pct / 100) * 15)
            bar = "\u2588" * bar_filled + "\u2591" * (15 - bar_filled)
            icon = spinner[tick % len(spinner)]
            elapsed = int(_time.monotonic() - t0)
            try:
                await progress_msg.edit_text(
                    f"{icon} *Converting to portrait...*\n"
                    f"{'━' * 24}\n"
                    f"\U0001f3b5 {beat_title}  ({done + 1}/{total})\n"
                    f"[{bar}] {pct}%  \u00b7  {elapsed}s",
                    parse_mode="Markdown",
                    reply_markup=cancel_kb,
                )
            except Exception:
                pass

        try:
            convert_task.result()
        except Exception as e:
            log.error("Portrait conversion failed for %s: %s", stem, e)
            try:
                import subprocess as _sp
                _sp.run(["pkill", "-9", "-f", str(portrait_path)],
                        capture_output=True, timeout=5)
            except Exception:
                pass
            if portrait_path.exists():
                try:
                    portrait_path.unlink()
                except Exception:
                    pass
            q["fail"] += 1
            try:
                await progress_msg.edit_text(
                    f"\u274c *Conversion failed:* {beat_title}\n"
                    f"{'━' * 24}\n"
                    f"{esc(str(e)[:200])}",
                    parse_mode="Markdown",
                )
            except Exception:
                pass
            if q.get("cancelled"):
                return
            q["index"] += 1
            await asyncio.sleep(1)
            await _yts_show_preview(chat_id, queue_key, context)
            return

        if q.get("cancelled"):
            try:
                import subprocess as _sp
                _sp.run(["pkill", "-9", "-f", str(portrait_path)],
                        capture_output=True, timeout=5)
            except Exception:
                pass
            return

        try:
            await progress_msg.edit_text(
                f"\u2705 *Converted!*\n"
                f"{'━' * 24}\n"
                f"\U0001f3b5 {beat_title}  ({done + 1}/{total})\n"
                f"[{'█' * 15}] 100%\n\n"
                f"\U0001f199 Now uploading to YouTube Shorts...",
                parse_mode="Markdown",
                reply_markup=cancel_kb,
            )
        except Exception:
            pass
    else:
        cancel_kb = InlineKeyboardMarkup([[
            InlineKeyboardButton("\u274c Cancel", callback_data=f"ytsrev:cancel:{queue_key}"),
        ]])
        progress_msg = await context.bot.send_message(
            chat_id,
            f"\U0001f199 *Uploading to YouTube Shorts...*\n"
            f"{'━' * 24}\n"
            f"\U0001f3b5 {beat_title}  ({done + 1}/{total})\n"
            f"{_yts_bar(done, total)}\n\n"
            f"\u2705 {q['ok']} shared  \u00b7  \u274c {q['fail']} failed",
            parse_mode="Markdown",
            reply_markup=cancel_kb,
        )

    # ── Phase 2: Upload to YouTube Shorts (with live progress) ──
    loop = asyncio.get_event_loop()
    max_upload_retries = 2
    upload_timeout = 600
    upload_ok = False
    upload_result = None
    _upload_progress = {"phase": "init", "pct": 0, "detail": "Starting..."}

    import functools as _ft

    for upload_attempt in range(max_upload_retries):
        if q.get("cancelled"):
            return

        _upload_progress.update(phase="init", pct=0, detail="Starting...")

        upload_task = asyncio.ensure_future(
            asyncio.wait_for(
                loop.run_in_executor(
                    None, _ft.partial(youtube_shorts_upload, stem, "public", progress=_upload_progress)
                ),
                timeout=upload_timeout,
            )
        )

        # Live progress loop — update Telegram message every 2 seconds
        spinner = ["\U0001f4e4", "\U0001f4e1", "\u2601\ufe0f", "\U0001f680"]  # 📤 📡 ☁️ 🚀
        tick = 0
        last_shown_pct = -1
        import time as _time
        t0 = _time.monotonic()

        while not upload_task.done():
            await asyncio.sleep(2)
            if upload_task.done() or q.get("cancelled"):
                break
            tick += 1
            phase = _upload_progress.get("phase", "init")
            pct = int(_upload_progress.get("pct", 0))
            detail = _upload_progress.get("detail", "")
            elapsed = int(_time.monotonic() - t0)

            # Only update if pct changed by ≥2% or every 3rd tick
            if abs(pct - last_shown_pct) < 2 and tick % 3 != 0:
                continue
            last_shown_pct = pct

            icon = spinner[tick % len(spinner)]
            bar_filled = int((pct / 100) * 15)
            bar = "\u2588" * bar_filled + "\u2591" * (15 - bar_filled)

            if phase == "uploading":
                phase_text = detail or "Uploading"
            elif phase == "thumbnail":
                phase_text = "Uploading thumbnail"
            else:
                phase_text = detail or "Starting"

            try:
                await progress_msg.edit_text(
                    f"{icon} *Uploading to YouTube Shorts...*\n"
                    f"{'━' * 24}\n"
                    f"\U0001f3b5 {beat_title}  ({done + 1}/{total})\n"
                    f"[{bar}] {pct}%  \u00b7  {elapsed}s\n"
                    f"_{phase_text}_",
                    parse_mode="Markdown",
                    reply_markup=cancel_kb,
                )
            except Exception:
                pass

        # Harvest the result
        try:
            result = upload_task.result()
            # ── Quota exceeded — stop queue immediately ──
            if result.get("quota_exceeded"):
                remaining = total - q["index"] - 1
                await _yts_quota_stop(context, chat_id, queue_key, q, remaining, total)
                return
            if result.get("status") == "ok":
                upload_ok = True
                upload_result = result
                break
            elif upload_attempt < max_upload_retries - 1:
                log.warning("YouTube Shorts upload attempt %d for %s returned status=%s, retrying...",
                            upload_attempt + 1, stem, result.get("status"))
                await asyncio.sleep(5)
            else:
                log.error("YouTube Shorts upload failed for %s after %d attempts: %s",
                          stem, max_upload_retries, result)
        except asyncio.TimeoutError:
            log.error("YouTube Shorts upload timed out for %s (attempt %d)", stem, upload_attempt + 1)
            if upload_attempt < max_upload_retries - 1:
                await asyncio.sleep(5)
        except Exception as e:
            err_lower = str(e).lower()
            if "quotaexceeded" in err_lower or ("403" in str(e) and "quota" in err_lower):
                log.warning("YouTube Shorts quota exceeded for %s", stem)
                remaining = total - q["index"] - 1
                await _yts_quota_stop(context, chat_id, queue_key, q, remaining, total)
                return
            log.error("YouTube Shorts upload error for %s: %s", stem, e, exc_info=True)
            if upload_attempt < max_upload_retries - 1:
                await asyncio.sleep(5)
            else:
                break

    if upload_ok and upload_result:
        q["ok"] += 1
        video_url = upload_result.get("url", "")
        try:
            await progress_msg.edit_text(
                f"\u2705 *Posted as YouTube Short!*\n"
                f"{'━' * 24}\n"
                f"\U0001f3b5 {beat_title}\n"
                f"\U0001f517 {video_url}\n"
                f"{_yts_bar(q['ok'] + q['fail'], total)}\n"
                f"\u2705 {q['ok']}  \u00b7  \u274c {q['fail']}",
                parse_mode="Markdown",
            )
        except Exception:
            pass
    else:
        q["fail"] += 1
        try:
            await progress_msg.edit_text(
                f"\u274c *Upload failed:* {beat_title}\n"
                f"{'━' * 24}\n"
                f"{_yts_bar(q['ok'] + q['fail'], total)}\n"
                f"\u2705 {q['ok']}  \u00b7  \u274c {q['fail']}",
                parse_mode="Markdown",
            )
        except Exception:
            pass

    if q.get("cancelled"):
        return

    q["index"] += 1
    await asyncio.sleep(1)
    await _yts_show_preview(chat_id, queue_key, context)


# ── /ig_setup — connect Instagram for Reels publishing ───────────────────────

async def cmd_ig_setup(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/ig_setup — connect Instagram via Facebook Business Login for Reels publishing."""
    if not is_allowed(update):
        return await deny(update)

    from ig_auth import load_token, is_token_valid, get_auth_url

    # Check if already connected with a proper Facebook Page token
    token = load_token()
    if token and is_token_valid():
        tok_preview = token.get("access_token", "")[:8] + "..."
        if not tok_preview.startswith("IGAA"):
            await update.message.reply_text(
                "\u2705 *Instagram is already connected!*\n\n"
                f"Token: `{tok_preview}`\n"
                f"IG User ID: `{token.get('ig_user_id', 'unknown')}`\n"
                f"Page ID: `{token.get('page_id', 'none')}`\n\n"
                "To reconnect with a different account, delete `ig_token.json` "
                "and run /ig\\_setup again.",
                parse_mode="Markdown",
            )
            return ConversationHandler.END
        # Has an IGAA token — needs re-auth
        await update.message.reply_text(
            "\u26a0\ufe0f *Your IG token is Instagram-native (IGAA)*\n\n"
            "Reels publishing requires a Facebook Page token. "
            "Let's re-authorize through Facebook Business Login...",
            parse_mode="Markdown",
        )

    # Check for app credentials
    if not os.environ.get("IG_APP_ID") or not os.environ.get("IG_APP_SECRET"):
        await update.message.reply_text(
            "\U0001f527 *Instagram Setup \u2014 Step 1: Create a Facebook App*\n\n"
            "1\ufe0f\u20e3 Go to developers.facebook.com\n"
            "2\ufe0f\u20e3 Create a new Business app\n"
            "3\ufe0f\u20e3 Add *Instagram Graph API* product\n"
            "4\ufe0f\u20e3 Under Settings \u2192 Basic, copy App ID and App Secret\n"
            "5\ufe0f\u20e3 Add `IG_APP_ID` and `IG_APP_SECRET` to your `.env` file\n"
            "6\ufe0f\u20e3 Restart bot and run /ig\\_setup again.",
            parse_mode="Markdown",
        )
        return ConversationHandler.END

    # Generate auth URL
    try:
        auth_url = get_auth_url()
    except Exception as e:
        await update.message.reply_text(f"\u274c Failed to generate auth URL: {e}")
        return ConversationHandler.END

    # Send auth URL and ask user to paste the code back
    await update.message.reply_text(
        "\U0001f511 *Instagram Setup \u2014 Authorize via Facebook*\n\n"
        "\u2757 Sign in with your *Facebook account* (not Instagram directly).\n"
        "This connects through your Facebook Page to get publishing permissions.\n\n"
        "*Steps:*\n"
        "1\ufe0f\u20e3 Open the link below\n"
        "2\ufe0f\u20e3 Authorize the app\n"
        "3\ufe0f\u20e3 Copy the code shown on the callback page\n"
        "4\ufe0f\u20e3 Paste it back here\n\n"
        "Send /cancel to abort.",
        parse_mode="Markdown",
    )
    # URL sent without parse_mode so underscores in query params don't break Markdown
    await update.message.reply_text(auth_url)

    return IG_SETUP_CODE


async def ig_setup_receive_code(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Receive the OAuth code pasted by the user and exchange it for tokens."""
    code = update.message.text.strip()

    if not code or len(code) < 10:
        await update.message.reply_text(
            "\u26a0\ufe0f That doesn't look like a valid code. "
            "Please paste the full code from the callback page, or /cancel."
        )
        return IG_SETUP_CODE

    await update.message.reply_text("\u23f3 Exchanging code for token...")

    try:
        from ig_auth import exchange_code
        loop = asyncio.get_event_loop()
        token_data = await loop.run_in_executor(None, exchange_code, code)
        tok_type = "EAAI" if token_data.get("access_token", "").startswith("EAAI") else "other"
        await update.message.reply_text(
            "\u2705 *Instagram connected!*\n\n"
            f"Token type: `{tok_type}` (Facebook Page)\n"
            f"IG User ID: `{token_data.get('ig_user_id', 'unknown')}`\n"
            f"Page ID: `{token_data.get('page_id', 'unknown')}`\n"
            f"Expires: `{token_data.get('expires_at', 'unknown')[:10]}`\n\n"
            "You can now run /ig to upload Reels! \U0001f389\n\n"
            "\U0001f4c2 /reels to browse & download portrait videos",
            parse_mode="Markdown",
        )
    except Exception as e:
        log.error("Instagram setup failed: %s", e, exc_info=True)
        await update.message.reply_text(
            f"\u274c Instagram setup failed:\n`{esc(str(e)[:400])}`\n\n"
            "Common fixes:\n"
            "\u2022 Make sure you have an IG Business/Creator account\n"
            "\u2022 Link it to a Facebook Page\n"
            "\u2022 Try /ig\\_setup again \u2014 codes expire quickly",
            parse_mode="Markdown",
        )

    return ConversationHandler.END


async def ig_setup_cancel(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Cancel /ig_setup conversation."""
    await update.message.reply_text("\u274c Instagram setup cancelled.")
    return ConversationHandler.END


# ── /ig — Instagram Reel upload scheduler ─────────────────────────────────────

def _load_clip_map() -> dict[str, str]:
    """
    Parse the rerender log to get stem → clip name mapping.
    Returns e.g. {"adx": "visual_5.mp4", "army": "visual_10.mp4", ...}
    """
    log_path = ROOT / "logs" / "rerender_varied.log"
    clip_map = {}
    if not log_path.exists():
        return clip_map
    try:
        lines = log_path.read_text().splitlines()
        current_stem = None
        for line in lines:
            if "[RENDER]" in line:
                current_stem = line.split("[RENDER]")[-1].strip()
            elif "[CLIP]" in line and current_stem:
                clip_name = line.split("[CLIP]")[-1].strip().split()[0]
                clip_map[current_stem] = clip_name
                current_stem = None
    except Exception:
        pass
    return clip_map


def _reorder_for_clip_variety(stems: list[str], clip_map: dict[str, str]) -> list[str]:
    """
    Reorder stems so consecutive beats use different visual clips.
    Maximizes variety by spacing out beats that share the same clip.
    """
    if len(stems) <= 1 or not clip_map:
        return stems

    # Group stems by clip
    by_clip: dict[str, list[str]] = {}
    unknown = []
    for s in stems:
        c = clip_map.get(s)
        if c:
            by_clip.setdefault(c, []).append(s)
        else:
            unknown.append(s)

    if not by_clip:
        return stems

    # Round-robin across clip groups (largest groups first for better spacing)
    groups = sorted(by_clip.values(), key=len, reverse=True)
    result = []
    idx = [0] * len(groups)
    while any(idx[i] < len(groups[i]) for i in range(len(groups))):
        for i, grp in enumerate(groups):
            if idx[i] < len(grp):
                result.append(grp[idx[i]])
                idx[i] += 1

    # Append unknown stems at the end
    result.extend(unknown)
    return result


async def cmd_ig(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/ig — Instagram Reels uploader with Create Reel + batch modes."""
    if not is_allowed(update):
        return await deny(update)

    from ig_auth import load_token, is_token_valid

    token = load_token()
    if not token or not is_token_valid():
        await update.message.reply_text(
            "\u274c Instagram not connected.\n"
            "Generate a token at developers.facebook.com and save ig_token.json.",
        )
        return

    ig_user_id = token.get("ig_user_id", "unknown")

    # Find all rendered beats
    out_dir = ROOT / "output"
    rendered = sorted(
        p.stem for p in out_dir.glob("*.mp4")
        if not p.stem.endswith("_9x16") and not p.stem.endswith("_thumb")
    )
    if not rendered:
        await update.message.reply_text("\u274c No rendered videos found in output/.")
        return

    # Check social log for already-uploaded
    from social_upload import load_social_log
    slog = load_social_log()
    already = {s for s, v in slog.items() if isinstance(v, dict) and v.get("instagram")}
    pending_raw = [s for s in rendered if s not in already]

    # Reorder for maximum clip variety (consecutive reels use different visuals)
    clip_map = _load_clip_map()
    pending = _reorder_for_clip_variety(pending_raw, clip_map) if clip_map else pending_raw

    pct_done = int((len(already) / len(rendered)) * 100) if rendered else 0
    bar_len = 15
    filled = int((len(already) / len(rendered)) * bar_len) if rendered else 0
    bar = "\u2588" * filled + "\u2591" * (bar_len - filled)

    lines = [
        f"\U0001f4f8 *Instagram Reels*",
        f"@leekthatsfy3",
        f"",
        f"[{bar}] {pct_done}%",
        f"\u2705 {len(already)} posted  \u00b7  \u23f3 {len(pending)} pending  \u00b7  \U0001f3ac {len(rendered)} total",
        "",
    ]
    if not pending:
        lines.append("\u2705 All beats already posted to Instagram!")
        await update.message.reply_text("\n".join(lines), parse_mode="Markdown")
        return

    lines.append("What would you like to do?")

    # Build inline keyboard  (short key to fit callback_data 64-byte limit)
    batch_key = f"ig{os.urandom(4).hex()}"
    _SOCIAL_BATCH_STEMS[batch_key] = pending

    buttons = [
        [InlineKeyboardButton(
            "\U0001f3ac Create Reel",
            callback_data=f"igsched:pick:{batch_key}",
        )],
        [InlineKeyboardButton(
            f"\U0001f680 Upload all {len(pending)} now",
            callback_data=f"igsched:now:{batch_key}",
        )],
        [InlineKeyboardButton(
            "\U0001f4c5 1 per day",
            callback_data=f"igsched:daily:{batch_key}",
        ),
        InlineKeyboardButton(
            "\u23f0 Every 12h",
            callback_data=f"igsched:12h:{batch_key}",
        )],
        [InlineKeyboardButton(
            "\U0001f552 Pick a time",
            callback_data=f"igsched:picktime:{batch_key}",
        )],
        [InlineKeyboardButton(
            "\u274c Cancel",
            callback_data=f"igsched:cancel:{batch_key}",
        )],
    ]
    await update.message.reply_text(
        "\n".join(lines),
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(buttons),
    )


_IG_QUEUE: dict[str, dict] = {}  # queue_key → {stems, index, ok, fail, delay_min}


async def igsched_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle Instagram scheduler button presses."""
    query = update.callback_query
    await query.answer()
    data = query.data  # igsched:{mode}:{batch_key} or igsched:pick:{batch_key}
    parts = data.split(":", 2)
    if len(parts) < 3:
        return
    _, mode, batch_key = parts

    if mode == "cancel":
        _SOCIAL_BATCH_STEMS.pop(batch_key, None)
        _IG_QUEUE.pop(batch_key, None)
        await query.edit_message_text("\u274c Cancelled.")
        return

    # ── Create Reel: show beat picker (page 0) ──
    if mode == "pick":
        stems = _SOCIAL_BATCH_STEMS.get(batch_key)
        if not stems:
            await query.edit_message_text("\u26a0\ufe0f Session expired. Run /ig again.")
            return
        await _ig_show_picker(query, batch_key, page=0)
        return

    # ── Handle picker page navigation ──
    if mode.startswith("page"):
        page = int(mode.replace("page", ""))
        await _ig_show_picker(query, batch_key, page=page)
        return

    # ── Handle single beat selection from picker ──
    if mode == "one":
        # batch_key here is actually "batchkey:stem"
        bk, stem = batch_key.rsplit(":", 1) if ":" in batch_key else (batch_key, "")
        stems_list = _SOCIAL_BATCH_STEMS.get(bk)
        if not stems_list or stem not in stems_list:
            await query.edit_message_text("\u26a0\ufe0f Session expired. Run /ig again.")
            return
        # Create a 1-beat queue
        queue_key = f"igq{os.urandom(4).hex()}"
        _IG_QUEUE[queue_key] = {
            "stems": [stem], "index": 0, "ok": 0, "fail": 0,
            "delay_min": 0, "chat_id": query.message.chat_id,
        }
        log.info("igsched_callback: created single queue_key=%s for stem=%s", queue_key, stem)
        await query.edit_message_text(
            f"\U0001f3ac *Create Reel:* `{stem}`\n"
            f"{'━' * 24}\n"
            f"Preparing preview...",
            parse_mode="Markdown",
        )
        await _ig_show_preview(query.message.chat_id, queue_key, context)
        return

    # ── Pick a time: show time grid ──
    if mode == "picktime":
        stems = _SOCIAL_BATCH_STEMS.get(batch_key)
        if not stems:
            await query.edit_message_text("\u26a0\ufe0f Session expired. Run /ig again.")
            return
        await _ig_show_time_picker(query, batch_key)
        return

    # ── Pick a time: frequency picker (after time selected) ──
    if mode == "tfreq":
        # batch_key is "HH:MM:batchkey"
        rest = batch_key  # e.g. "14:00:igabcdef12"
        await _ig_show_freq_picker(query, rest)
        return

    # ── Pick a time: start scheduled queue at chosen time + frequency ──
    if mode == "tgo":
        # batch_key is "delay:HH:MM:batchkey"
        parts2 = batch_key.split(":", 3)
        if len(parts2) < 4:
            await query.edit_message_text("\u26a0\ufe0f Bad schedule data. Run /ig again.")
            return
        delay_str, hh, mm, bk = parts2
        delay_min = int(delay_str)
        stems = _SOCIAL_BATCH_STEMS.pop(bk, None)
        if not stems:
            await query.edit_message_text("\u26a0\ufe0f Session expired. Run /ig again.")
            return

        # Calculate seconds until the chosen time (EST / America/New_York)
        from datetime import datetime, timezone
        from zoneinfo import ZoneInfo
        tz = ZoneInfo("America/New_York")
        now = datetime.now(tz)
        target = now.replace(hour=int(hh), minute=int(mm), second=0, microsecond=0)
        if target <= now:
            target = target + __import__("datetime").timedelta(days=1)
        wait_secs = (target - now).total_seconds()

        queue_key = f"igq{os.urandom(4).hex()}"
        _IG_QUEUE[queue_key] = {
            "stems": stems, "index": 0, "ok": 0, "fail": 0,
            "delay_min": delay_min, "chat_id": query.message.chat_id,
            "start_wait_secs": wait_secs,
        }
        # Persist schedule to disk so it survives bot restarts
        _add_schedule({
            "queue_key": queue_key, "platform": "ig", "type": "batch",
            "stems": stems, "index": 0, "ok": 0, "fail": 0,
            "delay_min": delay_min, "chat_id": query.message.chat_id,
            "fire_at_utc": target.astimezone(timezone.utc).isoformat(),
        })
        total = len(stems)
        freq_label = "1/day" if delay_min == 1440 else "every 12h" if delay_min == 720 else f"every {delay_min}m"
        target_str = target.strftime("%-I:%M %p EST")
        wait_hrs = int(wait_secs // 3600)
        wait_mins = int((wait_secs % 3600) // 60)
        wait_label = f"{wait_hrs}h {wait_mins}m" if wait_hrs else f"{wait_mins}m"

        log.info("igsched tgo: queue_key=%s stems=%d delay=%d start=%s (in %ds)",
                 queue_key, total, delay_min, target_str, int(wait_secs))

        cancel_kb = InlineKeyboardMarkup([[
            InlineKeyboardButton("\u274c Cancel", callback_data=f"igrev:cancel:{queue_key}"),
        ]])
        wait_msg = await query.edit_message_text(
            f"\U0001f552 *Scheduled: {total} Reels*\n"
            f"{'━' * 24}\n"
            f"\U0001f4c5 First post at *{target_str}*  ({wait_label} from now)\n"
            f"\u23f0 Then {freq_label}\n\n"
            f"Waiting...",
            parse_mode="Markdown",
            reply_markup=cancel_kb,
        )

        # Offload the long wait to a background task so the callback returns
        # immediately and the bot can process other commands in the meantime.
        async def _tgo_bg():
            _slept = 0
            while _slept < wait_secs:
                await asyncio.sleep(min(5, wait_secs - _slept))
                _slept += 5
                if _IG_QUEUE.get(queue_key, {}).get("cancelled"):
                    log.info("igsched tgo: cancelled during wait (after %ds)", int(_slept))
                    _remove_schedule(queue_key)
                    return
            _remove_schedule(queue_key)  # schedule fired
            _IG_QUEUE.get(queue_key, {}).pop("scheduled", None)
            _IG_QUEUE.get(queue_key, {}).pop("_sched_task", None)
            try:
                await wait_msg.delete()
            except Exception:
                pass
            await context.bot.send_message(
                query.message.chat_id,
                f"\U0001f680 *Time's up — starting Reels queue!*\n"
                f"{'━' * 24}\n"
                f"{total} reels · {freq_label}",
                parse_mode="Markdown",
            )
            await _ig_show_preview(query.message.chat_id, queue_key, context)

        _IG_QUEUE[queue_key]["scheduled"] = True
        _IG_QUEUE[queue_key]["_sched_task"] = asyncio.create_task(_tgo_bg())
        return

    # ── Batch modes ──
    stems = _SOCIAL_BATCH_STEMS.pop(batch_key, None)
    if not stems:
        await query.edit_message_text("\u26a0\ufe0f Session expired. Run /ig again.")
        return

    if mode == "now":
        delay_min = 0
    elif mode == "daily":
        delay_min = 1440
    elif mode == "12h":
        delay_min = 720
    else:
        delay_min = 0

    # Store queue state and show first preview
    queue_key = f"igq{os.urandom(4).hex()}"
    _IG_QUEUE[queue_key] = {
        "stems": stems, "index": 0, "ok": 0, "fail": 0,
        "delay_min": delay_min, "chat_id": query.message.chat_id,
    }
    log.info("igsched_callback: created queue_key=%s with %d stems, delay=%d", queue_key, len(stems), delay_min)
    total = len(stems)
    pct = 0
    bar_len = 15
    bar = "\u2591" * bar_len
    await query.edit_message_text(
        f"\U0001f3ac *Starting Reels queue*\n"
        f"{'━' * 24}\n"
        f"[{bar}] {pct}%  —  0/{total}\n\n"
        f"Loading first preview...",
        parse_mode="Markdown",
    )
    await _ig_show_preview(query.message.chat_id, queue_key, context)


async def _ig_show_time_picker(query, batch_key: str):
    """Show a grid of common posting times (EST) for scheduled Reels."""
    from datetime import datetime
    from zoneinfo import ZoneInfo
    tz = ZoneInfo("America/New_York")
    now = datetime.now(tz)
    now_str = now.strftime("%-I:%M %p")

    # Popular posting times (EST)
    time_slots = [
        ("9:00 AM",  "09", "00"),
        ("12:00 PM", "12", "00"),
        ("2:00 PM",  "14", "00"),
        ("5:00 PM",  "17", "00"),
        ("7:00 PM",  "19", "00"),
        ("9:00 PM",  "21", "00"),
    ]

    buttons = []
    row = []
    for label, hh, mm in time_slots:
        cb = f"igsched:tfreq:{hh}:{mm}:{batch_key}"
        row.append(InlineKeyboardButton(label, callback_data=cb))
        if len(row) == 3:
            buttons.append(row)
            row = []
    if row:
        buttons.append(row)
    buttons.append([InlineKeyboardButton("\u274c Back", callback_data=f"igsched:cancel:{batch_key}")])

    stems = _SOCIAL_BATCH_STEMS.get(batch_key, [])
    await query.edit_message_text(
        f"\U0001f552 *Pick a start time (EST)*\n"
        f"{'━' * 24}\n"
        f"Now: {now_str} EST\n"
        f"{len(stems)} reels queued\n\n"
        f"First Reel posts at the time you pick.\n"
        f"Then choose how often (daily / 12h).",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(buttons),
    )


async def _ig_show_freq_picker(query, rest: str):
    """After time is picked, ask for frequency (daily / 12h)."""
    # rest = "HH:MM:batchkey"
    parts = rest.split(":", 2)
    if len(parts) < 3:
        await query.edit_message_text("\u26a0\ufe0f Bad time data. Run /ig again.")
        return
    hh, mm, bk = parts
    from datetime import datetime
    from zoneinfo import ZoneInfo
    tz = ZoneInfo("America/New_York")
    now = datetime.now(tz)
    target = now.replace(hour=int(hh), minute=int(mm), second=0, microsecond=0)
    if target <= now:
        target = target + __import__("datetime").timedelta(days=1)
        day_label = "tomorrow"
    else:
        day_label = "today"
    time_label = target.strftime("%-I:%M %p EST")

    stems = _SOCIAL_BATCH_STEMS.get(bk, [])
    buttons = [
        [InlineKeyboardButton(
            "\U0001f4c5 1 per day",
            callback_data=f"igsched:tgo:1440:{hh}:{mm}:{bk}",
        ),
        InlineKeyboardButton(
            "\u23f0 Every 12h",
            callback_data=f"igsched:tgo:720:{hh}:{mm}:{bk}",
        )],
        [InlineKeyboardButton(
            "\u25c0 Change time",
            callback_data=f"igsched:picktime:{bk}",
        )],
    ]
    await query.edit_message_text(
        f"\U0001f552 *Starting at {time_label}* ({day_label})\n"
        f"{'━' * 24}\n"
        f"{len(stems)} reels queued\n\n"
        f"How often should Reels post?",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(buttons),
    )


async def _ig_show_picker(query, batch_key: str, page: int = 0):
    """Show paginated beat picker for Create Reel."""
    stems = _SOCIAL_BATCH_STEMS.get(batch_key, [])
    if not stems:
        await query.edit_message_text("\u26a0\ufe0f Session expired. Run /ig again.")
        return

    PAGE_SIZE = 8
    total_pages = (len(stems) + PAGE_SIZE - 1) // PAGE_SIZE
    page = max(0, min(page, total_pages - 1))
    page_stems = stems[page * PAGE_SIZE : (page + 1) * PAGE_SIZE]

    buttons = []
    for s in page_stems:
        title = s.replace("_", " ").title()
        # Truncate title for button (callback_data max 64 bytes)
        cb = f"igsched:one:{batch_key}:{s}"
        if len(cb.encode()) <= 64:
            buttons.append([InlineKeyboardButton(f"\U0001f3b5 {title}", callback_data=cb)])
        else:
            short_s = s[:20]
            buttons.append([InlineKeyboardButton(
                f"\U0001f3b5 {title[:25]}",
                callback_data=f"igsched:one:{batch_key}:{short_s}",
            )])

    # Navigation row
    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("\u25c0 Prev", callback_data=f"igsched:page{page-1}:{batch_key}"))
    nav.append(InlineKeyboardButton(f"{page+1}/{total_pages}", callback_data=f"igsched:page{page}:{batch_key}"))
    if page < total_pages - 1:
        nav.append(InlineKeyboardButton("Next \u25b6", callback_data=f"igsched:page{page+1}:{batch_key}"))
    buttons.append(nav)
    buttons.append([InlineKeyboardButton("\u274c Back", callback_data=f"igsched:cancel:{batch_key}")])

    await query.edit_message_text(
        f"\U0001f3ac *Create Reel — pick a beat*\n"
        f"{'━' * 24}\n"
        f"Page {page+1}/{total_pages}  \u00b7  {len(stems)} beats available",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(buttons),
    )


def _ig_bar(done: int, total: int, bar_len: int = 15) -> str:
    """Build a progress bar string with percentage: [████░░░░░░] 25%"""
    pct = int((done / total) * 100) if total else 0
    filled = int((done / total) * bar_len) if total else 0
    bar = "\u2588" * filled + "\u2591" * (bar_len - filled)
    return f"[{bar}] {pct}%"


async def _ig_show_preview(chat_id: int, queue_key: str, context):
    """Instant preview using thumbnail — NO conversion here (that happens on post)."""
    from social_upload import build_social_caption

    q = _IG_QUEUE.get(queue_key)
    if not q:
        return

    stems = q["stems"]
    idx = q["index"]
    total = len(stems)
    done = q["ok"] + q["fail"]

    if idx >= total:
        # ── All done ──
        await context.bot.send_message(
            chat_id,
            f"\U0001f3ac *Reels complete!*\n"
            f"{'━' * 24}\n"
            f"{_ig_bar(total, total)}\n\n"
            f"\u2705 {q['ok']} posted  \u00b7  \u274c {q['fail']} failed\n\n"
            f"\U0001f517 instagram.com/leekthatsfy3\n"
            f"\U0001f4c2 /reels to browse & download",
            parse_mode="Markdown",
        )
        _IG_QUEUE.pop(queue_key, None)
        return

    stem = stems[idx]
    beat_title = stem.replace("_", " ").title()

    # ── Build caption preview ──
    try:
        caption = build_social_caption(stem)
    except Exception:
        caption = f"{beat_title} \U0001f525\U0001f3b5"
    caption_preview = caption[:300] + ("..." if len(caption) > 300 else "")

    preview_text = (
        f"\U0001f3ac *New Reel*  \u2014  {idx + 1}/{total}\n"
        f"{'━' * 24}\n\n"
        f"\U0001f3b5 *{beat_title}*\n\n"
        f"\U0001f4dd {esc(caption_preview)}\n\n"
        f"{'━' * 24}\n"
        f"{_ig_bar(done, total)}\n"
        f"\u2705 {q['ok']}  \u00b7  \u274c {q['fail']}  \u00b7  "
        f"\u23f3 {total - idx} left"
    )

    buttons = [
        [
            InlineKeyboardButton("\U0001f199 Post now", callback_data=f"igrev:post:{queue_key}"),
            InlineKeyboardButton("\U0001f552 Schedule", callback_data=f"igrev:sched:{queue_key}"),
        ],
        [
            InlineKeyboardButton("\u23e9 Skip", callback_data=f"igrev:skip:{queue_key}"),
            InlineKeyboardButton("\U0001f6d1 Stop", callback_data=f"igrev:stop:{queue_key}"),
        ],
    ]

    # ── Send thumbnail preview (instant — no conversion needed) ──
    sent = False
    thumb = ROOT / "output" / f"{stem}_thumb.jpg"

    if thumb.exists():
        try:
            with open(thumb, "rb") as img:
                await context.bot.send_photo(
                    chat_id, img,
                    caption=preview_text,
                    parse_mode="Markdown",
                    reply_markup=InlineKeyboardMarkup(buttons),
                )
            sent = True
        except Exception as e:
            log.warning("Thumb preview send failed for %s: %s", stem, e)

    if not sent:
        await context.bot.send_message(
            chat_id, preview_text,
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(buttons),
        )


async def igrev_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle Reel preview approve/skip/stop. Bulletproof with timeouts."""
    query = update.callback_query
    try:
        await query.answer()
    except Exception:
        pass

    data = query.data  # igrev:{action}:{queue_key}  or  igrev:sat:HH:MM:{queue_key}
    parts = data.split(":", 2)
    if len(parts) < 3:
        log.warning("igrev_callback: malformed data=%s", data)
        return
    _, action, queue_key = parts

    # "sat" (schedule-at) has extra fields: igrev:sat:HH:MM:{queue_key}
    if action == "sat":
        sat_bits = queue_key.split(":", 2)  # "HH:MM:queue_key"
        if len(sat_bits) >= 3:
            queue_key = sat_bits[2]  # actual queue key

    log.info("igrev_callback: action=%s key=%s found=%s", action, queue_key, queue_key in _IG_QUEUE)

    q = _IG_QUEUE.get(queue_key)
    if not q:
        try:
            await query.edit_message_text(
                "⚠️ Session expired — run /ig again.",
            )
        except Exception:
            try:
                await query.edit_message_reply_markup(reply_markup=None)
            except Exception:
                pass
        return

    try:
        await _igrev_handle(query, action, queue_key, q, context)
    except Exception as e:
        log.error("igrev_callback CRASH: %s", e, exc_info=True)
        try:
            await context.bot.send_message(
                q.get("chat_id", query.message.chat_id),
                f"❌ *IG Reel error:* {esc(str(e)[:200])}\n\nRun /ig to retry.",
                parse_mode="Markdown",
            )
        except Exception:
            pass


async def _igrev_handle(query, action, queue_key, q, context):
    """Inner handler for igrev_callback — wrapped in try/except by caller."""
    stem = q["stems"][q["index"]]
    chat_id = q["chat_id"]
    total = len(q["stems"])
    beat_title = stem.replace("_", " ").title()

    # ── Stop ──
    if action == "stop":
        try:
            await query.edit_message_reply_markup(reply_markup=None)
        except Exception:
            pass
        remaining = total - q["index"]
        await context.bot.send_message(
            chat_id,
            f"\U0001f6d1 *Queue stopped*\n"
            f"{'━' * 24}\n"
            f"{_ig_bar(q['ok'] + q['fail'], total)}\n"
            f"\u2705 {q['ok']} shared  \u00b7  \u274c {q['fail']} failed  \u00b7  "
            f"\u23f3 {remaining} remaining\n\n"
            f"Run /ig to continue.",
            parse_mode="Markdown",
        )
        _IG_QUEUE.pop(queue_key, None)
        return

    # ── Skip ──
    if action == "skip":
        _cancel_pending_schedule(q, queue_key)
        try:
            await query.edit_message_reply_markup(reply_markup=None)
        except Exception:
            pass
        q["index"] += 1
        await _ig_show_preview(chat_id, queue_key, context)
        return

    # ── Cancel (during upload/wait) ──
    if action == "cancel":
        _cancel_pending_schedule(q, queue_key)
        try:
            await query.edit_message_reply_markup(reply_markup=None)
        except Exception:
            pass
        q["cancelled"] = True
        remaining = total - q["index"]
        await context.bot.send_message(
            chat_id,
            f"\U0001f6d1 *Cancelled*\n"
            f"{'━' * 24}\n"
            f"\u2705 {q['ok']} shared  \u00b7  \u274c {q['fail']} failed  \u00b7  "
            f"\u23f3 {remaining} skipped\n\n"
            f"Run /ig to continue.",
            parse_mode="Markdown",
        )
        _IG_QUEUE.pop(queue_key, None)
        _remove_schedule(queue_key)
        return

    # ── Schedule (show inline time picker) ──
    if action == "sched":
        from datetime import datetime
        from zoneinfo import ZoneInfo
        tz = ZoneInfo("America/New_York")
        now = datetime.now(tz)
        now_str = now.strftime("%-I:%M %p")
        time_slots = [
            ("9 AM",  "09", "00"), ("12 PM", "12", "00"),
            ("2 PM",  "14", "00"), ("5 PM",  "17", "00"),
            ("7 PM",  "19", "00"), ("9 PM",  "21", "00"),
        ]
        rows = []
        for i in range(0, len(time_slots), 3):
            row = []
            for label, hh, mm in time_slots[i:i+3]:
                # igrev:sat:HH:MM:{queue_key}  — "schedule at"
                row.append(InlineKeyboardButton(
                    label, callback_data=f"igrev:sat:{hh}:{mm}:{queue_key}",
                ))
            rows.append(row)
        rows.append([InlineKeyboardButton("\u2b05 Back", callback_data=f"igrev:back:{queue_key}")])
        try:
            await query.edit_message_reply_markup(
                reply_markup=InlineKeyboardMarkup(rows),
            )
        except Exception:
            pass
        return

    # ── Schedule at specific time ──
    if action == "sat":
        # data = igrev:sat:HH:MM:{queue_key}  — parse from full data string
        sat_parts = query.data.split(":", 5)
        if len(sat_parts) < 5:
            return
        _, _, hh, mm, qk = sat_parts[0], sat_parts[1], sat_parts[2], sat_parts[3], sat_parts[4]
        queue_key = qk  # override
        q = _IG_QUEUE.get(queue_key)
        if not q:
            try:
                await query.edit_message_text("\u26a0\ufe0f Session expired. Run /ig again.")
            except Exception:
                pass
            return

        from datetime import datetime, timedelta
        from zoneinfo import ZoneInfo
        tz = ZoneInfo("America/New_York")
        now = datetime.now(tz)
        target = now.replace(hour=int(hh), minute=int(mm), second=0, microsecond=0)
        if target <= now:
            target += timedelta(days=1)
        wait_secs = (target - now).total_seconds()
        target_str = target.strftime("%-I:%M %p EST")
        wait_hrs = int(wait_secs // 3600)
        wait_mins = int((wait_secs % 3600) // 60)
        wait_label = f"{wait_hrs}h {wait_mins}m" if wait_hrs else f"{wait_mins}m"
        stem_name = q["stems"][q["index"]].replace("_", " ").title()

        cancel_kb = InlineKeyboardMarkup([[
            InlineKeyboardButton("\u274c Cancel", callback_data=f"igrev:cancel:{queue_key}"),
        ]])
        try:
            await query.edit_message_text(
                f"\U0001f552 *Scheduled*\n"
                f"{'━' * 24}\n"
                f"\U0001f3b5 {stem_name}\n"
                f"\U0001f4c5 Posting at *{target_str}*  ({wait_label})\n\n"
                f"Waiting...",
                parse_mode="Markdown",
                reply_markup=cancel_kb,
            )
        except Exception:
            await context.bot.send_message(
                chat_id, f"\U0001f552 Scheduled: {stem_name} at {target_str}",
                reply_markup=cancel_kb,
            )

        # Persist single-post schedule to disk
        from datetime import timezone as _tz_mod2
        _add_schedule({
            "queue_key": queue_key, "platform": "ig", "type": "single",
            "stems": q["stems"], "index": q["index"], "ok": q["ok"], "fail": q["fail"],
            "delay_min": q["delay_min"], "chat_id": chat_id,
            "fire_at_utc": target.astimezone(_tz_mod2.utc).isoformat(),
        })

        # Offload wait + post to background task so bot stays responsive
        async def _sat_bg(_q=q, _qk=queue_key, _ws=wait_secs, _ctx=context, _cid=chat_id):
            _slept = 0
            while _slept < _ws:
                await asyncio.sleep(min(5, _ws - _slept))
                _slept += 5
                if _q.get("cancelled"):
                    _remove_schedule(_qk)
                    return
            _q.pop("scheduled", None)
            _q.pop("_sched_task", None)
            _remove_schedule(_qk)  # schedule fired
            await _ig_do_post(_qk, _q, _ctx)
        q["scheduled"] = True
        q["_sched_task"] = asyncio.create_task(_sat_bg())
        return

    # ── Back (from schedule picker → original preview) ──
    if action == "back":
        _cancel_pending_schedule(q, queue_key)
        try:
            await query.edit_message_reply_markup(reply_markup=None)
        except Exception:
            pass
        await _ig_show_preview(chat_id, queue_key, context)
        return

    # ── Post ──
    if action == "post":
        _cancel_pending_schedule(q, queue_key)
        try:
            await query.edit_message_reply_markup(reply_markup=None)
        except Exception:
            pass
        # Offload the entire post (convert + upload + delay) to a background
        # task so the callback returns immediately and the bot stays responsive.
        asyncio.create_task(_ig_do_post(queue_key, q, context))
        return


async def _ig_do_post(queue_key: str, q: dict, context):
    """Background task: convert → upload → delay → next preview. Non-blocking."""
    from social_upload import ig_upload, build_social_caption, convert_to_portrait

    chat_id = q["chat_id"]
    total = len(q["stems"])
    stem = q["stems"][q["index"]]
    beat_title = stem.replace("_", " ").title()

    # Handle delay between posts
    if q["delay_min"] > 0 and q["ok"] > 0:
        wait = q["delay_min"]
        hrs = wait // 60
        mins = wait % 60
        time_str = f"{hrs}h" if hrs and not mins else f"{mins}m" if not hrs else f"{hrs}h {mins}m"
        wait_msg = await context.bot.send_message(
            chat_id,
            f"\u23f0 *Next post in {time_str}*\n"
            f"{'━' * 24}\n"
            f"{_ig_bar(q['ok'] + q['fail'], total)}\n"
            f"\u2705 {q['ok']}/{total} posted so far",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton("\u274c Cancel", callback_data=f"igrev:cancel:{queue_key}"),
            ]]),
        )
        # Sleep in short chunks so cancel is responsive
        _wait_total = wait * 60
        _waited = 0
        while _waited < _wait_total:
            await asyncio.sleep(min(5, _wait_total - _waited))
            _waited += 5
            if q.get("cancelled"):
                log.info("igrev post: cancelled during delay (after %ds)", int(_waited))
                return
        try:
            await wait_msg.delete()
        except Exception:
            pass

    done = q["ok"] + q["fail"]

    # ── Phase 1: Convert to portrait ──
    portrait_path = ROOT / "output" / f"{stem}_9x16.mp4"
    need_convert = not portrait_path.exists()

    cancel_kb = InlineKeyboardMarkup([[
        InlineKeyboardButton("\u274c Cancel", callback_data=f"igrev:cancel:{queue_key}"),
    ]])

    if need_convert:
        progress_msg = await context.bot.send_message(
            chat_id,
            f"\U0001f504 *Converting to portrait...*\n"
            f"{'━' * 24}\n"
            f"\U0001f3b5 {beat_title}  ({done + 1}/{total})\n"
            f"[{'░' * 15}] 0%",
            parse_mode="Markdown",
            reply_markup=cancel_kb,
        )

        # Shared progress dict — updated by ffmpeg callback in executor thread
        conv_progress = {"pct": 0.0}
        spinner = ["\U0001f504", "\u23f3", "\U0001f4e1", "\u2699\ufe0f"]

        def _run_convert():
            def _on_pct(pct):
                conv_progress["pct"] = pct
            convert_to_portrait(stem, progress_cb=_on_pct)

        loop = asyncio.get_event_loop()
        convert_task = asyncio.ensure_future(
            loop.run_in_executor(None, _run_convert)
        )

        # Animate with REAL ffmpeg progress
        tick = 0
        last_pct = -1
        import time as _time
        t0 = _time.monotonic()
        while not convert_task.done():
            await asyncio.sleep(1.5)
            if convert_task.done() or q.get("cancelled"):
                break
            tick += 1
            pct = int(conv_progress["pct"])
            # Throttle edits: only when pct changes by ≥2, or every 4th tick
            if abs(pct - last_pct) < 2 and tick % 4 != 0:
                continue
            last_pct = pct
            bar_filled = int((pct / 100) * 15)
            bar = "\u2588" * bar_filled + "\u2591" * (15 - bar_filled)
            icon = spinner[tick % len(spinner)]
            elapsed = int(_time.monotonic() - t0)
            try:
                await progress_msg.edit_text(
                    f"{icon} *Converting to portrait...*\n"
                    f"{'━' * 24}\n"
                    f"\U0001f3b5 {beat_title}  ({done + 1}/{total})\n"
                    f"[{bar}] {pct}%  \u00b7  {elapsed}s",
                    parse_mode="Markdown",
                    reply_markup=cancel_kb,
                )
            except Exception:
                pass

        # Get conversion result
        try:
            convert_task.result()
        except Exception as e:
            log.error("Portrait conversion failed for %s: %s", stem, e)
            try:
                import subprocess as _sp
                _sp.run(["pkill", "-9", "-f", f"{stem}_9x16"],
                        capture_output=True, timeout=5)
            except Exception:
                pass
            if portrait_path.exists():
                try:
                    portrait_path.unlink()
                except Exception:
                    pass
            q["fail"] += 1
            try:
                await progress_msg.edit_text(
                    f"\u274c *Conversion failed:* {beat_title}\n"
                    f"{'━' * 24}\n"
                    f"{esc(str(e)[:200])}",
                    parse_mode="Markdown",
                )
            except Exception:
                pass
            if q.get("cancelled"):
                return
            q["index"] += 1
            await asyncio.sleep(1)
            await _ig_show_preview(chat_id, queue_key, context)
            return

        if q.get("cancelled"):
            try:
                import subprocess as _sp
                _sp.run(["pkill", "-9", "-f", f"{stem}_9x16"],
                        capture_output=True, timeout=5)
            except Exception:
                pass
            return

        # Show 100% before transitioning
        try:
            await progress_msg.edit_text(
                f"\u2705 *Converted!*\n"
                f"{'━' * 24}\n"
                f"\U0001f3b5 {beat_title}  ({done + 1}/{total})\n"
                f"[{'█' * 15}] 100%\n\n"
                f"\U0001f199 Now uploading to Reels...",
                parse_mode="Markdown",
                reply_markup=cancel_kb,
            )
        except Exception:
            pass
    else:
        # Already converted — go straight to upload
        cancel_kb = InlineKeyboardMarkup([[
            InlineKeyboardButton("\u274c Cancel", callback_data=f"igrev:cancel:{queue_key}"),
        ]])
        progress_msg = await context.bot.send_message(
            chat_id,
            f"\U0001f199 *Uploading to Reels...*\n"
            f"{'━' * 24}\n"
            f"\U0001f3b5 {beat_title}  ({done + 1}/{total})\n"
            f"{_ig_bar(done, total)}\n\n"
            f"\u2705 {q['ok']} shared  \u00b7  \u274c {q['fail']} failed",
            parse_mode="Markdown",
            reply_markup=cancel_kb,
        )

    # ── Phase 2: Upload to IG (with auto-retry + live progress) ──
    loop = asyncio.get_event_loop()
    max_upload_retries = 2  # 1 initial + 1 retry
    upload_timeout = 600   # 10 minutes per attempt
    upload_ok = False

    for upload_attempt in range(max_upload_retries):
        if q.get("cancelled"):
            return
        try:
            if upload_attempt > 0:
                retry_msg = f" (retry {upload_attempt}/{max_upload_retries - 1})"
                log.info("IG upload retry %d for %s", upload_attempt, stem)
                try:
                    await progress_msg.edit_text(
                        f"\U0001f504 *Retrying upload...*{retry_msg}\n"
                        f"{'━' * 24}\n"
                        f"\U0001f3b5 {beat_title}  ({done + 1}/{total})\n"
                        f"{_ig_bar(done, total)}",
                        parse_mode="Markdown",
                    )
                except Exception:
                    pass
                await asyncio.sleep(5)  # Brief pause before retry

            caption = build_social_caption(stem)
            # Shared progress dict — ig_upload updates this from executor thread
            _upload_progress = {"phase": "starting", "pct": 0, "detail": "Starting..."}
            import functools as _ft
            upload_task = asyncio.ensure_future(
                asyncio.wait_for(
                    loop.run_in_executor(
                        None, _ft.partial(ig_upload, stem, caption, progress=_upload_progress)
                    ),
                    timeout=upload_timeout,
                )
            )

            # Animate progress while upload runs
            _phase_icons = {
                "tunnel": "\U0001f310", "verifying": "\U0001f50d",
                "creating": "\U0001f4e6", "processing": "\u2699\ufe0f",
                "publishing": "\U0001f680", "done": "\u2705",
            }
            _last_text = ""
            _tick = 0
            _spinner = ["\u23f3", "\U0001f504", "\U0001f4e1", "\u2699\ufe0f"]
            import time as _time
            _t0 = _time.monotonic()
            while not upload_task.done():
                await asyncio.sleep(2)
                if upload_task.done() or q.get("cancelled"):
                    break
                _tick += 1
                phase = _upload_progress.get("phase", "?")
                pct = int(_upload_progress.get("pct", 0))
                detail = _upload_progress.get("detail", "")
                icon = _phase_icons.get(phase, _spinner[_tick % len(_spinner)])
                elapsed = int(_time.monotonic() - _t0)
                bar_filled = int((pct / 100) * 15)
                bar = "\u2588" * bar_filled + "\u2591" * (15 - bar_filled)
                new_text = (
                    f"{icon} *Uploading to Reels...*\n"
                    f"{'━' * 24}\n"
                    f"\U0001f3b5 {beat_title}  ({done + 1}/{total})\n"
                    f"[{bar}] {pct}%  \u00b7  {elapsed}s\n\n"
                    f"{detail}"
                )
                if new_text != _last_text:
                    try:
                        await progress_msg.edit_text(
                            new_text, parse_mode="Markdown",
                            reply_markup=cancel_kb,
                        )
                        _last_text = new_text
                    except Exception:
                        pass

            result = upload_task.result()
            if q.get("cancelled"):
                return
            if result.get("status") == "ok":
                q["ok"] += 1
                done = q["ok"] + q["fail"]
                try:
                    await progress_msg.edit_text(
                        f"\u2705 *Shared!*\n"
                        f"{'━' * 24}\n"
                        f"\U0001f3b5 {beat_title}\n"
                        f"{_ig_bar(done, total)}\n\n"
                        f"\u2705 {q['ok']} shared  \u00b7  \u274c {q['fail']} failed",
                        parse_mode="Markdown",
                    )
                except Exception:
                    pass
                upload_ok = True
                break  # Success — exit retry loop
            else:
                err_msg = result.get("error", "Upload failed")
                if upload_attempt < max_upload_retries - 1:
                    continue  # Retry
                q["fail"] += 1
                try:
                    await progress_msg.edit_text(
                        f"\u274c *Failed:* {beat_title}\n"
                        f"{'━' * 24}\n"
                        f"{esc(str(err_msg)[:200])}",
                        parse_mode="Markdown",
                    )
                except Exception:
                    pass
                break

        except asyncio.TimeoutError:
            log.error("IG upload TIMED OUT for %s (attempt %d)", stem, upload_attempt + 1)
            if upload_attempt < max_upload_retries - 1:
                continue  # Retry
            q["fail"] += 1
            try:
                await progress_msg.edit_text(
                    f"\u274c *Timed out:* {beat_title}\n"
                    f"{'━' * 24}\n"
                    f"Upload timed out after {max_upload_retries} attempts (10 min each).\n"
                    f"Try again later — IG servers may be slow.",
                    parse_mode="Markdown",
                )
            except Exception:
                pass
            break

        except Exception as e:
            err_str = str(e)
            log.error("IG upload failed for %s (attempt %d): %s", stem, upload_attempt + 1, e)

            # Token/auth errors should NOT be retried — they need user action
            is_auth_error = (
                "400" in err_str and ("token" in err_str.lower() or "IGAA" in err_str or "ig_setup" in err_str.lower())
            ) or "400" in err_str

            if not is_auth_error and upload_attempt < max_upload_retries - 1:
                continue  # Retry transient errors

            q["fail"] += 1
            if "token" in err_str.lower() or "IGAA" in err_str or "ig_setup" in err_str.lower():
                hint = "\n\n\U0001f511 Run /ig\\_setup to reconnect your IG account."
            elif "400" in err_str:
                hint = "\n\n\U0001f511 This may be a token issue — try /ig\\_setup"
            else:
                hint = ""
            try:
                await progress_msg.edit_text(
                    f"\u274c *Failed:* {beat_title}\n"
                    f"{'━' * 24}\n"
                    f"{esc(err_str[:200])}{hint}",
                    parse_mode="Markdown",
                )
            except Exception:
                pass
            break

    if q.get("cancelled"):
        return
    q["index"] += 1

    # Small delay to let user see result before next preview
    await asyncio.sleep(1.5)
    await _ig_show_preview(chat_id, queue_key, context)


# ── /reels — browse & download completed portrait reels ──────────────────────

async def cmd_reels(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Show completed portrait reels — tracking dashboard + downloads."""
    from pathlib import Path as _P
    reels_dir = _P(__file__).resolve().parent / "output"
    reel_files = sorted(reels_dir.glob("*_9x16.mp4"), key=lambda f: f.stat().st_mtime, reverse=True)

    # Load social log for upload status
    try:
        from social_upload import load_social_log
        slog = load_social_log()
    except Exception:
        slog = {}

    # Load clip map for visual info
    clip_map = _load_clip_map()

    # Count all rendered beats (not just reels)
    all_rendered = sorted(
        p.stem for p in reels_dir.glob("*.mp4")
        if not p.stem.endswith("_9x16") and not p.stem.endswith("_thumb")
    )

    # Count stats
    total_beats = len(all_rendered)
    converted = len(reel_files)
    uploaded_ig = sum(
        1 for s in all_rendered
        if s in slog and isinstance(slog[s], dict) and slog[s].get("instagram", {}).get("status") == "ok"
    )
    failed_ig = sum(
        1 for s in all_rendered
        if s in slog and isinstance(slog[s], dict) and slog[s].get("instagram") and slog[s]["instagram"].get("status") != "ok"
    )
    uploaded_tt = sum(
        1 for s in all_rendered
        if s in slog and isinstance(slog[s], dict) and isinstance(slog[s].get("tiktok"), dict) and slog[s]["tiktok"].get("status") == "ok"
    )

    if not reel_files:
        await update.message.reply_text(
            f"📂 *Reels Dashboard*\n"
            f"{'━' * 24}\n\n"
            f"🎵 {total_beats} beats rendered\n"
            f"📐 0 converted to portrait\n"
            f"✅ 0 uploaded to IG  ·  🔥 0 to TT\n\n"
            f"Run /ig or /tiktok to convert & upload.",
            parse_mode="Markdown",
        )
        return

    stems = []
    for f in reel_files:
        stem = f.stem.replace("_9x16", "")
        stems.append(stem)

    context.user_data["_reels_stems"] = stems
    context.user_data["_reels_slog"] = slog
    context.user_data["_reels_clip_map"] = clip_map
    await _reels_show_page(update.message.chat_id, 0, stems, slog, clip_map, context,
                           stats=(total_beats, converted, uploaded_ig, failed_ig, uploaded_tt))


async def _reels_show_page(chat_id: int, page: int, stems: list, slog: dict,
                           clip_map: dict, context, edit_msg=None, stats=None):
    """Show a page of completed reels with download buttons + tracking info."""
    PAGE_SIZE = 6
    total_pages = max(1, (len(stems) + PAGE_SIZE - 1) // PAGE_SIZE)
    page = max(0, min(page, total_pages - 1))
    page_stems = stems[page * PAGE_SIZE : (page + 1) * PAGE_SIZE]

    buttons = []
    for stem in page_stems:
        title = stem.replace("_", " ").title()
        ig_status = ""
        if stem in slog and "instagram" in slog[stem]:
            ig_info = slog[stem]["instagram"]
            if ig_info.get("status") == "ok":
                ig_status = " ✅"
            else:
                ig_status = " ❌"
        tt_status = ""
        if stem in slog and isinstance(slog[stem], dict) and slog[stem].get("tiktok"):
            tt_info = slog[stem]["tiktok"]
            if isinstance(tt_info, dict) and tt_info.get("status") == "ok":
                tt_status = " 🔥"
        # Show clip name if known
        clip = clip_map.get(stem, "")
        clip_tag = f" 🎬{clip.replace('.mp4','').replace('_',' ')}" if clip else ""
        label = f"📥 {title}{ig_status}{tt_status}"
        # Keep under 64 bytes for callback_data
        buttons.append([
            InlineKeyboardButton(label, callback_data=f"reels:dl:{stem}"),
        ])

    # Navigation row
    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("◀ Prev", callback_data=f"reels:pg:{page - 1}"))
    nav.append(InlineKeyboardButton(f"{page + 1}/{total_pages}", callback_data="reels:noop"))
    if page < total_pages - 1:
        nav.append(InlineKeyboardButton("Next ▶", callback_data=f"reels:pg:{page + 1}"))
    if nav:
        buttons.append(nav)

    # Build header with stats
    header_lines = [f"📂 *Reels Dashboard*  ({len(stems)} reels)"]
    if stats:
        if len(stats) == 5:
            total_beats, converted, uploaded_ig, failed_ig, uploaded_tt = stats
        else:
            total_beats, converted, uploaded_ig, failed_ig = stats
            uploaded_tt = 0
        header_lines.append(f"{'━' * 24}")
        header_lines.append(
            f"🎵 {total_beats} beats  ·  📐 {converted} portrait  ·  "
            f"✅ {uploaded_ig} IG  ·  🔥 {uploaded_tt} TT"
        )
        if failed_ig:
            header_lines[-1] += f"  ·  ❌ {failed_ig} failed"
    header_lines.append(f"{'━' * 24}")

    # Show clip info for this page
    page_info = []
    for stem in page_stems:
        title = stem.replace("_", " ").title()
        clip = clip_map.get(stem, "unknown")
        clip_short = clip.replace(".mp4", "").replace("_", " ")
        ig_icon = "✅" if (stem in slog and isinstance(slog.get(stem), dict) and
                          slog[stem].get("instagram", {}).get("status") == "ok") else "⏳"
        tt_icon = "🔥" if (stem in slog and isinstance(slog.get(stem), dict) and
                          isinstance(slog[stem].get("tiktok"), dict) and
                          slog[stem]["tiktok"].get("status") == "ok") else ""
        tt_tag = f" {tt_icon}" if tt_icon else ""
        page_info.append(f"{ig_icon}{tt_tag} {title} — _{clip_short}_")

    text = "\n".join(header_lines) + "\n\n" + "\n".join(page_info) + "\n"

    kb = InlineKeyboardMarkup(buttons)
    if edit_msg:
        try:
            await edit_msg.edit_text(text, parse_mode="Markdown", reply_markup=kb)
        except Exception:
            await context.bot.send_message(chat_id, text, parse_mode="Markdown", reply_markup=kb)
    else:
        await context.bot.send_message(chat_id, text, parse_mode="Markdown", reply_markup=kb)


async def reels_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle /reels download and pagination buttons."""
    query = update.callback_query
    try:
        await query.answer()
    except Exception:
        pass

    data = query.data  # reels:{action}:{value}
    parts = data.split(":", 2)
    if len(parts) < 3:
        return
    _, action, value = parts

    if action == "noop":
        return

    if action == "pg":
        # Page navigation
        try:
            page = int(value)
        except ValueError:
            return
        stems = context.user_data.get("_reels_stems", [])
        slog = context.user_data.get("_reels_slog", {})
        clip_map = context.user_data.get("_reels_clip_map", {})
        if not stems:
            await query.edit_message_text("⚠️ Session expired — run /reels again.")
            return
        await _reels_show_page(query.message.chat_id, page, stems, slog, clip_map, context, edit_msg=query.message)
        return

    if action == "dl":
        # Download a reel
        stem = value
        from pathlib import Path as _P
        reel_path = _P(__file__).resolve().parent / "output" / f"{stem}_9x16.mp4"
        if not reel_path.exists():
            await query.edit_message_text(f"⚠️ File not found: `{stem}_9x16.mp4`", parse_mode="Markdown")
            return

        title = stem.replace("_", " ").title()
        size_mb = reel_path.stat().st_size / (1024 * 1024)

        # Check upload status
        slog = context.user_data.get("_reels_slog", {})
        status_line = ""
        if stem in slog and "instagram" in slog[stem]:
            ig = slog[stem]["instagram"]
            if ig.get("status") == "ok":
                uploaded_at = ig.get("uploadedAt", "unknown")
                status_line = f"\n✅ Posted to IG · {uploaded_at[:10]}"
            else:
                status_line = f"\n❌ IG upload failed"

        # Show which visual clip was used
        clip_map = context.user_data.get("_reels_clip_map", {})
        clip_name = clip_map.get(stem, "unknown")
        clip_short = clip_name.replace(".mp4", "").replace("_", " ")

        caption = f"🎬 *{title}*\n📐 1080×1920 (portrait)\n💾 {size_mb:.1f} MB\n🎥 Clip: {clip_short}{status_line}"

        try:
            with open(reel_path, "rb") as f:
                await context.bot.send_document(
                    query.message.chat_id, f,
                    filename=f"{stem}_9x16.mp4",
                    caption=caption,
                    parse_mode="Markdown",
                )
        except Exception as e:
            log.error("Failed to send reel %s: %s", stem, e)
            await context.bot.send_message(
                query.message.chat_id,
                f"❌ Failed to send: {esc(str(e)[:200])}",
                parse_mode="Markdown",
            )


