async def cmd_ytdelete(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/ytdelete — delete the old duplicate YouTube videos (quota-aware)."""
    if not is_allowed(update):
        return await deny(update)

    if not _YT_DELETE_QUEUE:
        await update.message.reply_text("\u2705 All duplicate videos already deleted! Queue is empty.")
        return

    remaining = len(_YT_DELETE_QUEUE)
    await update.message.reply_text(
        f"\U0001f5d1 *Deleting {remaining} duplicate videos from YouTube...*\n"
        "Will stop on quota errors and you can re-run tomorrow.",
        parse_mode="Markdown",
    )

    loop = asyncio.get_event_loop()
    deleted = []
    quota_hit = False

    def _do_deletes():
        nonlocal quota_hit
        from youtube_auth import get_youtube_service
        youtube = get_youtube_service()
        to_remove = []
        for stem, vid in list(_YT_DELETE_QUEUE.items()):
            try:
                youtube.videos().delete(id=vid).execute()
                to_remove.append(stem)
            except Exception as e:
                err_str = str(e)
                if "quota" in err_str.lower():
                    quota_hit = True
                    break
                else:
                    # Non-quota error (maybe already deleted) — remove from queue
                    to_remove.append(stem)
        return to_remove

    removed = await loop.run_in_executor(None, _do_deletes)
    for stem in removed:
        _YT_DELETE_QUEUE.pop(stem, None)
        deleted.append(stem)

    remaining_now = len(_YT_DELETE_QUEUE)
    lines = [f"\U0001f5d1 *YouTube delete results:*\n"]
    lines.append(f"\u2705 Deleted: {len(deleted)}")
    if quota_hit:
        lines.append(f"\u26a0\ufe0f Quota hit — {remaining_now} remaining")
        lines.append("_Run /ytdelete again tomorrow after quota resets (midnight PT)._")
    elif remaining_now == 0:
        lines.append("\U0001f389 All duplicate videos deleted!")
    else:
        lines.append(f"\u23f3 Remaining: {remaining_now}")

    await update.message.reply_text("\n".join(lines), parse_mode="Markdown")


async def cmd_hardreset(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/hardreset — nuke ALL session state. Unsticks the bot from any stuck flow."""
    if not is_allowed(update):
        return await deny(update)

    cleared = []

    # 1. Clear all upload flow sessions (memory + disk)
    upl_sessions = context.bot_data.get("_upload_flow_sessions", {})
    if upl_sessions:
        cleared.append(f"Upload sessions: {len(upl_sessions)}")
        upl_sessions.clear()
    _save_sessions({})

    # 2. Clear all render sessions
    render_sessions = context.bot_data.get("_render_sessions", {})
    if render_sessions:
        cleared.append(f"Render sessions: {len(render_sessions)}")
        render_sessions.clear()

    # 3. Clear user_data intercept keys that cause stuck text routing
    stuck_keys = [
        "_title_edit", "_uplmeta_edit", "_perbeat_custom", "_perbeat_active",
        "_sched_upload_key", "_clip_folder_key",
    ]
    for key in stuck_keys:
        if context.user_data.get(key):
            cleared.append(f"Stuck intercept: {key}")
            context.user_data.pop(key, None)

    # 4. Kill any background tasks (stuck renders/uploads)
    bg_tasks = context.bot_data.get("_bg_tasks", set())
    if bg_tasks:
        killed = 0
        for task in list(bg_tasks):
            if not task.done():
                task.cancel()
                killed += 1
        if killed:
            cleared.append(f"Background tasks killed: {killed}")
        bg_tasks.clear()

    # 5. Kill any lingering ffmpeg processes
    try:
        result = subprocess.run(["pkill", "-f", "ffmpeg"], capture_output=True, timeout=5)
        if result.returncode == 0:
            cleared.append("Killed lingering ffmpeg")
    except Exception:
        pass

    # 6. Clean up temp thumbnail option files
    try:
        thumb_opts = list((ROOT / "output").glob("*_thumbopt_*.jpg"))
        for opt_file in thumb_opts:
            opt_file.unlink()
        if thumb_opts:
            cleared.append(f"Cleaned {len(thumb_opts)} temp thumbnail files")
    except Exception:
        pass

    # 7. Clear disk session file
    try:
        _SESSIONS_FILE.write_text("{}")
    except Exception:
        pass

    if cleared:
        summary = "\n".join(f"  ✅ {c}" for c in cleared)
        await update.message.reply_text(
            f"🔨 *Hard Reset Complete*\n\n{summary}\n\n"
            "Bot is clean. Use /upload or /batch to start fresh.",
            parse_mode="Markdown",
        )
    else:
        await update.message.reply_text(
            "🔨 *Hard Reset*\n\nNothing was stuck — bot is already clean.\n"
            "Use /upload or /batch to start fresh.",
            parse_mode="Markdown",
        )


async def cmd_logs(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/logs [N] — tail the last N lines of bot.log (default 30, max 100)."""
    if not is_allowed(update):
        return await deny(update)
    n = 30
    if context.args and context.args[0].isdigit():
        n = min(int(context.args[0]), 100)
    log_path = ROOT / "logs" / "bot.log"
    if not log_path.exists():
        await update.message.reply_text("❌ `logs/bot.log` not found.", parse_mode="Markdown")
        return
    with open(log_path) as _lf:
        tail_lines = _lf.readlines()[-n:]
    tail = "".join(tail_lines).strip()
    if len(tail) > 3800:
        tail = "…(truncated)\n" + tail[-3800:]
    await update.message.reply_text(f"```\n{tail or '(empty log)'}\n```", parse_mode="Markdown")


# ── /access — emergency access command, always shows how to get back in ──────

async def cmd_access(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/access — emergency: always shows TeamViewer ID + password so you never get locked out."""
    if not is_allowed(update):
        return await deny(update)
    # Read live TeamViewer session password
    try:
        proc = await asyncio.create_subprocess_shell(
            """osascript -e 'tell application "System Events" to tell process "TeamViewer" to tell window "TeamViewer" to value of every static text' 2>/dev/null""",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE
        )
        out, _ = await asyncio.wait_for(proc.communicate(), timeout=5)
        raw = out.decode().strip()
        import re as _re2
        m = _re2.search(r'\b([a-z0-9]{8})\b', raw)
        session_pw = m.group(1) if m else "restart TeamViewer to get one"
    except Exception:
        session_pw = "open TeamViewer app to see"

    tv_running = bool((await (await asyncio.create_subprocess_shell(
        "pgrep -x TeamViewer", stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE
    )).communicate())[0].decode().strip())

    status = "✅ Running" if tv_running else "❌ Not running — tap Start below"
    await update.message.reply_text(
        "🔐 *Emergency Access Info*\n"
        "━━━━━━━━━━━━━━━━━━━━━\n\n"
        f"*TeamViewer:* {status}\n"
        f"📋 *ID:* `1033911308`\n"
        f"🔑 *Session pw:* `{session_pw}` _(changes on restart)_\n"
        f"🔒 *Permanent pw:* `fyehize1` _(always works)_\n\n"
        "*Bot:* ✅ Running _(you sent this command so it's alive)_\n\n"
        "━━━━━━━━━━━━━━━━━━━━━\n"
        "💡 *Never lose access:*\n"
        "• TeamViewer ID never changes\n"
        "• Permanent pw `fyehize1` always works\n"
        "• Bot auto-restarts via LaunchAgent\n"
        "• Mac never sleeps (caffeinate running)\n",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup([
            [InlineKeyboardButton("🔵 Start TeamViewer", callback_data="remote:start_tv"),
             InlineKeyboardButton("📡 Full Remote Panel", callback_data="remote:refresh")],
        ])
    )


# ── /remote — remote view & control status panel ─────────────────────────────

async def cmd_remote(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/remote — show remote access status + controls. Apple Screen Sharing recommended for FL Studio."""
    if not is_allowed(update):
        return await deny(update)

    msg = await update.message.reply_text("🔍 Checking remote access status…")

    lines = ["📡 *Remote Access Panel*", "━━━━━━━━━━━━━━━━━━━━━"]

    # ── VNC / Screen Sharing ──────────────────────────────────────────────────
    vnc_ok = False
    try:
        proc = await asyncio.create_subprocess_shell(
            "launchctl list com.apple.screensharing 2>/dev/null | grep PID",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE
        )
        out, _ = await asyncio.wait_for(proc.communicate(), timeout=5)
        vnc_pid = out.decode().strip()
        if '"PID"' in vnc_pid or "PID" in vnc_pid:
            lines.append("🖥 *Apple Screen Sharing:* ✅ Running  `port 5900`")
            vnc_ok = True
        else:
            lines.append("🖥 *Apple Screen Sharing:* ⚠️ Not active — tap Enable below")
    except Exception:
        try:
            proc2 = await asyncio.create_subprocess_shell(
                "netstat -an | grep '*.5900' | grep LISTEN | head -1",
                stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE
            )
            out2, _ = await asyncio.wait_for(proc2.communicate(), timeout=5)
            if out2.decode().strip():
                lines.append("🖥 *Apple Screen Sharing:* ✅ Listening on `5900`")
                vnc_ok = True
            else:
                lines.append("🖥 *Apple Screen Sharing:* ❌ Not listening")
        except Exception:
            lines.append("🖥 *Apple Screen Sharing:* ❓ Unknown")

    # ── Screens Connect (openclaw gateway) ───────────────────────────────────
    try:
        proc = await asyncio.create_subprocess_shell(
            "launchctl list ai.openclaw.gateway 2>/dev/null | grep -E 'PID|ExitStatus'",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE
        )
        out, _ = await asyncio.wait_for(proc.communicate(), timeout=5)
        gw_info = out.decode().strip()
        if '"PID"' in gw_info:
            pid_part = [l for l in gw_info.splitlines() if "PID" in l]
            pid_val  = pid_part[0].split("=")[-1].strip().rstrip(";").strip() if pid_part else "?"
            lines.append(f"📱 *Screens Connect:* ✅ Running  `PID {pid_val}`")
        else:
            lines.append("📱 *Screens Connect:* ⚠️ Not running — restart with Fix button")
    except Exception:
        lines.append("📱 *Screens Connect:* ❓ Unknown")

    # ── Network ───────────────────────────────────────────────────────────────
    try:
        lan_proc = await asyncio.create_subprocess_shell(
            "ipconfig getifaddr en0 2>/dev/null || ipconfig getifaddr en1 2>/dev/null",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE
        )
        lan_out, _ = await asyncio.wait_for(lan_proc.communicate(), timeout=5)
        lan_ip = lan_out.decode().strip() or "Unknown"
    except Exception:
        lan_ip = "Unknown"

    try:
        wan_proc = await asyncio.create_subprocess_shell(
            "curl -s --max-time 5 https://api.ipify.org",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE
        )
        wan_out, _ = await asyncio.wait_for(wan_proc.communicate(), timeout=8)
        wan_ip = wan_out.decode().strip() or "Unknown"
    except Exception:
        wan_ip = "Unknown"

    lines.append(f"🏠 *LAN IP:* `{lan_ip}`  _(same WiFi)_")
    lines.append(f"🌐 *WAN IP:* `{wan_ip}`  _(outside network)_")

    # ── TeamViewer ────────────────────────────────────────────────────────────
    tv_running = False
    try:
        proc = await asyncio.create_subprocess_shell(
            "pgrep -x TeamViewer 2>/dev/null | head -1",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE
        )
        out, _ = await asyncio.wait_for(proc.communicate(), timeout=5)
        tv_pid = out.decode().strip()
        tv_id_proc = await asyncio.create_subprocess_shell(
            "defaults read com.teamviewer.teamviewer.preferences.Machine ClientID 2>/dev/null",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE
        )
        tv_id_out, _ = await asyncio.wait_for(tv_id_proc.communicate(), timeout=5)
        tv_client_id = tv_id_out.decode().strip() or "1033911308"
        tv_pass_proc = await asyncio.create_subprocess_shell(
            """osascript -e 'tell application "System Events" to tell process "TeamViewer" to tell window "TeamViewer" to value of every static text' 2>/dev/null""",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE
        )
        tv_pass_out, _ = await asyncio.wait_for(tv_pass_proc.communicate(), timeout=5)
        tv_pass_raw = tv_pass_out.decode().strip()
        import re as _re
        tv_pass_match = _re.search(r'\b([a-z0-9]{8})\b', tv_pass_raw)
        tv_session_pass = tv_pass_match.group(1) if tv_pass_match else "see TeamViewer app"
        if tv_pid:
            tv_running = True
            lines.append(f"🔵 *TeamViewer:* ⚠️ Running  `PID {tv_pid}`")
            lines.append(f"   📋 *ID:* `{tv_client_id}`")
            lines.append(f"   🔑 *Session pw:* `{tv_session_pass}` _(changes on restart)_")
            lines.append(f"   🔒 *Permanent pw:* `fyehize1` _(always works)_")
            if vnc_ok:
                lines.append("   ⚠️ _TeamViewer may crash FL Studio — tap Stop below_")
        else:
            lines.append("🔵 *TeamViewer:* ⬜ Not running")
            lines.append(f"   📋 *ID:* `{tv_client_id}`  |  🔒 *Permanent pw:* `fyehize1`")
    except Exception as e:
        lines.append(f"🔵 *TeamViewer:* ❓ Unknown ({e})")
        lines.append(f"   📋 *ID:* `1033911308`  |  🔒 *Permanent pw:* `fyehize1`")

    # ── SSH ───────────────────────────────────────────────────────────────────
    try:
        proc = await asyncio.create_subprocess_shell(
            "launchctl list com.openssh.sshd 2>/dev/null | grep PID | head -1",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE
        )
        out, _ = await asyncio.wait_for(proc.communicate(), timeout=5)
        ssh_info = out.decode().strip()
        if "PID" in ssh_info:
            lines.append("🔑 *SSH:* ✅ Enabled")
        else:
            lines.append("🔑 *SSH:* ⬜ Disabled  _(enable via System Settings → General → Sharing)_")
    except Exception:
        lines.append("🔑 *SSH:* ❓ Unknown")

    # ── Audio Routing ────────────────────────────────────────────────────────
    try:
        audio_proc = await asyncio.create_subprocess_shell(
            "SwitchAudioSource -c -t output 2>/dev/null",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE
        )
        audio_out, _ = await asyncio.wait_for(audio_proc.communicate(), timeout=5)
        current_audio = audio_out.decode().strip() or "Unknown"
    except Exception:
        current_audio = "Unknown"

    lines.append("")
    lines.append("━━━━━━━━━━━━━━━━━━━━━")
    lines.append("🔊 *Audio Output*")
    if "TeamViewer" in current_audio:
        lines.append(f"🎧 `{current_audio}` ✅")
        lines.append("   _Volt 1 + TeamViewer stream → audio on iPhone_")
    elif "FL + MONITOR" in current_audio:
        lines.append(f"🎧 `{current_audio}`")
        lines.append("   _ScreenCaptureKit streams all system audio_")
    elif "Volt 1" in current_audio:
        lines.append(f"🎧 `{current_audio}` ⚠️")
        lines.append("   _Local only — no remote audio! Tap a mode below_")
    else:
        lines.append(f"🎧 `{current_audio}`")

    # ── Connection guide ──────────────────────────────────────────────────────
    lines += [
        "",
        "━━━━━━━━━━━━━━━━━━━━━",
        "🍎 *Apple Screen Sharing (best for FL Studio):*",
        "No extra drivers — won't crash FL Studio!",
        f"1. Get *Screens 5* or *RealVNC Viewer* on iPhone",
        f"2. Same WiFi → connect to `{lan_ip}:5900`",
        f"3. Any network → use Screens Connect (auto-discovers)",
        "",
        "📱 *Screens app (recommended):*",
        "Open Screens → your Mac appears under Screens Connect",
        "_If it doesn't show: tap Fix Screens Connect below_",
        "",
        "🔵 *TeamViewer (backup — may crash FL Studio):*",
        "Works from anywhere, but its display driver conflicts",
        "with FL Studio's GPU rendering. Stop it when making beats.",
    ]

    # ── Buttons ───────────────────────────────────────────────────────────────
    row1 = [
        InlineKeyboardButton("🔄 Refresh", callback_data="remote:refresh"),
        InlineKeyboardButton("🖥 Enable Screen Sharing", callback_data="remote:enable_vnc"),
    ]
    row2 = [
        InlineKeyboardButton("🔧 Fix Screens Connect", callback_data="remote:fix_screens"),
        InlineKeyboardButton("📋 Connection Info", callback_data="remote:conninfo"),
    ]
    # TeamViewer row: show Start or Stop depending on state
    if tv_running:
        row3 = [
            InlineKeyboardButton("🛑 Stop TeamViewer", callback_data="remote:stop_tv"),
            InlineKeyboardButton("🎹 FL Studio Mode", callback_data="remote:flstudio_mode"),
        ]
    else:
        row3 = [
            InlineKeyboardButton("🔵 Start TeamViewer", callback_data="remote:start_tv"),
            InlineKeyboardButton("🎹 FL Studio Mode", callback_data="remote:flstudio_mode"),
        ]
    # Audio row
    row_audio = [
        InlineKeyboardButton("🔊 TeamViewer Audio", callback_data="remote:audio_tv"),
        InlineKeyboardButton("🔇 Volt 1 Only", callback_data="remote:audio_volt"),
    ]
    row4 = [
        InlineKeyboardButton("🔑 Enable SSH", callback_data="remote:enable_ssh"),
        InlineKeyboardButton("🔒 Lock Screen", callback_data="remote:lock"),
    ]
    row5 = [
        InlineKeyboardButton("💤 Sleep Display", callback_data="remote:sleep_display"),
    ]

    kb = InlineKeyboardMarkup([row1, row2, row3, row_audio, row4, row5])
    await safe_edit(msg, "\n".join(lines), parse_mode="Markdown", reply_markup=kb)


async def remote_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle /remote inline button taps."""
    query = update.callback_query
    if not is_allowed(update):
        await query.answer("Not authorized.", show_alert=True)
        return
    await query.answer()
    action = query.data.split(":", 1)[1]

    async def _run(cmd, timeout=10):
        proc = await asyncio.create_subprocess_shell(
            cmd,
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.STDOUT,
            env={**os.environ, "PATH": "/opt/homebrew/bin:/usr/local/bin:/usr/bin:/bin:" + os.environ.get("PATH", "")},
        )
        try:
            out, _ = await asyncio.wait_for(proc.communicate(), timeout=timeout)
            return out.decode("utf-8", errors="replace").strip(), proc.returncode
        except asyncio.TimeoutError:
            try: proc.kill()
            except Exception: pass
            return "(timed out)", -1

    if action == "refresh":
        # Re-run cmd_remote logic inline
        await safe_edit(query.message, "🔄 Refreshing…")
        # Fake the update to reuse cmd_remote
        context.args = []
        await cmd_remote(update, context)
        return

    if action == "enable_vnc":
        out, rc = await _run("sudo /bin/launchctl load -w /System/Library/LaunchDaemons/com.apple.screensharing.plist 2>&1 || echo 'Try: System Settings → General → Sharing → Screen Sharing'")
        await query.message.reply_text(
            f"🖥 *Screen Sharing Enable:*\n```\n{out[:500] or 'Done'}\n```\n"
            "_If this fails, enable manually: System Settings → General → Sharing → Screen Sharing_",
            parse_mode="Markdown"
        )
        return

    if action == "fix_screens":
        # Restart the openclaw/Screens Connect gateway
        out, rc = await _run(
            "launchctl unload ~/Library/LaunchAgents/ai.openclaw.gateway.plist 2>&1; "
            "sleep 2; "
            "launchctl load ~/Library/LaunchAgents/ai.openclaw.gateway.plist 2>&1",
            timeout=15
        )
        pid_out, _ = await _run("launchctl list ai.openclaw.gateway 2>/dev/null | grep PID")
        running = "PID" in pid_out
        await query.message.reply_text(
            f"🔧 *Screens Connect Restarted*\n"
            f"Status: {'✅ Running' if running else '⚠️ Not confirmed running'}\n"
            f"```\n{out[:300] or 'Done'}\n```\n"
            "_Now open Screens app — your Mac should appear within 30 seconds._",
            parse_mode="Markdown"
        )
        return

    if action == "start_tv":
        out, rc = await _run("open -a TeamViewer 2>&1", timeout=5)
        await query.message.reply_text(
            "🔵 *TeamViewer launched!*\n"
            "Open TeamViewer on your phone and connect using your ID + password.\n\n"
            "⚠️ _Remember: quit TeamViewer before opening FL Studio to avoid crashes._",
            parse_mode="Markdown"
        )
        return

    if action == "stop_tv":
        out, rc = await _run("pkill -x TeamViewer 2>&1; sleep 1; pgrep -x TeamViewer || echo 'STOPPED'", timeout=8)
        stopped = "STOPPED" in out or rc != 0
        if stopped:
            await query.message.reply_text(
                "🛑 *TeamViewer stopped!*\n\n"
                "FL Studio is safe to use now.\n"
                "Use *Apple Screen Sharing* to control your Mac:\n"
                "Open Screens app on your iPhone → connect to your Mac",
                parse_mode="Markdown"
            )
        else:
            await query.message.reply_text(
                "⚠️ TeamViewer may still be running. Try force-quitting from Activity Monitor.",
                parse_mode="Markdown"
            )
        return

    if action == "flstudio_mode":
        # One-tap: anti-crash TeamViewer + audio stream to iPhone
        steps = []

        # Step 1: Apply TeamViewer anti-crash settings (software rendering)
        tv_fixes = [
            'defaults write com.teamviewer.TeamViewer HardwareAcceleration -bool false',
            'defaults write com.teamviewer.TeamViewer ScreenCapturingType -int 0',
            'defaults write com.teamviewer.TeamViewer ColorDepth -int 1',
            'defaults write com.teamviewer.TeamViewer DisableAutoOptimization -bool true',
            'defaults write com.teamviewer.TeamViewer RemoteAudioEnabled -bool true',
            'defaults write com.teamviewer.teamviewer.preferences MultiMedia -dict-add AudioSendingVolumeV2 -string "1.00"',
        ]
        for fix in tv_fixes:
            await _run(fix)
        steps.append("🛡 Anti-crash: ✅ TeamViewer GPU off, software mode")

        # Step 2: Restart TeamViewer with safe settings
        tv_check, _ = await _run("pgrep -x TeamViewer | head -1")
        if tv_check.strip():
            await _run("pkill -x TeamViewer 2>&1", timeout=5)
            await asyncio.sleep(2)
        await _run("open -a TeamViewer 2>&1", timeout=5)
        await asyncio.sleep(2)
        tv_recheck, _ = await _run("pgrep -x TeamViewer | head -1")
        if tv_recheck.strip():
            steps.append("🔵 TeamViewer: ✅ Running (safe mode)")
        else:
            steps.append("🔵 TeamViewer: ⚠️ Could not start")

        # Step 3: Audio capture via ScreenCaptureKit (captures ALL system audio)
        audio_out, _ = await _run("SwitchAudioSource -c -t output")
        steps.append(f"🔊 Output: ✅ `{audio_out.strip()}` (SCK captures all)")

        # Step 4: Start ffmpeg audio stream (iPhone opens URL to hear audio)
        await _run(str(ROOT / "audio_stream.sh") + " stop", timeout=5)
        stream_out, _ = await _run(str(ROOT / "audio_stream.sh") + " start", timeout=8)
        stream_url = ""
        for ln in stream_out.splitlines():
            if ln.startswith("URL="):
                stream_url = ln.split("=", 1)[1]
        if "STARTED" in stream_out and stream_url:
            steps.append(f"🎧 Audio stream: ✅ Live!")
        elif "STARTED" in stream_out:
            steps.append("🎧 Audio stream: ✅ Started")
        else:
            steps.append("🎧 Audio stream: ⚠️ Check /logs")

        # Step 5: Get LAN IP
        lan_out, _ = await _run("ipconfig getifaddr en0 2>/dev/null || ipconfig getifaddr en1 2>/dev/null")
        lan_ip = lan_out.strip() or "your-mac-ip"
        if not stream_url:
            stream_url = f"http://{lan_ip}:8888/"

        await query.message.reply_text(
            "🎹 *FL Studio Mode — Activated!*\n"
            "━━━━━━━━━━━━━━━━━━━━━\n\n" +
            "\n".join(steps) + "\n\n"
            "━━━━━━━━━━━━━━━━━━━━━\n"
            "✅ *You're good to make beats!*\n\n"
            "🎹 *In FL Studio:*\n"
            "Audio device → `FL + MONITOR` or `Primary Sound Driver`\n\n"
            "📱 *Connect via TeamViewer as usual*\n"
            "GPU is off = no crashes!\n\n"
            "🎧 Tap the button below to hear audio on your iPhone:",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([
                [InlineKeyboardButton("🎧 Listen on iPhone (tap here)", url=stream_url)],
                [InlineKeyboardButton("🛑 Stop Audio Stream", callback_data="remote:stop_stream"),
                 InlineKeyboardButton("🔄 Refresh", callback_data="remote:refresh")],
            ])
        )
        return

    if action == "enable_ssh":
        out, rc = await _run("sudo systemsetup -setremotelogin on 2>&1", timeout=10)
        await query.message.reply_text(
            f"🔑 *SSH Enable:*\n```\n{out[:400] or 'Done'}\n```\n"
            "_Connect via: `ssh fyefye@<LAN IP>` on your local network_",
            parse_mode="Markdown"
        )
        return

    if action == "conninfo":
        lan_out, _ = await _run("ipconfig getifaddr en0 2>/dev/null || ipconfig getifaddr en1 2>/dev/null")
        wan_out, _ = await _run("curl -s --max-time 5 https://api.ipify.org")
        hostname_out, _ = await _run("hostname")
        wifi_out, _ = await _run("networksetup -getairportnetwork en0 2>/dev/null | head -1")
        lines = [
            "📋 *Connection Info*",
            "━━━━━━━━━━━━━━━━━━━━━",
            f"🏠 LAN IP:   `{lan_out or 'N/A'}`",
            f"🌐 WAN IP:   `{wan_out or 'N/A'}`",
            f"💻 Hostname: `{hostname_out or 'N/A'}`",
            f"📶 WiFi:     `{wifi_out or 'N/A'}`",
            "",
            "*Screens app (same network):*",
            f"`{lan_out or 'LAN_IP'}` — port 5900",
            "",
            "*Screens Connect (any network):*",
            "Your Mac should appear automatically in the Screens app.",
            "If not: tap 🔧 Fix Screens Connect above.",
        ]
        await query.message.reply_text("\n".join(lines), parse_mode="Markdown")
        return

    if action == "lock":
        out, rc = await _run(
            "osascript -e 'tell application \"System Events\" to keystroke \"q\" using {command down, control down}' 2>&1 || "
            "/System/Library/CoreServices/Menu\\ Extras/User.menu/Contents/Resources/CGSession -suspend 2>&1"
        )
        await query.message.reply_text("🔒 *Screen locked!*", parse_mode="Markdown")
        return

    if action == "sleep_display":
        out, rc = await _run("pmset displaysleepnow 2>&1 || caffeinate -u -t 1 2>&1")
        await query.message.reply_text("💤 *Display sleep triggered.*", parse_mode="Markdown")
        return

    if action == "audio_tv":
        # Start audio stream (ScreenCaptureKit captures all system audio)
        stream_out, _ = await _run(str(ROOT / "audio_stream.sh") + " start", timeout=8)
        lan_out, _ = await _run("ipconfig getifaddr en0 2>/dev/null || ipconfig getifaddr en1 2>/dev/null")
        lan_ip = lan_out.strip() or "your-mac-ip"
        stream_url = f"http://{lan_ip}:8888/"
        for ln in stream_out.splitlines():
            if ln.startswith("URL="):
                stream_url = ln.split("=", 1)[1]
        await query.message.reply_text(
            "🔊 *Audio Stream → iPhone*\n\n"
            "Capture: `ScreenCaptureKit` (all system audio)\n"
            "Stream: ✅ Live\n\n"
            "🎧 Tap below to listen:",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([
                [InlineKeyboardButton("🎧 Listen on iPhone", url=stream_url)],
                [InlineKeyboardButton("🛑 Stop Stream", callback_data="remote:stop_stream")],
            ])
        )
        return

    if action == "stop_stream":
        await _run(str(ROOT / "audio_stream.sh") + " stop", timeout=5)
        await query.message.reply_text(
            "🛑 *Audio stream stopped.*",
            parse_mode="Markdown"
        )
        return

    if action == "audio_volt":
        # Switch output to Volt 1 only (local, no remote audio) + stop stream
        await _run(str(ROOT / "audio_stream.sh") + " stop", timeout=5)
        await _run('SwitchAudioSource -s "Volt 1" -t output 2>&1')
        verify, _ = await _run("SwitchAudioSource -c -t output")
        await query.message.reply_text(
            "🔇 *Audio → Local Only*\n\n"
            f"Output: `{verify}`\n"
            "Audio stream: stopped\n\n"
            "Audio plays through Volt 1 only.\n"
            "_No audio will stream to your phone._",
            parse_mode="Markdown"
        )
        return


# ── /tools — custom on-the-go toolkit ────────────────────────────────────────

async def cmd_tools(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/tools — show quick-access toolkit, or /tools <name> to run one directly."""
    if not is_allowed(update):
        return await deny(update)

    # Works from both /tools command and inline button callbacks
    msg_target = (
        update.callback_query.message
        if update.callback_query
        else update.message
    )

    args = context.args or []
    tool = args[0].lower() if args else ""

    # ── Direct tool dispatch ──────────────────────────────────────────────────
    if tool == "diskspace":
        proc = await asyncio.create_subprocess_shell(
            "df -h / | tail -1 && echo '---' && du -sh output/ beats/ 2>/dev/null",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.STDOUT, cwd=str(ROOT),
        )
        out, _ = await proc.communicate()
        await msg_target.reply_text(f"💾 *Disk Space*\n```\n{out.decode(errors='replace').strip()}\n```", parse_mode="Markdown")
        return

    if tool == "beatcount":
        beats  = list((ROOT / "beats").glob("*.mp3")) + list((ROOT / "beats").glob("*.wav"))
        output = list((ROOT / "output").glob("*.mp4"))
        await msg_target.reply_text(
            f"🎵 *Beat Count*\n"
            f"Beats in queue: `{len(beats)}`\n"
            f"Rendered videos: `{len(output)}`\n"
            f"Not yet rendered: `{len(beats) - len([b for b in beats if (ROOT / 'output' / (b.stem + '.mp4')).exists()])}`",
            parse_mode="Markdown",
        )
        return

    if tool == "cpumem":
        proc = await asyncio.create_subprocess_shell(
            "top -l 1 -n 5 | grep -E 'CPU|PhysMem|python'",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.STDOUT,
        )
        out, _ = await proc.communicate()
        await msg_target.reply_text(f"🖥 *CPU / Memory*\n```\n{out.decode(errors='replace').strip()}\n```", parse_mode="Markdown")
        return

    if tool == "pip":
        pkg = " ".join(args[1:]) if len(args) > 1 else ""
        if not pkg:
            await msg_target.reply_text("Usage: `/tools pip <package>`", parse_mode="Markdown")
            return
        msg = await msg_target.reply_text(f"📦 Installing `{esc(pkg)}`…", parse_mode="Markdown")
        proc = await asyncio.create_subprocess_shell(
            f"{str(ROOT / '.venv/bin/pip')} install {pkg} -q",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.STDOUT, cwd=str(ROOT),
        )
        try:
            out, _ = await asyncio.wait_for(proc.communicate(), timeout=60)
        except asyncio.TimeoutError:
            proc.kill()
            await safe_edit(msg, "⏱ pip timed out.", parse_mode="Markdown")
            return
        result = out.decode(errors="replace").strip()[-1500:]
        await safe_edit(msg, f"📦 `{esc(pkg)}`\n```\n{result or 'Done.'}\n```", parse_mode="Markdown")
        return

    if tool == "gitlog":
        proc = await asyncio.create_subprocess_shell(
            "git log --oneline -10",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.STDOUT, cwd=str(ROOT),
        )
        out, _ = await proc.communicate()
        await msg_target.reply_text(f"📋 *Git Log (last 10)*\n```\n{out.decode(errors='replace').strip()}\n```", parse_mode="Markdown")
        return

    if tool == "gitstatus":
        proc = await asyncio.create_subprocess_shell(
            "git status --short",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.STDOUT, cwd=str(ROOT),
        )
        out, _ = await proc.communicate()
        await msg_target.reply_text(f"📋 *Git Status*\n```\n{out.decode(errors='replace').strip() or 'Clean working tree'}\n```", parse_mode="Markdown")
        return

    if tool == "gitpull":
        msg = await msg_target.reply_text("⬇️ Pulling latest from git…")
        proc = await asyncio.create_subprocess_shell(
            "git pull",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.STDOUT, cwd=str(ROOT),
        )
        try:
            out, _ = await asyncio.wait_for(proc.communicate(), timeout=30)
        except asyncio.TimeoutError:
            proc.kill()
            await safe_edit(msg, "⏱ git pull timed out.")
            return
        await safe_edit(msg, f"⬇️ *git pull*\n```\n{out.decode(errors='replace').strip()}\n```", parse_mode="Markdown")
        return

    if tool == "uptime":
        proc = await asyncio.create_subprocess_shell(
            "uptime && echo '' && date",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.STDOUT,
        )
        out, _ = await proc.communicate()
        await msg_target.reply_text(f"⏱ *System Uptime*\n```\n{out.decode(errors='replace').strip()}\n```", parse_mode="Markdown")
        return

    if tool == "network":
        proc = await asyncio.create_subprocess_shell(
            "curl -s --max-time 5 https://api.ipify.org && echo '' && networksetup -getinfo Wi-Fi 2>/dev/null | head -5",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.STDOUT,
        )
        try:
            out, _ = await asyncio.wait_for(proc.communicate(), timeout=10)
        except asyncio.TimeoutError:
            proc.kill()
            out = b"Timeout"
        await msg_target.reply_text(f"🌐 *Network*\n```\n{out.decode(errors='replace').strip()}\n```", parse_mode="Markdown")
        return

    if tool == "clearoutput":
        output_files = list((ROOT / "output").glob("*.mp4")) + list((ROOT / "output").glob("*.mp3")) + list((ROOT / "output").glob("*.mid"))
        count = len(output_files)
        if count == 0:
            await msg_target.reply_text("✅ output/ is already empty.")
            return
        for f in output_files:
            try:
                f.unlink()
            except Exception:
                pass
        await msg_target.reply_text(f"🗑 Deleted {count} files from `output/`.", parse_mode="Markdown")
        return

    if tool == "envcheck":
        checks = []
        checks.append(f"{'✅' if (ROOT / 'client_secret.json').exists() else '❌'} client_secret.json")
        checks.append(f"{'✅' if (ROOT / 'token.json').exists() else '❌'} token.json")
        checks.append(f"{'✅' if (ROOT / '.env').exists() else '❌'} .env file")
        checks.append(f"{'✅' if (ROOT / '.venv').exists() else '❌'} .venv")
        checks.append(f"{'✅' if (ROOT / 'config.yaml').exists() else '❌'} config.yaml")
        api_key = os.environ.get("ANTHROPIC_API_KEY", "")
        checks.append(f"{'✅' if api_key and api_key != 'YOUR_API_KEY_HERE' else '❌'} ANTHROPIC_API_KEY")
        await msg_target.reply_text("🔧 *Environment Check*\n" + "\n".join(checks), parse_mode="Markdown")
        return

    # ── Internal bot diagnostics ──────────────────────────────────────────────

    if tool == "healthcheck":
        lines = ["🏥 *Bot Health Check*\n"]
        # Required files
        for fname in ["client_secret.json", "token.json", ".env", "config.yaml", "beats", "output", "metadata"]:
            exists = (ROOT / fname).exists()
            lines.append(f"{'✅' if exists else '❌'} {fname}")
        # API key
        api_key = os.environ.get("ANTHROPIC_API_KEY", "")
        lines.append(f"{'✅' if api_key and api_key != 'YOUR_API_KEY_HERE' else '❌'} ANTHROPIC_API_KEY")
        # Token validity
        token_path = ROOT / "token.json"
        if token_path.exists():
            try:
                from google.oauth2.credentials import Credentials as _Creds
                _c = _Creds.from_authorized_user_file(str(token_path))
                if _c.valid:
                    lines.append("✅ token.json — valid")
                elif _c.expired and _c.refresh_token:
                    lines.append("⚠️ token.json — expired but refreshable")
                else:
                    lines.append("❌ token.json — expired, needs re-auth")
            except Exception as e:
                lines.append(f"❌ token.json — corrupt ({e})")
        # External tools
        for cmd, label in [("which ffmpeg", "ffmpeg"), ("which fluidsynth", "fluidsynth"), ("which caffeinate", "caffeinate")]:
            proc = await asyncio.create_subprocess_shell(cmd, stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE)
            out, _ = await proc.communicate()
            lines.append(f"{'✅' if out.strip() else '❌'} {label}")
        # Python packages
        for pkg in ["midiutil", "anthropic", "music21", "google.auth", "numpy", "telegram"]:
            try:
                __import__(pkg.replace("-", "_"))
                lines.append(f"✅ pkg:{pkg}")
            except ImportError:
                lines.append(f"❌ pkg:{pkg} MISSING")
        # Background tasks
        bg = len(context.bot_data.get("_bg_tasks", set()))
        lines.append(f"{'✅' if bg == 0 else '⚠️'} bg tasks running: {bg}")
        # uploads_log.json
        log_data = load_json_safe(ROOT / "uploads_log.json", None)
        if log_data is None:
            lines.append("⚠️ uploads_log.json — missing or corrupt")
        else:
            lines.append(f"✅ uploads_log.json — {len(log_data)} uploads logged")
        # Orphaned temp files
        temp_files = list((ROOT / "output").glob("*.mid")) + list((ROOT / "output").glob("*.mp3")) + list((ROOT / "output").glob("*.wav"))
        lines.append(f"{'⚠️' if temp_files else '✅'} orphaned temp files in output/: {len(temp_files)}")
        await msg_target.reply_text("\n".join(lines), parse_mode="Markdown")
        return

    if tool == "fixtoken":
        token_path = ROOT / "token.json"
        if not token_path.exists():
            await msg_target.reply_text(
                "ℹ️ `token.json` doesn't exist yet\\.\n\n"
                "Run this in Terminal to create it:\n"
                "```\ncd /Users/fyefye/yt_automation\n"
                ".venv/bin/python3.14 upload.py --dry-run\n```",
                parse_mode="Markdown",
            )
            return
        # Check if actually broken
        try:
            from google.oauth2.credentials import Credentials as _Creds
            _c = _Creds.from_authorized_user_file(str(token_path))
            if _c.valid:
                await msg_target.reply_text("✅ `token.json` is valid — no fix needed.", parse_mode="Markdown")
                return
            if _c.expired and _c.refresh_token:
                await msg_target.reply_text("⚠️ Token expired but has refresh token — will auto-refresh on next upload.", parse_mode="Markdown")
                return
        except Exception:
            pass
        # Delete bad token
        token_path.unlink(missing_ok=True)
        await msg_target.reply_text(
            "🗑 Deleted broken `token.json`\\.\n\n"
            "Re-auth required — run in Terminal:\n"
            "```\ncd /Users/fyefye/yt_automation\n"
            ".venv/bin/python3.14 upload.py --dry-run\n```",
            parse_mode="Markdown",
        )
        return

    if tool == "clearstuck":
        stuck_keys = [
            "melody_waiting_bpm", "melody_waiting_bars", "melody_waiting_style",
            "batchmel_waiting_count", "editfile_path", "editfile_start", "editfile_end",
            "rename_stem", "schedule_stem", "schedule_privacy",
        ]
        cleared = []
        ud = context.user_data
        for k in stuck_keys:
            if k in ud:
                del ud[k]
                cleared.append(k)
        if cleared:
            await msg_target.reply_text(
                f"🧹 *Cleared stuck state keys*\n```\n" + "\n".join(cleared) + "\n```\n\nConversation states reset.",
                parse_mode="Markdown",
            )
        else:
            await msg_target.reply_text("✅ No stuck state keys found — all clean.")
        return

    if tool == "cleantemp":
        exts = ["*.mid", "*.mp3", "*.wav"]
        removed = []
        for pat in exts:
            for f in (ROOT / "output").glob(pat):
                try:
                    f.unlink()
                    removed.append(f.name)
                except Exception:
                    pass
        if removed:
            await msg_target.reply_text(
                f"🧹 *Cleaned {len(removed)} temp files from output/*\n```\n" + "\n".join(removed[-20:]) + "\n```",
                parse_mode="Markdown",
            )
        else:
            await msg_target.reply_text("✅ No temp files found in output/ — already clean.")
        return

    if tool == "cleanmelodies":
        import time as _time
        days = int(args[1]) if len(args) > 1 and args[1].isdigit() else 30
        cutoff = _time.time() - (days * 86400)
        mel_dir = MELODIES_DIR
        if not mel_dir.exists():
            await msg_target.reply_text("ℹ️ No fy3pack/ folder found.")
            return
        removed = []
        for f in mel_dir.iterdir():
            try:
                if f.is_file() and f.stat().st_mtime < cutoff:
                    f.unlink()
                    removed.append(f.name)
            except Exception:
                pass
        total = len(list(mel_dir.iterdir())) if mel_dir.exists() else 0
        await msg_target.reply_text(
            f"🎵 *Melodies Cleanup*\nDeleted: `{len(removed)}` files older than `{days}` days\n"
            f"Remaining: `{total}` files",
            parse_mode="Markdown",
        )
        return

    if tool == "checkpkgs":
        pkgs = [
            ("midiutil",    "MIDIFile"),
            ("anthropic",   "Anthropic"),
            ("music21",     "converter"),
            ("google.auth", "credentials"),
            ("numpy",       "array"),
            ("telegram",    "Bot"),
            ("googleapiclient.discovery", "build"),
            ("google_auth_oauthlib.flow", "InstalledAppFlow"),
            ("yaml",        "safe_load"),
            ("dotenv",      "load_dotenv"),
        ]
        lines = ["📦 *Package Check*\n"]
        all_ok = True
        for pkg, _ in pkgs:
            try:
                __import__(pkg)
                lines.append(f"✅ {pkg}")
            except ImportError:
                lines.append(f"❌ {pkg} — MISSING  →  `/tools pip {pkg}`")
                all_ok = False
        if all_ok:
            lines.append("\n✅ All packages OK")
        await msg_target.reply_text("\n".join(lines), parse_mode="Markdown")
        return

    if tool == "backuplog":
        import shutil as _shutil, datetime as _dt
        log_path = ROOT / "uploads_log.json"
        if not log_path.exists():
            await msg_target.reply_text("❌ uploads_log.json not found — nothing to back up.")
            return
        ts = _dt.datetime.now().strftime("%Y%m%d_%H%M%S")
        backup_path = ROOT / f"uploads_log_backup_{ts}.json"
        _shutil.copy2(str(log_path), str(backup_path))
        log_data = load_json_safe(log_path, {})
        await msg_target.reply_text(
            f"✅ *Backup created*\n`{backup_path.name}`\n{len(log_data)} entries backed up.",
            parse_mode="Markdown",
        )
        return

    if tool == "fixmeta":
        stem = args[1] if len(args) > 1 else ""
        if not stem:
            await msg_target.reply_text("Usage: `/tools fixmeta <stem>`\nExample: `/tools fixmeta hood_legend`", parse_mode="Markdown")
            return
        meta_path = ROOT / "metadata" / f"{stem}.json"
        if not meta_path.exists():
            # Create default
            default = {"title": stem.replace("_", " ").title(), "artist": "LeekThatsFye", "description": "", "tags": ["type beat", "trap beat"]}
            meta_path.parent.mkdir(parents=True, exist_ok=True)
            meta_path.write_text(json.dumps(default, indent=2))
            await msg_target.reply_text(f"✅ Created default metadata for `{stem}`.", parse_mode="Markdown")
            return
        try:
            data = json.loads(meta_path.read_text())
            # Validate required keys
            fixed = False
            for key, default_val in [("title", stem.replace("_", " ").title()), ("artist", "LeekThatsFye"), ("description", ""), ("tags", [])]:
                if key not in data:
                    data[key] = default_val
                    fixed = True
            if fixed:
                meta_path.write_text(json.dumps(data, indent=2))
                await msg_target.reply_text(f"🔧 Fixed missing keys in `metadata/{stem}.json`.", parse_mode="Markdown")
            else:
                await msg_target.reply_text(f"✅ `metadata/{stem}.json` looks valid — no fix needed.", parse_mode="Markdown")
        except json.JSONDecodeError as e:
            # Corrupt — reset to default
            default = {"title": stem.replace("_", " ").title(), "artist": "LeekThatsFye", "description": "", "tags": ["type beat", "trap beat"]}
            meta_path.write_text(json.dumps(default, indent=2))
            await msg_target.reply_text(f"⚠️ `metadata/{stem}.json` was corrupt (`{e}`). Reset to defaults.", parse_mode="Markdown")
        return

    if tool == "clearbgtasks":
        bg_tasks = context.bot_data.get("_bg_tasks", set())
        count = len(bg_tasks)
        done_count = sum(1 for t in bg_tasks if t.done())
        # Prune completed tasks
        context.bot_data["_bg_tasks"] = {t for t in bg_tasks if not t.done()}
        remaining = len(context.bot_data["_bg_tasks"])
        await msg_target.reply_text(
            f"🧹 *Background Tasks*\n"
            f"Found: `{count}` (done: `{done_count}`, still running: `{remaining}`)\n"
            f"Pruned `{done_count}` completed tasks from tracker.",
            parse_mode="Markdown",
        )
        return

    if tool == "restorelog":
        # Find most recent backup
        backups = sorted(ROOT.glob("uploads_log_backup_*.json"), key=lambda f: f.stat().st_mtime, reverse=True)
        if not backups:
            await msg_target.reply_text("❌ No backup files found.")
            return
        latest = backups[0]
        # If a specific timestamp was given as arg
        if len(args) > 1:
            target = ROOT / f"uploads_log_backup_{args[1]}.json"
            if not target.exists():
                await msg_target.reply_text(f"❌ Backup not found: `{target.name}`\nAvailable:\n" + "\n".join(f"`{b.name}`" for b in backups[:5]), parse_mode="Markdown")
                return
            latest = target
        import shutil as _shutil
        _shutil.copy2(str(latest), str(ROOT / "uploads_log.json"))
        log_data = load_json_safe(ROOT / "uploads_log.json", {})
        await msg_target.reply_text(
            f"✅ *Restored uploads\\_log.json*\nFrom: `{latest.name}`\n{len(log_data)} entries restored.",
            parse_mode="Markdown",
        )
        return

    # ── Tool not matched — show menu ──────────────────────────────────────────
    kb = InlineKeyboardMarkup([
        [InlineKeyboardButton("💾 Disk Space",    callback_data="tool:diskspace"),
         InlineKeyboardButton("🎵 Beat Count",    callback_data="tool:beatcount")],
        [InlineKeyboardButton("🖥 CPU/Mem",       callback_data="tool:cpumem"),
         InlineKeyboardButton("⏱ Uptime",         callback_data="tool:uptime")],
        [InlineKeyboardButton("🌐 Network/IP",    callback_data="tool:network"),
         InlineKeyboardButton("🔧 Env Check",     callback_data="tool:envcheck")],
        [InlineKeyboardButton("📋 Git Log",       callback_data="tool:gitlog"),
         InlineKeyboardButton("📋 Git Status",    callback_data="tool:gitstatus")],
        [InlineKeyboardButton("⬇️ Git Pull",      callback_data="tool:gitpull"),
         InlineKeyboardButton("🗑 Clear Output",  callback_data="tool:clearoutput")],
        [InlineKeyboardButton("🏥 Health Check",  callback_data="tool:healthcheck"),
         InlineKeyboardButton("🔑 Fix Token",     callback_data="tool:fixtoken")],
        [InlineKeyboardButton("🧹 Clear Stuck",   callback_data="tool:clearstuck"),
         InlineKeyboardButton("🧹 Clean Temp",    callback_data="tool:cleantemp")],
        [InlineKeyboardButton("🎵 Clean Melodies",callback_data="tool:cleanmelodies"),
         InlineKeyboardButton("📦 Check Pkgs",    callback_data="tool:checkpkgs")],
        [InlineKeyboardButton("💾 Backup Log",    callback_data="tool:backuplog"),
         InlineKeyboardButton("♻️ Restore Log",   callback_data="tool:restorelog")],
        [InlineKeyboardButton("🔬 BG Tasks",      callback_data="tool:clearbgtasks")],
    ])
    await msg_target.reply_text(
        "🛠 *Quick Tools*\n\nTap a tool or use `/tools <name>` directly:\n\n"
        "*System:* `diskspace` • `beatcount` • `cpumem` • `uptime`\n"
        "`network` • `envcheck` • `gitlog` • `gitstatus`\n"
        "`gitpull` • `clearoutput` • `pip <pkg>`\n\n"
        "*Bot Repair:* `healthcheck` • `fixtoken` • `clearstuck`\n"
        "`cleantemp` • `cleanmelodies [days]` • `checkpkgs`\n"
        "`backuplog` • `restorelog` • `fixmeta <stem>` • `clearbgtasks`",
        reply_markup=kb,
        parse_mode="Markdown",
    )


async def tools_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle tool button taps."""
    query = update.callback_query
    if not is_allowed(update):
        await query.answer("⛔ Not authorized.", show_alert=True)
        return
    await query.answer()
    tool = query.data.split(":", 1)[1]
    # Re-use the same handler by faking context.args
    # Pass the real update so is_allowed() gets effective_user correctly
    context.args = [tool]
    await cmd_tools(update, context)


# ── /studio — YouTube Studio dashboard ───────────────────────────────────────

_STUDIO_BACK_KB = InlineKeyboardMarkup([[
    InlineKeyboardButton("🎬 Back to Studio", callback_data="studio:refresh")
]])


async def cmd_studio(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/studio — YouTube Studio-style control panel."""
    if not is_allowed(update):
        return await deny(update)
    msg_target = update.message or (update.callback_query and update.callback_query.message)
    await _send_studio_dashboard(msg_target, context)


async def _send_studio_dashboard(msg_target, context, edit: bool = False):
    """Build and send (or edit) the studio dashboard message."""
    beats    = list((ROOT / "beats").glob("*.mp3")) + list((ROOT / "beats").glob("*.wav"))
    rendered = [f for f in (ROOT / "output").glob("*.mp4") if _is_render_mp4(f)]
    log_data = load_json_safe(ROOT / "uploads_log.json", {})
    uploaded  = len(log_data)
    scheduled = sum(1 for v in log_data.values() if v.get("publishAt"))
    pending   = len([f for f in rendered if f.stem not in log_data])
    last_line = ""
    if log_data:
        last_item = sorted(log_data.items(), key=lambda x: x[1].get("uploadedAt", ""))[-1]
        last_line = f"\n📤 Last: *{esc(last_item[1].get('title', last_item[0])[:30])}*"

    header = (
        f"🎬 *LeekThatsFye Studio*\n"
        f"{'─' * 24}\n"
        f"🎵 Beats: `{len(beats)}`  •  🎬 Rendered: `{len(rendered)}`\n"
        f"✅ Uploaded: `{uploaded}`  •  ⏳ Pending: `{pending}`\n"
        f"📅 Scheduled: `{scheduled}`{last_line}\n"
        f"{'─' * 24}"
    )

    kb = InlineKeyboardMarkup([
        # ── Overview ──────────────────────────────────────────────────────────
        [InlineKeyboardButton("📊 Status",          callback_data="studio:status"),
         InlineKeyboardButton("📈 Analytics",       callback_data="studio:analytics")],
        [InlineKeyboardButton("📋 Upload Queue",    callback_data="studio:queue"),
         InlineKeyboardButton("📜 Upload Log",      callback_data="studio:log")],
        # ── Content ───────────────────────────────────────────────────────────
        [InlineKeyboardButton("▶️ Preview",          callback_data="studio:preview"),
         InlineKeyboardButton("🔁 Re-render",       callback_data="studio:rerender")],
        [InlineKeyboardButton("✏️ Edit Title",       callback_data="studio:titleeditor"),
         InlineKeyboardButton("📝 Description",     callback_data="studio:desceditor")],
        [InlineKeyboardButton("🏷 Edit Tags",        callback_data="studio:editjson"),
         InlineKeyboardButton("🔄 Auto-Rename",     callback_data="studio:autorename")],
        [InlineKeyboardButton("🖼 Thumbnail",        callback_data="studio:thumbnail"),
         InlineKeyboardButton("🎵 My Beats",         callback_data="studio:stash")],
        # ── Advanced Settings ─────────────────────────────────────────────────
        [InlineKeyboardButton("🎚 BPM / Key",       callback_data="studio:bpmeditor"),
         InlineKeyboardButton("🔒 Set Privacy",     callback_data="studio:privacy")],
        [InlineKeyboardButton("🖼 Thumb Manager",   callback_data="studio:thumbmanager"),
         InlineKeyboardButton("📦 Bulk Edit",       callback_data="studio:bulkedit")],
        # ── Upload ────────────────────────────────────────────────────────────
        [InlineKeyboardButton("🚀 Review & Upload", callback_data="studio:preupload"),
         InlineKeyboardButton("📅 Schedule",        callback_data="studio:schedule")],
        [InlineKeyboardButton("📦 Render All",      callback_data="studio:render")],
        # ── History + Stats ───────────────────────────────────────────────────
        [InlineKeyboardButton("📊 History + Stats", callback_data="studio:historystats")],
        # ── Tools ─────────────────────────────────────────────────────────────
        [InlineKeyboardButton("🏥 Health",          callback_data="studio:health"),
         InlineKeyboardButton("💾 Disk",            callback_data="studio:diskspace"),
         InlineKeyboardButton("📦 Pkgs",            callback_data="studio:checkpkgs")],
        [InlineKeyboardButton("🧹 Clear Temp",      callback_data="studio:cleantemp"),
         InlineKeyboardButton("🔑 Fix Token",       callback_data="studio:fixtoken")],
        [InlineKeyboardButton("📡 Remote Access",   callback_data="studio:remote"),
         InlineKeyboardButton("🤖 Bot Update",      callback_data="studio:botupdate")],
        # ── Refresh ───────────────────────────────────────────────────────────
        [InlineKeyboardButton("🔄 Refresh",         callback_data="studio:refresh")],
    ])

    if edit:
        try:
            await msg_target.edit_text(header, reply_markup=kb, parse_mode="Markdown")
            return
        except Exception:
            pass  # fall through to reply
    await msg_target.reply_text(header, reply_markup=kb, parse_mode="Markdown")


async def studio_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Route all studio: button taps."""
    query = update.callback_query
    if not is_allowed(update):
        await query.answer("⛔ Not authorized.", show_alert=True)
        return
    await query.answer()
    action = query.data.split(":", 1)[1]

    BACK_KB = _STUDIO_BACK_KB

    # ── Refresh dashboard ─────────────────────────────────────────────────────
    if action == "refresh":
        await _send_studio_dashboard(query.message, context, edit=True)
        return

    # ── Inline: Status ────────────────────────────────────────────────────────
    if action == "status":
        beats     = list((ROOT / "beats").glob("*.mp3")) + list((ROOT / "beats").glob("*.wav"))
        rendered  = [f for f in (ROOT / "output").glob("*.mp4") if _is_render_mp4(f)]
        log_data  = load_json_safe(ROOT / "uploads_log.json", {})
        not_done  = [b for b in beats if not (ROOT / "output" / (safe_stem(b) + ".mp4")).exists()]
        lines = [
            "📊 *Status*\n",
            f"🎵 Total beats: `{len(beats)}`",
            f"🎬 Rendered:    `{len(rendered)}`",
            f"⏳ Not rendered: `{len(not_done)}`",
            f"✅ Uploaded:    `{len(log_data)}`",
            f"📅 Scheduled:   `{sum(1 for v in log_data.values() if v.get('publishAt'))}`",
        ]
        if not_done:
            lines.append("\n*Not yet rendered:*")
            for b in not_done[:10]:
                lines.append(f"  • `{safe_stem(b)}`")
            if len(not_done) > 10:
                lines.append(f"  _…and {len(not_done) - 10} more_")
        await query.message.reply_text("\n".join(lines), parse_mode="Markdown", reply_markup=BACK_KB)
        return

    # ── Inline: Queue ─────────────────────────────────────────────────────────
    if action == "queue":
        rendered = {f.stem for f in (ROOT / "output").glob("*.mp4") if _is_render_mp4(f)}
        log_data = load_json_safe(ROOT / "uploads_log.json", {})
        pending  = [s for s in sorted(rendered) if s not in log_data]
        if not pending:
            await query.message.reply_text("✅ Queue empty — all rendered videos uploaded!", reply_markup=BACK_KB)
            return
        lines = [f"📋 *Upload Queue ({len(pending)} ready)*\n"]
        for stem in pending:
            meta  = load_json_safe(ROOT / "metadata" / f"{stem}.json", {})
            title = meta.get("title", stem)
            mp4   = ROOT / "output" / f"{stem}.mp4"
            size  = f"{mp4.stat().st_size / 1_048_576:.1f} MB" if mp4.exists() else "?"
            priv  = meta.get("privacy", "public")
            priv_icon = {"public": "🌐", "unlisted": "🔗", "private": "🔒"}.get(priv, "🌐")
            lines.append(f"{priv_icon} *{esc(title)}*  `{size}`\n  `{stem}`")
        await query.message.reply_text("\n".join(lines), parse_mode="Markdown", reply_markup=BACK_KB)
        return

    # ── Inline: Upload Log ────────────────────────────────────────────────────
    if action == "log":
        log_data = load_json_safe(ROOT / "uploads_log.json", {})
        if not log_data:
            await query.message.reply_text("📜 No uploads yet.", reply_markup=BACK_KB)
            return
        sorted_items = sorted(log_data.items(), key=lambda x: x[1].get("uploadedAt", ""), reverse=True)[:20]
        lines = [f"📜 *Upload Log ({len(log_data)} videos)*\n"]
        for stem, info in sorted_items:
            pub = f"  📅 _{info['publishAt'][:10]}_" if info.get("publishAt") else ""
            lines.append(f"• [{esc(info.get('title', stem)[:35])}]({info.get('url', '')}){pub}")
        await query.message.reply_text(
            "\n".join(lines), parse_mode="Markdown",
            reply_markup=BACK_KB, disable_web_page_preview=True,
        )
        return

    # ── Inline: Analytics ─────────────────────────────────────────────────────
    if action == "analytics":
        await _qm_analytics(query.message, context)
        return

    # ── Inline: History + Stats ───────────────────────────────────────────────
    if action == "historystats":
        log_data = load_json_safe(ROOT / "uploads_log.json", {})
        if not log_data:
            await query.message.reply_text("📊 No uploads yet.", reply_markup=BACK_KB)
            return
        wait_msg = await query.message.reply_text("📊 Fetching YouTube stats…")
        try:
            from youtube_auth import get_youtube_service as _yt_svc
            yt = _yt_svc()
            video_ids = [v["videoId"] for v in log_data.values() if v.get("videoId")]
            stats_map = {}
            # Batch fetch (YouTube allows up to 50 IDs per call)
            for i in range(0, len(video_ids), 50):
                batch = video_ids[i:i+50]
                resp = yt.videos().list(part="statistics", id=",".join(batch)).execute()
                for item in resp.get("items", []):
                    s = item.get("statistics", {})
                    stats_map[item["id"]] = {
                        "views": int(s.get("viewCount", 0)),
                        "likes": int(s.get("likeCount", 0)),
                    }
            # Sort by views descending
            ranked = []
            for stem, info in log_data.items():
                vid = info.get("videoId", "")
                st  = stats_map.get(vid, {})
                ranked.append((stem, info, st.get("views", 0), st.get("likes", 0)))
            ranked.sort(key=lambda x: x[2], reverse=True)
            lines = [f"📊 *Upload Stats — {len(ranked)} videos*\n"]
            for i, (stem, info, views, likes) in enumerate(ranked[:20], 1):
                title = info.get("title", stem)[:30]
                v_str = f"{views:,}" if views else "–"
                l_str = f"{likes:,}" if likes else "–"
                lines.append(f"*{i}.* [{esc(title)}]({info.get('url','')})  👁 {v_str}  👍 {l_str}")
        except Exception as e:
            # Fallback: log without stats
            lines = [f"📊 *Upload Log* _(stats unavailable: {esc(str(e)[:80])})_\n"]
            for stem, info in sorted(log_data.items(), key=lambda x: x[1].get("uploadedAt",""), reverse=True)[:20]:
                lines.append(f"• [{esc(info.get('title',stem)[:35])}]({info.get('url','')})")
        try:
            await safe_edit(wait_msg, "\n".join(lines), parse_mode="Markdown")
            await wait_msg.reply_text("↑ Stats", reply_markup=BACK_KB)
        except Exception:
            await query.message.reply_text("\n".join(lines)[:4000], parse_mode="Markdown",
                                           reply_markup=BACK_KB, disable_web_page_preview=True)
        return

    # ── Advanced: Thumbnail Manager ───────────────────────────────────────────
    if action == "thumbmanager":
        beats = sorted(
            list((ROOT / "beats").glob("*.mp3")) + list((ROOT / "beats").glob("*.wav"))
        )
        if not beats:
            await query.message.reply_text("🎵 No beats found.", reply_markup=BACK_KB)
            return
        lines = ["🖼 *Thumbnail Manager*\n"]
        for b in beats:
            stem   = safe_stem(b)
            custom = ROOT / "images" / f"{stem}.jpg"
            thumb  = ROOT / "output" / f"{stem}_thumb.jpg"
            if custom.exists():
                size = f"{custom.stat().st_size/1024:.0f}KB"
                status = f"✅ Custom ({size})"
            elif thumb.exists():
                status = "🖼 Auto-generated"
            else:
                status = "⬜ Default"
            lines.append(f"• `{stem}` — {status}")
        lines.append("\nTap /thumbnail to upload a custom thumb for any beat.")
        text = "\n".join(lines)
        # Send in chunks if too long
        if len(text) > 3800:
            text = text[:3800] + "\n…(truncated)"
        await query.message.reply_text(text, parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([
                [InlineKeyboardButton("🖼 Open Thumbnail Tool", callback_data="studio:thumbnail")],
                [InlineKeyboardButton("🎬 Back to Studio",      callback_data="studio:refresh")],
            ]))
        return

    # ── Advanced: Privacy Setter ──────────────────────────────────────────────
    if action == "privacy":
        # Show all beats with current privacy setting
        beats = sorted(
            list((ROOT / "beats").glob("*.mp3")) + list((ROOT / "beats").glob("*.wav"))
        )
        if not beats:
            await query.message.reply_text("🎵 No beats found.", reply_markup=BACK_KB)
            return
        buttons = []
        for b in beats:
            stem = safe_stem(b)
            meta = load_json_safe(ROOT / "metadata" / f"{stem}.json", {})
            priv = meta.get("privacy", "public")
            icon = {"public": "🌐", "unlisted": "🔗", "private": "🔒"}.get(priv, "🌐")
            title = meta.get("title", stem)[:22]
            buttons.append([InlineKeyboardButton(f"{icon} {title}", callback_data=f"studio:privpick:{stem}")])
        buttons.append([InlineKeyboardButton("🎬 Back to Studio", callback_data="studio:refresh")])
        await query.message.reply_text(
            "🔒 *Set Privacy*\nTap a beat to change its privacy setting:",
            reply_markup=InlineKeyboardMarkup(buttons),
            parse_mode="Markdown",
        )
        return

    if action.startswith("privpick:"):
        stem = action.split(":", 1)[1]
        meta = load_json_safe(ROOT / "metadata" / f"{stem}.json", {})
        title = meta.get("title", stem)
        curr  = meta.get("privacy", "public")
        await query.message.reply_text(
            f"🔒 *{esc(title)}*\nCurrent: `{curr}`\n\nSelect new privacy:",
            reply_markup=InlineKeyboardMarkup([
                [InlineKeyboardButton("🌐 Public",   callback_data=f"studio:privset:{stem}:public"),
                 InlineKeyboardButton("🔗 Unlisted", callback_data=f"studio:privset:{stem}:unlisted"),
                 InlineKeyboardButton("🔒 Private",  callback_data=f"studio:privset:{stem}:private")],
                [InlineKeyboardButton("◀ Back",      callback_data="studio:privacy")],
            ]),
            parse_mode="Markdown",
        )
        return

    if action.startswith("privset:"):
        _, stem, privacy = action.split(":", 2)
        meta_path = ROOT / "metadata" / f"{stem}.json"
        meta = load_json_safe(meta_path, {})
        meta["privacy"] = privacy
        meta_path.write_text(json.dumps(meta, indent=2))
        icon = {"public": "🌐", "unlisted": "🔗", "private": "🔒"}.get(privacy, "🌐")
        await query.message.reply_text(
            f"{icon} *{esc(meta.get('title', stem))}*\nPrivacy set to `{privacy}` ✅\n"
            f"This will be used when you upload this beat.",
            parse_mode="Markdown", reply_markup=BACK_KB,
        )
        return

    # ── Tool shortcuts ────────────────────────────────────────────────────────
    if action in ("health", "diskspace", "checkpkgs", "cleantemp", "fixtoken",
                  "clearbgtasks", "backuplog", "cleanmelodies", "beatcount"):
        context.args = [action]
        await cmd_tools(update, context)
        return

    # ── Render All ────────────────────────────────────────────────────────────
    if action == "render":
        await query.message.reply_text("📦 Starting render… I'll update you when done.")
        task = asyncio.create_task(run_render_live(query.message, context))
        context.bot_data.setdefault("_bg_tasks", set()).add(task)
        task.add_done_callback(lambda t: context.bot_data.get("_bg_tasks", set()).discard(t))
        return

    # ── Conversation entry points (send slash command as tappable link) ───────
    # ── Studio: Remote Access shortcut ───────────────────────────────────────
    if action == "remote":
        await query.message.reply_text("/remote")
        return

    # ── Studio: Auto-Rename shortcut ─────────────────────────────────────────
    if action == "autorename":
        await query.message.reply_text(
            "🔄 *Auto-Rename*\n\nPick an artist, then format all titles to: Beat Name [Artist] Type Beat\n\n"
            "👇 Tap to launch:",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton("🎬 Back to Studio", callback_data="studio:refresh"),
            ]]),
        )
        await query.message.reply_text("/autorename")
        return

    # ── Studio: Bot Update shortcut ──────────────────────────────────────────
    if action == "botupdate":
        await query.message.reply_text(
            "🤖 *Bot Update*\n\nSee what's new + tip of the day\n\n"
            "👇 Tap to launch:",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton("🎬 Back to Studio", callback_data="studio:refresh"),
            ]]),
        )
        await query.message.reply_text("/botupdate")
        return

    _conv_map = {
        "preupload": ("/preupload",  "🚀 Review & rename titles before uploading"),
        "schedule":  ("/schedule",   "📅 Open the scheduler"),
        "rename":    ("/rename",     "✏️ Rename a beat"),
        "editjson":  ("/editjson",   "🏷 Edit metadata fields"),
        "thumbnail": ("/thumbnail",  "🖼 Upload a thumbnail"),
        "rerender":  ("/rerender",   "🔁 Re-render a beat"),
        "preview":   ("/preview",    "▶️ Preview a rendered video"),
        "stash":     ("/fy3stash",   "🎵 Browse your beats"),
        "bulkedit":  ("/bulkedit",   "📦 Bulk-edit tags/descriptions"),
    }
    if action in _conv_map:
        slash_cmd, label = _conv_map[action]
        await query.message.reply_text(
            f"{label}\n\n👇 Tap the command below:",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton("🎬 Back to Studio", callback_data="studio:refresh"),
            ]]),
        )
        await query.message.reply_text(slash_cmd)
        return

    # ── BPM/Key editor entry (handled by studio_bpm_conv) ────────────────────
    if action == "bpmeditor":
        # Entry point is a CallbackQueryHandler in studio_bpm_conv — this branch
        # won't be reached because the conv handler intercepts it first.
        # But as a fallback:
        await query.message.reply_text(
            "🎚 *BPM / Key Editor*\n\nTap /bpmeditor or use the studio — this should open automatically.",
            parse_mode="Markdown", reply_markup=BACK_KB,
        )
        return

    if action == "desceditor":
        await query.message.reply_text(
            "📝 *Description Editor*\n\nThis should open automatically.",
            parse_mode="Markdown", reply_markup=BACK_KB,
        )
        return


