async def studio_bpm_receive(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Parse 'BPM Key' input and save to metadata."""
    if not is_allowed(update):
        return await deny(update)

    stem = context.user_data.get("studio_bpm_stem")
    if not stem:
        return ConversationHandler.END

    text  = (update.message.text or "").strip()
    parts = text.split(None, 1)

    if not parts[0].isdigit():
        await update.message.reply_text(
            "❌ Format must be: `144 C Minor`\nFirst part must be a number (BPM).",
            parse_mode="Markdown",
        )
        return STUDIO_BPM

    bpm = int(parts[0])
    key = parts[1].strip() if len(parts) > 1 else ""

    meta_path = ROOT / "metadata" / f"{stem}.json"
    meta = load_json_safe(meta_path, {})
    meta["bpm"] = bpm
    if key:
        meta["key"] = key
    meta_path.write_text(json.dumps(meta, indent=2))

    context.user_data.pop("studio_bpm_stem", None)
    await update.message.reply_text(
        f"✅ *{esc(meta.get('title', stem))}* updated!\n"
        f"BPM: `{bpm}`" + (f"  •  Key: `{esc(key)}`" if key else "") + "\n\n"
        "Changes saved to metadata.",
        parse_mode="Markdown",
        reply_markup=_STUDIO_BACK_KB,
    )
    return ConversationHandler.END


