# ── /autorename — clean all titles to "Beat Name {Artist} Type Beat" ──────────

def _autorename_title(stem: str, existing_title: str, artist: str) -> str:
    """
    Format a beat title as: '<Clean Name> {Artist} Type Beat'
    Strips existing type beat / artist / prod suffixes first.
    """
    base = existing_title.strip() if existing_title.strip() else stem.replace("_", " ")
    strip_patterns = [
        r"\s*[\|\-–—]\s*.*$",                  # everything after | - –
        r"\s+\[free\].*$",                      # [FREE] prefix leftovers
        r"^\[free\]\s*",                         # leading [FREE]
        r"\s+(type\s+beat|typebeat).*$",         # "type beat" and everything after
        r"\s+biggkutt\d*.*$",                    # "biggkutt8" etc.
        r"\s+leekthatsfye.*$",                   # "leekthatsfye" etc.
        r"\s+(free\s+)?(prod|produced)\s+by.*$", # "prod by ..."
        r"\s+\d{4}$",                            # trailing year
        r"\s+(official\s+)?(audio|video)$",      # "official audio"
        r"\s+x\s+\w+$",                          # "x ArtistName" collabs
    ]
    cleaned = base
    for pat in strip_patterns:
        cleaned = re.sub(pat, "", cleaned, flags=re.IGNORECASE).strip()
    cleaned = cleaned.title() if cleaned else stem.replace("_", " ").title()
    return f"{cleaned} {artist} Type Beat"


async def cmd_autorename(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/autorename — pick an artist, then rename all beats to 'Beat Name {Artist} Type Beat'."""
    if not is_allowed(update):
        return await deny(update)

    beats = sorted(
        list((ROOT / "beats").glob("*.mp3")) + list((ROOT / "beats").glob("*.wav"))
    )
    if not beats:
        await update.message.reply_text("No beats found.")
        return

    # Store beat stems for after artist pick
    ar_key = f"ar_{int(time.time())}_{os.urandom(4).hex()}"
    context.bot_data.setdefault("_autorename_sessions", {})[ar_key] = {
        "stems": [safe_stem(b) for b in beats],
        "ts": time.time(),
    }

    # Show artist picker
    rows = []
    for display, seo_name in _TOP_ARTISTS:
        rows.append([InlineKeyboardButton(
            f"🎤 {display}",
            callback_data=f"autorenart:{seo_name[:20]}:{ar_key}"
        )])
    rows.append([InlineKeyboardButton("❌ Cancel", callback_data=f"autorenart:__cancel__:{ar_key}")])
    kb = InlineKeyboardMarkup(rows)

    await update.message.reply_text(
        f"✏️ Auto-Rename — {len(beats)} beats\n\n"
        f"Pick an artist for the title format:\n"
        f"Beat Name [Artist] Type Beat",
        reply_markup=kb,
    )


async def autorename_artist_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle autorenart:{artist}:{ar_key} — artist picked, show preview."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("Not authorized.", show_alert=True)
        return
    await query.answer()

    parts = query.data.split(":", 2)
    if len(parts) != 3:
        await safe_edit(query.message, "Malformed callback.")
        return
    _, artist_choice, ar_key = parts

    if artist_choice == "__cancel__":
        context.bot_data.get("_autorename_sessions", {}).pop(ar_key, None)
        await safe_edit(query.message, "❌ Auto-rename cancelled.")
        return

    sessions = context.bot_data.get("_autorename_sessions", {})
    session = sessions.pop(ar_key, None)
    if not session:
        await safe_edit(query.message, "Session expired. Send /autorename again.")
        return

    stems = session["stems"]
    meta_dir = ROOT / "metadata"
    changes = []

    for stem in stems:
        mf = meta_dir / f"{stem}.json"
        meta = load_json_safe(mf, {})
        old_title = meta.get("title", stem.replace("_", " ").title())
        new_title = _autorename_title(stem, old_title, artist_choice)
        if old_title != new_title:
            changes.append((stem, old_title, new_title))

    if not changes:
        await safe_edit(query.message, f"All titles already match {artist_choice} Type Beat format!")
        return

    # Store pending changes + artist for confirmation
    context.user_data["_autorename_pending"] = changes
    context.user_data["_autorename_artist"] = artist_choice

    preview_lines = [f"✏️ Auto-Rename Preview\nFormat: Beat Name {artist_choice} Type Beat\n"]
    for stem, old_title, new_title in changes[:20]:
        preview_lines.append(f"  {old_title[:30]}  →  {new_title[:40]}")
    if len(changes) > 20:
        preview_lines.append(f"  ...and {len(changes) - 20} more")
    preview_lines.append(f"\n{len(changes)} title(s) will be updated.")

    kb = InlineKeyboardMarkup([
        [InlineKeyboardButton("✅ Apply All", callback_data="autorename:apply"),
         InlineKeyboardButton("❌ Cancel", callback_data="autorename:cancel")],
        [InlineKeyboardButton("🔧 Pick One by One", callback_data="autorename:pick")],
    ])
    await safe_edit(query.message, "\n".join(preview_lines), reply_markup=kb)


async def autorename_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle apply/cancel/pick from /autorename."""
    query = update.callback_query
    if not is_allowed(update):
        await query.answer("Not authorized.", show_alert=True)
        return
    await query.answer()
    action = query.data.split(":", 1)[1]

    pending = context.user_data.get("_autorename_pending", [])
    artist = context.user_data.get("_autorename_artist", "BiggKutt8")
    meta_dir = ROOT / "metadata"

    if action == "cancel":
        context.user_data.pop("_autorename_pending", None)
        context.user_data.pop("_autorename_artist", None)
        await safe_edit(query.message, "❌ Auto-rename cancelled.")
        return

    if action == "apply":
        count = 0
        for stem, old_title, new_title in pending:
            mf   = meta_dir / f"{stem}.json"
            meta = load_json_safe(mf, {})
            meta["title"] = new_title
            mf.write_text(json.dumps(meta, indent=2))
            count += 1
        context.user_data.pop("_autorename_pending", None)
        context.user_data.pop("_autorename_artist", None)
        await safe_edit(
            query.message,
            f"✅ {count} title(s) updated to {artist} Type Beat format!\n"
            f"Run /preupload to review before uploading.",
        )
        return

    if action == "pick":
        # Show pick-one-by-one menu
        if not pending:
            await safe_edit(query.message, "✅ Nothing left to rename.")
            return
        stem, old_title, new_title = pending[0]
        context.user_data["_autorename_pending"] = pending  # keep full list
        kb = InlineKeyboardMarkup([
            [InlineKeyboardButton("✅ Apply This",  callback_data="autorename:yes"),
             InlineKeyboardButton("⏭ Skip",         callback_data="autorename:skip")],
            [InlineKeyboardButton("✅ Apply All Remaining", callback_data="autorename:apply")],
            [InlineKeyboardButton("❌ Done",         callback_data="autorename:cancel")],
        ])
        await safe_edit(
            query.message,
            f"✏️ *Rename?* ({len(pending)} remaining)\n\n"
            f"*From:* `{esc(old_title)}`\n"
            f"*To:*   `{esc(new_title)}`",
            parse_mode="Markdown",
            reply_markup=kb,
        )
        return

    if action == "yes":
        if pending:
            stem, old_title, new_title = pending[0]
            mf   = meta_dir / f"{stem}.json"
            meta = load_json_safe(mf, {})
            meta["title"] = new_title
            mf.write_text(json.dumps(meta, indent=2))
            pending = pending[1:]
            context.user_data["_autorename_pending"] = pending
        if not pending:
            context.user_data.pop("_autorename_pending", None)
            await safe_edit(query.message, "✅ All done! Titles updated.")
            return
        # Show next
        stem, old_title, new_title = pending[0]
        kb = InlineKeyboardMarkup([
            [InlineKeyboardButton("✅ Apply This",  callback_data="autorename:yes"),
             InlineKeyboardButton("⏭ Skip",         callback_data="autorename:skip")],
            [InlineKeyboardButton("✅ Apply All Remaining", callback_data="autorename:apply")],
            [InlineKeyboardButton("❌ Done",         callback_data="autorename:cancel")],
        ])
        await safe_edit(
            query.message,
            f"✏️ *Rename?* ({len(pending)} remaining)\n\n"
            f"*From:* `{esc(old_title)}`\n"
            f"*To:*   `{esc(new_title)}`",
            parse_mode="Markdown",
            reply_markup=kb,
        )
        return

    if action == "skip":
        if pending:
            pending = pending[1:]
            context.user_data["_autorename_pending"] = pending
        if not pending:
            context.user_data.pop("_autorename_pending", None)
            await safe_edit(query.message, "✅ Done — skipped remaining beats.")
            return
        stem, old_title, new_title = pending[0]
        kb = InlineKeyboardMarkup([
            [InlineKeyboardButton("✅ Apply This",  callback_data="autorename:yes"),
             InlineKeyboardButton("⏭ Skip",         callback_data="autorename:skip")],
            [InlineKeyboardButton("✅ Apply All Remaining", callback_data="autorename:apply")],
            [InlineKeyboardButton("❌ Done",         callback_data="autorename:cancel")],
        ])
        await safe_edit(
            query.message,
            f"✏️ *Rename?* ({len(pending)} remaining)\n\n"
            f"*From:* `{esc(old_title)}`\n"
            f"*To:*   `{esc(new_title)}`",
            parse_mode="Markdown",
            reply_markup=kb,
        )
        return


