async def _daily_botupdate_job(app):
    """Send a daily tip at 10 AM ET (15:00 UTC)."""
    while True:
        now_utc    = datetime.now(timezone.utc)
        target_utc = now_utc.replace(hour=15, minute=0, second=0, microsecond=0)
        if now_utc >= target_utc:
            target_utc += timedelta(days=1)
        await asyncio.sleep((target_utc - now_utc).total_seconds())
        try:
            from datetime import date
            day_index = date.today().timetuple().tm_yday % len(_BOT_TIPS)
            cat, tip  = _BOT_TIPS[day_index]
            await app.bot.send_message(
                chat_id=ALLOWED_ID,
                text=f"💡 *Daily Tip*\n\n{cat} — _{esc(tip)}_\n\n_Run /botupdate for full update_",
                parse_mode="Markdown",
            )
        except Exception as e:
            log.warning("Daily bot tip failed: %s", e)


# ── /editfile — patch a file remotely from phone ──────────────────────────────
EDITFILE_WAITING = 66


async def cmd_editfile(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/editfile <file> <start> <end> — view and replace a range of lines."""
    if not is_allowed(update):
        return await deny(update)
    args = context.args or []
    if len(args) < 3:
        await update.message.reply_text(
            "📄 *Edit a file remotely*\n\n"
            "Usage: `/editfile <filename> <start_line> <end_line>`\n\n"
            "Example: `/editfile telegram_bot.py 100 105`\n\n"
            "Bot will show you the current lines then wait for your replacement text. "
            "Run `/restart` after to apply.",
            parse_mode="Markdown",
        )
        return ConversationHandler.END

    filename = args[0]
    try:
        start_line = int(args[1])
        end_line   = int(args[2])
    except ValueError:
        await update.message.reply_text("⚠️ Line numbers must be integers.")
        return ConversationHandler.END

    # Only allow files inside the project root (no path traversal)
    filepath = (ROOT / filename).resolve()
    if not str(filepath).startswith(str(ROOT)):
        await update.message.reply_text("❌ File must be inside the project folder.")
        return ConversationHandler.END
    if not filepath.exists() or not filepath.is_file():
        await update.message.reply_text(f"❌ File not found: `{esc(filename)}`", parse_mode="Markdown")
        return ConversationHandler.END

    with open(filepath) as _ef:
        all_lines = _ef.readlines()
    total = len(all_lines)
    start_line = max(1, min(start_line, total))
    end_line   = max(start_line, min(end_line, total))

    excerpt = "".join(all_lines[start_line - 1 : end_line])
    if len(excerpt) > 3000:
        excerpt = excerpt[:3000] + "\n…(truncated)"

    context.user_data["editfile_path"]  = str(filepath)
    context.user_data["editfile_start"] = start_line
    context.user_data["editfile_end"]   = end_line

    await update.message.reply_text(
        f"📄 `{esc(filename)}` lines {start_line}–{end_line} "
        f"(of {total}):\n```\n{excerpt}\n```\n\n"
        "Send your replacement text (replaces that entire range).\n"
        "Or /cancel to abort.",
        parse_mode="Markdown",
    )
    return EDITFILE_WAITING


async def editfile_replacement_handler(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Receive replacement text and write it into the file."""
    if not is_allowed(update):
        return await deny(update)

    filepath   = context.user_data.get("editfile_path")
    start_line = context.user_data.get("editfile_start")
    end_line   = context.user_data.get("editfile_end")

    if not filepath:
        return ConversationHandler.END

    new_text = update.message.text or ""
    try:
        with open(filepath) as _ef:
            all_lines = _ef.readlines()
        # Replace range [start_line-1 : end_line] with the new text
        new_lines = (
            all_lines[:start_line - 1]
            + [new_text + "\n"]
            + all_lines[end_line:]
        )
        with open(filepath, "w") as _ef:
            _ef.writelines(new_lines)
        fname = Path(filepath).name
        await update.message.reply_text(
            f"✅ `{esc(fname)}` lines {start_line}–{end_line} updated.\n\n"
            "Run `/restart` to apply the changes.",
            parse_mode="Markdown",
        )
    except Exception as _we:
        await update.message.reply_text(f"❌ Write failed: `{esc(str(_we)[:300])}`", parse_mode="Markdown")

    # Clear state
    context.user_data.pop("editfile_path",  None)
    context.user_data.pop("editfile_start", None)
    context.user_data.pop("editfile_end",   None)
    return ConversationHandler.END


async def editfile_cancel(update: Update, context: ContextTypes.DEFAULT_TYPE):
    context.user_data.pop("editfile_path",  None)
    context.user_data.pop("editfile_start", None)
    context.user_data.pop("editfile_end",   None)
    await update.message.reply_text("❌ Edit cancelled.")
    return ConversationHandler.END


# ── /ytsetup ──────────────────────────────────────────────────────────────────
# Diagnose YouTube OAuth setup and give exact fix instructions.

async def cmd_ytsetup(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Check YouTube auth files and tell user exactly what to do."""
    if not is_allowed(update):
        return await deny(update)

    client_secret = ROOT / "client_secret.json"
    token_file    = ROOT / "token.json"

    has_secret = client_secret.exists()
    has_token  = token_file.exists()

    if has_secret and has_token:
        # Both exist — check if token is still valid
        try:
            from google.oauth2.credentials import Credentials
            from google.auth.transport.requests import Request
            creds = Credentials.from_authorized_user_file(str(token_file))
            if creds.valid:
                await update.message.reply_text(
                    "✅ *YouTube auth is fully set up and valid!*\n\n"
                    "Run /upload to start uploading.",
                    parse_mode="Markdown",
                )
                return
            elif creds.expired and creds.refresh_token:
                try:
                    creds.refresh(Request())
                    with open(token_file, "w") as f:
                        f.write(creds.to_json())
                    await update.message.reply_text(
                        "✅ *Token refreshed successfully!*\n\nRun /upload — you're good to go.",
                        parse_mode="Markdown",
                    )
                    return
                except Exception as e:
                    await update.message.reply_text(
                        f"⚠️ *Token expired and refresh failed:* `{esc(str(e)[:200])}`\n\n"
                        "Delete `token.json` and run /ytsetup again — you'll need to sign in once more.\n\n"
                        "On your Mac:\n`rm /Users/fyefye/yt_automation/token.json`",
                        parse_mode="Markdown",
                    )
                    return
        except Exception as e:
            pass  # Fall through to instructions

    lines = ["🔑 *YouTube Setup Status*\n"]
    lines.append(f"{'✅' if has_secret else '❌'} `client_secret.json` — {'found' if has_secret else 'MISSING'}")
    lines.append(f"{'✅' if has_token  else '❌'} `token.json`          — {'found' if has_token  else 'not yet (created on first login)'}")

    if not has_secret:
        lines += [
            "\n*Step 1 — Get your client_secret.json:*",
            "1. Go to → console.cloud.google.com",
            "2. Create project (or pick existing)",
            "3. Enable *YouTube Data API v3*",
            "4. APIs & Services → Credentials → Create Credentials → OAuth 2.0 Client ID",
            "5. Application type: *Desktop app*",
            "6. Click Download JSON → rename file to `client_secret.json`",
            "7. Copy it to:\n   `/Users/fyefye/yt_automation/client_secret.json`",
            "\nThen run /ytsetup again.",
        ]
    else:
        lines += [
            "\n*Step 2 — Authorize (one time only):*",
            "Run this in Terminal on your Mac:",
            "`cd /Users/fyefye/yt_automation`",
            "`.venv/bin/python3.14 upload.py --dry-run`",
            "\nA browser will open → sign in with your YouTube account → allow access.",
            "`token.json` will be saved automatically.",
            "\nAfter that, /upload works forever (auto-refreshes).",
        ]

    await update.message.reply_text("\n".join(lines), parse_mode="Markdown")


