# ── /analytics ────────────────────────────────────────────────────────────────
# Pull real view/like/comment counts from YouTube Data API for uploaded videos.

async def cmd_analytics(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Fetch view/like counts from YouTube for all uploaded videos."""
    if not is_allowed(update):
        return await deny(update)

    log_data = load_json_safe(ROOT / "uploads_log.json", {})
    if not log_data:
        await update.message.reply_text("📭 No uploads yet. Upload some beats first.")
        return

    msg = await update.message.reply_text("📊 Fetching YouTube analytics...")

    try:
        # Import here so missing google libs don't crash the whole bot
        import sys as _sys
        _sys.path.insert(0, str(ROOT))
        from youtube_auth import get_youtube_service  # type: ignore

        youtube  = get_youtube_service()
        video_ids = [
            entry["videoId"]
            for entry in log_data.values()
            if entry.get("videoId")
        ]

        if not video_ids:
            await safe_edit(msg, "⚠️ No video IDs found in uploads log.")
            return

        # YouTube allows up to 50 IDs per request
        all_stats = {}
        for i in range(0, len(video_ids), 50):
            chunk = video_ids[i : i + 50]
            resp  = youtube.videos().list(
                part="statistics,snippet",
                id=",".join(chunk),
            ).execute()
            for item in resp.get("items", []):
                vid_id = item["id"]
                stats  = item.get("statistics", {})
                title  = item.get("snippet", {}).get("title", vid_id)
                all_stats[vid_id] = {
                    "title":    title,
                    "views":    int(stats.get("viewCount",    0)),
                    "likes":    int(stats.get("likeCount",    0)),
                    "comments": int(stats.get("commentCount", 0)),
                }

        # Sort by views descending
        sorted_stats = sorted(all_stats.values(), key=lambda x: x["views"], reverse=True)

        lines = [f"📊 *YouTube Analytics* — {len(sorted_stats)} videos\n"]
        total_views = sum(s["views"] for s in sorted_stats)
        total_likes = sum(s["likes"] for s in sorted_stats)
        lines.append(f"👁 Total views: *{total_views:,}*")
        lines.append(f"👍 Total likes: *{total_likes:,}*\n")

        for s in sorted_stats[:15]:  # Show top 15
            lines.append(
                f"• *{esc(s['title'][:40])}*\n"
                f"  👁 {s['views']:,}  👍 {s['likes']:,}  💬 {s['comments']:,}"
            )
        if len(sorted_stats) > 15:
            lines.append(f"\n...and {len(sorted_stats)-15} more")

        out = "\n".join(lines)
        if len(out) > 4000:
            out = out[:4000] + "\n...(truncated)"
        await safe_edit(msg, out, parse_mode="Markdown")

    except ImportError:
        await safe_edit(msg, "❌ Google API library not installed. Run:\n`pip install google-api-python-client`", parse_mode="Markdown")
    except Exception as e:
        err = str(e)
        if "insufficient" in err.lower() or "forbidden" in err.lower() or "scope" in err.lower():
            await safe_edit(
                msg,
                "⚠️ *YouTube Analytics needs extra permission.*\n\n"
                "Delete `token.json` in the project folder, then run:\n"
                "`python upload.py --dry-run`\n\n"
                "Sign in again — this time it will request read access too.",
                parse_mode="Markdown",
            )
        else:
            await safe_edit(msg, f"❌ Error: {esc(err)}", parse_mode="Markdown")


