def _midi_to_mp3(midi_path: Path, mp3_path: Path, style: str = "trap") -> bool:
    """Convert MIDI to MP3 using FluidSynth with GeneralUser GS soundfont.

    Applies style-tuned reverb and chorus so each genre sounds like it's
    in the right room:
      - trap / drill: tight, punchy, small room
      - plugg: large ethereal space, wide stereo
      - boom bap: medium hall, vinyl warmth
      - r&b: warm room, lush reverb
    """
    # Reverb map: (room-size, damp, width, level)
    # room-size: 0.0–1.0 (larger = more reverb tail)
    # damp: 0.0–1.0 (higher = darker, more damped highs)
    # width: 0.0–100.0 (stereo width)
    # level: 0.0–1.0 (reverb send level)
    _reverb_map = {
        "trap":    ("0.30", "0.60", "0.6",  "0.72"),   # tight, punchy room
        "drill":   ("0.18", "0.70", "0.4",  "0.65"),   # dry and hard
        "plugg":   ("0.80", "0.20", "1.0",  "0.65"),   # large, ethereal space
        "bap":     ("0.55", "0.40", "0.85", "0.70"),   # medium hall, vinyl
        "rnb":     ("0.62", "0.45", "0.80", "0.75"),   # warm lush room
        "fy3pack": ("0.55", "0.35", "0.90", "0.68"),   # splice loop: present + airy, not washy
    }
    _gk  = _STYLE_GROOVE.get(style, "trap")
    # Check style directly first (e.g. "fy3pack" has its own profile), then fall back to groove family
    rv   = _reverb_map.get(style, _reverb_map.get(_gk, _reverb_map["trap"]))

    try:
        sf2_candidates = [
            Path("/opt/homebrew/share/soundfonts/GeneralUser.sf2"),
            Path("/usr/share/sounds/sf2/FluidR3_GM.sf2"),
            Path("/usr/share/sounds/sf2/default.sf2"),
            Path("/opt/homebrew/share/soundfonts/default.sf2"),
        ]
        sf2 = next((p for p in sf2_candidates if p.exists()), None)
        if sf2:
            wav_path = midi_path.with_suffix(".wav")
            # Enable reverb (-R 1) and chorus (-C 1) with style-tuned settings
            r = subprocess.run(
                ["fluidsynth", "-ni", "-g", "1.5",
                 "-R", "1", "-C", "1",
                 "-o", f"synth.reverb.room-size={rv[0]}",
                 "-o", f"synth.reverb.damp={rv[1]}",
                 "-o", f"synth.reverb.width={rv[2]}",
                 "-o", f"synth.reverb.level={rv[3]}",
                 "-o", "synth.chorus.depth=5.0",
                 "-o", "synth.chorus.speed=0.28",
                 "-o", "synth.chorus.level=0.45",
                 "-o", "synth.chorus.nr=3",
                 "-F", str(wav_path), "-r", "44100",
                 str(sf2), str(midi_path)],
                capture_output=True, timeout=90,
            )
            if r.returncode == 0 and wav_path.exists():
                # Normalise + light compression so it sounds punchy
                subprocess.run(
                    ["ffmpeg", "-y", "-i", str(wav_path),
                     "-af", "loudnorm=I=-14:TP=-1.5:LRA=11",
                     "-b:a", "192k", str(mp3_path)],
                    capture_output=True, timeout=60,
                )
                wav_path.unlink(missing_ok=True)
                return mp3_path.exists()
    except Exception:
        pass
    return False


def _extract_dominant_pitch(audio_path: Path) -> float | None:
    """Use ffmpeg + numpy to get the dominant frequency from a voice note."""
    try:
        import numpy as np
        # Extract raw PCM
        result = subprocess.run(
            ["ffmpeg", "-y", "-i", str(audio_path),
             "-ar", "22050", "-ac", "1", "-f", "f32le", "-"],
            capture_output=True, timeout=30,
        )
        if result.returncode != 0 or not result.stdout:
            return None
        samples = np.frombuffer(result.stdout, dtype=np.float32)
        if len(samples) < 512:
            return None
        # Use autocorrelation on the middle third (skip silence at edges)
        mid_start = len(samples) // 3
        mid_end   = 2 * len(samples) // 3
        chunk     = samples[mid_start:mid_end]
        # Autocorrelation pitch detection
        sr = 22050
        corr = np.correlate(chunk, chunk, mode="full")
        corr = corr[len(corr) // 2:]
        # Min lag = sr/500 Hz (500Hz max), max = sr/60 Hz (60Hz min)
        lo = max(1, int(sr / 500))
        hi = min(len(corr) - 1, int(sr / 60))
        peak = lo + int(np.argmax(corr[lo:hi]))
        freq = sr / peak
        return float(freq)
    except Exception:
        return None


def _freq_to_midi_note(freq: float) -> int:
    """Convert frequency (Hz) to MIDI note number."""
    import math
    if freq <= 0:
        return 57  # A3 default
    midi = round(69 + 12 * math.log2(freq / 440.0))
    return max(36, min(84, midi))


