# ── Musical keys — every melody gets a random key ────────────────────────────
import random as _random
_MUSICAL_KEYS = [
    "C major", "C minor", "C# minor", "D major", "D minor",
    "Eb major", "Eb minor", "E major", "E minor",
    "F major", "F minor", "F# minor",
    "G major", "G minor", "Ab major", "Ab minor",
    "A major", "A minor", "Bb major", "Bb minor",
    "B major", "B minor",
]

def _random_key() -> str:
    """Pick a random musical key for variety — weighted toward minor keys (trap loves minor)."""
    minor_keys = [k for k in _MUSICAL_KEYS if "minor" in k]
    major_keys = [k for k in _MUSICAL_KEYS if "major" in k]
    # 70% minor, 30% major — trap is predominantly minor
    if _random.random() < 0.7:
        return _random.choice(minor_keys)
    return _random.choice(major_keys)


# ── Artist Database — load from JSON ─────────────────────────────────────────
def _load_artist_db() -> dict:
    """Load artist database from artist_db.json. Returns empty dict on failure."""
    _db_path = Path(__file__).parent / "artist_db.json"
    try:
        with open(_db_path) as f:
            return json.load(f)
    except Exception as e:
        log.error(f"Failed to load artist_db.json: {e}")
        return {"artists": {}, "categories": {}}

_ARTIST_DB = _load_artist_db()


def _save_artist_db():
    """Save artist database back to JSON (for adding new artists)."""
    _db_path = Path(__file__).parent / "artist_db.json"
    try:
        with open(_db_path, "w") as f:
            json.dump(_ARTIST_DB, f, indent=2, ensure_ascii=False)
    except Exception as e:
        log.error(f"Failed to save artist_db.json: {e}")


