async def _research_artist_albums(artist_name: str, category: str) -> tuple[dict, str]:
    """Use Claude to research an artist's REAL discography and sonic DNA.

    Returns (albums_dict, emoji) where albums_dict matches the artist_db format.
    NEVER returns generic prompts — even fallbacks are rich with musicological detail.

    Strategy:
      1. Try AI research (primary) — real albums with deep sonic DNA
      2. Retry once on failure
      3. If API completely unavailable, use category-specific rich fallbacks
         that still have real scales, modes, BPMs, instruments, and production details
    """
    import json as _json

    def _rich_fallback() -> tuple[dict, str]:
        """Category-specific rich fallback — still has deep musical detail, never generic."""
        cat_dna = _CATEGORY_FALLBACK_DNA.get(category, _CATEGORY_FALLBACK_DNA["atl_legends"])
        albums = {}
        for era_key, era_data in cat_dna.items():
            albums[era_key] = {
                "name": f"{era_key.replace('_', ' ').title()} — {artist_name}",
                "prompt": era_data["prompt_tpl"].format(name=artist_name),
            }
        return albums, "🎵"

    if not ANTHROPIC_API_KEY:
        log.warning(f"[research] No API key — using rich category fallback for {artist_name}")
        return _rich_fallback()

    _system_prompt = (
        "You are an elite musicologist and trap/hip-hop production expert. "
        "You have encyclopedic knowledge of every artist's discography, their producers, "
        "the scales and modes used in their music, their BPM ranges, signature instruments, "
        "chord voicings, and production techniques. You respond ONLY with valid JSON."
    )

    _user_prompt = (
        f'Research the artist/producer "{artist_name}" and create detailed album profiles '
        f"for AI instrumental melody generation.\n\n"
        f"CRITICAL RULES — follow ALL of these:\n"
        f"1. List their REAL albums/mixtapes/projects with correct years (up to 8, minimum 3)\n"
        f"2. For EACH album, write a 150-250 word ACE-Step melody generation prompt\n"
        f"3. Every single prompt MUST contain ALL of these — no exceptions:\n"
        f"   • Specific musical key: 'in C minor' or 'in F# minor' etc\n"
        f"   • Scale/mode name: Phrygian, Dorian, Aeolian, Mixolydian, harmonic minor, Lydian, etc\n"
        f"   • BPM range: '135-145 bpm'\n"
        f"   • Name at least one specific producer who worked on that album\n"
        f"   • Specific instruments: grand piano, Omnisphere bells, clean guitar, Rhodes, strings, etc\n"
        f"   • Chord characteristics: min7, add9, sus4, tritone, Phrygian flat-2, etc\n"
        f"   • Production techniques: reverb type (plate/hall/spring), distortion, filter sweeps, delay, etc\n"
        f"   • Reference at least one specific song title from that album\n"
        f"   • End EVERY prompt with: 'no drums, no vocals, instrumental melody'\n"
        f"4. Choose one perfect emoji for this artist\n\n"
        f"OUTPUT FORMAT — ONLY valid JSON, no markdown fences, no explanation:\n"
        f'{{"emoji": "🔥", "albums": {{"album_key": {{"name": "Album Title (Year)", '
        f'"prompt": "...detailed prompt..."}}}}}}\n\n'
        f"• album_key: lowercase snake_case, max 25 chars\n"
        f"• Each prompt: 150-250 words of deep musicological detail\n"
        f"• If you're unsure of this artist, create plausible era-based profiles "
        f"informed by the category '{category}' and their likely sound"
    )

    for attempt in range(2):  # Try twice
        try:
            import anthropic as _anthropic
            client = _anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)

            resp = await asyncio.get_event_loop().run_in_executor(
                None,
                lambda: client.messages.create(
                    model="claude-sonnet-4-20250514",
                    max_tokens=4000,
                    system=_system_prompt,
                    messages=[{"role": "user", "content": _user_prompt}],
                ),
            )

            raw = resp.content[0].text.strip()
            # Strip markdown fences if present
            for fence in ("```json", "```JSON", "```"):
                if raw.startswith(fence):
                    raw = raw[len(fence):]
                    break
            if raw.endswith("```"):
                raw = raw[:-3]
            raw = raw.strip()

            data = _json.loads(raw)
            albums = data.get("albums", {})
            emoji = data.get("emoji", "🎵")

            if not albums or not isinstance(albums, dict):
                log.warning(f"[research] Attempt {attempt+1}: empty albums for {artist_name}")
                continue

            # Validate — every album must have name + prompt with real musical detail
            valid_albums = {}
            for key, val in albums.items():
                if not isinstance(val, dict) or not val.get("name") or not val.get("prompt"):
                    continue
                p = val["prompt"].rstrip(". ")
                # Ensure prompt has real musical content (not generic filler)
                has_key = any(k in p.lower() for k in ["minor", "major", "phrygian", "dorian",
                             "aeolian", "mixolydian", "lydian", "harmonic"])
                has_bpm = "bpm" in p.lower()
                if not has_key or not has_bpm:
                    # Enrich thin prompts with category DNA
                    cat_dna = _CATEGORY_FALLBACK_DNA.get(category, _CATEGORY_FALLBACK_DNA["atl_legends"])
                    peak_dna = cat_dna.get("peak_era", {}).get("prompt_tpl", "")
                    # Splice in missing musical detail
                    if not has_key:
                        p += ", Aeolian minor with chromatic tension"
                    if not has_bpm:
                        p += ", 135-150 bpm"
                # Ensure proper ending
                if "no drums" not in p.lower():
                    p += ", no drums, no vocals, instrumental melody"
                valid_albums[key[:25]] = {"name": val["name"], "prompt": p}

            if len(valid_albums) < 2:
                log.warning(f"[research] Attempt {attempt+1}: only {len(valid_albums)} valid for {artist_name}")
                continue

            log.info(f"[research] AI generated {len(valid_albums)} rich albums for {artist_name}")
            return valid_albums, emoji

        except _json.JSONDecodeError as e:
            log.warning(f"[research] Attempt {attempt+1}: JSON parse failed for {artist_name}: {e}")
            continue
        except Exception as e:
            log.error(f"[research] Attempt {attempt+1}: failed for {artist_name}: {e}")
            if attempt == 0:
                await asyncio.sleep(2)  # Brief pause before retry
                continue
            break

    # Both attempts failed — use rich category fallback (still has real musical DNA)
    log.warning(f"[research] All attempts failed for {artist_name} — using rich category fallback")
    return _rich_fallback()


# ── Variation count options ──────────────────────────────────────────────────
_VARIATION_COUNTS = [1, 2, 3, 4, 5]


# ── Artist/Album picker keyboards ───────────────────────────────────────────
def _artist_category_keyboard() -> InlineKeyboardMarkup:
    """Top-level: pick a category of artists/producers."""
    cats = _ARTIST_DB.get("categories", {})
    rows = []
    for cat_key, cat_info in cats.items():
        # Count artists in this category
        count = sum(1 for a in _ARTIST_DB.get("artists", {}).values()
                    if a.get("category") == cat_key)
        rows.append([InlineKeyboardButton(
            f"{cat_info['emoji']} {cat_info['name']} ({count})",
            callback_data=f"ace_cat:{cat_key}",
        )])
    rows.append([
        InlineKeyboardButton("🔍 Search Artist", callback_data="ace_search"),
    ])
    rows.append([
        InlineKeyboardButton("🎹 Back to Styles", callback_data="melody_back_styles"),
    ])
    return InlineKeyboardMarkup(rows)


def _artist_list_keyboard(category: str, page: int = 0) -> InlineKeyboardMarkup:
    """List artists in a category, paginated."""
    artists = [(k, v) for k, v in _ARTIST_DB.get("artists", {}).items()
               if v.get("category") == category]
    artists.sort(key=lambda x: x[1]["name"])

    PAGE = 8
    total_pages = max(1, (len(artists) + PAGE - 1) // PAGE)
    start = page * PAGE
    chunk = artists[start:start + PAGE]

    rows = []
    pair = []
    for key, info in chunk:
        btn = InlineKeyboardButton(
            f"{info.get('emoji', '🎵')} {info['name']}",
            callback_data=f"ace_artist:{key}",
        )
        pair.append(btn)
        if len(pair) == 2:
            rows.append(pair)
            pair = []
    if pair:
        rows.append(pair)

    # Nav
    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("◀", callback_data=f"ace_artpage:{category}:{page-1}"))
    nav.append(InlineKeyboardButton(f"{page+1}/{total_pages}", callback_data="melody_noop"))
    if page < total_pages - 1:
        nav.append(InlineKeyboardButton("▶", callback_data=f"ace_artpage:{category}:{page+1}"))
    rows.append(nav)
    rows.append([
        InlineKeyboardButton("🔙 Categories", callback_data="ace_albums_menu"),
        InlineKeyboardButton("🔍 Search", callback_data="ace_search"),
    ])
    return InlineKeyboardMarkup(rows)


def _album_list_keyboard(artist_key: str) -> InlineKeyboardMarkup:
    """List albums for an artist."""
    artist = _ARTIST_DB.get("artists", {}).get(artist_key, {})
    albums = artist.get("albums", {})
    rows = []
    for alb_key, alb_info in albums.items():
        rows.append([InlineKeyboardButton(
            f"💿 {alb_info['name']}",
            callback_data=f"ace_album:{artist_key}:{alb_key}",
        )])
    rows.append([
        InlineKeyboardButton("🔙 Back", callback_data=f"ace_cat:{artist.get('category', 'atl_legends')}"),
    ])
    return InlineKeyboardMarkup(rows)


def _variation_count_keyboard(style_or_album_data: str) -> InlineKeyboardMarkup:
    """Ask how many variations (1-5). style_or_album_data is passed through."""
    rows = []
    row = []
    for n in _VARIATION_COUNTS:
        emoji = ["1️⃣", "2️⃣", "3️⃣", "4️⃣", "5️⃣"][n - 1]
        row.append(InlineKeyboardButton(
            f"{emoji} {n}",
            callback_data=f"ace_numvar:{n}:{style_or_album_data}",
        ))
        if len(row) == 3:
            rows.append(row)
            row = []
    if row:
        rows.append(row)
    rows.append([InlineKeyboardButton("🔙 Back", callback_data="melody_back_styles")])
    return InlineKeyboardMarkup(rows)


