def _scale_to_interval_names(full_scale: list[int]) -> str:
    """Convert MIDI integer list to interval name string for LLM musical context."""
    _IV = {0:"root",1:"b2",2:"maj2",3:"min3",4:"maj3",5:"p4",
           6:"tritone",7:"p5",8:"min6",9:"maj6",10:"min7",11:"maj7"}
    if not full_scale:
        return "unknown"
    root = full_scale[0] % 12
    seen, names = set(), []
    for n in full_scale:
        iv = (n - root) % 12
        if iv not in seen:
            seen.add(iv)
            names.append(_IV.get(iv, str(iv)))
    return ", ".join(names)


def _abc_to_phrase_notes(abc_str: str, scale_set: set[int], base_octave_midi: int,
                          vel_base: int = 88) -> list[tuple] | None:
    """
    Parse an ABC notation string into (midi, start_beat, dur_beats, velocity) tuples
    using music21. Snaps any out-of-key notes to nearest in-scale pitch.
    Returns None if parsing fails.
    """
    try:
        from music21 import converter as m21conv
        score = m21conv.parse(abc_str, format="abc")
        notes_out = []
        beat_pos   = 0.0
        for el in score.flatten().notesAndRests:
            dur_beats = float(el.duration.quarterLength)
            if el.isRest:
                beat_pos += dur_beats
                continue
            # el is a Note or Chord — take the highest pitch for melody
            if hasattr(el, "pitches"):
                pitch = max(el.pitches, key=lambda p: p.midi)
            else:
                pitch = el.pitch
            midi = pitch.midi
            # Octave-clamp to comfortable melody range (MIDI 48-96)
            while midi < 48:
                midi += 12
            while midi > 96:
                midi -= 12
            # Snap out-of-key to nearest in-scale
            if midi not in scale_set:
                midi = min(scale_set, key=lambda n: abs(n - midi))
            notes_out.append((midi, beat_pos, max(0.25, dur_beats), vel_base))
            beat_pos += dur_beats
        return notes_out if notes_out else None
    except Exception as _pe:
        log.debug("_abc_to_phrase_notes parse error: %s", _pe)
        return None


def _analyze_fy3pack_midi(path) -> str:
    """Read one fy3pack MIDI and return a compact 16-note sequence string for LLM context.
    Gives Claude a concrete example from the real library instead of abstract description.
    Returns empty string on any failure (non-blocking).
    """
    try:
        from music21 import converter as m21conv
        score = m21conv.parse(str(path))
        notes_out = []
        for el in score.flatten().notes:
            if hasattr(el, "pitch"):
                notes_out.append((el.pitch.nameWithOctave, round(float(el.quarterLength), 2)))
            elif hasattr(el, "pitches") and el.pitches:
                p = max(el.pitches, key=lambda x: x.midi)
                notes_out.append((p.nameWithOctave, round(float(el.quarterLength), 2)))
        return " | ".join(f"{n}({d})" for n, d in notes_out[:16])
    except Exception:
        return ""


def _ai_make_phrases(style: str, full_scale: list[int], bpm: int, root_name: str) -> dict | None:
    """
    Ask Claude Haiku to generate 4 melody phrases in ABC notation, then parse with
    music21 for strict music-theory validation.

    ABC notation is text-native — LLMs write it far more reliably than raw MIDI numbers.
    music21 validates pitch spelling, rhythm, and key adherence.

    Returns {"A": [...], "Ar": [...], "B": [...], "C": [...]}
    of (midi_note, start_beat, dur_beats, velocity) tuples.
    Returns None on any failure — caller falls back to hardcoded _make_phrase.
    """
    # Re-read API key live
    api_key = os.environ.get("ANTHROPIC_API_KEY", "").strip()
    env_file = ROOT / ".env"
    if env_file.exists():
        for _line in env_file.read_text().splitlines():
            if _line.strip().startswith("ANTHROPIC_API_KEY="):
                api_key = _line.strip().split("=", 1)[1].strip()
                break
    if not api_key or api_key == "YOUR_API_KEY_HERE":
        return None

    style_desc    = _AI_STYLE_DESCRIPTORS.get(style, _AI_STYLE_DESCRIPTOR_DEFAULT)
    interval_str  = _scale_to_interval_names(full_scale)
    groove_family = _STYLE_GROOVE.get(style, "trap")
    scale_set     = set(full_scale)
    base_midi     = full_scale[0] if full_scale else 69

    # ── Build ABC key signature from root + scale type ────────────────────────
    # music21 parses ABC key signatures like "K:Am" or "K:Dmaj"
    _M21_ROOTS = {
        "C":"C","C#":"C#","Db":"Db","D":"D","D#":"D#","Eb":"Eb",
        "E":"E","F":"F","F#":"F#","Gb":"Gb","G":"G","G#":"G#","Ab":"Ab",
        "A":"A","A#":"A#","Bb":"Bb","B":"B",
    }
    root_clean = root_name.replace("♭","b").replace("♯","#").strip() or "A"
    # Determine major/minor from scale intervals
    _intervals  = _MELODY_SCALES.get(style, [0,2,3,5,7,8,10])
    _is_minor   = 3 in _intervals and 4 not in _intervals  # has min3, no maj3
    abc_key     = f"{root_clean}{'m' if _is_minor else ''}"

    # ── Select prompt persona ─────────────────────────────────────────────────
    _CINEMATIC_FAMILIES = {"bap", "rnb"}
    _CINEMATIC_STYLES   = {"metro","kendrick","rodwave","nas","three6",
                           "popsmoke","boi1da","kaleel","dark","lofi"}
    is_cinematic = groove_family in _CINEMATIC_FAMILIES or style in _CINEMATIC_STYLES

    # ── ABC notation primer included in every prompt ──────────────────────────
    abc_primer = (
        "ABC NOTATION QUICK REFERENCE:\n"
        "- Notes: C D E F G A B (uppercase = octave 4, lowercase = octave 5)\n"
        "- Octave up: append ' (e.g. c' = C6). Octave down: append , (e.g. C, = C3)\n"
        "- Durations: C = quarter, C2 = half, C4 = whole, C/ = 8th, C// = 16th\n"
        "- Rest: z (e.g. z2 = half rest)\n"
        "- Bar line: |\n"
        "- Tie: - (e.g. C-C = tied quarter+quarter = half)\n"
        f"- Key signature: K:{abc_key} (already set — DO NOT add sharps/flats not in this key)\n"
        "- Time: 4/4 (4 quarter beats per bar)\n"
        "- Default note length: L:1/4 (each plain letter = 1 beat)\n\n"
        f"ALLOWED SCALE INTERVALS: {interval_str}\n"
        f"Root note: {root_clean}\n"
        "Every note MUST use only the pitches in this scale. No accidentals, no chromatic tones."
    )

    if is_cinematic:
        persona = (
            "You are an expert melodic composer in the style of AIVA — cinematic, emotionally "
            "intelligent, motif-driven. Generate a 16-bar melody in ABC notation with emotional "
            "dynamics and motif-based evolution.\n\n"
            "Principles:\n"
            "- Build arc: tension (A/Ar) → emotional peak (B) → resolution (C)\n"
            "- Transform motifs: invert, augment rhythmically, vary register\n"
            "- Expressive leaps (3+ semitones) that resolve naturally\n"
            "- Use rests dramatically — silence creates anticipation\n"
            "- Full dynamic range: quiet searching phrases vs. peak intensity\n"
            "- No mechanical repetition — every phrase evolves"
        )
    else:
        persona = (
            "You are an expert human producer-composer writing beats in the spirit of MusicLM — "
            "short motifs, street-level human phrasing, emotionally direct.\n\n"
            "Rules:\n"
            "- Build from 2-4 note motifs, repeat with variation\n"
            "- Each phrase needs at least one expressive leap (3+ semitones) that resolves\n"
            "- No straight scale runs. No constant stepwise motion.\n"
            "- Leave rests — don't fill every beat. Silence is rhythm.\n"
            "- Call (A) → variation (Ar) → contrast (B) → resolution (C)\n"
            "- Endings must feel earned, not obvious"
        )

    system_prompt = (
        f"{persona}\n\n"
        f"{abc_primer}\n\n"
        "OUTPUT FORMAT (strict):\n"
        "Return exactly 4 blocks, one per phrase, labeled with === markers:\n"
        "=== A ===\n"
        "X:1\nT:A\nM:4/4\nL:1/4\nQ:1/4=BPM\nK:KEY\n"
        "| bar1 | bar2 | bar3 | bar4 |\n"
        "=== Ar ===\n"
        "X:2\nT:Ar\nM:4/4\nL:1/4\nQ:1/4=BPM\nK:KEY\n"
        "| bar1 | bar2 | bar3 | bar4 |\n"
        "=== B ===\n"
        "X:3\nT:B\nM:4/4\nL:1/4\nQ:1/4=BPM\nK:KEY\n"
        "| bar1 | bar2 | bar3 | bar4 |\n"
        "=== C ===\n"
        "X:4\nT:C\nM:4/4\nL:1/4\nQ:1/4=BPM\nK:KEY\n"
        "| bar1 | bar2 | bar3 | bar4 |\n\n"
        f"Replace BPM with {bpm} and KEY with {abc_key}.\n"
        "No explanation. No extra text. Only the 4 labeled blocks."
    )

    # ── fy3pack style DNA — inject real fingerprint from analyzed MIDI library ──
    import random as _rand
    _fp = _FY3_STYLE_FINGERPRINT
    fingerprint_context = (
        "STYLE DNA from my analyzed MIDI library (fy3pack — 24 real trap/plugg loops):\n"
        f"- Primary interval: +2 semitones (whole step up) — most common move\n"
        f"- Freely repeat notes (0 semitones) — legato, connected feel, not robotic\n"
        f"- Use perfect 4ths (±5) and 5ths (±7) for larger expressive leaps\n"
        f"- 16th notes: 49% of all durations — fast, flowing rhythm\n"
        f"- 8th notes: 43% — for breathing room between runs\n"
        f"- Velocity: stay between {_fp['velocity_min']}–{_fp['velocity_max']}, avg {_fp['velocity_avg']}, slight variation only\n"
        f"- Melodic range: within ~2 octaves ({_fp['avg_range_semitones']} semitones)\n"
        f"- Ascending bias — phrases tend to climb, then resolve down\n"
        f"- This is modern trap/plugg production DNA\n"
    )
    # Sample a random fy3pack MIDI for a concrete note-sequence example
    _fy3_files = list(MELODIES_DIR.glob("*.mid"))
    if _fy3_files:
        _sample_path = _rand.choice(_fy3_files)
        _sample_seq  = _analyze_fy3pack_midi(_sample_path)
        if _sample_seq:
            fingerprint_context += (
                f"\nCONCRETE EXAMPLE from my library ({_sample_path.stem[:40]}):\n"
                f"{_sample_seq}\n"
                f"Generate something NEW in this style — same DNA, never copy this directly.\n"
            )

    user_prompt = (
        f"{fingerprint_context}\n"
        f"Style: {style} — {style_desc}\n"
        f"Key: {root_clean} ({abc_key})\n"
        f"Scale: {interval_str}\n"
        f"BPM: {bpm}\n\n"
        "Generate the 16-bar melody as 4 ABC notation phrases (A, Ar, B, C). "
        "Each phrase = exactly 4 bars. Strict in-key only. "
        "Use the fy3pack style DNA above to shape the rhythm and melodic feel."
    )

    try:
        import anthropic as _anthropic
        _client = _anthropic.Anthropic(api_key=api_key)
        _resp   = _client.messages.create(
            model="claude-haiku-4-5",
            max_tokens=1500,
            system=system_prompt,
            messages=[{"role": "user", "content": user_prompt}],
        )
        raw_text = _resp.content[0].text.strip()
    except Exception as _exc:
        log.warning("_ai_make_phrases: API error style=%s: %s", style, _exc)
        return None

    # ── Parse the 4 labeled blocks ────────────────────────────────────────────
    import re as _re
    result: dict[str, list] = {"A": [], "Ar": [], "B": [], "C": []}

    # Velocity map per phrase — builds the emotional arc
    _vel_map = {"A": 85, "Ar": 90, "B": 105, "C": 80}

    # Split on === markers
    _blocks = _re.split(r"===\s*(A|Ar|B|C)\s*===", raw_text)
    # _blocks[0] = preamble (discard), then alternating [label, content, label, content...]
    _block_dict: dict[str, str] = {}
    for _i in range(1, len(_blocks) - 1, 2):
        _label   = _blocks[_i].strip()
        _content = _blocks[_i + 1].strip() if _i + 1 < len(_blocks) else ""
        if _label in result:
            _block_dict[_label] = _content

    if not _block_dict:
        log.warning("_ai_make_phrases: no labeled blocks found for style=%s", style)
        return None

    for phrase_key in ["A", "Ar", "B", "C"]:
        abc_content = _block_dict.get(phrase_key, "")
        if not abc_content:
            log.warning("_ai_make_phrases: missing phrase %s for style=%s", phrase_key, style)
            result[phrase_key] = []
            continue

        # Ensure the ABC header lines are present
        if "X:" not in abc_content:
            abc_content = f"X:1\nT:{phrase_key}\nM:4/4\nL:1/4\nQ:1/4={bpm}\nK:{abc_key}\n{abc_content}"

        parsed = _abc_to_phrase_notes(abc_content, scale_set, base_midi,
                                       vel_base=_vel_map.get(phrase_key, 88))
        if parsed:
            result[phrase_key] = parsed
        else:
            log.warning("_ai_make_phrases: parse failed for phrase %s style=%s", phrase_key, style)
            result[phrase_key] = []

    # Reject if any phrase empty
    if any(len(v) == 0 for v in result.values()):
        log.warning("_ai_make_phrases: incomplete result for style=%s — falling back", style)
        return None

    return result


