def _humanize_notes(notes: list, bpm: int, groove_key: str = "trap") -> list:
    """
    Apply micro-timing, velocity shaping, swing, duration variation, and
    syncopation accents to make MIDI notes feel like a real producer programmed them.

    Extra groove emphasis:
    - Swing pushes off-beat 8ths late (strong in boom bap, subtle in trap)
    - Beat-1 of every bar gets a velocity boost (downbeat punch)
    - Random push accents simulate human finger-drumming emphasis
    - Duration varies ±dur_jitter so no two notes have identical gate length
    - Timing jitter is ±timing_jitter beats (scaled, so it feels proportional at any BPM)
    """
    import random
    profile       = _GROOVE_PROFILES.get(groove_key, _GROOVE_PROFILES["trap"])
    beat_sec      = 60.0 / bpm
    timing_jitter = profile["timing_jitter"] * beat_sec  # convert to beats
    vel_jitter    = profile["vel_jitter"]
    dur_jitter    = profile["dur_jitter"]
    swing_ratio   = profile["swing_ratio"]
    beat1_boost   = profile["beat1_boost"]
    push_prob     = profile["push_prob"]

    result = []
    for item in notes:
        if item is None:
            result.append(None)
            continue
        n, start, dur, vel = item

        # ── Micro-timing: random human imprecision ──────────────────────────
        t_off = random.uniform(-timing_jitter, timing_jitter)

        # ── Swing: push off-beat 8th notes late ────────────────────────────
        # Off-beat 8ths land near beat+0.5 — push them forward by swing_ratio
        frac = start % 1.0
        if 0.35 < frac < 0.65:
            t_off += swing_ratio
        # Also swing 16th-note "e" positions (0.25) slightly
        elif 0.15 < frac < 0.35:
            t_off += swing_ratio * 0.4

        new_start = max(0.0, start + t_off)

        # ── Velocity: dynamic accent shaping ───────────────────────────────
        v_off = random.randint(-vel_jitter, vel_jitter)

        # Downbeat (beat 1 of every bar = beat position divisible by 4)
        if (start % 4.0) < 0.15:
            v_off += beat1_boost

        # Beat 3 gets a mild accent too (backbeat feel)
        elif abs((start % 4.0) - 2.0) < 0.15:
            v_off += beat1_boost // 2

        # Random syncopation push — makes it feel like the producer leaned in
        if random.random() < push_prob:
            v_off += random.randint(4, 10)

        new_vel = max(40, min(127, vel + v_off))

        # ── Duration: no two notes have identical gate length ───────────────
        new_dur = max(0.05, dur * (1.0 + random.uniform(-dur_jitter, dur_jitter)))

        result.append((n, new_start, new_dur, new_vel))
    return result


def _build_fy3pack_phrase(phrase_type: str, scale: list, bpm: int) -> list:
    """
    Data-driven splice-loop phrase builder for the fy3pack style.

    Bypasses ABC notation and LLM entirely — directly generates note tuples
    using the real statistical DNA extracted from 24 @liljan loop kit MIDIs:
      - Rhythm cells weighted from real occurrence counts
      - Intervals weighted from real interval histogram (1,727 notes)
      - Velocity: gaussian(93, 8) clamped to 78–107
      - Pitch range: MIDI 57–82 (comfortable 2-octave melody window)
      - 26% rest density — breathing room, not wall-to-wall notes
      - 63% rhythm cell repetition — loopable, motif-based

    Returns list of (midi_note, start_beat, dur_beats, velocity) tuples.
    Rests are represented as None (skipped by caller).
    """
    import random as _r

    # ── Helpers ──────────────────────────────────────────────────────────────
    def _weighted_choice(weighted_list):
        """Pick item from [(value, weight), ...] list."""
        total = sum(w for _, w in weighted_list)
        r = _r.random() * total
        acc = 0
        for val, w in weighted_list:
            acc += w
            if r <= acc:
                return val
        return weighted_list[-1][0]

    # Build the full valid pitch set from the actual scale (never returns C by accident)
    _scale_set = set()
    for _oct in range(-3, 5):
        for _s in scale:
            _n = _s + (_oct * 12)
            if 45 <= _n <= 95:
                _scale_set.add(_n)
    # Emergency fallback: if scale is empty, use chromatic in range
    if not _scale_set:
        _scale_set = set(range(57, 83))

    def _snap_to_scale(midi_note):
        """Clamp pitch to nearest valid in-scale note in MIDI 57–82 window."""
        midi_note = max(57, min(82, midi_note))
        return min(_scale_set, key=lambda n: (abs(n - midi_note), n))

    def _vel():
        """Velocity: tight gaussian centered on 93, clamped 78–107."""
        return max(78, min(107, int(_r.gauss(93, 8))))

    # ── Build seed motif (2–4 notes) ─────────────────────────────────────────
    # Phrase A: ascending bias from a mid-range start pitch
    # Phrase B: contrast — start lower, use a leap
    # Phrase Ar: A transposed up 1–3 semitones + 16th shift
    # Phrase C: return to A motif, end on a held note

    # Start pitch: land near scale[1] or scale[2] (mid-scale, not root)
    mid_pitch = _snap_to_scale(scale[min(2, len(scale)-1)] if scale else 69)

    motif_length = _r.choice([2, 3, 3, 4, 4])  # 3–4 note motifs are most common
    motif_pitches = [mid_pitch]
    for _ in range(motif_length - 1):
        delta = _weighted_choice(_FY3_INTERVAL_WEIGHTS)
        next_p = _snap_to_scale(motif_pitches[-1] + delta)
        motif_pitches.append(next_p)

    # Phrase-specific motif variations
    if phrase_type == "Ar":
        # Transpose up 1–3 semitones
        shift = _r.choice([1, 2, 2, 3])
        motif_pitches = [_snap_to_scale(p + shift) for p in motif_pitches]
    elif phrase_type == "B":
        # Contrast: start from a different scale degree, add a larger leap
        b_start = _snap_to_scale(scale[min(4, len(scale)-1)] if len(scale) > 4 else mid_pitch - 5)
        motif_pitches = [b_start]
        for _ in range(motif_length - 1):
            # Bias toward larger intervals (4ths, 5ths) for contrast
            contrast_weights = [(d, w) for d, w in _FY3_INTERVAL_WEIGHTS if abs(d) >= 3]
            delta = _weighted_choice(contrast_weights) if contrast_weights else _weighted_choice(_FY3_INTERVAL_WEIGHTS)
            motif_pitches.append(_snap_to_scale(motif_pitches[-1] + delta))
    elif phrase_type == "C":
        # Return to A motif — same as A, end phrase on held note
        pass  # motif_pitches stays as A

    # ── Pick the primary rhythm cell ─────────────────────────────────────────
    primary_cell = _weighted_choice(_FY3_RHYTHM_CELLS)

    # Phrase Ar: shift rhythm by one 16th (subtle variation)
    if phrase_type == "Ar":
        shifted = primary_cell[1:] + (primary_cell[0],)
        primary_cell = shifted

    # ── Build 4 bars (16 beats) of notes ─────────────────────────────────────
    bars_per_phrase = 4
    total_beats = bars_per_phrase * 4   # 16 beats
    notes = []
    beat_pos = 0.0
    repeat_prob = 0.65   # 65% chance to repeat the same motif+cell each iteration

    motif_idx = 0        # which pitch in the motif we're at
    cell_idx  = 0        # which duration in the cell we're at
    current_motif  = list(motif_pitches)
    current_cell   = list(primary_cell)

    while beat_pos < total_beats - 0.01:
        remaining = total_beats - beat_pos

        # Maybe insert a rest (26% of timeline) — preferably 16th or 8th rests
        rest_choices = [0.25, 0.25, 0.5, 0.5, None, None, None, None]  # weighted toward no rest
        if _r.random() < 0.26 and remaining > 0.5:
            rest_dur = _r.choice([0.25, 0.5])
            rest_dur = min(rest_dur, remaining)
            beat_pos += rest_dur
            notes.append(None)   # rest marker
            continue

        # Maybe mutate the motif (37% of the time — matches 63% repeat ratio)
        if _r.random() > repeat_prob and len(current_motif) > 0:
            delta = _weighted_choice(_FY3_INTERVAL_WEIGHTS)
            new_p = _snap_to_scale(current_motif[motif_idx % len(current_motif)] + delta)
            current_motif[motif_idx % len(current_motif)] = new_p

        # Pick pitch from current motif position
        pitch = current_motif[motif_idx % len(current_motif)]
        motif_idx += 1

        # Prevent boring consecutive repeats: max 2 in a row, then force a step
        _recent = [n for n in notes[-2:] if n is not None]
        if len(_recent) >= 2 and all(isinstance(x, tuple) and x[0] == pitch for x in _recent):
            # Force a step move — pick a non-unison interval
            step_weights = [(d, w) for d, w in _FY3_INTERVAL_WEIGHTS if d != 0]
            delta = _weighted_choice(step_weights)
            pitch = _snap_to_scale(pitch + delta)

        # Pick duration from current cell position
        dur = current_cell[cell_idx % len(current_cell)]
        cell_idx += 1

        # On phrase C's last bar: end on a held note
        if phrase_type == "C" and beat_pos >= total_beats - 4.0:
            remaining_beats = total_beats - beat_pos
            if remaining_beats >= 1.0:
                dur = min(remaining_beats, _r.choice([1.0, 2.0]))
                # Return to root note for resolution
                pitch = _snap_to_scale(scale[0] if scale else 69)

        dur = min(dur, remaining)
        if dur < 0.1:
            break

        vel = _vel()
        notes.append((pitch, beat_pos, dur, vel))
        beat_pos += dur

    return notes


def _build_melody_midi(root_note: int, style: str = "dark", bars: int = 16, bpm: int = 140,
                        instr_override: int | None = None, root_name: str = "") -> Path:
    """
    Generate a 16-bar MIDI melody with full song structure:
    A (bars 1-4) → Ar (5-8) → B (9-12) → C/resolution (13-16)
    Returns path to the .mid file.
    instr_override: MIDI program number to override the style default.
    root_name: human-readable key name (e.g. "A", "C#") passed to AI composer for context.
    """
    from midiutil import MIDIFile

    scale_intervals = _MELODY_SCALES.get(style, _MELODY_SCALES["dark"])
    # Land in a comfortable octave — octave 5 (MIDI 60-72) for leads
    base  = (root_note % 12) + 60
    scale = [base + i for i in scale_intervals]
    # Also include the octave above for reach notes
    scale_hi = [n + 12 for n in scale]
    full_scale = scale + scale_hi

    # Instrument: user override > style default > fallback
    instr = instr_override if instr_override is not None else _STYLE_INSTRUMENT.get(style, 4)

    import random as _rng

    beats_per_bar = 4
    phrase_beats  = beats_per_bar * 4  # 4 bars per phrase
    groove_key    = _STYLE_GROOVE.get(style, "trap")

    # ── fy3pack: SINGLE-TRACK splice-loop output (no bass, no pad) ───────────
    # Splice loops are melody only — bass/pad tracks ruin the clean loop sound.
    if style == "fy3pack":
        midi = MIDIFile(1)
        midi.addTempo(0, 0, bpm)
        midi.addProgramChange(0, 0, 0, instr)

        # Build all-in-scale lookup for strict pitch enforcement
        _fy3_scale_set = set()
        for _oct in range(-2, 4):
            for _s in full_scale:
                _n = _s + (_oct * 12)
                if 50 <= _n <= 90:
                    _fy3_scale_set.add(_n)

        for phrase_idx, phrase_type in enumerate(["A", "Ar", "B", "C"]):
            phrase_start = float(phrase_idx * phrase_beats)
            raw_notes = _build_fy3pack_phrase(phrase_type, full_scale, bpm)
            # Apply light plugg humanization (no swing — splice loops are straight)
            humanized = _humanize_notes(raw_notes, bpm, "plugg")
            prev_pitch = None
            for item in humanized:
                if item is None:
                    continue
                n, start, dur, vel = item
                # Strict scale enforcement — snap any out-of-key note
                if n not in _fy3_scale_set:
                    n = min(_fy3_scale_set, key=lambda x: (abs(x - n), x)) if _fy3_scale_set else n
                # No more than 3 consecutive identical pitches (prevents boring repeats)
                if n == prev_pitch:
                    candidates = [x for x in _fy3_scale_set if x != n and abs(x - n) <= 5]
                    if candidates:
                        n = min(candidates, key=lambda x: abs(x - n))
                prev_pitch = n
                n = max(50, min(90, n))
                midi.addNote(0, 0, n, phrase_start + start, max(0.05, dur), vel)

        tmp = tempfile.NamedTemporaryFile(suffix=".mid", delete=False, dir=ROOT / "output")
        with open(tmp.name, "wb") as f:
            midi.writeFile(f)
        return Path(tmp.name)

    # ── All other styles: original 3-track path ───────────────────────────────
    # 3 tracks: 0=lead melody, 1=bass, 2=chord pad
    midi = MIDIFile(3)

    # ── Track 0: Lead melody ────────────────────────────────────────────────
    track = 0
    midi.addTempo(track, 0, bpm)
    midi.addProgramChange(track, 0, 0, instr)

    # ── Try AI human-composer first; fall back to hardcoded if unavailable ──────
    _ai_phrases = _ai_make_phrases(style, full_scale, bpm, root_name or "A")
    if _ai_phrases is not None:
        log.info("melody: AI phrases generated for style=%s root=%s", style, root_name)
    else:
        log.info("melody: using hardcoded fallback for style=%s", style)

    for phrase_idx, phrase_type in enumerate(["A", "Ar", "B", "C"]):
        phrase_start = phrase_idx * phrase_beats
        if _ai_phrases is not None:
            phrase_notes = _ai_phrases[phrase_type]
        else:
            phrase_notes = _make_phrase(style, phrase_type, full_scale)
        # Apply groove humanization — adds micro-timing, swing, velocity shaping
        phrase_notes = _humanize_notes(phrase_notes, bpm, groove_key)
        for item in phrase_notes:
            if item is None:
                continue
            n, start, dur, vel = item
            n = max(36, min(96, n))
            midi.addNote(track, 0, n, phrase_start + start, max(0.05, dur), vel)

    # ── Track 1: Bass ───────────────────────────────────────────────────────
    # Root note on beats 1 and 3, with slight timing variation for groove
    midi.addTempo(1, 0, bpm)
    bass_instr = 33   # GM 33 = Finger Bass (warm, punchy)
    midi.addProgramChange(1, 1, 0, bass_instr)
    bass_root = max(36, min(55, base - 12))   # one octave below lead base

    for bar in range(bars):
        bar_start = float(bar * beats_per_bar)
        # Beat 1 — hard hit
        midi.addNote(1, 1, bass_root,
                     bar_start + _rng.uniform(-0.015, 0.015),
                     _rng.uniform(0.80, 0.95),
                     _rng.randint(90, 108))
        # Beat 3 — slightly softer, slight variation
        midi.addNote(1, 1, bass_root,
                     bar_start + 2.0 + _rng.uniform(-0.015, 0.015),
                     _rng.uniform(0.70, 0.85),
                     _rng.randint(78, 96))
        # Occasional beat-2.5 ghost for plugg/rnb groove feel
        if groove_key in ("plugg", "rnb") and _rng.random() < 0.35:
            midi.addNote(1, 1, bass_root,
                         bar_start + 1.5 + _rng.uniform(-0.01, 0.01),
                         0.25,
                         _rng.randint(55, 70))

    # ── Track 2: Chord Pad ──────────────────────────────────────────────────
    # Root + 5th sustained chord every 2 bars — fills the frequency space
    midi.addTempo(2, 0, bpm)
    # Cinematic styles get strings (49), others get Warm Pad (89)
    _cinematic = {"metro", "ti_atl", "rodwave", "popsmoke", "polog", "three6",
                  "centralcee", "headieone", "boi1da", "kendrick", "nas"}
    pad_instr = 49 if style in _cinematic else 89
    midi.addProgramChange(2, 2, 0, pad_instr)

    pad_root  = max(36, min(60, base - 12))
    pad_fifth = full_scale[4] if len(full_scale) > 4 else pad_root + 7
    chord_dur = beats_per_bar * 2 - 0.1   # sustain for 2 bars

    for phrase_idx in range(4):
        for half in range(2):
            c_start = float(phrase_idx * phrase_beats + half * beats_per_bar * 2)
            # Velocity varies phrase to phrase — swells and fades for dynamics
            pad_vel = _rng.randint(48, 62) if half == 0 else _rng.randint(42, 55)
            for pn in [pad_root, pad_fifth]:
                midi.addNote(2, 2, max(36, min(84, pn)),
                             c_start + _rng.uniform(0.0, 0.02),
                             chord_dur,
                             pad_vel)

    tmp = tempfile.NamedTemporaryFile(suffix=".mid", delete=False, dir=ROOT / "output")
    with open(tmp.name, "wb") as f:
        midi.writeFile(f)
    return Path(tmp.name)


