def _ace_instr_keyboard(style: str, bpm: int) -> InlineKeyboardMarkup:
    """Instrument picker for ACE-Step — regenerates with chosen instrument."""
    rows = []
    pair = []
    # Fix #61: Telegram callback_data max is 64 bytes
    # "ace_instr_pick:" = 15, so style+bpm+tag must fit in 49 chars
    s = style[:20]
    for lbl, tag, emoji in _ACE_INSTRUMENTS:
        btn = InlineKeyboardButton(
            f"{emoji} {lbl}",
            callback_data=f"ace_instr_pick:{s}:{bpm}:{tag[:18]}"
        )
        pair.append(btn)
        if len(pair) == 2:
            rows.append(pair)
            pair = []
    if pair:
        rows.append(pair)
    rows.append([InlineKeyboardButton("🎹 Back to Styles", callback_data="melody_back_styles")])
    return InlineKeyboardMarkup(rows)


def _build_ace_prompt(style: str, custom_prompt: str = "",
                      instrument_override: str | None = None,
                      note_name: str = "") -> str:
    """Build the final ACE-Step prompt with quality suffix and overrides."""
    prompt = _ACESTEP_STYLES.get(style, "dark trap melody, no drums, no vocals, instrumental melody")
    if style == "ace_custom" and custom_prompt:
        prompt = custom_prompt
        if "no drums" not in prompt.lower():
            prompt += ", no drums"
        if "no vocals" not in prompt.lower():
            prompt += ", no vocals"
        if "instrumental" not in prompt.lower():
            prompt += ", instrumental"
    elif style == "ace_custom":
        prompt = "dark cinematic trap melody, minor key, piano and strings, atmospheric, no drums, no vocals, instrumental melody"

    # Instrument override — prepend to guide the generation
    if instrument_override:
        prompt = f"{instrument_override} melody, " + prompt

    # Key from humming
    if note_name:
        prompt += f", {note_name}"

    # Quality suffix for richer, more human-sounding output
    prompt += _ACE_QUALITY_SUFFIX
    return prompt


def _ace_variation_keyboard(style: str, bpm: int, num_vars: int) -> InlineKeyboardMarkup:
    """Variation picker — pick one favorite or select multiple for batch track-out."""
    var_emojis = ["1️⃣", "2️⃣", "3️⃣", "4️⃣", "5️⃣"]
    rows = []
    # Row of pick buttons
    pick_row = []
    for i in range(num_vars):
        pick_row.append(InlineKeyboardButton(
            f"{var_emojis[i]} Pick V{i+1}",
            callback_data=f"ace_var:{style}:{bpm}:{i}",
        ))
    rows.append(pick_row)
    # Batch track-out — MIDI + stems for ALL variations at once
    rows.append([
        InlineKeyboardButton("📦 Track-Out ALL (MIDI+Stems)", callback_data="ace_batch_trackout"),
    ])
    # Action buttons
    rows.append([
        InlineKeyboardButton(f"🔄 Regen All {num_vars}", callback_data=f"melody_regen:{style}:{bpm}"),
        InlineKeyboardButton("🎹 Change Style", callback_data="melody_back_styles"),
    ])
    rows.append([
        InlineKeyboardButton("🎸 Change Instrument", callback_data=f"ace_instr:{style}:{bpm}"),
        InlineKeyboardButton("📝 Change BPM", callback_data=f"melody_bpm:{style}"),
    ])
    rows.append([
        InlineKeyboardButton("❌ Done", callback_data="melody_done"),
    ])
    return InlineKeyboardMarkup(rows)


async def _do_generate_acestep(target_msg, context, style: str, bpm: int,
                               instrument_override: str | None = None,
                               album_prompt: str | None = None,
                               album_label: str | None = None,
                               num_variations: int | None = None):
    """Generate melody variations via ACE-Step AI — 60s WAV each, unique per variation.

    Each variation gets a DIFFERENT key, slightly shifted BPM, and unique prompt
    mutations so they sound genuinely different — not just different seeds.
    Output: lossless WAV at 48kHz, 27 inference steps, guidance_scale 7.0.
    """
    import datetime as _dt

    style_label = album_label or next(
        (lbl for lbl, sk, _, _ in _MELODY_STYLES if sk == style), style.replace("ace_", "").title()
    )
    note_name = context.user_data.get("melody_note_name", "")
    note_str = f" in *{note_name}*" if note_name else ""

    # How many variations
    n_vars = num_variations or context.user_data.get("ace_num_variations", 3)
    n_vars = max(1, min(5, n_vars))

    # Pick a random key for this generation (unless user hummed one)
    if note_name:
        key_scale = f"{note_name} minor"
    else:
        key_scale = _random_key()
    key_display = key_scale

    # Build prompt — album prompt overrides style prompt
    if album_prompt:
        prompt = album_prompt + _ACE_QUALITY_SUFFIX
        if instrument_override:
            prompt = f"{instrument_override} melody, " + prompt
        if note_name:
            prompt += f", {note_name}"
    else:
        custom_prompt = context.user_data.get("ace_custom_prompt", "")
        prompt = _build_ace_prompt(style, custom_prompt, instrument_override, note_name)

    # Instrument label for display
    instr_label = ""
    if instrument_override:
        instr_label = f" — *{instrument_override}*"

    # Time estimate: ~60s per variation at 27 steps (sequential individual tasks)
    est_time = n_vars * 60
    est_str = f"~{est_time // 60}m {est_time % 60}s" if est_time >= 60 else f"~{est_time}s"

    try:
        await safe_edit(
            target_msg,
            f"🤖 *ACE-Step AI* generating *{n_vars} unique variation{'s' if n_vars > 1 else ''}*\n"
            f"🎹 *{style_label}*{instr_label}{note_str}\n"
            f"🎵 _60s WAV × {n_vars} — each in a different key & feel_\n"
            f"⏳ _{est_str} — sit tight_",
            parse_mode="Markdown",
        )
    except Exception:
        pass

    # Generate — returns list of dicts with path/key/bpm per variation
    variation_results = await _acestep_submit_and_poll(
        prompt, bpm, key_scale, target_msg, style_label, note_str,
        duration=60, num_variations=n_vars,
    )
    if not variation_results:
        return

    # Store all variations — now dicts with path/key/bpm
    var_paths = [v["path"] for v in variation_results]
    context.user_data["ace_variations"] = var_paths
    context.user_data["ace_variation_info"] = variation_results  # full info
    context.user_data["ace_last_mp3"] = var_paths[0]
    context.user_data["ace_last_style"] = style
    context.user_data["ace_last_bpm"] = bpm
    context.user_data["ace_last_key"] = key_display

    # Send each variation with its unique key/BPM info
    var_emojis = ["1️⃣", "2️⃣", "3️⃣", "4️⃣", "5️⃣"]
    for i, vr in enumerate(variation_results):
        v_key = vr["key"]
        v_bpm = vr["bpm"]
        vp = Path(vr["path"])
        if not vp.exists() or vp.stat().st_size == 0:
            log.warning(f"_do_generate_acestep: V{i+1} file missing or empty")
            continue
        fsize = vp.stat().st_size
        caption = (
            f"{var_emojis[i]} *Variation {i+1}* — *{style_label}*{instr_label}\n"
            f"🎵 {v_bpm}bpm  |  {v_key}  |  60s WAV  |  ACE-Step 1.5"
        )
        try:
            if fsize > 50 * 1024 * 1024:
                # Too large for reply_audio — send as document
                with open(vr["path"], "rb") as f:
                    await target_msg.reply_document(
                        document=f,
                        filename=f"ai_{style}_{v_bpm}bpm_{v_key.replace(' ', '')}_{i+1}.wav",
                        caption=caption,
                        parse_mode="Markdown",
                    )
            else:
                with open(vr["path"], "rb") as f:
                    await target_msg.reply_audio(
                        audio=f,
                        filename=f"ai_{style}_{v_bpm}bpm_{v_key.replace(' ', '')}_{i+1}.wav",
                        caption=caption,
                        parse_mode="Markdown",
                        title=f"{style_label} V{i+1} {v_bpm}bpm {v_key}",
                        performer="LeekThatsFye AI",
                    )
        except Exception as e:
            log.warning(f"_do_generate_acestep: variation {i+1} send failed: {e}")
            # Fallback: try as document
            try:
                with open(vr["path"], "rb") as f:
                    await target_msg.reply_document(
                        document=f,
                        filename=f"ai_{style}_{v_bpm}bpm_{v_key.replace(' ', '')}_{i+1}.wav",
                        caption=caption,
                        parse_mode="Markdown",
                    )
            except Exception as e2:
                log.warning(f"_do_generate_acestep: V{i+1} document fallback also failed: {e2}")

    if len(variation_results) == 1:
        # Single variation — go straight to action buttons
        context.user_data["ace_last_mp3"] = var_paths[0]
        vr = variation_results[0]
        await target_msg.reply_text(
            f"🔥 *{style_label}* in *{vr['key']}* @ *{vr['bpm']}bpm* delivered!\n\n"
            f"Extract MIDI, stems, change instrument, or generate again:",
            parse_mode="Markdown",
            reply_markup=_ace_regen_keyboard(style, bpm),
        )
    else:
        # Build key summary for all variations
        key_summary = " · ".join(
            f"V{vr['var_index']+1}={vr['key']}" for vr in variation_results
        )
        await target_msg.reply_text(
            f"🔥 *{len(variation_results)} unique variations* of *{style_label}*\n"
            f"🎵 _{key_summary}_\n\n"
            f"👆 Listen to all {len(variation_results)} above, then *pick your favorite(s)*.\n"
            f"Pick one for MIDI/stems, or *select multiple* for batch track-out.",
            parse_mode="Markdown",
            reply_markup=_ace_variation_keyboard(style, bpm, len(variation_results)),
        )


async def _do_generate(target_msg, context, style: str, bpm: int):
    """Core: build MIDI, send audio+MIDI, show regen buttons — bulletproof."""
    root_note  = context.user_data.get("melody_root_note", 57)
    note_name  = context.user_data.get("melody_note_name", "")
    instr_prog = context.user_data.get("melody_instr_override")   # None = use style default

    style_label   = next((lbl for lbl, sk, _, _ in _MELODY_STYLES if sk == style), style.title())
    instr_label   = next((lbl for lbl, p, _ in _INSTRUMENTS if p == instr_prog), None) if instr_prog is not None else None
    note_str      = f" in *{note_name}*" if note_name else ""
    instr_str     = f" — *{instr_label}*" if instr_label else ""

    # Status message
    try:
        await safe_edit(
            target_msg,
            f"🎹 Generating *{style_label}*{note_str}{instr_str} @ *{bpm}bpm*…",
            parse_mode="Markdown",
        )
    except Exception:
        pass

    # Generate MIDI (thread pool — won't block the event loop)
    try:
        midi_path = await asyncio.get_event_loop().run_in_executor(
            None, _build_melody_midi, root_note, style, 16, bpm, instr_prog, note_name
        )
    except Exception as e:
        await target_msg.reply_text(f"❌ MIDI generation failed: {e}")
        return

    mp3_path  = midi_path.with_suffix(".mp3")
    converted = await asyncio.get_event_loop().run_in_executor(
        None, _midi_to_mp3, midi_path, mp3_path, style
    )

    caption = (
        f"🎹 *{style_label} Melody*{note_str}{instr_str}\n"
        f"BPM: {bpm}  |  16 bars  |  A→B→A'→C\n\n"
        f"_Drop the MIDI into FL Studio, assign any plugin — done._"
    )

    sent_audio = False
    try:
        if converted and mp3_path.exists():
            with open(mp3_path, "rb") as f:
                await target_msg.reply_audio(
                    audio=f,
                    filename=f"melody_{style}_{bpm}bpm.mp3",
                    caption=caption,
                    parse_mode="Markdown",
                    title=f"{style_label} {bpm}bpm",
                    performer="LeekThatsFye AI",
                )
            sent_audio = True
    except Exception as e:
        log.warning("_do_generate: mp3 send failed: %s", e)

    # ── Save a permanent copy to fy3pack/ folder ───────────────────────────────
    import re as _re, datetime as _dt
    _ts       = _dt.datetime.now().strftime("%Y%m%d_%H%M%S")
    _key_part = f"_{note_name}" if note_name else ""
    _instr_part = f"_{_re.sub(r'[^a-z0-9]', '', (instr_label or '').lower())}" if instr_label else ""
    _save_stem = f"{_ts}_{style}{_key_part}_{bpm}bpm{_instr_part}"
    _saved_mid  = MELODIES_DIR / f"{_save_stem}.mid"
    _saved_mp3  = MELODIES_DIR / f"{_save_stem}.mp3"
    try:
        import shutil
        shutil.copy2(midi_path, _saved_mid)
        if converted and mp3_path.exists():
            shutil.copy2(mp3_path, _saved_mp3)
    except Exception as e:
        log.warning("melody save to folder failed: %s", e)

    # Always send MIDI
    midi_sent = False
    try:
        with open(midi_path, "rb") as f:
            await target_msg.reply_document(
                document=f,
                filename=f"{_save_stem}.mid",
                caption="🎹 MIDI — drag into FL Studio" if sent_audio else caption,
                parse_mode="Markdown" if not sent_audio else None,
            )
        midi_sent = True
    except Exception as e:
        log.error("_do_generate: MIDI send failed: %s", e)

    # Cleanup temp files (saved copies are in melodies/ already)
    for p in [midi_path, mp3_path]:
        try:
            if p and p.exists():
                p.unlink()
        except Exception:
            pass

    if not midi_sent:
        await target_msg.reply_text("❌ Couldn't send melody files. Try again.")

    # Show the regen/action keyboard in a fresh message so it's always at the bottom
    regen_label = instr_label or style_label
    await target_msg.reply_text(
        f"✅ *{regen_label}* melody delivered!\n_Saved to `🔥 fy3pack/` folder_ 💾\n\nWhat next?",
        parse_mode="Markdown",
        reply_markup=_regen_keyboard(style, bpm),
    )


async def melody_cancel(update: Update, context: ContextTypes.DEFAULT_TYPE):
    for k in ["melody_root_note","melody_note_name","melody_instr_override",
              "melody_waiting_voice","melody_last_style","melody_last_bpm",
              "melody_waiting_bpm","melody_bpm_style"]:
        context.user_data.pop(k, None)
    target = update.message or (update.callback_query and update.callback_query.message)
    if target:
        try:
            await target.reply_text("❌ Melody session cancelled. Use /melody to start again.")
        except Exception:
            pass
    return ConversationHandler.END


# ── /batchmelody ──────────────────────────────────────────────────────────────
BATCHMEL_WAITING = 65   # waiting for custom count text input


async def _run_batch_melody(target_msg, context, count: int, style_filter: str | None = None):
    """Generate `count` melodies via ACE-Step AI. Optional style_filter limits to one style."""
    import random as _rb

    # Pick styles
    if style_filter and style_filter != "__random__":
        # Single artist — generate N variations of that style
        info = _STYLE_KEY_TO_INFO.get(style_filter)
        if not info:
            await target_msg.reply_text(f"⚠️ Unknown style: {style_filter}")
            return
        picks = [info] * count
    else:
        # Random — pick N different styles
        pool = _MELODY_STYLES[:]
        _rb.shuffle(pool)
        picks = pool[:count]

    status = await target_msg.reply_text(
        f"🤖 *ACE-Step Batch — generating {count} melodies…* (0/{count})\n"
        f"_~{count}min — each melody is 60s WAV_",
        parse_mode="Markdown",
    )

    done, failed = 0, 0
    for i, (label, style, bpm, emoji) in enumerate(picks, 1):
        await safe_edit(
            status,
            f"🤖 *ACE-Step Batch* ({i}/{count})\n"
            f"Current: {emoji} *{esc(label)}* @ {bpm}bpm\n"
            f"✅ Done: {done}  ❌ Failed: {failed}",
            parse_mode="Markdown",
        )
        try:
            # Generate 1 variation per style for batch speed
            context.user_data["ace_num_variations"] = 1
            await _do_generate_acestep(target_msg, context, style, bpm, num_variations=1)
            done += 1
        except Exception as _be:
            log.warning("batchmelody: %s failed: %s", style, _be)
            await target_msg.reply_text(
                f"⚠️ *{esc(label)}* failed: `{esc(str(_be)[:100])}`",
                parse_mode="Markdown",
            )
            failed += 1

    await safe_edit(
        status,
        f"✅ *Batch complete!* {done}/{count} ACE-Step melodies generated\n"
        f"All 60s WAVs are above 👆",
        parse_mode="Markdown",
    )


BATCHMEL_STYLE = 66   # waiting for artist/style pick after count

