def _batchmel_style_kb() -> InlineKeyboardMarkup:
    """Build style picker for batch melody — categories + All Random."""
    rows = [[InlineKeyboardButton(
        "🎲 All Random (mixed styles)",
        callback_data="bmelstyle:__random__"
    )]]
    pair = []
    for i, (emoji, label, keys) in enumerate(_STYLE_CATEGORIES):
        short = f"{emoji} {label.split('/')[0].strip()[:14]}"
        btn = InlineKeyboardButton(short, callback_data=f"bmelcat:{i}")
        pair.append(btn)
        if len(pair) == 2:
            rows.append(pair)
            pair = []
    if pair:
        rows.append(pair)
    return InlineKeyboardMarkup(rows)


def _batchmel_artist_kb(cat_idx: int) -> InlineKeyboardMarkup:
    """Show individual artists within a category for batch melody picker."""
    _emoji, _label, keys = _STYLE_CATEGORIES[cat_idx]
    rows = []
    # "All in category" — generates N random from this category
    rows.append([InlineKeyboardButton(
        f"✅ All {_label.split('/')[0].strip()} (random mix)",
        callback_data=f"bmelstyle:cat_{cat_idx}"
    )])
    pair = []
    for key in keys:
        info = _STYLE_KEY_TO_INFO.get(key)
        if not info:
            continue
        lbl, style_key, bpm, em = info
        btn = InlineKeyboardButton(
            f"{em} {lbl[:18]}",
            callback_data=f"bmelstyle:{style_key}"
        )
        pair.append(btn)
        if len(pair) == 2:
            rows.append(pair)
            pair = []
    if pair:
        rows.append(pair)
    rows.append([InlineKeyboardButton("⬅️ Back", callback_data="bmelcat:back")])
    return InlineKeyboardMarkup(rows)


async def batchmel_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle batch count button press → show style picker."""
    query = update.callback_query
    if not query:
        return BATCHMEL_WAITING
    if not is_allowed(update):
        await query.answer("⛔ Not authorized.", show_alert=True)
        return BATCHMEL_WAITING
    await query.answer()
    data = query.data

    if data == "batchmel:custom":
        context.user_data["batchmel_waiting_count"] = True
        await query.message.reply_text(
            "How many melodies? Type a number (1–20):"
        )
        return BATCHMEL_WAITING

    count = int(data.split(":")[1])
    context.user_data["batchmel_count"] = count
    kb = _batchmel_style_kb()
    await safe_edit(
        query.message,
        f"🤖 *{count} melodies* — now pick the style:\n\n"
        f"*All Random* = mixed styles\n"
        f"Or pick a category → pick a specific artist",
        parse_mode="Markdown",
        reply_markup=kb,
    )
    return BATCHMEL_STYLE


async def batchmel_cat_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle category navigation in batch melody picker."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("Not authorized.", show_alert=True)
        return BATCHMEL_STYLE
    await query.answer()
    data = query.data
    count = context.user_data.get("batchmel_count", 3)

    cat_choice = data.split(":")[1]
    if cat_choice == "back":
        kb = _batchmel_style_kb()
        await safe_edit(
            query.message,
            f"🤖 *{count} melodies* — now pick the style:\n\n"
            f"*All Random* = mixed styles\n"
            f"Or pick a category → pick a specific artist",
            parse_mode="Markdown",
            reply_markup=kb,
        )
    else:
        cat_idx = int(cat_choice)
        kb = _batchmel_artist_kb(cat_idx)
        cat_label = _STYLE_CATEGORIES[cat_idx][0] + " " + _STYLE_CATEGORIES[cat_idx][1]
        await safe_edit(
            query.message,
            f"🤖 *{count} melodies* — *{cat_label}*\n\n"
            f"Pick a specific artist or *All* for mixed:",
            parse_mode="Markdown",
            reply_markup=kb,
        )
    return BATCHMEL_STYLE


async def batchmel_style_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle final style pick → launch batch generation."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("Not authorized.", show_alert=True)
        return BATCHMEL_STYLE
    await query.answer()

    count = context.user_data.get("batchmel_count", 3)
    style_choice = query.data.split(":")[1]

    if style_choice == "__random__":
        # All random
        await _run_batch_melody(query.message, context, count, style_filter=None)
    elif style_choice.startswith("cat_"):
        # All from a category — pick random styles from that category
        import random as _rb
        cat_idx = int(style_choice[4:])
        _e, _l, cat_keys = _STYLE_CATEGORIES[cat_idx]
        cat_styles = [_STYLE_KEY_TO_INFO[k] for k in cat_keys if k in _STYLE_KEY_TO_INFO]
        _rb.shuffle(cat_styles)
        picks = cat_styles[:count]
        # Generate each
        status = await query.message.reply_text(
            f"🤖 *ACE-Step Batch — {count} melodies from {_l}…*",
            parse_mode="Markdown",
        )
        done, failed = 0, 0
        for i, (label, style, bpm, emoji) in enumerate(picks, 1):
            await safe_edit(
                status,
                f"🤖 *Batch* ({i}/{count})\n"
                f"Current: {emoji} *{esc(label)}* @ {bpm}bpm\n"
                f"✅ {done}  ❌ {failed}",
                parse_mode="Markdown",
            )
            try:
                await _do_generate_acestep(query.message, context, style, bpm, num_variations=1)
                done += 1
            except Exception as _be:
                log.warning("batchmelody cat: %s failed: %s", style, _be)
                failed += 1
        await safe_edit(status, f"✅ *Batch done!* {done}/{count} melodies", parse_mode="Markdown")
    else:
        # Specific artist style
        await _run_batch_melody(query.message, context, count, style_filter=style_choice)

    return ConversationHandler.END


async def batchmel_text_handler(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle custom count text input for /batchmelody."""
    if not is_allowed(update):
        return await deny(update)
    if not context.user_data.get("batchmel_waiting_count"):
        return BATCHMEL_WAITING

    text = (update.message.text or "").strip()
    try:
        count = int(text)
        if not (1 <= count <= 20):
            raise ValueError
    except ValueError:
        await update.message.reply_text("⚠️ Enter a number between 1 and 20.")
        return BATCHMEL_WAITING

    context.user_data["batchmel_waiting_count"] = False
    context.user_data["batchmel_count"] = count
    kb = _batchmel_style_kb()
    await update.message.reply_text(
        f"🤖 *{count} melodies* — now pick the style:\n\n"
        f"*All Random* = mixed styles\n"
        f"Or pick a category → pick a specific artist",
        parse_mode="Markdown",
        reply_markup=kb,
    )
    return BATCHMEL_STYLE


async def cmd_mymelodies(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Browse and re-download saved melodies from the fy3pack/ folder."""
    if not is_allowed(update):
        return await deny(update)

    args_list = (context.args or [])
    sub = args_list[0].lower() if args_list else "list"

    # ── /mymelodies list [filter] ──────────────────────────────────────────────
    if sub in ("list", "ls", ""):
        filt = args_list[1].lower() if len(args_list) > 1 else ""
        # Collect all audio files (WAV + MP3), deduplicate by stem, prefer WAV
        all_audio = sorted(
            list(MELODIES_DIR.glob("*.wav")) + list(MELODIES_DIR.glob("*.mp3")),
            key=lambda f: f.stat().st_mtime, reverse=True,
        )
        seen_stems = set()
        melodies = []
        for f in all_audio:
            if f.stem not in seen_stems:
                seen_stems.add(f.stem)
                melodies.append(f)
        if filt:
            melodies = [f for f in melodies if filt in f.stem.lower()]

        if not melodies:
            msg = "🔥 *fy3pack/* folder is empty." if not filt else f"🔥 No melodies matching *{filt}*."
            await update.message.reply_text(msg, parse_mode="Markdown")
            return

        # Show last 20
        lines = [f"🔥 *fy3pack/* — {len(melodies)} saved{(' (filter: '+filt+')') if filt else ''}:\n"]
        for i, f in enumerate(melodies[:20], 1):
            fmt_icon = "🎵" if f.suffix == ".wav" else "🎶"
            has_midi = "🎹" if f.with_suffix(".mid").exists() else ""
            kb = f.stat().st_size // 1024
            lines.append(f"{fmt_icon}{has_midi} `{i:02d}.` {f.stem}  _{kb}kb {f.suffix}_")
        if len(melodies) > 20:
            lines.append(f"\n_…and {len(melodies)-20} more. Use `/mymelodies list <style>` to filter._")
        lines.append("\n_`/mymelodies get <N>` — re-download_")
        lines.append("_`/mymelodies trackout <N>` — MIDI + stems_")
        lines.append("_`/mymelodies clear` — delete all_")
        await update.message.reply_text("\n".join(lines), parse_mode="Markdown")

    # ── /mymelodies get <N> ────────────────────────────────────────────────────
    elif sub in ("get", "dl", "download", "send"):
        if len(args_list) < 2:
            await update.message.reply_text("Usage: `/mymelodies get <number>`", parse_mode="Markdown")
            return
        try:
            idx = int(args_list[1]) - 1
        except ValueError:
            await update.message.reply_text("⚠️ Give a number, e.g. `/mymelodies get 3`", parse_mode="Markdown")
            return
        # Find audio files — WAV + MP3, deduplicate by stem
        audio_files = sorted(
            list(MELODIES_DIR.glob("*.wav")) + list(MELODIES_DIR.glob("*.mp3")),
            key=lambda f: f.stat().st_mtime, reverse=True,
        )
        seen_stems = set()
        unique_audio = []
        for f in audio_files:
            if f.stem not in seen_stems:
                seen_stems.add(f.stem)
                unique_audio.append(f)
        audio_files = unique_audio

        if idx < 0 or idx >= len(audio_files):
            await update.message.reply_text(f"⚠️ Only {len(audio_files)} melodies saved.", parse_mode="Markdown")
            return

        audio_file = audio_files[idx]
        midi_file = audio_file.with_suffix(".mid")
        msg = await update.message.reply_text(f"📤 Sending *{audio_file.stem}*…", parse_mode="Markdown")
        try:
            with open(str(audio_file), "rb") as f:
                await update.message.reply_audio(
                    audio=f,
                    filename=audio_file.name,
                    title=audio_file.stem,
                    performer="LeekThatsFye AI",
                )
            if midi_file.exists():
                with open(str(midi_file), "rb") as f:
                    await update.message.reply_document(
                        document=f,
                        filename=midi_file.name,
                        caption="🎹 MIDI — drag into FL Studio",
                    )
            await safe_edit(msg, f"✅ Sent `{audio_file.name}`", parse_mode="Markdown")
        except Exception as e:
            await safe_edit(msg, f"❌ Failed: {e}")

    # ── /mymelodies clear ──────────────────────────────────────────────────────
    elif sub in ("clear", "delete", "wipe"):
        mids = list(MELODIES_DIR.glob("*.mid"))
        mp3s = list(MELODIES_DIR.glob("*.mp3"))
        wavs = list(MELODIES_DIR.glob("*.wav"))
        total = len(mids) + len(mp3s) + len(wavs)
        if total == 0:
            await update.message.reply_text("📂 Folder already empty.")
            return
        for f in mids + mp3s + wavs:
            try:
                f.unlink()
            except Exception:
                pass
        await update.message.reply_text(
            f"🗑 Deleted {total} files from `fy3pack/`.", parse_mode="Markdown"
        )

    # ── /mymelodies stats ──────────────────────────────────────────────────────
    elif sub in ("stats", "info"):
        mids = list(MELODIES_DIR.glob("*.mid"))
        mp3s = list(MELODIES_DIR.glob("*.mp3"))
        wavs = list(MELODIES_DIR.glob("*.wav"))
        all_files = mids + mp3s + wavs
        total_mb = sum(f.stat().st_size for f in all_files) / 1_048_576
        # Count by style
        from collections import Counter
        style_counts: Counter = Counter()
        for f in wavs + mp3s:
            parts = f.stem.split("_")
            if len(parts) >= 3:
                style_counts[parts[2]] += 1
        top = style_counts.most_common(5)
        lines = [
            f"🔥 *fy3pack/* stats",
            f"WAV files: {len(wavs)}",
            f"MP3 files: {len(mp3s)}",
            f"MIDI files: {len(mids)}",
            f"Total size: {total_mb:.1f} MB",
            "",
            "*Top styles:*",
        ]
        for sty, cnt in top:
            lines.append(f"  • `{sty}` — {cnt}x")
        await update.message.reply_text("\n".join(lines), parse_mode="Markdown")

    # ── /mymelodies trackout <N> — track-out a saved melody ──────────────────
    elif sub in ("trackout", "track-out", "to"):
        if len(args_list) < 2:
            await update.message.reply_text(
                "Usage: `/mymelodies trackout <number>`\n"
                "Example: `/mymelodies trackout 3` — extracts MIDI + stems from melody #3",
                parse_mode="Markdown",
            )
            return
        try:
            idx = int(args_list[1]) - 1
        except ValueError:
            await update.message.reply_text("⚠️ Give a number, e.g. `/mymelodies trackout 3`", parse_mode="Markdown")
            return

        # Find audio files — WAV or MP3
        audio_files = sorted(
            list(MELODIES_DIR.glob("*.wav")) + list(MELODIES_DIR.glob("*.mp3")),
            key=lambda f: f.stat().st_mtime, reverse=True,
        )
        # Deduplicate by stem (prefer WAV over MP3)
        seen_stems = set()
        unique_audio = []
        for f in audio_files:
            if f.stem not in seen_stems:
                seen_stems.add(f.stem)
                unique_audio.append(f)
        audio_files = unique_audio

        if idx < 0 or idx >= len(audio_files):
            await update.message.reply_text(f"⚠️ Only {len(audio_files)} melodies saved.", parse_mode="Markdown")
            return

        audio_file = audio_files[idx]
        msg = await update.message.reply_text(
            f"📦 *Track-Out* for *{audio_file.stem}*…\n"
            f"🎼 _Extracting MIDI + separating stems_",
            parse_mode="Markdown",
        )

        sent_count = 0
        audio_path = str(audio_file)

        # MIDI
        midi_out = str(audio_file.with_suffix(".mid"))
        try:
            midi_result = await _run_ml_tool("midi", audio_path, midi_out)
            num_notes = midi_result.get("num_notes", 0)
            midi_path = Path(midi_result.get("midi_path", midi_out))
            if num_notes > 0 and midi_path.exists():
                with open(str(midi_path), "rb") as f:
                    await update.message.reply_document(
                        document=f,
                        filename=f"{audio_file.stem}.mid",
                        caption=f"🎼 *MIDI* — {num_notes} notes",
                        parse_mode="Markdown",
                    )
                sent_count += 1
        except Exception as e:
            log.warning(f"[mymelodies trackout] MIDI failed: {e}")

        # Stems
        stems_dir = str(audio_file.parent / (audio_file.stem + "_stems"))
        try:
            stem_result = await _run_ml_tool("stems", audio_path, stems_dir)
            for name in ["drums", "bass", "other", "vocals"]:
                sp = stem_result.get(name)
                if sp and Path(sp).exists() and Path(sp).stat().st_size > 0:
                    fsize = Path(sp).stat().st_size
                    try:
                        if fsize > 50 * 1024 * 1024:
                            raise ValueError("too large for reply_audio")
                        with open(sp, "rb") as f:
                            await update.message.reply_audio(
                                audio=f,
                                filename=f"{audio_file.stem}_{name}.wav",
                                title=f"{name.title()} Stem",
                                performer="Demucs AI",
                            )
                        sent_count += 1
                    except Exception:
                        try:
                            with open(sp, "rb") as f:
                                await update.message.reply_document(
                                    document=f,
                                    filename=f"{audio_file.stem}_{name}.wav",
                                    caption=f"🎛️ {name.title()} Stem",
                                )
                            sent_count += 1
                        except Exception as e2:
                            log.warning(f"[mymelodies trackout] {name} stem send failed: {e2}")
        except Exception as e:
            log.warning(f"[mymelodies trackout] Stems failed: {e}")

        await safe_edit(
            msg,
            f"📦 *Track-Out Complete* — {sent_count} files from *{audio_file.stem}*\n"
            f"🎛️ _MIDI + stems ready for FL Studio_",
            parse_mode="Markdown",
        )

    else:
        await update.message.reply_text(
            "🔥 *fy3pack/* commands:\n"
            "`/mymelodies` — list all saved\n"
            "`/mymelodies list <style>` — filter by name\n"
            "`/mymelodies get <N>` — re-download melody #N\n"
            "`/mymelodies trackout <N>` — extract MIDI + stems from #N\n"
            "`/mymelodies stats` — usage stats\n"
            "`/mymelodies clear` — delete all",
            parse_mode="Markdown",
        )


# ══════════════════════════════════════════════════════════════════════════════
# STUDY MY PRODUCTION — AI learns from your MIDIs, MP3s, and FL Studio projects
# ══════════════════════════════════════════════════════════════════════════════

_STUDY_PROFILE_PATH = Path(__file__).parent / "my_production_profile.json"


def _load_study_profile() -> dict:
    """Load the user's production study profile."""
    try:
        with open(_STUDY_PROFILE_PATH) as f:
            return json.load(f)
    except Exception:
        return {
            "scanned_files": [],
            "analysis": {},
            "style_dna": "",
            "common_keys": [],
            "common_bpms": [],
            "common_scales": [],
            "chord_patterns": [],
            "instruments": [],
            "total_files_scanned": 0,
            "last_scan": None,
        }


def _save_study_profile(profile: dict):
    """Save the production study profile (atomic write)."""
    tmp = str(_STUDY_PROFILE_PATH) + ".tmp"
    try:
        with open(tmp, "w") as f:
            json.dump(profile, f, indent=2, default=str)
        os.replace(tmp, _STUDY_PROFILE_PATH)
    except Exception as e:
        log.error(f"Failed to save study profile: {e}")
        try:
            os.unlink(tmp)
        except OSError:
            pass


async def _analyze_midi_file(midi_path: str) -> dict:
    """Analyze a MIDI file for musical patterns — keys, scales, chords, BPM, instruments."""
    import subprocess, json as _json
    analysis_script = '''
import sys, json

try:
    import mido
    mid = mido.MidiFile(sys.argv[1])

    notes = []
    tempo = 120
    for track in mid.tracks:
        for msg in track:
            if msg.type == "set_tempo":
                tempo = round(mido.tempo2bpm(msg.tempo))
            if msg.type == "note_on" and msg.velocity > 0:
                notes.append(msg.note % 12)

    # Detect key using Krumhansl-Schmuckler
    from collections import Counter
    pitch_counts = Counter(notes)
    pitch_hist = [pitch_counts.get(i, 0) for i in range(12)]

    # Major profile
    major_profile = [6.35, 2.23, 3.48, 2.33, 4.38, 4.09, 2.52, 5.19, 2.39, 3.66, 2.29, 2.88]
    # Minor profile
    minor_profile = [6.33, 2.68, 3.52, 5.38, 2.60, 3.53, 2.54, 4.75, 3.98, 2.69, 3.34, 3.17]

    note_names = ["C", "C#", "D", "Eb", "E", "F", "F#", "G", "Ab", "A", "Bb", "B"]

    best_key = "C"
    best_mode = "minor"
    best_corr = -1

    for shift in range(12):
        rotated = pitch_hist[shift:] + pitch_hist[:shift]
        # Major correlation
        mean_r = sum(rotated) / 12
        mean_p = sum(major_profile) / 12
        num = sum((r - mean_r) * (p - mean_p) for r, p in zip(rotated, major_profile))
        den_r = sum((r - mean_r)**2 for r in rotated) ** 0.5
        den_p = sum((p - mean_p)**2 for p in major_profile) ** 0.5
        if den_r * den_p > 0:
            corr = num / (den_r * den_p)
            if corr > best_corr:
                best_corr = corr
                best_key = note_names[shift]
                best_mode = "major"
        # Minor correlation
        mean_p = sum(minor_profile) / 12
        num = sum((r - mean_r) * (p - mean_p) for r, p in zip(rotated, minor_profile))
        den_p = sum((p - mean_p)**2 for p in minor_profile) ** 0.5
        if den_r * den_p > 0:
            corr = num / (den_r * den_p)
            if corr > best_corr:
                best_corr = corr
                best_key = note_names[shift]
                best_mode = "minor"

    # Note range and density
    all_notes_raw = []
    for track in mid.tracks:
        for msg in track:
            if msg.type == "note_on" and msg.velocity > 0:
                all_notes_raw.append(msg.note)

    result = {
        "bpm": tempo,
        "key": f"{best_key} {best_mode}",
        "total_notes": len(all_notes_raw),
        "note_range": max(all_notes_raw) - min(all_notes_raw) if all_notes_raw else 0,
        "lowest_note": min(all_notes_raw) if all_notes_raw else 0,
        "highest_note": max(all_notes_raw) if all_notes_raw else 0,
        "top_intervals": [],
        "num_tracks": len(mid.tracks),
    }

    # Intervals
    if len(all_notes_raw) > 1:
        intervals = [abs(all_notes_raw[i+1] - all_notes_raw[i]) for i in range(len(all_notes_raw)-1)]
        int_counts = Counter(intervals)
        result["top_intervals"] = [{"interval": iv, "count": c} for iv, c in int_counts.most_common(5)]

    print("__RESULT__" + json.dumps(result) + "__END__")
except Exception as e:
    print(f"__ERROR__{e}__END__")
'''
    try:
        proc = await asyncio.create_subprocess_exec(
            _ML_PYTHON, "-c", analysis_script, midi_path,
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.PIPE,
        )
        stdout, _ = await asyncio.wait_for(proc.communicate(), timeout=30)
        output = stdout.decode()
        if "__RESULT__" in output:
            result_str = output.split("__RESULT__")[1].split("__END__")[0]
            return _json.loads(result_str)
    except Exception as e:
        log.warning(f"[study] MIDI analysis failed for {midi_path}: {e}")
    return {}


async def _analyze_audio_file(audio_path: str) -> dict:
    """Analyze an MP3/WAV for key, BPM, and tonal character using basic-pitch + librosa."""
    # First extract MIDI to get note content
    midi_out = audio_path.rsplit(".", 1)[0] + "_study.mid"
    try:
        result = await _run_ml_tool("midi", audio_path, midi_out, timeout_s=120)
        num_notes = result.get("num_notes", 0)
        midi_path = result.get("midi_path", midi_out)
        if num_notes > 0 and Path(midi_path).exists():
            analysis = await _analyze_midi_file(midi_path)
            analysis["source"] = "audio_to_midi"
            analysis["original_file"] = audio_path
            # Cleanup temp MIDI
            try:
                Path(midi_path).unlink()
            except Exception:
                pass
            return analysis
    except Exception as e:
        log.warning(f"[study] Audio analysis failed for {audio_path}: {e}")
    return {}


async def _build_production_dna(profile: dict) -> str:
    """Use Claude to synthesize all analyzed files into a production DNA profile."""
    if not ANTHROPIC_API_KEY or not profile.get("analysis"):
        return ""

    try:
        import anthropic as _anthropic
        client = _anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)

        analyses = profile["analysis"]
        summary_parts = []
        for fname, data in list(analyses.items())[:30]:
            if data:
                summary_parts.append(
                    f"File: {fname}\n"
                    f"  Key: {data.get('key', '?')}, BPM: {data.get('bpm', '?')}\n"
                    f"  Notes: {data.get('total_notes', '?')}, Range: {data.get('note_range', '?')} semitones\n"
                    f"  Top intervals: {data.get('top_intervals', [])}"
                )

        analysis_text = "\n\n".join(summary_parts)

        response = await asyncio.get_event_loop().run_in_executor(
            None,
            lambda: client.messages.create(
                model="claude-sonnet-4-20250514",
                max_tokens=2000,
                system=(
                    "You are an elite music production analyst. Analyze the musical patterns across "
                    "these production files and create a detailed 'Production DNA' profile. "
                    "Identify: most common keys, typical BPM ranges, preferred scales/modes, "
                    "characteristic interval patterns, melodic tendencies (stepwise vs leaps), "
                    "harmonic language, dynamic patterns. Be very specific with musical terminology. "
                    "This will be used to generate AI melodies that match this producer's unique style."
                ),
                messages=[{
                    "role": "user",
                    "content": f"Analyze these {len(analyses)} production files and create my Production DNA:\n\n{analysis_text}",
                }],
            ),
        )
        return response.content[0].text
    except Exception as e:
        log.error(f"[study] Failed to build production DNA: {e}")
        return ""


async def cmd_studyproduction(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Study My Production — scan MIDIs, MP3s, and FL Studio projects to learn your style.

    /study scan <path>  — scan a folder for production files
    /study analyze      — analyze all scanned files
    /study profile      — show your production DNA
    /study generate     — generate a melody in YOUR style
    /study clear        — reset your profile
    """
    if not is_allowed(update):
        return await deny(update)

    args_list = context.args or []
    sub = args_list[0].lower() if args_list else "help"

    # ── /study scan [path] — scan folder for MIDIs, MP3s, FLPs ────────────
    if sub == "scan":
        scan_path = " ".join(args_list[1:]) if len(args_list) > 1 else str(Path.home())
        scan_dir = Path(scan_path)

        if not scan_dir.exists():
            await update.message.reply_text(f"⚠️ Path not found: `{scan_path}`", parse_mode="Markdown")
            return

        msg = await update.message.reply_text(
            f"🔍 *Scanning* `{scan_path}`…\n"
            f"_Looking for MIDIs, MP3s, WAVs, and FL Studio projects_",
            parse_mode="Markdown",
        )

        # Find production files — limit to 3 levels deep to avoid scanning forever
        found_files = {"midi": [], "audio": [], "flp": []}

        _EXT_MAP = {
            "midi": {".mid", ".midi"},
            "audio": {".mp3", ".wav"},
            "flp": {".flp"},
        }

        # Walk manually with depth limit instead of ** glob
        for depth_pattern in ["*", "*/*", "*/*/*"]:
            if sum(len(v) for v in found_files.values()) >= 150:
                break
            try:
                for f in scan_dir.glob(depth_pattern):
                    if not f.is_file():
                        continue
                    ext = f.suffix.lower()
                    for category, exts in _EXT_MAP.items():
                        if ext in exts and len(found_files[category]) < 50:
                            try:
                                if f.stat().st_size > 100:
                                    found_files[category].append(str(f))
                            except OSError:
                                pass
            except Exception:
                pass

        total = sum(len(v) for v in found_files.values())
        if total == 0:
            await safe_edit(
                msg,
                f"📂 No production files found in `{scan_path}`\n"
                f"_Try scanning a folder with your beats, MIDIs, or FL Studio projects._",
                parse_mode="Markdown",
            )
            return

        # Save to profile
        profile = _load_study_profile()
        for category, files in found_files.items():
            for f in files:
                if f not in profile["scanned_files"]:
                    profile["scanned_files"].append(f)
        _save_study_profile(profile)

        await safe_edit(
            msg,
            f"✅ *Found {total} production files!*\n"
            f"🎹 MIDI: {len(found_files['midi'])}\n"
            f"🎵 Audio (MP3/WAV): {len(found_files['audio'])}\n"
            f"🎛️ FL Studio (.flp): {len(found_files['flp'])}\n\n"
            f"_Run `/study analyze` to analyze your style._",
            parse_mode="Markdown",
        )

    # ── /study analyze — analyze all scanned files ────────────────────────────
    elif sub == "analyze":
        profile = _load_study_profile()
        files = profile.get("scanned_files", [])

        if not files:
            await update.message.reply_text(
                "⚠️ No files to analyze. Run `/study scan <path>` first.",
                parse_mode="Markdown",
            )
            return

        msg = await update.message.reply_text(
            f"🔬 *Analyzing {len(files)} files*…\n"
            f"_This may take a few minutes_",
            parse_mode="Markdown",
        )

        analyzed = 0
        for i, fpath in enumerate(files):
            if fpath in profile.get("analysis", {}):
                analyzed += 1
                continue  # Already analyzed

            ext = Path(fpath).suffix.lower()
            result = {}

            if ext in (".mid", ".midi"):
                result = await _analyze_midi_file(fpath)
            elif ext in (".mp3", ".wav"):
                result = await _analyze_audio_file(fpath)
            elif ext == ".flp":
                # FLP files are binary — we note them but can't parse deeply without pyflp
                result = {"type": "flp", "path": fpath, "size_kb": Path(fpath).stat().st_size // 1024}

            if result:
                if "analysis" not in profile:
                    profile["analysis"] = {}
                profile["analysis"][Path(fpath).name] = result
                analyzed += 1

            # Progress update every 5 files
            if (i + 1) % 5 == 0:
                try:
                    await safe_edit(
                        msg,
                        f"🔬 *Analyzing files* — {i+1}/{len(files)}…\n"
                        f"✅ {analyzed} analyzed",
                        parse_mode="Markdown",
                    )
                except Exception:
                    pass

        # Collect statistics
        keys = []
        bpms = []
        for data in profile.get("analysis", {}).values():
            if isinstance(data, dict):
                if data.get("key"):
                    keys.append(data["key"])
                if data.get("bpm") and isinstance(data["bpm"], (int, float)):
                    bpms.append(int(data["bpm"]))

        from collections import Counter
        profile["common_keys"] = [k for k, _ in Counter(keys).most_common(5)]
        profile["common_bpms"] = sorted(set(bpms))[:10]
        profile["total_files_scanned"] = analyzed
        profile["last_scan"] = str(Path(files[0]).parent) if files else None

        # Build Production DNA with Claude
        try:
            await safe_edit(msg, "🧬 *Building your Production DNA*…", parse_mode="Markdown")
        except Exception:
            pass
        dna = await _build_production_dna(profile)
        if dna:
            profile["style_dna"] = dna
        _save_study_profile(profile)

        # Fix #35: Avoid min/max on empty list + make the ternary clearer
        if bpms:
            bpm_str = f"🥁 BPM range: {min(bpms)}-{max(bpms)} bpm\n\n"
            result_text = (
                f"✅ *Analysis Complete!*\n"
                f"🔬 {analyzed} files analyzed\n"
                f"🎵 Top keys: {', '.join(profile['common_keys'][:3]) or 'N/A'}\n"
                f"{bpm_str}"
                f"_Run `/study profile` to see your Production DNA._\n"
                f"_Run `/study generate` to make a melody in YOUR style._"
            )
        else:
            result_text = (
                f"✅ *Analysis Complete!* — {analyzed} files analyzed\n"
                f"_Run `/study profile` to see your Production DNA._"
            )
        await safe_edit(msg, result_text, parse_mode="Markdown")

    # ── /study profile — show production DNA ──────────────────────────────────
    elif sub in ("profile", "dna", "me"):
        profile = _load_study_profile()

        if not profile.get("style_dna"):
            await update.message.reply_text(
                "⚠️ No production profile yet.\n"
                "Run `/study scan <path>` then `/study analyze` first.",
                parse_mode="Markdown",
            )
            return

        dna_preview = profile["style_dna"][:1500]
        if len(profile["style_dna"]) > 1500:
            dna_preview += "…"

        lines = [
            "🧬 *Your Production DNA*\n",
            f"📊 Files analyzed: {profile.get('total_files_scanned', 0)}",
            f"🎵 Top keys: {', '.join(profile.get('common_keys', [])[:5])}",
            f"🥁 BPM range: {', '.join(str(b) for b in profile.get('common_bpms', [])[:5])}",
            "",
            f"_{dna_preview}_",
            "",
            "_Use `/study generate` to create a melody matching YOUR style._",
        ]
        await update.message.reply_text("\n".join(lines), parse_mode="Markdown")

    # ── /study generate — generate melody matching your style ─────────────────
    elif sub in ("generate", "gen", "make"):
        profile = _load_study_profile()
        dna = profile.get("style_dna", "")

        if not dna:
            await update.message.reply_text(
                "⚠️ No production profile yet. Run `/study scan` + `/study analyze` first.",
                parse_mode="Markdown",
            )
            return

        # Build a prompt from the user's production DNA
        common_keys = profile.get("common_keys", ["C minor"])
        common_bpms = profile.get("common_bpms", [140])
        key_scale = _random.choice(common_keys) if common_keys else "C minor"
        bpm = _random.choice(common_bpms) if common_bpms else 140

        # Extract style info from DNA using Claude (non-blocking)
        try:
            import anthropic as _anthropic
            client = _anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)
            resp = await asyncio.get_event_loop().run_in_executor(
                None,
                lambda: client.messages.create(
                    model="claude-sonnet-4-20250514",
                    max_tokens=500,
                    system=(
                        "You are an ACE-Step music generator prompt engineer. Given a producer's DNA "
                        "profile, create a single detailed music generation prompt that captures their "
                        "unique style. Include: key, scale/mode, specific instruments, chord types, "
                        "melodic movement, rhythmic feel, production techniques. No drums, no vocals, "
                        "instrumental melody only. Keep it under 200 words."
                    ),
                    messages=[{
                        "role": "user",
                        "content": f"Create a melody prompt matching this producer's DNA:\n\n{dna[:2000]}",
                    }],
                ),
            )
            custom_prompt = resp.content[0].text
        except Exception as e:
            log.error(f"[study] Failed to generate style prompt: {e}")
            custom_prompt = f"melodic beat in {key_scale}, {bpm} bpm, no drums, no vocals, instrumental melody"

        # Add quality suffix
        custom_prompt += _ACE_QUALITY_SUFFIX

        msg = await update.message.reply_text(
            f"🧬 *Generating melody from YOUR Production DNA*\n"
            f"🎵 _{key_scale} @ {bpm}bpm_\n"
            f"⏳ _~60 seconds_",
            parse_mode="Markdown",
        )

        # Use ACE-Step with the custom prompt
        results = await _acestep_submit_and_poll(
            custom_prompt, bpm, key_scale, msg, "My Style", "",
            duration=60, num_variations=1,
        )
        if results:
            vr = results[0]
            try:
                with open(vr["path"], "rb") as f:
                    await update.message.reply_audio(
                        audio=f,
                        filename=f"mystyle_{bpm}bpm_{key_scale.replace(' ', '')}.wav",
                        caption=(
                            f"🧬 *Your Style Melody*\n"
                            f"🎵 {vr['bpm']}bpm | {vr['key']} | 60s WAV"
                        ),
                        parse_mode="Markdown",
                        title=f"My Style {bpm}bpm {key_scale}",
                        performer="LeekThatsFye AI",
                    )
            except Exception as e:
                log.warning(f"[study] Failed sending melody: {e}")

    # ── /study clear — reset profile ──────────────────────────────────────────
    elif sub in ("clear", "reset"):
        _save_study_profile({
            "scanned_files": [],
            "analysis": {},
            "style_dna": "",
            "common_keys": [],
            "common_bpms": [],
            "common_scales": [],
            "chord_patterns": [],
            "instruments": [],
            "total_files_scanned": 0,
            "last_scan": None,
        })
        await update.message.reply_text(
            "🗑 Production profile cleared. Start fresh with `/study scan <path>`.",
            parse_mode="Markdown",
        )

    else:
        await update.message.reply_text(
            "🧬 *Study My Production* — AI learns YOUR style\n\n"
            "`/study scan <path>` — scan folder for MIDIs/MP3s/FLPs\n"
            "`/study analyze` — analyze all scanned files\n"
            "`/study profile` — view your Production DNA\n"
            "`/study generate` — make a melody in YOUR style\n"
            "`/study clear` — reset everything\n\n"
            "_Example: `/study scan ~/Music/My Beats`_\n"
            "_Or: `/study scan ~/Documents/FL Studio`_",
            parse_mode="Markdown",
        )


# ══════════════════════════════════════════════════════════════════════════════
# MELODY INTELLIGENCE SCANNER — AI scans the internet for trending sounds
# ══════════════════════════════════════════════════════════════════════════════
# Scans YouTube, SoundCloud, Spotify charts, social media for trending melody
# patterns. Analyzes what's charting, what producers/instruments/scales are hot,
# and builds an ever-growing knowledge base the bot learns from daily.

_INTEL_DB_PATH = Path(__file__).parent / "melody_intel.json"


def _load_intel_db() -> dict:
    """Load the melody intelligence database."""
    try:
        with open(_INTEL_DB_PATH) as f:
            return json.load(f)
    except Exception:
        return {
            "last_scan": None,
            "scan_count": 0,
            "trending_keys": [],
            "trending_bpms": [],
            "trending_instruments": [],
            "trending_producers": [],
            "trending_styles": [],
            "platform_insights": {},
            "daily_reports": [],
            "knowledge_base": "",
        }


def _save_intel_db(db: dict):
    """Save the melody intelligence database (atomic write)."""
    tmp = str(_INTEL_DB_PATH) + ".tmp"
    try:
        with open(tmp, "w") as f:
            json.dump(db, f, indent=2, default=str)
        os.replace(tmp, _INTEL_DB_PATH)
    except Exception as e:
        log.error(f"Failed to save intel db: {e}")
        try:
            os.unlink(tmp)
        except OSError:
            pass


async def _scan_platform_trends() -> dict:
    """Use Claude to research current trending sounds across music platforms.

    Claude analyzes what's trending on YouTube, SoundCloud, Spotify, IG, and X
    for melody patterns, keys, BPMs, instruments, producers, and styles.
    """
    if not ANTHROPIC_API_KEY:
        return {}

    try:
        import anthropic as _anthropic
        client = _anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)

        _sys_prompt = (
            "You are an elite music industry analyst and melodic trend researcher. "
            "You track what's trending across ALL music platforms. "
            "Your expertise covers: YouTube type beat trends, SoundCloud underground scenes, "
            "Spotify chart analysis, Instagram Reels audio trends, TikTok viral sounds, "
            "and X/Twitter music discourse.\n\n"
            "Respond with ONLY valid JSON (no markdown, no commentary before/after). Format:\n"
            "{\n"
            '  "trending_keys": ["C minor", "F# minor", ...],\n'
            '  "trending_bpms": [140, 145, ...],\n'
            '  "trending_instruments": ["Omnisphere", ...],\n'
            '  "trending_producers": ["Metro Boomin", ...],\n'
            '  "trending_styles": ["dark melodic trap", ...],\n'
            '  "platform_insights": {"youtube": "...", "soundcloud": "...", "spotify": "...", "tiktok_reels": "...", "twitter_x": "..."},\n'
            '  "melodic_patterns": {"scales_modes": [...], "chord_progressions": [...], "sound_design": [...], "production_techniques": [...]},\n'
            '  "knowledge_update": "Detailed paragraph..."\n'
            "}"
        )
        _user_msg = (
            "What are the LATEST trending melody patterns and sounds across music "
            "platforms? Specific details on: keys, BPMs, instruments, scales, "
            "modes, chord progressions, VSTs, producers. ONLY output JSON."
        )
        response = await asyncio.get_event_loop().run_in_executor(
            None,
            lambda: client.messages.create(
                model="claude-sonnet-4-20250514",
                max_tokens=3000,
                system=_sys_prompt,
                messages=[{"role": "user", "content": _user_msg}],
            ),
        )

        text = response.content[0].text.strip()
        # Fix #41: Use balanced brace matching instead of greedy regex
        # Find the first { and track brace depth
        start = text.find("{")
        if start >= 0:
            depth = 0
            end = start
            for i in range(start, len(text)):
                if text[i] == "{":
                    depth += 1
                elif text[i] == "}":
                    depth -= 1
                    if depth == 0:
                        end = i + 1
                        break
            json_str = text[start:end]
            return json.loads(json_str)
    except Exception as e:
        log.error(f"[intel] Platform scan failed: {e}")
    return {}


async def _daily_intel_scan():
    """Background job: scan music platforms daily and update the knowledge base."""
    import datetime as _dt  # Fix #44: import OUTSIDE the conditional
    while True:
        try:
            await asyncio.sleep(3600 * 12)  # Every 12 hours

            db = _load_intel_db()
            scan_data = await _scan_platform_trends()

            if scan_data:
                # Merge new data — preserve types (Fix #45: keep BPMs as ints)
                for key in ["trending_keys", "trending_instruments",
                            "trending_producers", "trending_styles"]:
                    existing = list(db.get(key, []))
                    new_items = scan_data.get(key, [])
                    seen = set(str(x) for x in existing)
                    for item in new_items:
                        if str(item) not in seen:
                            existing.append(item)
                            seen.add(str(item))
                    db[key] = existing[-50:]

                # BPMs: ensure they stay as integers
                existing_bpms = []
                for x in db.get("trending_bpms", []):
                    try: existing_bpms.append(int(x))
                    except (ValueError, TypeError): pass
                for b in scan_data.get("trending_bpms", []):
                    try: existing_bpms.append(int(b))
                    except (ValueError, TypeError): pass
                db["trending_bpms"] = sorted(set(existing_bpms))[-50:]

                if scan_data.get("platform_insights"):
                    db["platform_insights"] = scan_data["platform_insights"]

                if scan_data.get("knowledge_update"):
                    report = {
                        "date": _dt.datetime.now().isoformat(),
                        "update": scan_data["knowledge_update"],
                        "melodic_patterns": scan_data.get("melodic_patterns", {}),
                    }
                    db["daily_reports"] = (db.get("daily_reports", []) + [report])[-5:]
                    all_knowledge = "\n\n".join(
                        f"[{r['date'][:10]}] {r['update']}"
                        for r in db["daily_reports"]
                    )
                    db["knowledge_base"] = all_knowledge

                db["last_scan"] = _dt.datetime.now().isoformat()
                db["scan_count"] = db.get("scan_count", 0) + 1
                _save_intel_db(db)
                log.info(f"[intel] Daily scan complete — scan #{db['scan_count']}")
            else:
                log.info("[intel] Daily scan returned no data — skipping")

        except Exception as e:
            log.error(f"[intel] Daily scan error: {e}")
            await asyncio.sleep(300)  # Wait 5min on error


async def cmd_intel(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Melody Intelligence Scanner — scan the internet for trending sounds.

    /intel scan      — manually trigger a scan now
    /intel trends    — show current trending data
    /intel knowledge — show full knowledge base
    /intel generate  — generate melody based on what's trending
    """
    if not is_allowed(update):
        return await deny(update)

    args_list = context.args or []
    sub = args_list[0].lower() if args_list else "help"

    # ── /intel scan — manually trigger scan ────────────────────────────────────
    if sub == "scan":
        if not ANTHROPIC_API_KEY:
            await update.message.reply_text("⚠️ ANTHROPIC_API_KEY not set.")
            return

        msg = await update.message.reply_text(
            "🌐 *Melody Intelligence Scanner*\n"
            "🔍 _Scanning YouTube, SoundCloud, Spotify, IG, X…_\n"
            "⏳ _Analyzing trending melodies, keys, BPMs, instruments_",
            parse_mode="Markdown",
        )

        scan_data = await _scan_platform_trends()
        if not scan_data:
            await safe_edit(msg, "❌ Scan failed — try again later.")
            return

        # Save to database — preserve types (Fix #45)
        db = _load_intel_db()
        import datetime as _dt

        for key in ["trending_keys", "trending_instruments",
                    "trending_producers", "trending_styles"]:
            existing = list(db.get(key, []))
            new_items = scan_data.get(key, [])
            seen = set(str(x) for x in existing)
            for item in new_items:
                if str(item) not in seen:
                    existing.append(item)
                    seen.add(str(item))
            db[key] = existing[-50:]

        # BPMs: ensure they stay as integers
        existing_bpms = []
        for x in db.get("trending_bpms", []):
            try: existing_bpms.append(int(x))
            except (ValueError, TypeError): pass
        for b in scan_data.get("trending_bpms", []):
            try: existing_bpms.append(int(b))
            except (ValueError, TypeError): pass
        db["trending_bpms"] = sorted(set(existing_bpms))[-50:]

        if scan_data.get("platform_insights"):
            db["platform_insights"] = scan_data["platform_insights"]

        if scan_data.get("knowledge_update"):
            report = {
                "date": _dt.datetime.now().isoformat(),
                "update": scan_data["knowledge_update"],
                "melodic_patterns": scan_data.get("melodic_patterns", {}),
            }
            db["daily_reports"] = (db.get("daily_reports", []) + [report])[-5:]
            all_knowledge = "\n\n".join(
                f"[{r['date'][:10]}] {r['update']}"
                for r in db["daily_reports"]
            )
            db["knowledge_base"] = all_knowledge

        db["last_scan"] = _dt.datetime.now().isoformat()
        db["scan_count"] = db.get("scan_count", 0) + 1
        _save_intel_db(db)

        # Build summary
        lines = [
            "✅ *Scan Complete!*\n",
            f"🔑 *Trending Keys:* {', '.join(scan_data.get('trending_keys', [])[:6])}",
            f"🥁 *Hot BPMs:* {', '.join(str(b) for b in scan_data.get('trending_bpms', [])[:6])}",
            f"🎹 *Hot Instruments:* {', '.join(scan_data.get('trending_instruments', [])[:5])}",
            f"🎧 *Hot Producers:* {', '.join(scan_data.get('trending_producers', [])[:5])}",
            "",
        ]
        insights = scan_data.get("platform_insights", {})
        if insights:
            lines.append("*Platform Insights:*")
            for platform, insight in list(insights.items())[:5]:
                lines.append(f"  • *{platform}:* _{str(insight)[:80]}_")

        lines.append(f"\n_Scan #{db['scan_count']} | Use `/intel trends` for full data_")
        await safe_edit(msg, "\n".join(lines), parse_mode="Markdown")

    # ── /intel trends — show current trending data ─────────────────────────────
    elif sub in ("trends", "trending", "hot"):
        db = _load_intel_db()
        if not db.get("last_scan"):
            await update.message.reply_text(
                "⚠️ No scan data yet. Run `/intel scan` first.",
                parse_mode="Markdown",
            )
            return

        lines = [
            "🌐 *Melody Intelligence — Current Trends*\n",
            f"📅 Last scan: _{db['last_scan'][:16]}_",
            f"📊 Total scans: {db.get('scan_count', 0)}\n",
            f"🔑 *Keys:* {', '.join(db.get('trending_keys', [])[:8])}",
            f"🥁 *BPMs:* {', '.join(str(b) for b in db.get('trending_bpms', [])[:8])}",
            f"🎹 *Instruments:* {', '.join(db.get('trending_instruments', [])[:6])}",
            f"🎧 *Producers:* {', '.join(db.get('trending_producers', [])[:6])}",
            f"🎵 *Styles:* {', '.join(db.get('trending_styles', [])[:5])}",
        ]

        insights = db.get("platform_insights", {})
        if insights:
            lines.append("\n*Platform Breakdown:*")
            for platform, insight in insights.items():
                lines.append(f"  • *{platform}:* _{str(insight)[:100]}_")

        lines.append(f"\n_`/intel generate` — make a melody from trends_")
        lines.append(f"_`/intel knowledge` — full knowledge base_")
        # Fix #48: Truncate to Telegram's 4096 char limit
        text = "\n".join(lines)
        if len(text) > 4000:
            text = text[:3990] + "\n…"
        await update.message.reply_text(text, parse_mode="Markdown")

    # ── /intel knowledge — full knowledge base ─────────────────────────────────
    elif sub in ("knowledge", "kb", "learn"):
        db = _load_intel_db()
        kb = db.get("knowledge_base", "")
        if not kb:
            await update.message.reply_text(
                "⚠️ Knowledge base empty. Run `/intel scan` to build it.",
                parse_mode="Markdown",
            )
            return

        # Show last report with melodic patterns
        last_report = db.get("daily_reports", [{}])[-1] if db.get("daily_reports") else {}
        patterns = last_report.get("melodic_patterns", {})

        lines = ["🧠 *Melody Intelligence Knowledge Base*\n"]
        if patterns:
            if patterns.get("scales_modes"):
                lines.append(f"🎼 *Hot Scales/Modes:* {', '.join(patterns['scales_modes'][:5])}")
            if patterns.get("chord_progressions"):
                lines.append(f"🎹 *Hot Chords:* {', '.join(patterns['chord_progressions'][:4])}")
            if patterns.get("sound_design"):
                lines.append(f"🎧 *Hot Sounds:* {', '.join(patterns['sound_design'][:4])}")
            if patterns.get("production_techniques"):
                lines.append(f"🎛️ *Hot Techniques:* {', '.join(patterns['production_techniques'][:4])}")
            lines.append("")

        # Fix #47: Truncate knowledge to fit Telegram 4096 char limit
        header_len = len("\n".join(lines)) + 10
        max_kb_len = min(2000, 4000 - header_len)
        preview = kb[:max_kb_len]
        if len(kb) > max_kb_len:
            preview += "…"
        lines.append(f"_{preview}_")
        text = "\n".join(lines)
        if len(text) > 4000:
            text = text[:3990] + "\n…"
        await update.message.reply_text(text, parse_mode="Markdown")

    # ── /intel generate — generate melody based on trending data ───────────────
    elif sub in ("generate", "gen", "make"):
        db = _load_intel_db()
        kb = db.get("knowledge_base", "")

        if not kb and not db.get("trending_keys"):
            await update.message.reply_text(
                "⚠️ No intelligence data. Run `/intel scan` first.",
                parse_mode="Markdown",
            )
            return

        # Pick from trending data
        trending_keys = db.get("trending_keys", ["C minor"])
        trending_bpms = db.get("trending_bpms", [140])
        key_scale = _random.choice(trending_keys) if trending_keys else "C minor"
        # Handle BPM — might be string or int
        try:
            bpm = int(_random.choice(trending_bpms)) if trending_bpms else 140
        except (ValueError, TypeError):
            bpm = 140

        # Build prompt from intelligence data (non-blocking)
        try:
            import anthropic as _anthropic
            client = _anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)
            _intel_content = (
                f"Create a trending melody prompt based on this intelligence:\n\n"
                f"Trending keys: {db.get('trending_keys', [])}\n"
                f"Trending BPMs: {db.get('trending_bpms', [])}\n"
                f"Trending instruments: {db.get('trending_instruments', [])}\n"
                f"Trending styles: {db.get('trending_styles', [])}\n"
                f"Knowledge: {kb[:1500]}"
            )
            resp = await asyncio.get_event_loop().run_in_executor(
                None,
                lambda: client.messages.create(
                    model="claude-sonnet-4-20250514",
                    max_tokens=500,
                    system=(
                        "You are an ACE-Step music generator prompt engineer. Given current music "
                        "intelligence data about what's trending, create a single detailed prompt "
                        "for generating a melody that captures the LATEST trending sound. "
                        "Include: key, scale/mode, instruments, chord types, melodic movement, "
                        "rhythmic feel, production techniques. Reference specific trending VSTs "
                        "and sounds. No drums, no vocals, instrumental melody only. Under 200 words."
                    ),
                    messages=[{"role": "user", "content": _intel_content}],
                ),
            )
            custom_prompt = resp.content[0].text
        except Exception as e:
            log.error(f"[intel] Failed to build trending prompt: {e}")
            custom_prompt = (
                f"trending melodic beat in {key_scale}, {bpm} bpm, "
                f"modern production style, no drums, no vocals, instrumental melody"
            )

        custom_prompt += _ACE_QUALITY_SUFFIX

        msg = await update.message.reply_text(
            f"🌐 *Generating from Trending Intelligence*\n"
            f"🎵 _{key_scale} @ {bpm}bpm_\n"
            f"🔥 _Based on latest platform trends_\n"
            f"⏳ _~60 seconds_",
            parse_mode="Markdown",
        )

        results = await _acestep_submit_and_poll(
            custom_prompt, bpm, key_scale, msg, "Trending", "",
            duration=60, num_variations=1,
        )
        if results:
            vr = results[0]
            try:
                with open(vr["path"], "rb") as f:
                    await update.message.reply_audio(
                        audio=f,
                        filename=f"trending_{vr['bpm']}bpm_{vr['key'].replace(' ', '')}.wav",
                        caption=(
                            f"🌐 *Trending Melody*\n"
                            f"🎵 {vr['bpm']}bpm | {vr['key']} | 60s WAV\n"
                            f"🔥 _Generated from latest platform intelligence_"
                        ),
                        parse_mode="Markdown",
                        title=f"Trending {vr['bpm']}bpm {vr['key']}",
                        performer="LeekThatsFye AI",
                    )
            except Exception as e:
                log.warning(f"[intel] Failed sending trending melody: {e}")

    else:
        await update.message.reply_text(
            "🌐 *Melody Intelligence Scanner*\n"
            "_AI scans the internet for trending sounds daily_\n\n"
            "`/intel scan` — scan YouTube/SoundCloud/Spotify/IG/X now\n"
            "`/intel trends` — view current trending data\n"
            "`/intel knowledge` — full knowledge base\n"
            "`/intel generate` — make a melody from what's trending\n\n"
            "_Auto-scans every 12 hours to keep knowledge fresh_",
            parse_mode="Markdown",
        )


# ── AI Assistant ──────────────────────────────────────────────────────────────
# Powered by Claude. /ai command OR just talk freely — any plain text message
# that isn't a command is routed here. The assistant knows the full pipeline
# state (beats, renders, uploads) and can fix metadata, give advice, etc.

ANTHROPIC_API_KEY = os.environ.get("ANTHROPIC_API_KEY", "")

# Per-user conversation history so Claude remembers context
_ai_histories: dict[int, list[dict]] = {}
_AI_MAX_HISTORY = 20  # messages kept per user


def _ai_system_prompt() -> str:
    """Build a real-time system prompt that includes current pipeline state."""
    beats    = sorted(list((ROOT / "beats").glob("*.mp3")) + list((ROOT / "beats").glob("*.wav")))
    rendered = [f for f in (ROOT / "output").glob("*.mp4") if _is_render_mp4(f)]
    log_data = load_json_safe(ROOT / "uploads_log.json", {})
    uploaded = list(log_data.keys())
    not_rendered = [safe_stem(b) for b in beats if not already_rendered(b)]
    clips    = [c.name for c in sorted((ROOT / "images").glob("*.mp4"))]

    beat_list = ", ".join(safe_stem(b) for b in beats) or "none"
    rendered_list = ", ".join(f.stem for f in rendered) or "none"
    uploaded_list = ", ".join(uploaded) or "none"
    not_rendered_list = ", ".join(not_rendered) or "none"
    clip_list = ", ".join(clips) or "none"

    return f"""You are an AI assistant built into LeekThatsFye's YouTube beat automation Telegram bot.

## Your role
Help LeekThatsFye run his YouTube beat channel efficiently. You know the full pipeline:
beats/ → render.py → output/ → upload.py → YouTube

## Current pipeline state (live)
- Total beats: {len(beats)} → {beat_list}
- Rendered: {len(rendered)} → {rendered_list}
- Uploaded to YouTube: {len(uploaded)} → {uploaded_list}
- Not yet rendered: {len(not_rendered)} → {not_rendered_list}
- Visualizer clips available: {clip_list}

## Bot commands you can suggest
/batch — render all unrendered beats (picks clip visually)
/fy3stash — pick specific beats to render by number
/render — render everything
/seo — generate missing metadata
/seoaudit — score all beats SEO (0-100) + auto-fix
/seotags — per-beat tag editor + artist picker
/seodesc — per-beat SEO description generator
/addartist — add new artist to bot knowledge
/tagboost — auto-apply SEO tags to all beats
/tags — preview/apply tags for one beat
/editjson — edit title/description/tags
/upload — upload all ready beats (runs in background — can render simultaneously)
/schedule — schedule uploads one per day
/queue — show what's ready to upload
/log — uploaded video URLs
/analytics — YouTube view/like counts
/rerender — re-render a beat with a new clip
/delrender — delete rendered video files (keeps audio + metadata)
/preview — send a rendered video here
/play — listen to a beat
/clips — show available visualizer clips
/status — counts overview
/tasks — see all currently running tasks (render, upload, etc.)
/ghostprod — generate a full ghost-production beat brief
/melody — generate a MIDI melody (or hum a note first to match your key)
/scanbeats — browse your Mac's local beat folders (25 BEATZ!, 2025, Music) and import beats
/scanfolder <path> — scan any custom folder on your Mac for beats to import
/addbeat <name> — import a specific beat by name from the last scan index

## What you can do
- Write SEO YouTube titles, descriptions, and tags on demand — just ask
- Explain what any command does
- Diagnose issues the user describes
- Suggest what to do next based on pipeline state
- Give YouTube growth advice for a rap beat producer
- Keep conversation context across messages

## Tone
Casual, direct, helpful. LeekThatsFye is a producer — keep it real, no fluff.
Never say you can't do something you actually can.
If asked to write metadata, write it immediately — don't ask for confirmation first.

## Constraints
- You cannot directly run commands — suggest them
- All actions go through the bot commands or the user's Mac
- Do NOT make up video IDs or URLs"""


async def _ai_reply(user_id: int, user_msg: str) -> str:
    """Send message to Claude, maintain history, return response text."""
    # Always re-read from env in case user updated .env after bot start
    api_key = os.environ.get("ANTHROPIC_API_KEY", "").strip()
    # Also re-read .env file directly so updates take effect without restart
    env_file = ROOT / ".env"
    if env_file.exists():
        for line in env_file.read_text().splitlines():
            line = line.strip()
            if line.startswith("ANTHROPIC_API_KEY="):
                api_key = line.split("=", 1)[1].strip()
                break

    if not api_key or api_key == "YOUR_API_KEY_HERE":
        return (
            "🤖 *AI needs an API key to work*\n\n"
            "Get your key at console.anthropic.com → API Keys → Create.\n\n"
            "Then in Terminal on your Mac:\n"
            "`nano /Users/fyefye/yt_automation/.env`\n\n"
            "Replace `YOUR_API_KEY_HERE` with your key \\(starts with `sk-ant-api03-`\\)\n\n"
            "Save → Ctrl\\+O, Enter, Ctrl\\+X. Bot auto\\-picks it up on next message — no restart needed."
        )

    # Init or load history
    if user_id not in _ai_histories:
        _ai_histories[user_id] = []

    history = _ai_histories[user_id]
    history.append({"role": "user", "content": user_msg})

    # Trim to max history (keep pairs)
    if len(history) > _AI_MAX_HISTORY:
        _ai_histories[user_id] = history[-_AI_MAX_HISTORY:]
        history = _ai_histories[user_id]

    try:
        import anthropic as _anthropic
        client = _anthropic.Anthropic(api_key=api_key)

        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=1024,
            system=_ai_system_prompt(),
            messages=history,
        )

        reply_text = response.content[0].text
        history.append({"role": "assistant", "content": reply_text})
        return reply_text

    except Exception as e:
        err = str(e)
        log.error("AI reply error: %s", err)
        if "authentication" in err.lower() or "api_key" in err.lower() or "401" in err:
            return (
                "❌ *API key rejected*\n\n"
                "Your key may be wrong or expired.\n"
                "Go to console.anthropic.com → create a fresh key → paste into `.env`\n"
                "_(Key must start with `sk-ant-api03-`, not `sk-ant-oat01-`)_"
            )
        if "rate" in err.lower() or "429" in err:
            return "⏳ Rate limited — try again in a moment."
        return f"❌ AI error: {err[:200]}"


async def cmd_ai(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/ai [message] — talk to the AI assistant."""
    if not is_allowed(update):
        return await deny(update)

    # Get the message after /ai
    text = " ".join(context.args).strip() if context.args else ""
    if not text:
        await update.message.reply_text(
            "🤖 *AI Assistant* — I know your full pipeline.\n\n"
            "Just talk to me:\n"
            "• _\"write SEO tags for army beat\"_\n"
            "• _\"what should I do next?\"_\n"
            "• _\"my render failed, what happened?\"_\n"
            "• _\"write a YouTube description for hood legend\"_\n\n"
            "Or just send any message — no /ai needed.",
            parse_mode="Markdown",
        )
        return

    msg = await update.message.reply_text("🤖 thinking...", parse_mode="Markdown")
    reply = await _ai_reply(update.effective_user.id, text)

    # Telegram message limit is 4096 chars
    if len(reply) > 4000:
        reply = reply[:4000] + "\n\n_(truncated)_"

    await safe_edit(msg, reply, parse_mode="Markdown")


async def cmd_ai_clear(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/aiclear — wipe conversation history so AI starts fresh."""
    if not is_allowed(update):
        return await deny(update)
    _ai_histories.pop(update.effective_user.id, None)
    await update.message.reply_text("🧹 AI conversation history cleared.")


async def handle_plain_text(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    Catch any plain text message that isn't a command — route to AI.
    This makes the bot feel like a real assistant: just talk to it.
    """
    if not is_allowed(update):
        return await deny(update)
    if not update.message or not update.message.text:
        return

    text = update.message.text.strip()
    if not text or text.startswith("/"):
        return

    # ── Intercept: title edit input ──────────────────────────────────────
    title_edit = context.user_data.get("_title_edit")
    if title_edit:
        context.user_data.pop("_title_edit", None)
        render_key = title_edit["render_key"]
        stem = title_edit["stem"]
        new_title = text.strip()
        if not new_title:
            await update.message.reply_text("Title can't be empty. Try again.")
            context.user_data["_title_edit"] = title_edit
            return
        _save_title_for_stem(stem, new_title)
        # Show updated title review
        sessions = context.bot_data.get("_render_sessions", {})
        session = sessions.get(render_key)
        if session:
            stems = session["stems"]
            kb = _build_title_review_kb(render_key, stems)
            try:
                await context.bot.edit_message_text(
                    chat_id=title_edit["chat_id"],
                    message_id=title_edit["msg_id"],
                    text=_title_review_text(stems),
                    reply_markup=kb,
                )
            except Exception:
                await update.message.reply_text(
                    _title_review_text(stems),
                    reply_markup=kb,
                )
        else:
            await update.message.reply_text(f"Title updated to: {new_title}\n(Session expired — send /batch again to render.)")
        return

    # ── Intercept: upload metadata edit (title or tags) ─────────────────
    uplmeta_edit = context.user_data.get("_uplmeta_edit")
    if uplmeta_edit:
        context.user_data.pop("_uplmeta_edit", None)
        edit_type = uplmeta_edit["type"]          # "title" or "tags"
        session_key = uplmeta_edit["session_key"]
        stem = uplmeta_edit["stem"]
        idx = uplmeta_edit["index"]
        msg_id = uplmeta_edit["msg_id"]
        chat_id = uplmeta_edit["chat_id"]

        meta_path = ROOT / "metadata" / f"{stem}.json"
        meta = load_json_safe(meta_path, {})

        if edit_type == "title":
            new_title = text.strip()
            if not new_title:
                await update.message.reply_text("Title can't be empty. Try again.")
                context.user_data["_uplmeta_edit"] = uplmeta_edit
                return
            meta["title"] = new_title
        elif edit_type == "tags":
            new_tags = [t.strip() for t in text.split(",") if t.strip()]
            if not new_tags:
                await update.message.reply_text("Send at least one tag (comma separated). Try again.")
                context.user_data["_uplmeta_edit"] = uplmeta_edit
                return
            meta["tags"] = new_tags

        meta_path.write_text(json.dumps(meta, indent=2))

        # Recover upload session stems
        upload_sessions = _get_upload_sessions(context)
        upl_session = upload_sessions.get(session_key)
        if upl_session:
            stems = upl_session["stems"]
            try:
                await context.bot.edit_message_text(
                    chat_id=chat_id,
                    message_id=msg_id,
                    text=_uplmeta_edit_text(stems, idx),
                    reply_markup=_uplmeta_edit_kb(session_key, stems, idx),
                )
            except Exception:
                await update.message.reply_text(
                    _uplmeta_edit_text(stems, idx),
                    reply_markup=_uplmeta_edit_kb(session_key, stems, idx),
                )
        else:
            field = "Title" if edit_type == "title" else "Tags"
            await update.message.reply_text(f"✅ {field} updated for {stem}.\n(Session expired — try /upload again.)")
        return

    # ── Intercept: new clip folder name ──────────────────────────────────
    clip_folder_key = context.user_data.get("_clip_folder_key")
    if clip_folder_key:
        context.user_data.pop("_clip_folder_key", None)
        sessions = context.bot_data.get("_clip_upload_sessions", {})
        session = sessions.get(clip_folder_key)
        if session and session.get("awaiting_folder_name"):
            folder_name = text.strip()
            if not folder_name or "/" in folder_name or "\\" in folder_name:
                await update.message.reply_text("Invalid folder name. Try again.")
                context.user_data["_clip_folder_key"] = clip_folder_key
                return
            temp_path = Path(session["temp_path"])
            if not temp_path.exists():
                sessions.pop(clip_folder_key, None)
                await update.message.reply_text("Temp file expired. Send the clip again.")
                return
            artist_dir = ROOT / "images" / folder_name
            artist_dir.mkdir(parents=True, exist_ok=True)
            safe_name = "default_visual.mp4"
            dest = artist_dir / safe_name
            temp_path.rename(dest)
            sessions.pop(clip_folder_key, None)
            saved_mb = dest.stat().st_size / (1024 * 1024)
            await update.message.reply_text(
                f"Created folder {folder_name}/ and saved as {folder_name}/{safe_name} ({saved_mb:.1f} MB)"
            )
            return

    # ── Intercept: per-beat date/time input (custom prompt OR active editor) ─
    perbeat_cust = context.user_data.get("_perbeat_custom")
    perbeat_active = context.user_data.get("_perbeat_active")
    perbeat_info = perbeat_cust or perbeat_active
    if perbeat_info:
        # Try parsing text as a date/time
        parsed = _parse_custom_datetime(text)
        if not parsed and perbeat_cust:
            # Explicit custom prompt — they must type a valid time
            await update.message.reply_text(
                "⚠️ Couldn't parse that. Try:\n  1am\n  tomorrow 6pm\n  Feb 25 3pm\n  2/25 18:00"
            )
            return  # keep _perbeat_custom and _perbeat_active set
        if not parsed:
            # Active editor but not a parseable date — let it fall through to AI
            pass
        else:
            # Valid date/time parsed — apply it
            context.user_data.pop("_perbeat_custom", None)
            session_key = perbeat_info["session_key"]
            idx = perbeat_info["index"]
            msg_id = perbeat_info["msg_id"]
            chat_id = perbeat_info["chat_id"]

            sessions = _get_upload_sessions(context)
            session = sessions.get(session_key)
            if not session:
                context.user_data.pop("_perbeat_active", None)
                await update.message.reply_text("Session expired — try /upload again.")
                return

            session.setdefault("_perbeat_sched", {})
            stems = session["stems"]
            stem = stems[idx] if idx < len(stems) else stems[-1]
            session["_perbeat_sched"][stem] = parsed.isoformat()
            _save_sessions(sessions)

            time_label = parsed.strftime("%a %b %d, %I:%M %p ET")
            # Auto-advance to next beat or overview
            if idx < len(stems) - 1:
                next_idx = idx + 1
                context.user_data["_perbeat_active"] = {
                    "session_key": session_key,
                    "index": next_idx,
                    "msg_id": msg_id,
                    "chat_id": chat_id,
                }
                try:
                    await context.bot.edit_message_text(
                        chat_id=chat_id, message_id=msg_id,
                        text=f"✅ {esc(stem)} → {time_label}\n\n" + _perbeat_edit_text(session, next_idx),
                        reply_markup=_perbeat_edit_kb(session_key, stems, next_idx),
                    )
                except Exception:
                    await update.message.reply_text(
                        f"✅ {esc(stem)} → {time_label}\n\n" + _perbeat_edit_text(session, next_idx),
                        reply_markup=_perbeat_edit_kb(session_key, stems, next_idx),
                    )
            else:
                context.user_data.pop("_perbeat_active", None)
                try:
                    await context.bot.edit_message_text(
                        chat_id=chat_id, message_id=msg_id,
                        text=f"✅ {esc(stem)} → {time_label}\n\n" + _perbeat_sched_text(session),
                        reply_markup=_perbeat_overview_kb(session_key, stems, session.get("_perbeat_sched", {})),
                    )
                except Exception:
                    await update.message.reply_text(
                        f"✅ {esc(stem)} → {time_label}\n\n" + _perbeat_sched_text(session),
                        reply_markup=_perbeat_overview_kb(session_key, stems, session.get("_perbeat_sched", {})),
                    )
            return

    # ── Intercept: custom schedule input for upload flow ──────────────────
    if context.user_data.get("_sched_upload_key"):
        await upload_custom_schedule_handler(update, context)
        return

    # Show typing indicator
    try:
        await update.message.chat.send_action("typing")
    except Exception:
        pass

    msg = await update.message.reply_text("🤖 thinking...", parse_mode="Markdown")
    reply = await _ai_reply(update.effective_user.id, text)

    if len(reply) > 4000:
        reply = reply[:4000] + "\n\n_(truncated)_"

    await safe_edit(msg, reply, parse_mode="Markdown")


# ── Bug Scanner ────────────────────────────────────────────────────────────────

def _run_bug_scan(app) -> list:
    """Run all health checks. Returns list of issue strings."""
    issues = []

    beats_dir  = ROOT / "beats"
    output_dir = ROOT / "output"
    meta_dir   = ROOT / "metadata"

    beats = list(beats_dir.glob("*.mp3")) + list(beats_dir.glob("*.wav"))
    stems = [safe_stem(b) for b in beats]

    # 1. Beats missing metadata JSON
    missing_meta = [s for s in stems if not (meta_dir / f"{s}.json").exists()]
    if missing_meta:
        issues.append(f"⚠️ {len(missing_meta)} beat(s) missing metadata JSON: {', '.join(missing_meta[:5])}" +
                      ("…" if len(missing_meta) > 5 else ""))

    # 2. Beats missing BPM or key in metadata
    missing_bpm_key = []
    for s in stems:
        mf = meta_dir / f"{s}.json"
        if mf.exists():
            m = load_json_safe(mf, {})
            if not m.get("bpm") or not m.get("key"):
                missing_bpm_key.append(s)
    if missing_bpm_key:
        issues.append(f"⚠️ {len(missing_bpm_key)} beat(s) missing BPM or key: {', '.join(missing_bpm_key[:5])}" +
                      ("…" if len(missing_bpm_key) > 5 else ""))

    # 3. Beats missing renders
    no_render = [s for s in stems if not (output_dir / f"{s}.mp4").exists()]
    if no_render:
        issues.append(f"🔲 {len(no_render)} beat(s) have no render yet: {', '.join(no_render[:5])}" +
                      ("…" if len(no_render) > 5 else ""))

    # 4. Broken renders (0 bytes or < 100KB)
    broken = []
    for mp4 in output_dir.glob("*.mp4"):
        if not _is_render_mp4(mp4):
            continue
        try:
            sz = mp4.stat().st_size
            if sz < 100_000:
                broken.append(f"{mp4.name} ({sz} bytes)")
        except OSError:
            broken.append(f"{mp4.name} (unreadable)")
    if broken:
        issues.append(f"💥 {len(broken)} broken render(s): {', '.join(broken[:5])}" +
                      ("…" if len(broken) > 5 else ""))

    # 5. Orphaned renders (mp4 exists but no matching beat file)
    beat_stem_set = set(stems)
    orphaned = [mp4.stem for mp4 in output_dir.glob("*.mp4")
                if _is_render_mp4(mp4) and mp4.stem not in beat_stem_set]
    if orphaned:
        issues.append(f"👻 {len(orphaned)} orphaned render(s) (no beat file): {', '.join(orphaned[:5])}" +
                      ("…" if len(orphaned) > 5 else ""))

    # 6. Stale overwrite sessions (older than 2 hours)
    if app is not None:
        ow_sessions = app.bot_data.get("_ow_sessions", {})
        now_ts = time.time()
        stale_keys = [k for k in ow_sessions if now_ts - float(k.split("_")[1]) > 7200]
        if stale_keys:
            issues.append(f"🕰 {len(stale_keys)} stale overwrite session(s) (>2h old) — run /bugbot fix to clear")

    # 7. Log errors in last hour
    log_file = ROOT / "logs" / "bot.log"
    error_count = 0
    if log_file.exists():
        try:
            cutoff = time.time() - 3600
            with open(log_file, "r", errors="replace") as f:
                for line in f:
                    if "ERROR" in line or "CRITICAL" in line:
                        # Try to parse timestamp if present
                        error_count += 1
            if error_count:
                issues.append(f"📋 {error_count} ERROR/CRITICAL line(s) in bot.log (recent)")
        except Exception:
            pass

    # 8. Missing required metadata fields (title/artist empty)
    bad_meta = []
    for s in stems:
        mf = meta_dir / f"{s}.json"
        if mf.exists():
            m = load_json_safe(mf, {})
            if not m.get("title") or not m.get("artist"):
                bad_meta.append(s)
    if bad_meta:
        issues.append(f"📝 {len(bad_meta)} beat(s) missing title/artist in metadata: {', '.join(bad_meta[:5])}" +
                      ("…" if len(bad_meta) > 5 else ""))

    # 9. Upload log orphans (in uploads_log but no render)
    uploads_log = load_json_safe(ROOT / "uploads_log.json", {})
    ul_orphans = [s for s in uploads_log if not (output_dir / f"{s}.mp4").exists()]
    if ul_orphans:
        issues.append(f"📤 {len(ul_orphans)} upload log entry/entries with no render: {', '.join(ul_orphans[:5])}" +
                      ("…" if len(ul_orphans) > 5 else ""))

    # 10. Beats with empty description or empty tags in metadata (bad for YouTube SEO)
    empty_seo = []
    for s in stems:
        mf = meta_dir / f"{s}.json"
        if mf.exists():
            m = load_json_safe(mf, {})
            if not str(m.get("description", "")).strip() or not m.get("tags", []):
                empty_seo.append(s)
    if empty_seo:
        issues.append(
            f"🏷 {len(empty_seo)} beat(s) missing description/tags (bad YouTube SEO): "
            + ", ".join(empty_seo[:5]) + ("…" if len(empty_seo) > 5 else "")
        )

    # 11. YouTube token age — token.json older than 7 days may need re-auth
    token_file = ROOT / "token.json"
    if token_file.exists():
        token_age_days = (time.time() - token_file.stat().st_mtime) / 86400
        if token_age_days > 7:
            issues.append(
                f"🔑 YouTube token.json is {token_age_days:.0f} days old — "
                f"may need re-auth. Run `python upload.py` to trigger browser login if uploads fail."
            )

    # 12. asyncio StreamReader limit check — ensure the LimitOverrunError fix is in place
    bot_src = ROOT / "telegram_bot.py"
    if bot_src.exists():
        src_text = bot_src.read_text(encoding="utf-8", errors="replace")
        if "limit=1024 * 1024" not in src_text and "limit=1_048_576" not in src_text:
            issues.append(
                "💥 CRITICAL: asyncio StreamReader 1MB limit NOT found in run_render_live() — "
                "renders may crash mid-batch with LimitOverrunError. Run /bugbot → Patch Bug."
            )

    # 13. Unrendered beats count — warn if >10 piling up
    no_render_count = len([s for s in stems if not (output_dir / f"{s}.mp4").exists()])
    if no_render_count > 10:
        issues.append(
            f"🔲 {no_render_count} beats have no render yet — run /batch to catch up."
        )

    return issues


async def _hourly_bug_job(app):
    """Background coroutine — runs a health scan every hour, notifies on critical issues."""
    while True:
        await asyncio.sleep(3600)
        try:
            log.info("[hourly bug scan] Starting health check…")
            issues = await asyncio.get_event_loop().run_in_executor(None, _run_bug_scan, app)
            if issues:
                log.warning("[hourly bug scan] Found %d issue(s)", len(issues))
                critical = [i for i in issues if "broken" in i.lower() or "💥" in i]
                if critical:
                    msg = "🐛 *Bug scan found critical issue(s):*\n" + "\n".join(critical)
                    try:
                        await app.bot.send_message(chat_id=ALLOWED_ID, text=msg, parse_mode="Markdown")
                    except Exception as e:
                        log.warning("Bug scan notify failed: %s", e)
            else:
                log.info("[hourly bug scan] All clear ✅")
        except Exception as e:
            log.error("[hourly bug scan] Scan failed: %s", e)


async def cmd_bugbot(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Manual trigger: /bugbot — runs full health scan and shows results."""
    if not is_allowed(update): return
    msg = await update.message.reply_text("🔍 Running full bug scan…")
    try:
        issues = await asyncio.get_event_loop().run_in_executor(None, _run_bug_scan, context.application)
    except Exception as e:
        await safe_edit(msg, f"❌ Scan failed: `{esc(str(e))}`", parse_mode="Markdown")
        return

    if not issues:
        await safe_edit(msg, "✅ *Bug Scan: All Clear!*\n\nNo issues found — everything looks healthy. 🎉",
                        parse_mode="Markdown")
        return

    lines = ["🐛 *Bug Scan Report*", "━━━━━━━━━━━━━━━"]
    lines += issues
    lines += ["", f"_Found {len(issues)} issue(s)_"]

    kb = InlineKeyboardMarkup([
        [InlineKeyboardButton("🔧 Fix All Auto", callback_data="bugbot:fix"),
         InlineKeyboardButton("🩹 Patch Bug",    callback_data="bugbot:patch")],
        [InlineKeyboardButton("❌ Dismiss",       callback_data="bugbot:dismiss")],
    ])
    await safe_edit(msg, "\n".join(lines), parse_mode="Markdown", reply_markup=kb)


async def bugbot_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle inline buttons from /bugbot."""
    query = update.callback_query
    if not query or not is_allowed(update):
        if query: await query.answer("Not authorized.", show_alert=True)
        return
    await query.answer()
    action = query.data.split(":", 1)[1] if ":" in query.data else ""

    if action == "dismiss":
        await safe_edit(query.message, "✅ Dismissed.")
        return

    if action == "patch":
        # Store the message so patch handler can edit it
        context.user_data["bugbot_patch_msg_id"] = query.message.message_id
        context.user_data["bugbot_patch_chat_id"] = query.message.chat_id
        await safe_edit(
            query.message,
            "🩹 *Patch Bug*\n\n"
            "Describe the bug — what went wrong?\n"
            "_(e.g. \"renders stop after 2 videos with a stream error\")_\n\n"
            "I'll pull the recent error logs, analyze the code, and generate a fix.",
            parse_mode="Markdown",
        )
        return BUGBOT_PATCH

    if action == "apply":
        patch = context.user_data.get("pending_patch", {})
        old_str = patch.get("old", "")
        new_str = patch.get("new", "")
        desc    = patch.get("description", "patch")

        if not old_str or not new_str:
            await safe_edit(query.message, "⚠️ No pending patch found — run /bugbot again.")
            return

        bot_file = ROOT / "telegram_bot.py"
        original = bot_file.read_text(encoding="utf-8")

        if old_str not in original:
            await safe_edit(
                query.message,
                "⚠️ Patch no longer applies — the code has changed since the patch was generated.\n"
                "Run /bugbot again to generate a fresh patch.",
                parse_mode="Markdown",
            )
            return

        patched = original.replace(old_str, new_str, 1)

        # Write to temp file and py_compile to verify syntax BEFORE overwriting
        import tempfile as _tf
        tmp_path = Path(_tf.mktemp(suffix=".py"))
        try:
            tmp_path.write_text(patched, encoding="utf-8")
            result = subprocess.run(
                [sys.executable, "-m", "py_compile", str(tmp_path)],
                capture_output=True, timeout=30,
            )
            if result.returncode != 0:
                err = result.stderr.decode(errors="replace")[-400:]
                await safe_edit(
                    query.message,
                    f"❌ *Syntax error in patch — NOT applied:*\n```\n{esc(err)}\n```\n"
                    f"The bot is unchanged. Try describing the bug differently.",
                    parse_mode="Markdown",
                )
                return
        finally:
            tmp_path.unlink(missing_ok=True)

        # Syntax OK — write the patch
        bot_file.write_text(patched, encoding="utf-8")
        await safe_edit(
            query.message,
            f"✅ *Patch applied!*\n`{esc(desc)}`\n\nRestarting bot in 3 seconds…",
            parse_mode="Markdown",
        )
        await asyncio.sleep(3)

        # Restart via launchctl
        plist = Path.home() / "Library" / "LaunchAgents" / "com.ytautomation.telegrambot.plist"
        uid   = str(os.getuid())
        subprocess.Popen(["launchctl", "bootout",   f"gui/{uid}", str(plist)])
        await asyncio.sleep(2)
        subprocess.Popen(["launchctl", "bootstrap", f"gui/{uid}", str(plist)])
        return

    if action == "skip_patch":
        context.user_data.pop("pending_patch", None)
        await safe_edit(query.message, "⏭ Patch skipped. Run /bugbot to try again.")
        return

    if action == "fix":
        await safe_edit(query.message, "🔧 Auto-fixing issues…")
        fixed = []
        skipped = []

        # Fix 1: Delete 0-byte / broken renders so they re-render next /batch
        output_dir = ROOT / "output"
        for mp4 in output_dir.glob("*.mp4"):
            if not _is_render_mp4(mp4):
                continue
            try:
                if mp4.stat().st_size < 100_000:
                    mp4.unlink()
                    fixed.append(f"🗑 Deleted broken render: `{mp4.name}`")
            except OSError:
                skipped.append(f"⚠️ Could not delete `{mp4.name}`")

        # Fix 2: Clear stale overwrite sessions
        ow_sessions = context.bot_data.get("_ow_sessions", {})
        now_ts = time.time()
        stale_keys = [k for k in list(ow_sessions.keys()) if now_ts - float(k.split("_")[1]) > 7200]
        for k in stale_keys:
            del ow_sessions[k]
        if stale_keys:
            fixed.append(f"🧹 Cleared {len(stale_keys)} stale session(s)")

        # Fix 3: Create missing metadata stubs (so beats aren't invisible)
        beats_dir = ROOT / "beats"
        meta_dir  = ROOT / "metadata"
        beats     = list(beats_dir.glob("*.mp3")) + list(beats_dir.glob("*.wav"))
        meta_dir.mkdir(exist_ok=True)
        for b in beats:
            s  = safe_stem(b)
            mf = meta_dir / f"{s}.json"
            if not mf.exists():
                stub = {"title": s.replace("_", " ").title(), "artist": "LeekThatsFye",
                        "description": "", "tags": []}
                mf.write_text(json.dumps(stub, indent=2))
                fixed.append(f"📝 Created metadata stub: `{s}`")

        # Fix 4: Fill empty description/tags in existing metadata (YouTube SEO)
        # Use the SEO description builder if available, else a solid fallback
        def _get_seo_desc(stem, meta):
            try:
                return _build_seo_description(stem, meta)
            except Exception:
                return (
                    f"🎵 {meta.get('title', stem.replace('_', ' ').title())} | Type Beat | Prod. by LeekThatsFye\n\n"
                    "Perfect for artists looking for a hard trap/melodic instrumental.\n"
                    "BPM and key info in the metadata — reach out for custom beats.\n\n"
                    "📲 Tag me on IG: @leekthatsfye\n"
                    "✅ Free for non-profit use — tag @leekthatsfye\n"
                    "💰 For exclusive/non-exclusive leases, DM or visit the link in bio.\n\n"
                    "Beats produced by LeekThatsFye | 2026 Type Beats | Rap Beats | Free Beats\n\n"
                    "#typebeat #freebeat #trapbeat #leekthatsfye #2026typebeat"
                )
        _SEO_BASE_TAGS = [
            "type beat", "free type beat", "trap beat", "rap instrumental",
            "hip hop instrumental", "free rap beat", "trap instrumental",
            "2026 type beat", "new type beat 2026", "leekthatsfye",
            "leek thats fye", "prod by leekthatsfye", "free beat",
            "beats for sale", "rap beat 2026",
        ]
        for b in beats:
            s  = safe_stem(b)
            mf = meta_dir / f"{s}.json"
            if not mf.exists():
                continue
            try:
                m = load_json_safe(mf, {})
                changed = False
                if not str(m.get("description", "")).strip():
                    m["description"] = _get_seo_desc(s, m)
                    changed = True
                if not m.get("tags", []):
                    title = m.get("title", s.replace("_", " ").title())
                    m["tags"] = _suggest_tags(s, m) or ([f"{title} type beat", f"{title} beat"] + _SEO_BASE_TAGS)
                    changed = True
                if changed:
                    mf.write_text(json.dumps(m, indent=2))
                    fixed.append(f"🏷 Filled SEO data for: `{s}`")
            except Exception:
                pass

        lines = ["🔧 *Auto-Fix Complete*", "━━━━━━━━━━━━━━━"]
        if fixed:
            lines += fixed
        if skipped:
            lines += skipped
        if not fixed and not skipped:
            lines.append("Nothing auto-fixable found.")
        lines.append("\n_Re-run /bugbot to check remaining issues_")
        await safe_edit(query.message, "\n".join(lines), parse_mode="Markdown")


async def bugbot_patch_receive(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    Receives the bug description typed by the user after tapping 🩹 Patch Bug.
    Pulls recent error logs, reads the bot source, calls Claude API to generate
    a patch, shows it to the user with [✅ Apply] [⏭ Skip] buttons.
    """
    if not is_allowed(update):
        return ConversationHandler.END

    description = (update.message.text or "").strip()
    if not description:
        await update.message.reply_text("⚠️ Please describe the bug in a sentence or two.")
        return BUGBOT_PATCH

    msg = await update.message.reply_text("🔍 Pulling logs and analyzing code…")

    # ── Gather recent error logs ──────────────────────────────────────────────
    log_file  = ROOT / "logs" / "bot.log"
    error_lines = []
    if log_file.exists():
        try:
            with open(log_file, "r", errors="replace") as _lf:
                all_lines = _lf.readlines()
            # Grab last 200 lines that contain ERROR/Traceback/Exception
            for _l in all_lines[-1000:]:
                if any(k in _l for k in ("ERROR", "CRITICAL", "Traceback", "Exception", "ValueError", "LimitOverrun")):
                    error_lines.append(_l.rstrip())
            error_lines = error_lines[-80:]  # cap at 80
        except Exception:
            pass
    log_snippet = "\n".join(error_lines) if error_lines else "(no recent errors in log)"

    # ── Read relevant portion of bot source ──────────────────────────────────
    bot_src_path = ROOT / "telegram_bot.py"
    try:
        bot_src = bot_src_path.read_text(encoding="utf-8", errors="replace")
        # Try to find the relevant function by looking for keywords in description
        keywords = [w for w in description.lower().split() if len(w) > 4]
        # Extract ~60 lines around the most relevant match
        src_snippet = ""
        for kw in keywords:
            idx = bot_src.lower().find(kw)
            if idx != -1:
                start_line = bot_src[:idx].count("\n")
                lines_list = bot_src.splitlines()
                snippet_lines = lines_list[max(0, start_line - 10):start_line + 50]
                src_snippet = "\n".join(snippet_lines)
                break
        if not src_snippet:
            # Fallback: send first 100 lines of run_render_live
            rl_idx = bot_src.find("async def run_render_live")
            if rl_idx != -1:
                src_snippet = bot_src[rl_idx:rl_idx + 3000]
    except Exception:
        src_snippet = "(could not read source)"

    # ── Call Claude API ───────────────────────────────────────────────────────
    api_key = os.environ.get("ANTHROPIC_API_KEY", "").strip()
    if not api_key or api_key == "YOUR_API_KEY_HERE":
        await safe_edit(
            msg,
            "⚠️ *No Claude API key configured* — can't auto-generate patch.\n\n"
            f"*Recent errors from log:*\n```\n{esc(log_snippet[:1500])}\n```\n\n"
            "Fix manually then run /bugbot to verify.",
            parse_mode="Markdown",
        )
        return ConversationHandler.END

    await safe_edit(msg, "🤖 Asking Claude to generate a fix…")

    system_prompt = (
        "You are a Python bot patcher. The user will give you a bug description, "
        "recent error logs, and a snippet of the Python source file telegram_bot.py.\n\n"
        "Your job: return ONLY a valid JSON object (no markdown, no explanation) with these keys:\n"
        '  "old": the EXACT string to find in the source (must be unique in context),\n'
        '  "new": the replacement string (fixed code),\n'
        '  "description": one-line summary of what the patch does.\n\n'
        "Rules:\n"
        "- The 'old' string must appear verbatim in the source — copy it exactly.\n"
        "- The 'new' string must be valid Python with correct indentation.\n"
        "- Keep the patch minimal — only change what's broken.\n"
        "- If you cannot determine a safe patch, return: "
        '{"old":"","new":"","description":"Cannot auto-patch — needs manual review"}'
    )

    user_prompt = (
        f"Bug description: {description}\n\n"
        f"Recent error log:\n{log_snippet[:3000]}\n\n"
        f"Relevant source code:\n{src_snippet[:4000]}"
    )

    try:
        import anthropic as _anthropic
        _client = _anthropic.Anthropic(api_key=api_key)
        response = await asyncio.get_event_loop().run_in_executor(
            None,
            lambda: _client.messages.create(
                model="claude-haiku-4-5",
                max_tokens=1024,
                system=system_prompt,
                messages=[{"role": "user", "content": user_prompt}],
            ),
        )
        raw_text = response.content[0].text.strip()

        # Strip any markdown code fences if Claude wrapped it
        if raw_text.startswith("```"):
            raw_text = "\n".join(
                l for l in raw_text.splitlines()
                if not l.strip().startswith("```")
            )

        patch = json.loads(raw_text)
        old_str = patch.get("old", "")
        new_str = patch.get("new", "")
        desc    = patch.get("description", "patch")

    except json.JSONDecodeError:
        await safe_edit(
            msg,
            "⚠️ Claude returned invalid JSON. Raw response:\n"
            f"```\n{esc(raw_text[:600])}\n```",
            parse_mode="Markdown",
        )
        return ConversationHandler.END
    except Exception as _ae:
        await safe_edit(msg, f"❌ Claude API error: `{esc(str(_ae))}`", parse_mode="Markdown")
        return ConversationHandler.END

    if not old_str:
        await safe_edit(
            msg,
            f"🤷 *Claude couldn't auto-patch this one:*\n_{esc(desc)}_\n\n"
            f"Recent errors for manual review:\n```\n{esc(log_snippet[:1200])}\n```",
            parse_mode="Markdown",
        )
        return ConversationHandler.END

    # Verify 'old' is actually in the source
    bot_src = bot_src_path.read_text(encoding="utf-8")
    if old_str not in bot_src:
        await safe_edit(
            msg,
            "⚠️ Claude generated a patch but the target string wasn't found in the source.\n"
            f"Description: _{esc(desc)}_\n\nMay need manual review.",
            parse_mode="Markdown",
        )
        return ConversationHandler.END

    # Store for apply step
    context.user_data["pending_patch"] = {"old": old_str, "new": new_str, "description": desc}

    # Show the patch to user
    old_preview = old_str[:300].replace("`", "'")
    new_preview = new_str[:300].replace("`", "'")
    kb = InlineKeyboardMarkup([
        [InlineKeyboardButton("✅ Apply + Restart", callback_data="bugbot:apply"),
         InlineKeyboardButton("⏭ Skip",            callback_data="bugbot:skip_patch")],
    ])
    await safe_edit(
        msg,
        f"🩹 *Proposed Patch*\n`{esc(desc)}`\n\n"
        f"*Remove:*\n```\n{esc(old_preview)}\n```\n\n"
        f"*Replace with:*\n```\n{esc(new_preview)}\n```",
        parse_mode="Markdown",
        reply_markup=kb,
    )
    return ConversationHandler.END


# ── Daily morning report ───────────────────────────────────────────────────────
# Sends a status summary to the owner every morning at 9 AM Eastern.

async def _send_morning_report(app):
    """Called by the daily job — sends status summary with pipeline health."""
    beats    = list((ROOT / "beats").glob("*.mp3")) + list((ROOT / "beats").glob("*.wav"))
    rendered = [f for f in (ROOT / "output").glob("*.mp4") if _is_render_mp4(f)]
    log_data = load_json_safe(ROOT / "uploads_log.json", {})
    uploaded = list(log_data.keys())
    not_rendered = [b for b in beats if not already_rendered(b)]
    not_uploaded = len(rendered) - len(uploaded)

    # ── Buffer + queue info ──
    buffer = _queue_buffer_days()
    queue_ct = _queue_count()
    q_data = _load_upload_queue()
    autopilot = q_data["settings"].get("autopilot_enabled", False)
    warn_days = q_data["settings"].get("buffer_warning_days", 7)

    lines = [
        "☀️ *Morning Report*",
        "━" * 24,
        f"📊 Buffer: *{buffer} days* | Queue: {queue_ct} beats",
        f"🤖 Autopilot: {'ON ✅' if autopilot else 'OFF ⏸'}",
    ]

    # ── Today's schedule (videos going live today) ──
    et_tz = _get_et_tz()
    today = datetime.now(et_tz).date()
    going_live = []
    for stem, entry in log_data.items():
        pa = entry.get("publishAt")
        if pa:
            try:
                from dateutil.parser import isoparse
                pub_dt = isoparse(pa).astimezone(et_tz)
                if pub_dt.date() == today:
                    going_live.append((stem, pub_dt.strftime("%-I:%M %p")))
            except Exception:
                pass
    if going_live:
        gl_str = ", ".join(f"{s} @ {t}" for s, t in going_live[:4])
        if len(going_live) > 4:
            gl_str += f" +{len(going_live) - 4} more"
        lines.append(f"📅 Going live: {gl_str}")

    lines.append("")

    # ── Inventory ──
    lines.extend([
        f"🎵 Beats: {len(beats)} | 🎬 Rendered: {len(rendered)} | ☁️ Uploaded: {len(uploaded)}",
    ])
    if not_rendered:
        lines.append(f"🔲 Not rendered: {len(not_rendered)}")
    if not_uploaded > 0:
        lines.append(f"📤 Ready to upload: {not_uploaded}")

    # ── Cross-platform stats (last 24h) ──
    try:
        from social_upload import load_social_log
        slog = load_social_log()
        now_utc = datetime.now(timezone.utc)
        yt_24h = tt_24h = ig_24h = shorts_24h = 0
        for stem, platforms in slog.items():
            for plat, pdata in platforms.items():
                ts = pdata.get("uploaded_at") or pdata.get("timestamp") or ""
                if ts:
                    try:
                        from dateutil.parser import isoparse
                        dt = isoparse(ts)
                        if (now_utc - dt).total_seconds() < 86400:
                            if plat == "tiktok": tt_24h += 1
                            elif plat == "instagram": ig_24h += 1
                            elif plat == "youtube_shorts": shorts_24h += 1
                    except Exception:
                        pass
        # Count YouTube uploads in last 24h
        for stem, entry in log_data.items():
            ts = entry.get("uploadedAt", "")
            if ts:
                try:
                    from dateutil.parser import isoparse
                    dt = isoparse(ts)
                    if (now_utc - dt).total_seconds() < 86400:
                        yt_24h += 1
                except Exception:
                    pass
        if yt_24h or shorts_24h or tt_24h or ig_24h:
            lines.append(
                f"\n*Yesterday:*\n"
                f"  📺 YouTube: {yt_24h} | 🎬 Shorts: {shorts_24h}\n"
                f"  🎵 TikTok: {tt_24h} | 📸 IG: {ig_24h}"
            )
    except Exception as se:
        log.warning("Morning report social stats failed: %s", se)

    # ── Buffer warning ──
    if buffer < warn_days:
        lines.append(f"\n⚠️ *Only {buffer} days of content left — time to cook!*")
    elif not not_rendered and not_uploaded == 0 and queue_ct == 0:
        lines.append("\n⚠️ *Queue is empty — drop beats here or run /seedqueue*")

    # ── Health check section ──────────────────────────────────────────────────
    try:
        health_issues = await asyncio.get_event_loop().run_in_executor(None, _run_bug_scan, app)
        lines.append("\n🔍 *Health Check:*")
        if health_issues:
            for issue in health_issues[:6]:
                lines.append(f"  {issue}")
            if len(health_issues) > 6:
                lines.append(f"  _…and {len(health_issues) - 6} more — run /bugbot for full report_")
        else:
            lines.append("  ✅ All systems healthy")
    except Exception as he:
        log.warning("Health check in morning report failed: %s", he)

    try:
        await app.bot.send_message(
            chat_id=ALLOWED_ID,
            text="\n".join(lines),
            parse_mode="Markdown",
        )
    except Exception as e:
        log.warning("Morning report failed: %s", e)


async def _daily_report_job(app):
    """Background coroutine — fires at 8 AM ET (13:00 UTC) every day."""
    while True:
        now_utc    = datetime.now(timezone.utc)
        target_utc = now_utc.replace(hour=13, minute=0, second=0, microsecond=0)
        if now_utc >= target_utc:
            target_utc += timedelta(days=1)
        wait_secs = (target_utc - now_utc).total_seconds()
        log.info("Morning report in %.0f s (%.1f h)", wait_secs, wait_secs / 3600)
        await asyncio.sleep(wait_secs)
        await _send_morning_report(app)


# ── /videoedit — beat-synced LIT video editor ─────────────────────────────────

VIDEOEDIT_PICK  = 90   # waiting for beat selection
VIDEOEDIT_STYLE = 91   # waiting for intensity selection

_VE_PAGE_SIZE = 8


def _ve_beat_keyboard(page: int = 0) -> InlineKeyboardMarkup:
    """Paged inline keyboard listing all available beats."""
    stems = sorted(
        safe_stem(b)
        for b in (list((ROOT / "beats").glob("*.mp3")) +
                  list((ROOT / "beats").glob("*.wav")))
    )
    total_pages = max(1, (len(stems) + _VE_PAGE_SIZE - 1) // _VE_PAGE_SIZE)
    page = max(0, min(page, total_pages - 1))
    start = page * _VE_PAGE_SIZE
    chunk = stems[start:start + _VE_PAGE_SIZE]

    rows = [[InlineKeyboardButton(s, callback_data=f"ve:beat:{s}:{page}")]
            for s in chunk]

    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("◀ Prev", callback_data=f"ve:page:{page - 1}"))
    if page < total_pages - 1:
        nav.append(InlineKeyboardButton("Next ▶", callback_data=f"ve:page:{page + 1}"))
    if nav:
        rows.append(nav)

    rows.append([InlineKeyboardButton("❌ Cancel", callback_data="ve:cancel")])
    return InlineKeyboardMarkup(rows)


def _ve_style_keyboard(stem: str) -> InlineKeyboardMarkup:
    return InlineKeyboardMarkup([
        [InlineKeyboardButton("🔥 Subtle",       callback_data=f"ve:style:{stem}:subtle")],
        [InlineKeyboardButton("🔥🔥 Medium",     callback_data=f"ve:style:{stem}:medium")],
        [InlineKeyboardButton("🔥🔥🔥 FIRE",     callback_data=f"ve:style:{stem}:fire")],
        [InlineKeyboardButton("❌ Cancel",        callback_data="ve:cancel")],
    ])


