    # ── Global error handler — transient-aware, never spams user ─────────────
    async def _error_handler(update: object, context: ContextTypes.DEFAULT_TYPE):
        err = context.error
        # Transient network blips — just log as warning, don't touch user
        if isinstance(err, (TimedOut, NetworkError)):
            log.warning("Transient network error (auto-recovered): %s", err)
            return
        # Rate limit — log only
        if isinstance(err, RetryAfter):
            log.warning("Rate limited by Telegram for %ss", getattr(err, "retry_after", "?"))
            return
        # Everything else — log full traceback + notify user
        log.error("Unhandled exception", exc_info=err)
        try:
            msg_text = f"⚠️ Internal error: `{esc(str(err)[:200])}`"
            if isinstance(update, Update):
                if update.callback_query:
                    await update.callback_query.answer("⚠️ Something went wrong. Try again.", show_alert=True)
                elif update.message:
                    await update.message.reply_text(msg_text, parse_mode="Markdown")
        except Exception:
            pass

