    import time as _time
    _restart_count = 0
    # Infinite restart loop — never gives up.
    # If the bot ran >60s before crashing, it was healthy → reset backoff counter.
    while True:
        _t_start = _time.monotonic()
        try:
            main()
            break  # clean exit via /restart (os.execv) — should never reach here normally
        except Exception as _exc:
            _uptime = _time.monotonic() - _t_start
            if _uptime > 60:
                _restart_count = 0   # was running fine — treat as fresh start
            _restart_count += 1
            _wait = min(60, 5 * _restart_count)
            log.warning(
                "[AUTO-RESTART #%d] crashed after %.0fs: %r — waiting %ds before restart",
                _restart_count, _uptime, _exc, _wait,
            )
            _time.sleep(_wait)
